import {
  Component,
  computed,
  effect,
  inject,
  input,
  signal,
  TemplateRef,
  ViewChild,
} from '@angular/core';
import { Validators, FormGroup } from '@angular/forms';
import { CommonModule } from '@angular/common';
import { takeUntilDestroyed } from '@angular/core/rxjs-interop';
import { finalize } from 'rxjs';

import { ButtonModule } from 'primeng/button';
import { InputTextModule } from 'primeng/inputtext';
import { Observable } from 'rxjs';
import { faPalette } from '@fortawesome/free-solid-svg-icons';
import { FontAwesomeModule } from '@fortawesome/angular-fontawesome';
import { v4 as uuidv4 } from 'uuid';

import {
  ThemeListItem,
  ThemeCreateRequest,
  ThemeUpdateRequest,
  EntitiesService,
  ThemeResponse,
  ThemeCustomHTMLTag,
} from '../../../../../api';
import {
  createDropdownField,
  createModalListField,
  createTextAreaField,
  createTextField,
  FieldConfiguration,
  FormFieldConfig,
  ListFieldModalConfig,
} from '../../../../../shared/models';
import { EntitySectionBaseComponent } from '../../base';
import {
  isDefined,
  isEmpty,
  isNullOrUndefined,
} from '../../../../../shared/utils';
import {
  LogoCustomizationSectionComponent,
  LogoCustomizationConfig,
} from '../../shared/logo-customization-section/logo-customization-section.component';
import { DynamicFormComponent } from '../../../../../shared/components/forms/dynamic-form/dynamic-form.component';
import { GridComponent } from '../../../../../shared/components/grid/grid.component';
import { EntityOperationRegistryService } from '../../../services/entity/entity-operation-registry.service';
import { ModalListFormComponent } from '../../../../../shared/components/forms/modal-list-form/modal-list-form.component';
import { LogoTemplateContext } from '../../../models';
import { ApiUrlService } from '../../../../../core/services/api-url.service';

type ThemeEntity = ThemeListItem | Partial<ThemeCreateRequest>;
interface CustomTag extends ThemeCustomHTMLTag {
  id: string;
}

@Component({
  selector: 'app-theme-details-section',
  imports: [
    CommonModule,
    ButtonModule,
    InputTextModule,
    GridComponent,
    DynamicFormComponent,
    FontAwesomeModule,
    LogoCustomizationSectionComponent,
  ],
  templateUrl: './theme-details-section.component.html',
  styleUrl: './theme-details-section.component.scss',
})
export class ThemeDetailsSectionComponent extends EntitySectionBaseComponent<ThemeEntity> {
  @ViewChild('customTemplate', { static: true }) logoTemplate:
    | TemplateRef<LogoTemplateContext>
    | undefined;

  @ViewChild(LogoCustomizationSectionComponent) logoSectionRef:
    | LogoCustomizationSectionComponent
    | undefined;

  readonly ownerId = input<string | null>(null);
  readonly entitiesService = inject(EntitiesService);
  private readonly operationRegistry = inject(EntityOperationRegistryService);
  private readonly apiUrlService = inject(ApiUrlService);

  private readonly hasLogoChangesSignal = signal(false);
  private readonly logoUploadTimestamp = signal(Date.now());

  readonly logoConfig = computed((): LogoCustomizationConfig => {
    const entity = this.entity() as ThemeResponse;
    return {
      entityType: 'themes',
      entityId: isDefined(entity?.id) ? entity.id : '',
      apiBasePath: '/entities',
      sizes: ['small'],
    };
  });

  protected override actions = [
    {
      label: 'Cancel',
      action: () => {
        this.cancelEdit();
        this.logoSectionRef?.clearLogoChanges();
        this.hasLogoChangesSignal.set(false);
      },
      severity: 'secondary' as const,
    },
    {
      label: 'Save',
      action: (formData: FormGroup) => {
        this.onSubmit(formData);
      },
      severity: 'primary' as const,
      disabled: (form?: FormGroup) => {
        if (isNullOrUndefined(form)) return true;
        const hasFormChanges = !form.pristine && form.valid;
        return !hasFormChanges && !this.hasLogoChangesSignal();
      },
      loading: () => this.isSubmitting(),
    },
  ];

  onLogoChangesUpdate(hasChanges: boolean): void {
    this.hasLogoChangesSignal.set(hasChanges);
  }

  protected override onSubmit(formGroup: FormGroup): void {
    if (isNullOrUndefined(this.entity()) || !formGroup.valid) return;

    const formData = this.getDirtyValues(formGroup);
    const hasFormChanges = Object.keys(formData).length > 0;

    if (!hasFormChanges && !this.hasLogoChangesSignal()) {
      this.isFormEditable.set(false);
      return;
    }

    this.submitChanges(formData);
  }

  protected override submitChanges(
    formData: Record<string, unknown> | Record<string, string | number>[],
  ): void {
    const currentTheme = this.entity() as ThemeResponse;
    if (isNullOrUndefined(currentTheme)) return;

    this.isFormEditable.set(false);
    this.isSubmitting.set(true);

    const logoComponent = this.logoSectionRef;
    if (logoComponent?.hasLogoChanges() === true) {
      logoComponent
        .uploadLogos()
        .then(() => this.updateThemeDetails(currentTheme.id, formData))
        .catch(() => {
          this.isFormEditable.set(true);
          this.isSubmitting.set(false);
        });
    } else {
      this.updateThemeDetails(currentTheme.id, formData);
    }
  }

  private updateThemeDetails(
    themeId: string,
    formData: Record<string, unknown> | Record<string, string | number>[],
  ): void {
    this.entitiesService
      .updateTheme(themeId, formData as ThemeUpdateRequest)
      .pipe(
        takeUntilDestroyed(this.destroyRef),
        finalize(() => this.isSubmitting.set(false)),
      )
      .subscribe({
        next: (response) => {
          this.clearUnsavedChanges();
          this.isFormEditable.set(false);
          this.logoSectionRef?.clearLogoChanges();
          this.hasLogoChangesSignal.set(false);
          // Bust the browser image cache so the grid shows the new logo
          this.logoUploadTimestamp.set(Date.now());
          this.broadcastService.broadcast('entity-updated', {
            entityType: 'theme',
            operation: 'update',
            entityId: themeId,
            data: response,
          });
        },
        error: () => {
          this.isFormEditable.set(true);
        },
      });
  }

  readonly themeDetails = computed(() => {
    const themeDetails = this.entity();
    if (!isDefined(themeDetails)) return [];

    return [
      { key: 'Name', value: themeDetails.name },
      {
        key: 'Description',
        value:
          themeDetails.description ??
          this.translate.instant('SHARED.COMMON.NONE'),
      },
      {
        key: 'Custom CSS Link',
        value: isEmpty(themeDetails?.settings?.cssSrc)
          ? this.translate.instant('SHARED.COMMON.NONE')
          : themeDetails.settings.cssSrc,
      },
      {
        key: 'Custom Tags',
        value:
          (themeDetails?.customTags?.length ?? 0) > 0
            ? themeDetails.customTags
                .map((tag: CustomTag) => tag.name)
                .join(', ')
            : this.translate.instant('SHARED.COMMON.NONE'),
      },
      {
        key: 'Web Logo',
        value: '',
        imageUrl: `${this.apiUrlService.getCurrentApiUrl()}/entities/themes/${themeDetails.id}/logo?size=small&t=${this.logoUploadTimestamp()}`,
      },
    ];
  });

  faPalette = faPalette;
  customHtmlTagModalConfig: ListFieldModalConfig<CustomTag> | undefined;

  constructor() {
    super();

    effect(() => {
      if (this.logoTemplate) {
        this.columns = [
          { field: 'key', header: '', transform: 'uppercase' },
          { field: 'value', header: '', cellTemplate: this.logoTemplate },
        ];
      }
    });
  }

  protected override updateFormFields(): void {
    const theme = this.entity();

    this.customHtmlTagModalConfig = {
      modalComponent: ModalListFormComponent,
      modalTitle: 'Custom HTML Tags',
      subHeader:
        'Enter the details for an HTML tag that will be injected into the page at your chosen location.',
      defaultItemProvider: () => ({
        id: uuidv4(),
        name: '',
        tag: 'script',
        location: 'head',
        attributes: '',
        contents: '',
      }),
      listItemFormatter: (item: CustomTag) => this.stateItemToListItem(item),
      modalFields: (item: CustomTag | undefined): FormFieldConfig[] => {
        return [
          createTextField('name', 'Name', item?.name, {
            name: 'name',
            validations: [
              {
                name: 'required',
                validator: Validators.required,
                message: 'Name is required',
              },
            ],
          }),
          createDropdownField(
            'location',
            'Location',
            [
              { label: 'Header', value: 'head' },
              { label: 'Body', value: 'body' },
            ],
            item?.location,
            {
              name: 'location',

              validations: [
                {
                  name: 'required',
                  validator: Validators.required,
                  message: 'Location is required',
                },
              ],
            },
          ),
          createTextField('tag', 'Tag Type', item?.tag, {
            name: 'tag',
            validations: [
              {
                name: 'required',
                validator: Validators.required,
                message: 'Tag Type is required',
              },
            ],
          }),
          createTextAreaField(
            'attributes',
            'Tag Attributes',
            item?.attributes,
            {
              name: 'attributes',
              validations: [],
              props: { rows: 5 },
              hint: `A list of tag attributes, one per line, in the format: attr="value"`,
            },
          ),
          createTextAreaField('contents', 'Tag Contents', item?.contents, {
            name: 'contents',
            validations: [],
            props: { rows: 5 },
          }),
        ];
      },
    };

    this.formFields = [
      createTextField('name', 'Name', theme?.name, {
        name: 'name',
        validations: [
          {
            name: 'required',
            validator: Validators.required,
            message: 'Name is required',
          },
        ],
      }),
      createTextField('description', 'Description', theme?.description, {
        name: 'description',
        validations: [
          {
            name: 'required',
            validator: Validators.required,
            message: 'Description is required',
          },
        ],
      }),
      {
        name: 'settings',
        key: 'settings',
        type: 'group',
        fields: [
          createTextField(
            'cssSrc',
            'Custom CSS Link',
            theme?.settings?.cssSrc,
            {
              name: 'cssSrc',
              validations: [],
            },
          ),
        ],
      },
      ...(this.createMode()
        ? []
        : [
            createModalListField<CustomTag>(
              'customTags',
              'Custom Tags',
              theme?.customTags ?? [],
              {
                name: 'customTags',
                validations: [],
                props: {
                  modalConfig: this.customHtmlTagModalConfig,
                },
              },
            ) as FormFieldConfig<unknown>,
          ]),
    ];
  }

  override getUpdateMethod(): (
    id: string,
    data: Partial<ThemeEntity>,
  ) => Observable<ThemeResponse> {
    return (
      this.operationRegistry.getOperation<
        ThemeEntity,
        ThemeCreateRequest,
        ThemeResponse,
        'update'
      >('theme', 'update') ??
      ((id, data) => this.entitiesService.updateTheme(id, data))
    );
  }

  stateItemToListItem(item: CustomTag): FieldConfiguration {
    return {
      id: item.id,
      title: item.name,
      icon: 'code',
      display: '',
    };
  }
}
