import { CommonModule } from '@angular/common';
import {
  Component,
  computed,
  effect,
  inject,
  input,
  untracked,
} from '@angular/core';
import { Validators } from '@angular/forms';

import { ButtonModule } from 'primeng/button';
import { MessageModule } from 'primeng/message';
import { FontAwesomeModule } from '@fortawesome/angular-fontawesome';
import { faMap } from '@fortawesome/free-solid-svg-icons';
import { v4 as uuidv4 } from 'uuid';
import { Observable } from 'rxjs';

import {
  MapSetListItem,
  MapSetResponse,
  MapsetCreateRequest,
  MapSetLayer,
  EntitiesService,
} from '../../../../../api';
import { DynamicFormComponent } from '../../../../../shared/components/forms/dynamic-form/dynamic-form.component';
import { GridComponent } from '../../../../../shared/components/grid/grid.component';
import {
  createTextField,
  createNumberField,
  createDropdownField,
  createTextAreaField,
  createModalListField,
  FormFieldConfig,
  ListFieldModalConfig,
} from '../../../../../shared/models';
import { isDefined } from '../../../../../shared/utils';
import { EntitySectionBaseComponent } from '../../base';
import { ModalListFormComponent } from '../../../../../shared/components/forms/modal-list-form/modal-list-form.component';
import { EntityOperationRegistryService } from '../../../services/entity/entity-operation-registry.service';
import { TranslatePipe } from '@ngx-translate/core';

type FormValue = string | number | object | null | undefined;

interface LayerFormValue {
  servers?: string | string[];
  overlays?: LayerFormValue[];
  [key: string]: unknown;
}

@Component({
  selector: 'app-map-set-details-section',
  imports: [
    CommonModule,
    ButtonModule,
    GridComponent,
    DynamicFormComponent,
    MessageModule,
    FontAwesomeModule,
    TranslatePipe,
  ],
  templateUrl: './map-set-details-section.component.html',
  styleUrl: './map-set-details-section.component.scss',
})
export class MapSetDetailsSectionComponent extends EntitySectionBaseComponent<
  MapSetListItem | Partial<MapsetCreateRequest>
> {
  readonly ownerId = input<string | null>(null);
  private readonly entitiesService = inject(EntitiesService);
  private readonly operationRegistry = inject(EntityOperationRegistryService);

  readonly mapSetDetails = computed(() => {
    const mapSet = this.entity();
    this.languageService.currentLanguage();
    if (!isDefined(mapSet)) return [];

    const none = this.translate.instant('SHARED.COMMON.NONE');

    const layerNameList = (mapSet.layers ?? [])
      .map((l) => l.name ?? '')
      .filter((n) => n.length > 0);
    const layerNames =
      layerNameList.length > 0 ? layerNameList.join(', ') : none;

    const overlayNameList = (mapSet.overlays ?? [])
      .map((o) => o.name ?? '')
      .filter((n) => n.length > 0);
    const overlayNames =
      overlayNameList.length > 0 ? overlayNameList.join(', ') : none;

    return [
      {
        key: this.translate.instant('ADMIN.MAP_SETS.DETAILS.FIELDS.NAME'),
        value: mapSet.name,
      },
      {
        key: this.translate.instant('ADMIN.MAP_SETS.DETAILS.FIELDS.LAYERS'),
        value: layerNames,
      },
      {
        key: this.translate.instant('ADMIN.MAP_SETS.DETAILS.FIELDS.OVERLAYS'),
        value: overlayNames,
      },
    ];
  });

  mapSetLayersModalConfig: ListFieldModalConfig<MapSetLayer> | undefined;
  mapSetOverlaysModalConfig: ListFieldModalConfig<MapSetLayer> | undefined;
  faIconMap = faMap;

  constructor() {
    super();

    // Setup columns for the read-only grid view
    this.columns = [
      { field: 'key', header: '', transform: 'uppercase' },
      { field: 'value', header: '' },
    ];

    effect(() => {
      const entity = this.entity();
      if (isDefined(entity) && !this.createMode()) {
        untracked(() => {
          this.updateFormFields();
        });
      }
    });
  }

  protected override updateFormFields(): void {
    const mapSet = this.entity();

    const t = (key: string, params?: object) =>
      this.translate.instant(key, params);
    const req = (field: string) =>
      t('SHARED.COMMON.FORMS.SHARED.REQUIRED', { field });
    const numMin = (field: string, min: number) =>
      t('SHARED.COMMON.FORMS.NUMBER.MIN', { field, min });
    const numMax = (field: string, max: number) =>
      t('SHARED.COMMON.FORMS.NUMBER.MAX', { field, max });

    const nameLabel = t('ADMIN.MAP_SETS.DETAILS.MODAL.FIELDS.NAME');
    const attributionLabel = t(
      'ADMIN.MAP_SETS.DETAILS.MODAL.FIELDS.ATTRIBUTION',
    );
    const orderLabel = t('ADMIN.MAP_SETS.DETAILS.MODAL.FIELDS.ORDER');
    const minZoomLabel = t('ADMIN.MAP_SETS.DETAILS.MODAL.FIELDS.MIN_ZOOM');
    const maxZoomLabel = t('ADMIN.MAP_SETS.DETAILS.MODAL.FIELDS.MAX_ZOOM');
    const projectionLabel = t('ADMIN.MAP_SETS.DETAILS.MODAL.FIELDS.PROJECTION');
    const imageTypeLabel = t('ADMIN.MAP_SETS.DETAILS.MODAL.FIELDS.IMAGE_TYPE');
    const layerNameLabel = t('ADMIN.MAP_SETS.DETAILS.MODAL.FIELDS.LAYER_NAME');
    const serverTypeLabel = t(
      'ADMIN.MAP_SETS.DETAILS.MODAL.FIELDS.SERVER_TYPE',
    );
    const serversLabel = t('ADMIN.MAP_SETS.DETAILS.MODAL.FIELDS.SERVERS');

    // MapSetLayer Modal Form Configuration
    this.mapSetLayersModalConfig = {
      modalComponent: ModalListFormComponent,
      showEditButton: true,
      modalTitle: t('ADMIN.MAP_SETS.DETAILS.MODAL.TITLE.LAYER'),
      subHeader: t('ADMIN.MAP_SETS.DETAILS.MODAL.DESCRIPTION.LAYER'),
      defaultItemProvider: () => ({
        name: '',
        projection: 'EPSG:900913',
        minZoom: 0,
        maxZoom: 18,
        serverType: 'wms',
        order: 0,
        imageType: 'png',
        layerName: '',
        servers: [],
        overlays: [],
        attribution: null,
      }),
      listItemFormatter: (item: MapSetLayer) => {
        return {
          id: item.name ?? uuidv4(),
          title: item.name,
          display: t('ADMIN.MAP_SETS.DETAILS.MODAL.LAYER_DISPLAY', {
            serverType: item.serverType,
            minZoom: item.minZoom,
            maxZoom: item.maxZoom,
          }),
          icon: 'pi pi-map',
        };
      },
      modalFields: (item: MapSetLayer | undefined): FormFieldConfig[] => {
        // format server list to comma-separated text for editing in a textarea
        const formattedServers = Array.isArray(item?.servers)
          ? item.servers.join(', ')
          : '';

        return [
          createTextField('name', nameLabel, item?.name, {
            name: 'name',
            validations: [
              {
                name: 'required',
                validator: Validators.required,
                message: req(nameLabel),
              },
            ],
          }),
          createTextField('attribution', attributionLabel, item?.attribution, {
            name: 'attribution',
          }),
          createNumberField('order', orderLabel, item?.order ?? 0, {
            name: 'order',
            validations: [
              {
                name: 'required',
                validator: Validators.required,
                message: req(orderLabel),
              },
            ],
          }),
          createNumberField('minZoom', minZoomLabel, item?.minZoom ?? 0, {
            name: 'minZoom',
            validations: [
              {
                name: 'required',
                validator: Validators.required,
                message: req(minZoomLabel),
              },
              {
                name: 'min',
                validator: Validators.min(0),
                message: numMin(minZoomLabel, 0),
              },
              {
                name: 'max',
                validator: Validators.max(20),
                message: numMax(minZoomLabel, 20),
              },
            ],
          }),
          createNumberField('maxZoom', maxZoomLabel, item?.maxZoom ?? 18, {
            name: 'maxZoom',
            validations: [
              {
                name: 'required',
                validator: Validators.required,
                message: req(maxZoomLabel),
              },
              {
                name: 'min',
                validator: Validators.min(0),
                message: numMin(maxZoomLabel, 0),
              },
              {
                name: 'max',
                validator: Validators.max(20),
                message: numMax(maxZoomLabel, 20),
              },
            ],
          }),
          createDropdownField(
            'projection',
            projectionLabel,
            [
              { value: 'EPSG:900913', label: 'Mercator (EPSG:900913)' },
              { value: 'EPSG:4326', label: 'WGS84 (EPSG:4326)' },
            ],
            item?.projection ?? 'EPSG:900913',
            {
              name: 'projection',
              validations: [
                {
                  name: 'required',
                  validator: Validators.required,
                  message: req(projectionLabel),
                },
              ],
            },
          ),
          createDropdownField(
            'imageType',
            imageTypeLabel,
            [
              { value: 'png', label: 'PNG' },
              { value: 'jpg', label: 'JPG' },
              { value: 'jpeg', label: 'JPEG' },
              { value: 'gif', label: 'GIF' },
              { value: 'mvt', label: 'MVT' },
            ],
            item?.imageType ?? 'png',
            {
              name: 'imageType',
              validations: [
                {
                  name: 'required',
                  validator: Validators.required,
                  message: req(imageTypeLabel),
                },
              ],
            },
          ),
          createTextField('layerName', layerNameLabel, item?.layerName, {
            name: 'layerName',
            validations: [
              {
                name: 'required',
                validator: Validators.required,
                message: req(layerNameLabel),
              },
            ],
          }),
          createDropdownField(
            'serverType',
            serverTypeLabel,
            [
              { value: 'google', label: 'Google' },
              { value: 'wms', label: 'WMS' },
              { value: 'osm', label: 'OSM' },
              { value: 'wmts', label: 'WMTS' },
              { value: 'dds', label: 'DDS' },
              { value: 'tms', label: 'TMS' },
              { value: 'mbs', label: 'MapBox Style' },
            ],
            item?.serverType ?? 'wms',
            {
              name: 'serverType',
              validations: [
                {
                  name: 'required',
                  validator: Validators.required,
                  message: req(serverTypeLabel),
                },
              ],
            },
          ),
          createTextAreaField('servers', serversLabel, formattedServers, {
            name: 'servers',
            placeholder: 'http://server1.com, http://server2.com',
            validations: [
              {
                name: 'required',
                validator: Validators.required,
                message: t(
                  'ADMIN.MAP_SETS.DETAILS.MODAL.VALIDATION.SERVERS_REQUIRED',
                ),
              },
            ],
          }),
        ];
      },
    };

    // MapSetOverlay Modal Form Configuration
    this.mapSetOverlaysModalConfig = {
      ...this.mapSetLayersModalConfig,
      modalTitle: t('ADMIN.MAP_SETS.DETAILS.MODAL.TITLE.OVERLAY'),
      subHeader: t('ADMIN.MAP_SETS.DETAILS.MODAL.DESCRIPTION.OVERLAY'),
    };

    // format the servers lists inside layers/overlays to comma-separated strings for dynamic forms editing
    const formatLayersForForm = (
      layersList: MapSetLayer[] = [],
    ): MapSetLayer[] => {
      return layersList.map((layer) => ({
        ...layer,
        servers: Array.isArray(layer.servers)
          ? (layer.servers.join(', ') as unknown as string[])
          : layer.servers,
        overlays: formatLayersForForm(layer.overlays),
      }));
    };

    const fieldNameLabel = t('ADMIN.MAP_SETS.DETAILS.FIELDS.NAME');
    this.formFields = [
      createTextField('name', fieldNameLabel, mapSet?.name, {
        name: 'name',
        validations: [
          {
            name: 'required',
            validator: Validators.required,
            message: req(fieldNameLabel),
          },
        ],
      }),
    ];

    this.formFields.push(
      createModalListField<MapSetLayer>(
        'layers',
        t('ADMIN.MAP_SETS.DETAILS.FIELDS.LAYERS'),
        formatLayersForForm(mapSet?.layers ?? []),
        {
          layout: 'horizontal',
          labelWidth: '1/3',
          name: 'layers',
          props: {
            modalConfig: this.mapSetLayersModalConfig,
          },
        },
      ) as FormFieldConfig<unknown>,
      createModalListField<MapSetLayer>(
        'overlays',
        t('ADMIN.MAP_SETS.DETAILS.FIELDS.OVERLAYS'),
        formatLayersForForm(mapSet?.overlays ?? []),
        {
          layout: 'horizontal',
          labelWidth: '1/3',
          name: 'overlays',
          props: {
            modalConfig: this.mapSetOverlaysModalConfig,
          },
        },
      ) as FormFieldConfig<unknown>,
    );
  }

  override getUpdateMethod(): (
    id: string,
    data: Partial<MapSetResponse | MapsetCreateRequest>,
  ) => Observable<MapSetResponse> {
    return (
      this.operationRegistry.getOperation<
        MapSetResponse | MapsetCreateRequest,
        MapsetCreateRequest,
        MapSetResponse,
        'update'
      >('map-set', 'update') ??
      ((id, data) => this.entitiesService.updateMapSet(id, data))
    );
  }

  protected override onFormValueChange(
    formData: Record<string, FormValue>,
  ): void {
    const transformedData = this.transformFormData(formData);
    this.formValueChange.emit(transformedData);
  }

  protected override transformFormData(
    formData: Record<string, unknown>,
  ): Record<string, string | number | object | null | undefined> {
    const transformedData = { ...formData };

    const transformLayer = (layer: LayerFormValue): MapSetLayer => {
      const updatedLayer = { ...layer };
      if (typeof updatedLayer.servers === 'string') {
        updatedLayer.servers = updatedLayer.servers
          .split(',')
          .map((s: string) => s.trim())
          .filter(Boolean);
      }
      if (Array.isArray(updatedLayer.overlays)) {
        updatedLayer.overlays = updatedLayer.overlays.map(transformLayer);
      }
      return updatedLayer as MapSetLayer;
    };

    if (Array.isArray(transformedData['layers'])) {
      transformedData['layers'] = transformedData['layers'].map(transformLayer);
    }
    if (Array.isArray(transformedData['overlays'])) {
      transformedData['overlays'] =
        transformedData['overlays'].map(transformLayer);
    }

    return transformedData as Record<
      string,
      string | number | object | null | undefined
    >;
  }
}
