import { CommonModule } from '@angular/common';
import { Component, computed, inject } from '@angular/core';
import { Validators } from '@angular/forms';
import { EMPTY, Observable } from 'rxjs';

import { ButtonModule } from 'primeng/button';

import {
  UserRoleListItem,
  UserRoleCreateRequest,
  AccountsService,
} from '../../../../../api';
import { DynamicFormComponent } from '../../../../../shared/components/forms/dynamic-form/dynamic-form.component';
import { GridComponent } from '../../../../../shared/components/grid/grid.component';
import { createTextField } from '../../../../../shared/models';
import { isDefined, isNullOrUndefined } from '../../../../../shared/utils';
import { EntitySectionBaseComponent } from '../../base';
import { MessageModule } from 'primeng/message';
import { FontAwesomeModule } from '@fortawesome/angular-fontawesome';
import { faUserLock } from '@fortawesome/free-solid-svg-icons';
import { TranslatePipe } from '@ngx-translate/core';

@Component({
  selector: 'app-user-role-details-section',
  imports: [
    CommonModule,
    ButtonModule,
    GridComponent,
    DynamicFormComponent,
    MessageModule,
    FontAwesomeModule,
    TranslatePipe,
  ],
  templateUrl: './user-role-details-section.component.html',
  styleUrl: './user-role-details-section.component.scss',
})
export class UserRoleDetailsSectionComponent extends EntitySectionBaseComponent<
  UserRoleListItem | Partial<UserRoleCreateRequest>
> {
  private readonly accountsService = inject(AccountsService);
  faUserLock = faUserLock;

  readonly userRoleDetails = computed(() => {
    const userRoleDetails = this.entity();
    if (!isDefined(userRoleDetails)) return [];

    return [
      {
        key: this.translate.instant('ADMIN.USER_ROLES.DETAILS.FIELDS.NAME'),
        value: userRoleDetails.name,
      },
      {
        key: this.translate.instant(
          'ADMIN.USER_ROLES.DETAILS.FIELDS.DESCRIPTION',
        ),
        value: userRoleDetails.description,
      },
    ];
  });

  constructor() {
    super();

    // Setup initial columns
    this.columns = [
      { field: 'key', header: '', transform: 'uppercase' },
      { field: 'value', header: '' },
    ];
  }

  protected override updateFormFields(): void {
    const userRole = this.entity();

    this.formFields = [
      createTextField(
        'name',
        this.translate.instant('ADMIN.USER_ROLES.DETAILS.FIELDS.NAME'),
        userRole?.name,
        {
          name: 'name',
          validations: [
            {
              name: 'required',
              validator: Validators.required,
              message: 'Name is required',
            },
          ],
        },
      ),
      createTextField(
        'description',
        this.translate.instant('ADMIN.USER_ROLES.DETAILS.FIELDS.DESCRIPTION'),
        userRole?.description,
        {
          name: 'description',
          validations: [
            {
              name: 'required',
              validator: Validators.required,
              message: 'Description is required',
            },
          ],
        },
      ),
    ];
  }

  protected override buildUpdateRequest(
    formData: Record<string, unknown>,
  ): Observable<unknown> {
    const userRole = this.entity();
    if (isNullOrUndefined(userRole)) return EMPTY;
    return this.accountsService.updateUserRole(userRole.id, formData);
  }

  protected override onSubmitSuccess(response: unknown): void {
    const userRole = this.entity();
    if (isNullOrUndefined(userRole)) return;
    this.broadcastService.broadcast('entity-updated', {
      entityType: 'user-role',
      operation: 'update',
      entityId: userRole.id,
      data: response,
    });
  }
}
