import {
  ChangeDetectorRef,
  Component,
  computed,
  effect,
  inject,
  input,
  OnInit,
  signal,
  untracked,
} from '@angular/core';
import { isDefined, isNullOrUndefined } from '../../../../../shared/utils';
import { CommonModule } from '@angular/common';
import { takeUntilDestroyed } from '@angular/core/rxjs-interop';
import { ReactiveFormsModule, Validators } from '@angular/forms';

import {
  AssetTagListItem,
  AssetTagCreateRequest,
  EntitiesService,
} from '../../../../../api';
import { DynamicFormComponent } from '../../../../../shared/components/forms/dynamic-form/dynamic-form.component';
import { GridComponent } from '../../../../../shared/components/grid/grid.component';
import {
  createDropdownField,
  createTextField,
} from '../../../../../shared/models';
import { EntitySectionBaseComponent } from '../../base';
import { TranslatePipe } from '@ngx-translate/core';
import { EMPTY, Observable } from 'rxjs';

@Component({
  selector: 'app-asset-tag-details-section',
  imports: [
    CommonModule,
    ReactiveFormsModule,
    GridComponent,
    DynamicFormComponent,
    TranslatePipe,
  ],
  templateUrl: './asset-tag-details-section.component.html',
  styleUrl: './asset-tag-details-section.component.scss',
})
export class AssetTagDetailsSectionComponent
  extends EntitySectionBaseComponent<
    AssetTagListItem | Partial<AssetTagCreateRequest>
  >
  implements OnInit
{
  readonly ownerId = input<string | null>(null);
  private readonly entitiesService = inject(EntitiesService);

  private readonly cdr = inject(ChangeDetectorRef);
  protected readonly selectOptionsLoaded = signal<boolean>(false);

  readonly assetTagDetails = computed(() => {
    const assetTagDetails = this.entity();
    this.languageService.currentLanguage();

    if (!isDefined(assetTagDetails)) return [];

    return [
      {
        key: this.translate.instant('ADMIN.ASSET_TAGS.DETAILS.FIELDS.NAME'),
        value: assetTagDetails.name,
      },
      {
        key: this.translate.instant(
          'ADMIN.ASSET_TAGS.DETAILS.FIELDS.SERIAL_NUMBER',
        ),
        value:
          assetTagDetails.serialNumber ??
          this.translate.instant('SHARED.COMMON.NONE'),
      },
      {
        key: this.translate.instant(
          'ADMIN.ASSET_TAGS.DETAILS.FIELDS.ASSET_TAG_TYPE',
        ),
        value:
          assetTagDetails.assetTagType?.name ??
          this.translate.instant('SHARED.COMMON.NONE'),
      },
      {
        key: this.translate.instant('ADMIN.ASSET_TAGS.DETAILS.FIELDS.MODE'),
        value:
          assetTagDetails.mode ?? this.translate.instant('SHARED.COMMON.NONE'),
      },
    ];
  });
  selectOptions: Record<string, { label: string; value: string }[]> = {};

  constructor() {
    super();

    // Setup initial columns
    this.columns = [
      { field: 'key', header: '', transform: 'uppercase' },
      { field: 'value', header: '' },
    ];

    effect(() => {
      const selectOptionsLoaded = this.selectOptionsLoaded();
      if (selectOptionsLoaded) {
        untracked(() => {
          this.updateFormFields();
          this.cdr.detectChanges();
        });
      }
    });
  }

  ngOnInit(): void {
    this.loadSelectOptions();
  }

  private loadSelectOptions(): void {
    const asset = this.entity();
    const ownerIdValue = this.ownerId();

    const effectiveOwnerId = asset?.owner?.id ?? ownerIdValue;

    if (isNullOrUndefined(effectiveOwnerId)) {
      this.selectOptions = {};
      this.selectOptionsLoaded.set(true);
      this.updateFormFields();
      return;
    }

    this.entitiesService
      .listAssetTagTypes(effectiveOwnerId)
      .pipe(takeUntilDestroyed(this.destroyRef))
      .subscribe((result) => {
        this.selectOptions = {
          assetTagTypes: result.items
            .map((item) => ({ label: item.name ?? '', value: item.id }))
            .sort((a, b) => a.label.localeCompare(b.label)),
        };

        this.selectOptionsLoaded.set(true);
      });
  }

  protected override updateFormFields(): void {
    const assetTag = this.entity();
    this.formFields = [
      createTextField(
        'name',
        this.translate.instant('ADMIN.ASSET_TAGS.DETAILS.FIELDS.NAME'),
        assetTag?.name,
        {
          name: 'name',
          validations: [
            {
              name: 'required',
              validator: Validators.required,
              message: this.translate.instant(
                'SHARED.COMMON.FORMS.SHARED.REQUIRED',
                {
                  field: this.translate.instant(
                    'ADMIN.ASSET_TAGS.DETAILS.FIELDS.NAME',
                  ),
                },
              ),
            },
          ],
        },
      ),

      createTextField(
        'serialNumber',
        this.translate.instant('ADMIN.ASSET_TAGS.DETAILS.FIELDS.SERIAL_NUMBER'),
        assetTag?.serialNumber,
        {
          name: 'serialNumber',
          validations: [
            {
              name: 'required',
              validator: Validators.required,
              message: this.translate.instant(
                'SHARED.COMMON.FORMS.SHARED.REQUIRED',
                {
                  field: this.translate.instant(
                    'ADMIN.ASSET_TAGS.DETAILS.FIELDS.SERIAL_NUMBER',
                  ),
                },
              ),
            },
          ],
        },
      ),

      createDropdownField(
        'assetTagType',
        this.translate.instant(
          'ADMIN.ASSET_TAGS.DETAILS.FIELDS.ASSET_TAG_TYPE',
        ),
        this.selectOptions?.['assetTagTypes'] ?? [],
        assetTag?.assetTagType?.id,
        {
          name: 'assetTagType',
          validations: [
            {
              name: 'required',
              validator: Validators.required,
              message: this.translate.instant(
                'SHARED.COMMON.FORMS.SHARED.REQUIRED',
                {
                  field: this.translate.instant(
                    'ADMIN.ASSET_TAGS.DETAILS.FIELDS.ASSET_TAG_TYPE',
                  ),
                },
              ),
            },
          ],
          props: {
            appendTo: 'body',
          },
        },
      ),
      createDropdownField(
        'mode',
        this.translate.instant('ADMIN.ASSET_TAGS.DETAILS.FIELDS.MODE'),
        [
          {
            label: this.translate.instant('ADMIN.ASSET_TAGS.MODES.FIXED'),
            value: 'fixed',
          },
          {
            label: this.translate.instant('ADMIN.ASSET_TAGS.MODES.MOVABLE'),
            value: 'movable',
          },
          {
            label: this.translate.instant('ADMIN.ASSET_TAGS.MODES.STOCK'),
            value: 'stock',
          },
        ],
        assetTag?.mode,
        {
          name: 'mode',
          validations: [
            {
              name: 'required',
              validator: Validators.required,
              message: this.translate.instant(
                'SHARED.COMMON.FORMS.SHARED.REQUIRED',
                {
                  field: this.translate.instant(
                    'ADMIN.ASSET_TAGS.DETAILS.FIELDS.MODE',
                  ),
                },
              ),
            },
          ],
          props: {
            appendTo: 'body',
          },
        },
      ),
    ];
  }

  protected override buildUpdateRequest(
    formData: Record<string, unknown>,
  ): Observable<unknown> {
    const assetTag = this.entity();
    if (isNullOrUndefined(assetTag)) return EMPTY;
    const updatedData = { ...formData };
    if (isDefined(updatedData['assetTagType'])) {
      const tagTypeId = updatedData['assetTagType'] as string;
      const tagType = this.selectOptions?.['assetTagTypes']?.find(
        (option) => option.value === tagTypeId,
      );
      updatedData['assetTagType'] = tagType
        ? { id: tagTypeId, name: tagType.label }
        : {
            id: tagTypeId,
            name: assetTag.assetTagType?.name ?? 'Unknown Tag Type',
          };
    }
    return this.entitiesService.updateAssetTag(assetTag.id, updatedData);
  }

  protected override onSubmitSuccess(response: unknown): void {
    const assetTag = this.entity();
    if (isNullOrUndefined(assetTag)) return;
    this.broadcastService.broadcast('entity-updated', {
      entityType: 'asset-tag',
      operation: 'update',
      entityId: assetTag.id,
      data: response,
    });
  }

  protected override onFormValueChange(
    formData: Record<string, string | number | object>,
  ): void {
    const transformedData = { ...formData };
    if (isDefined(transformedData['assetTagType'])) {
      const tagTypeId = transformedData['assetTagType'] as string;
      const tagType = this.selectOptions?.['assetTagTypes']?.find(
        (option) => option.value === tagTypeId,
      );
      if (tagType) {
        transformedData['assetTagType'] = {
          id: tagTypeId,
          name: tagType.label,
        };
      }
    }

    this.formValueChange.emit(transformedData);
  }
}
