import {
  Component,
  computed,
  effect,
  inject,
  input,
  signal,
  untracked,
} from '@angular/core';
import { takeUntilDestroyed } from '@angular/core/rxjs-interop';

import {
  AssetListItem,
  EntitiesService,
  TelemetryStateResponse,
} from '../../../../../api';
import {
  createDateField,
  createNumberField,
  MeasurementUnitType,
} from '../../../../../shared/models';
import {
  isDefined,
  isEmpty,
  isNullOrUndefined,
} from '../../../../../shared/utils';
import { EntitySectionBaseComponent } from '../../base';
import { MeasurementUnitsService } from '../../../../../shared/services/measurement-units/measurement-units.service';
import { ApiSchemaService } from '../../../../../core/services/api-schema.service';
import { CommonModule } from '@angular/common';
import { MessageModule } from 'primeng/message';
import { GridComponent } from '../../../../../shared/components/grid/grid.component';
import { catchError, EMPTY, finalize, Subject, switchMap } from 'rxjs';
import { AssetOdoHourChangesSectionComponent } from '../asset-odo-hour-changes-section/asset-odo-hour-changes-section.component';
import { DynamicFormComponent } from '../../../../../shared/components/forms/dynamic-form/dynamic-form.component';
import { TranslatePipe } from '@ngx-translate/core';

@Component({
  selector: 'app-asset-counter-type-section',
  imports: [
    CommonModule,
    MessageModule,
    GridComponent,
    DynamicFormComponent,
    AssetOdoHourChangesSectionComponent,
    TranslatePipe,
  ],
  templateUrl: './asset-counter-type-section.component.html',
  styleUrls: ['./asset-counter-type-section.component.scss'],
})
export class AssetCounterTypeSectionComponent extends EntitySectionBaseComponent<AssetListItem> {
  counterType = input<'hours' | 'odometer'>('hours');
  location = input<TelemetryStateResponse | null>(null);

  private readonly entitiesService = inject(EntitiesService);
  private readonly measurementsService = inject(MeasurementUnitsService);
  readonly apiSchemaService = inject(ApiSchemaService);

  private readonly assetLocation = signal<TelemetryStateResponse | null>(null);

  /** Subject to trigger asset location loads */
  private readonly assetIdSource = new Subject<string>();

  /** Warning when counters are unavailable */
  protected readonly warning = computed(() => {
    this.languageService.currentLanguage();
    const location = this.assetLocation();
    if (!(location?.countersAvailable ?? false)) {
      return this.translate.instant(
        'ADMIN.ASSETS.COUNTERS.WARNINGS.UNAVAILABLE',
      );
    }
    return null;
  });

  /** Whether the counter can be edited — only on legacy schema when counters are available */
  protected readonly canEdit = computed(() => {
    if (this.apiSchemaService.usesModernSchema()) return false;
    const location = this.assetLocation();
    return location?.countersAvailable === true;
  });

  private formatDateString(dateString: string | undefined): string {
    if (!isDefined(dateString)) return '';
    try {
      const date = new Date(dateString);
      if (Number.isNaN(date.getTime())) return 'Invalid Date';
      return date.toLocaleDateString(undefined, {
        weekday: 'long',
        day: 'numeric',
        month: 'long',
      });
    } catch (e) {
      console.error('Error parsing date:', e);
      return 'Invalid Date';
    }
  }

  private toDisplayValue(value: number): number {
    if (this.counterType() === 'odometer') {
      return this.measurementsService.fromBackend(
        MeasurementUnitType.DISTANCE,
        value,
        4,
      );
    }
    if (this.counterType() === 'hours') {
      return Math.round(value * 10) / 10;
    }
    return value;
  }

  private toBackendValue(value: number | string): number {
    const numValue = Number(value);
    if (this.counterType() === 'odometer') {
      return Number(
        this.measurementsService.toBackend(
          MeasurementUnitType.DISTANCE,
          numValue,
          4,
        ),
      );
    }
    if (this.counterType() === 'hours') {
      return Math.round(numValue * 10) / 10;
    }
    return numValue;
  }

  private getCounterLabel(): string {
    return this.counterType() === 'odometer'
      ? this.translate.instant('ADMIN.ASSETS.COUNTERS.ODOMETER.TITLE')
      : this.translate.instant('ADMIN.ASSETS.COUNTERS.HOURS.TITLE');
  }

  /**
   * Resolves the raw odometer value to display. Prefers the device's own
   * telemetry reading over the managed counter so the live view shows the real
   * device odometer rather than an odo-change-adjusted value.
   * Order: telemetry.odometer -> telemetry.total_mileage -> counters.odometer.
   * Hours always uses the managed counter.
   */
  private getDisplayRawValue(location: TelemetryStateResponse | null): number {
    if (this.counterType() === 'odometer') {
      const telemetry = location?.telemetry as
        | Record<string, unknown>
        | undefined;
      const readNumber = (key: string): number | undefined => {
        const value = telemetry?.[key];
        return typeof value === 'number' && Number.isFinite(value) && value > 0
          ? value
          : undefined;
      };
      const deviceOdometer =
        readNumber('odometer') ?? readNumber('total_mileage');
      if (isDefined(deviceOdometer)) return deviceOdometer;
    }
    return location?.counters?.[this.counterType()] ?? 0;
  }

  readonly assetDetails = computed(() => {
    const assetDetails = this.entity();
    this.languageService.currentLanguage();

    if (!isDefined(assetDetails)) return [];

    const location = this.assetLocation();
    if (!location?.counters || isEmpty(location.counters)) return [];

    const rawValue = this.getDisplayRawValue(location);
    const value = this.toDisplayValue(rawValue);
    const formattedDate = this.formatDateString(location.date);

    return [
      {
        key:
          this.counterType() === 'odometer'
            ? this.translate.instant('ADMIN.ASSETS.COUNTERS.ODOMETER.TITLE')
            : this.translate.instant('ADMIN.ASSETS.COUNTERS.HOURS.TITLE'),
        value: value,
      },
      {
        key: this.translate.instant('ADMIN.ASSETS.COUNTERS.DATE'),
        value: formattedDate,
      },
    ];
  });

  title = computed(() => {
    this.languageService.currentLanguage();
    return this.counterType() === 'odometer'
      ? this.translate.instant('ADMIN.ASSETS.COUNTERS.ODOMETER.TITLE')
      : this.translate.instant('ADMIN.ASSETS.COUNTERS.HOURS.TITLE');
  });

  subTitle = computed(() => {
    this.languageService.currentLanguage();
    return this.counterType() === 'odometer'
      ? this.translate.instant('ADMIN.ASSETS.COUNTERS.ODOMETER.DESCRIPTION')
      : this.translate.instant('ADMIN.ASSETS.COUNTERS.HOURS.DESCRIPTION');
  });

  /** Maps counterType to the changeType expected by the odo-hour-changes component */
  readonly odoHourChangeType = computed(() =>
    this.counterType() === 'odometer' ? ('odo' as const) : ('hours' as const),
  );

  constructor() {
    super();

    this.columns = [
      { field: 'key', header: '', transform: 'uppercase' },
      { field: 'value', header: '' },
    ];

    this.assetIdSource
      .pipe(
        switchMap((id) => {
          this.assetLocation.set(null);
          return this.entitiesService.getAssetLocation(id).pipe(
            catchError(() => {
              this.assetLocation.set(null);
              return EMPTY;
            }),
          );
        }),
        takeUntilDestroyed(),
      )
      .subscribe((location) => {
        this.assetLocation.set(location);
      });

    let previousEntityId: string | undefined;

    effect(() => {
      const passedLocation = this.location();
      if (isDefined(passedLocation)) {
        untracked(() => this.assetLocation.set(passedLocation));
        return;
      }

      const assetDetails = this.entity();
      const currentEntityId = assetDetails?.id;

      if (isDefined(currentEntityId) && currentEntityId !== previousEntityId) {
        previousEntityId = currentEntityId;
        this.assetIdSource.next(currentEntityId);
      }
    });

    effect(() => {
      const assetDetails = this.entity();
      const location = this.assetLocation();
      if (assetDetails && location) {
        this.updateFormFields();
      }
    });
  }

  protected override updateFormFields(): void {
    const location = this.assetLocation();
    const rawValue = location?.counters?.[this.counterType()] ?? 0;
    const value = this.toDisplayValue(rawValue);

    const dateString = location?.date;
    const initialDateValue = isDefined(dateString)
      ? new Date(dateString)
      : null;

    this.formFields = [
      createNumberField('value', this.getCounterLabel(), value, {
        name: 'value',
        props: {
          suffix:
            this.counterType() === 'odometer'
              ? this.measurementsService.getUnitConfig(
                  MeasurementUnitType.DISTANCE,
                )
              : 'hours',
          maxFractionDigits: 4,
        },
      }),

      createDateField(
        'date',
        this.translate.instant('ADMIN.ASSETS.COUNTERS.DATE'),
        initialDateValue,
        {
          name: 'date',
          props: {
            showTime: true,
            timeOnly: false,
            dateFormat: 'mm/dd/yy',
            hourFormat: '24',
            showIcon: true,
            appendTo: 'body',
          },
        },
      ),
    ];
  }

  protected override submitChanges(formData: Record<string, unknown>): void {
    const asset = this.entity();
    if (isNullOrUndefined(asset)) return;

    const transformedData = this.transformFormData(formData);

    this.entitiesService
      .updateAsset(asset.id, {
        counterValues: {
          [this.counterType()]: transformedData as {
            value: number;
            date: string;
          },
        },
      })
      .pipe(
        takeUntilDestroyed(this.destroyRef),
        finalize(() => this.isSubmitting.set(false)),
      )
      .subscribe({
        next: () => {
          this.isFormEditable.set(false);
          this.clearUnsavedChanges();
          this.broadcastService.broadcast('entity-updated', {
            entityType: 'asset',
            entityId: asset.id,
          });
        },
        error: () => {
          this.isFormEditable.set(true);
        },
      });
  }

  protected override onFormValueChange(
    formData: Record<string, unknown>,
  ): void {
    this.formValueChange.emit(this.transformFormData(formData));
  }

  protected override transformFormData(formData: Record<string, unknown>) {
    const transformedData = { ...formData };

    if (isDefined(transformedData['value'])) {
      transformedData['value'] = this.toBackendValue(
        transformedData['value'] as string | number,
      );
    }

    if (transformedData['date'] instanceof Date) {
      transformedData['date'] = transformedData['date'].toISOString();
    }

    return transformedData;
  }
}
