import { TreeNode } from 'primeng/api';
import { AssetListItem, AssetResponse, IdName } from '../../../../api';
import { isDefined } from '../../../../shared/utils';

/**
 * Extended AssetListItem with `sharedFrom`, a hand-added field not in the
 * upstream OpenAPI spec, populated when the requesting client is not the owner.
 */
export interface AssetListItemWithSharedFrom extends AssetListItem {
  sharedFrom?: IdName | null;
}

/**
 * Extended AssetResponse with `sharedFrom`, a hand-added field not in the
 * upstream OpenAPI spec, populated when the requesting client is not the owner.
 */
export interface AssetResponseWithSharedFrom extends AssetResponse {
  sharedFrom?: IdName | null;
}

/**
 * Determine whether an asset is shared-in from another client, from the
 * perspective of `currentClientId` (the currently selected client). The backend
 * has been seen to populate `sharedFrom` with the viewing client itself (e.g.
 * for newly-created assets that were never shared); treating that as
 * shared-from-self produces a spurious label, so we require `sharedFrom` to
 * point at a *different* client than the viewer.
 */
export function isAssetSharedIn(
  asset: { sharedFrom?: IdName | null },
  currentClientId?: string | null,
): boolean {
  const sharedFromId = asset.sharedFrom?.id;
  if (!isDefined(sharedFromId)) {
    return false;
  }
  if (!isDefined(currentClientId)) {
    return true;
  }
  return sharedFromId !== currentClientId;
}

/**
 * Extended AssetListItem with parentId support for tree hierarchies.
 */
export interface AssetWithParentId extends AssetListItemWithSharedFrom {
  parentId?: string | null;
  children?: boolean;
}

/**
 * Asset Tree Node with leaf indicator for lazy loading
 */
export interface AssetTreeNode extends TreeNode {
  data?: AssetWithParentId;
  children?: AssetTreeNode[];
  leaf?: boolean;
}

/**
 * Builds a tree structure from a flat list of assets using parentId relationships
 */
export class AssetTreeBuilder {
  /**
   * Convert flat asset list to hierarchical tree nodes
   * @param assets Flat list of assets with parentId
   * @returns Array of root-level tree nodes with children nested
   */
  static buildTree(
    assets: AssetWithParentId[],
    isAdmin = false,
    currentClientId?: string | null,
  ): AssetTreeNode[] {
    if (!Array.isArray(assets) || assets.length === 0) {
      return [];
    }

    // Create a map of asset ID to asset for O(1) lookup
    const assetMap = new Map<string, AssetWithParentId>();
    assets.forEach((asset) => {
      if (isDefined(asset.id)) {
        assetMap.set(asset.id, asset);
      }
    });

    // Create a map of parentId to children for grouping
    const childrenMap = new Map<string, AssetWithParentId[]>();
    const rootAssets: AssetWithParentId[] = [];

    assets.forEach((asset) => {
      const parentId = asset.parentId;
      const hasValidParent =
        isDefined(parentId) &&
        parentId !== '' &&
        parentId !== '0' &&
        assetMap.has(parentId);

      if (!hasValidParent) {
        rootAssets.push(asset);
      } else {
        if (!childrenMap.has(parentId)) {
          childrenMap.set(parentId, []);
        }
        childrenMap.get(parentId)?.push(asset);
      }
    });

    // Build tree recursively
    return rootAssets.map((asset) =>
      this.buildNode(asset, assetMap, childrenMap, isAdmin, currentClientId),
    );
  }

  /**
   * Convert list to nodes without root filtering
   */
  static mapToNodes(
    assets: AssetWithParentId[],
    isAdmin = false,
    currentClientId?: string | null,
  ): AssetTreeNode[] {
    const assetMap = new Map<string, AssetWithParentId>();
    assets.forEach((asset) => {
      if (isDefined(asset.id)) {
        assetMap.set(asset.id, asset);
      }
    });

    const childrenMap = new Map<string, AssetWithParentId[]>();
    assets.forEach((asset) => {
      const parentId = asset.parentId;
      const hasValidParent =
        isDefined(parentId) &&
        parentId !== '' &&
        parentId !== '0' &&
        assetMap.has(parentId);

      if (hasValidParent) {
        if (!childrenMap.has(parentId)) {
          childrenMap.set(parentId, []);
        }
        childrenMap.get(parentId)?.push(asset);
      }
    });

    return assets.map((asset) =>
      this.buildNode(asset, assetMap, childrenMap, isAdmin, currentClientId),
    );
  }

  /**
   * Build a single tree node and its children
   */
  private static buildNode(
    asset: AssetWithParentId,
    assetMap: Map<string, AssetWithParentId>,
    childrenMap: Map<string, AssetWithParentId[]>,
    isAdmin: boolean,
    currentClientId?: string | null,
  ): AssetTreeNode {
    const assetId = asset.id;
    const children = (assetId ? childrenMap.get(assetId) : null) ?? [];
    const hasChildren = children.length > 0;

    const isSharedIn = isAssetSharedIn(asset, currentClientId);
    const treatAsDisabled = isSharedIn && !isAdmin;

    const node: AssetTreeNode = {
      key: assetId,
      data: asset,
      children: hasChildren
        ? children.map((child) =>
            this.buildNode(
              child,
              assetMap,
              childrenMap,
              isAdmin,
              currentClientId,
            ),
          )
        : undefined,
      leaf: !hasChildren && asset.children !== true,
      expanded: hasChildren, // Only expand if we have loaded children
      styleClass: treatAsDisabled ? 'shared-asset-row' : undefined,
      selectable: !treatAsDisabled,
    };

    return node;
  }

  /**
   * Flatten tree nodes back to a list (useful for filtering/sorting)
   */
  static flattenTree(nodes: AssetTreeNode[]): AssetWithParentId[] {
    const flattened: AssetWithParentId[] = [];

    const traverse = (treeNodes: AssetTreeNode[]): void => {
      treeNodes.forEach((node) => {
        if (isDefined(node.data)) {
          flattened.push(node.data);
        }
        if (isDefined(node.children) && node.children.length > 0) {
          traverse(node.children);
        }
      });
    };

    traverse(nodes);
    return flattened;
  }
}
