import {
  Component,
  computed,
  effect,
  inject,
  OnInit,
  signal,
  untracked,
} from '@angular/core';
import { takeUntilDestroyed } from '@angular/core/rxjs-interop';
import {
  combineLatest,
  catchError,
  forkJoin,
  of,
  Subject,
  switchMap,
  debounceTime,
  Observable,
} from 'rxjs';
import { CommonModule } from '@angular/common';
import { ConfirmationService } from 'primeng/api';

import {
  AssetRatingProfileListItem,
  AssetRatingProfileListResponse,
  AssetResponse,
  AssetUpdateRequest,
  AssetCreateRequest,
  EntitiesService,
} from '../../../../../api';
import {
  createMultiselectField,
  createDropdownField,
  createAutocompleteField,
  FormFieldConfig,
} from '../../../../../shared/models';
import { isDefined, isNullOrUndefined } from '../../../../../shared/utils';
import { BulkTypedEntitySectionBaseComponent } from '../../../components/base/bulk-typed-entity-section-base';
import {
  DEFAULT_LIST_SIZE,
  DEFAULT_SYSTEM_ID,
} from '../../../../../core/models';
import { DynamicFormComponent } from '../../../../../shared/components/forms/dynamic-form/dynamic-form.component';
import { GridComponent } from '../../../../../shared/components/grid/grid.component';

import { UtilityService } from '../../../../../core/services/utility.service';
import { isEmpty } from 'lodash-es';
import { FormToRequestMapper } from '../../../utils/form-to-request-mapper';
import { TranslatePipe } from '@ngx-translate/core';

@Component({
  selector: 'app-asset-profiles-section',
  imports: [CommonModule, GridComponent, DynamicFormComponent, TranslatePipe],
  providers: [ConfirmationService],
  templateUrl: './asset-profiles-section.component.html',
  styleUrl: './asset-profiles-section.component.scss',
})
export class AssetProfilesSectionComponent
  extends BulkTypedEntitySectionBaseComponent<
    AssetResponse,
    AssetUpdateRequest,
    AssetCreateRequest,
    AssetResponse
  >
  implements OnInit
{
  private readonly entitiesService = inject(EntitiesService);
  private readonly utilityService = inject(UtilityService);
  private readonly confirmationService = inject(ConfirmationService);
  protected readonly selectOptionsLoaded = signal<boolean>(false);
  selectOptions: Record<string, { label: string; value: string }[]> = {};

  private readonly effectiveOwnerIdSignal = computed(() => {
    const bulkEditContext = this.bulkContext();
    if (isDefined(bulkEditContext)) return bulkEditContext.ownerId;
    const entity = this.entity() as AssetResponse | null;
    return entity?.owner?.id ?? '';
  });

  readonly assetDetails = computed(() => {
    const assetDetails = this.entity();
    this.languageService.currentLanguage();

    if (this.isBulkMode) {
      return [
        { key: 'Asset Rating', value: '' },
        { key: 'Asset State', value: '' },
        { key: 'Road Profile', value: '' },
        { key: 'Geo Lock Profile', value: '' },
      ];
    }

    if (!isDefined(assetDetails)) return [];

    return [
      {
        key: this.translate.instant(
          'ADMIN.ASSETS.PROFILES.FIELDS.ASSET_RATING',
        ),
        value:
          assetDetails.ratingProfile?.name ??
          this.translate.instant('SHARED.COMMON.NONE'),
      },
      {
        key: this.translate.instant('ADMIN.ASSETS.PROFILES.FIELDS.ASSET_STATE'),
        value: isEmpty(assetDetails.assetStateProfiles)
          ? this.translate.instant('SHARED.COMMON.NONE')
          : assetDetails.assetStateProfiles
              ?.map((state) => state.name)
              .join(', '),
      },
      {
        key: this.translate.instant(
          'ADMIN.ASSETS.PROFILES.FIELDS.ROAD_PROFILE',
        ),
        value:
          assetDetails.roadProfile?.name ??
          this.translate.instant('SHARED.COMMON.NONE'),
      },
      {
        key: this.translate.instant(
          'ADMIN.ASSETS.PROFILES.FIELDS.GEO_LOCK_PROFILE',
        ),
        value:
          assetDetails.geoLockProfile?.name ??
          this.translate.instant('SHARED.COMMON.NONE'),
      },
    ];
  });
  private readonly searchAssetRatingSubject = new Subject<string>();
  private readonly assetRatingSuggestions = signal<
    AssetRatingProfileListItem[]
  >([]);
  private requestMapper?: FormToRequestMapper<AssetUpdateRequest>;

  constructor() {
    super();

    // Setup initial columns
    this.columns = [
      { field: 'key', header: '', transform: 'uppercase' },
      { field: 'value', header: '' },
    ];

    // React to entity changes
    effect(() => {
      const assetDetails = this.entity();
      if (assetDetails && this.selectOptionsLoaded()) {
        this.initializeRequestMapper();
        this.updateFormFields();
      }
    });

    effect(() => {
      const ownerId = this.effectiveOwnerIdSignal();
      this.selectOptionsLoaded.set(false);
      untracked(() => this.loadSelectOptions(ownerId));
    });
  }

  protected get effectiveOwnerId(): string {
    const bulkEditContext = this.bulkContext();
    if (isDefined(bulkEditContext)) return bulkEditContext.ownerId;
    const entity = this.entity() as AssetResponse | null;
    return entity?.owner?.id ?? '';
  }

  ngOnInit() {
    this.setupSearchAssetRating();
  }

  private loadSelectOptions(ownerId: string) {
    if (!isDefined(ownerId) || ownerId === '') {
      this.selectOptions = {};
      this.selectOptionsLoaded.set(true);
      return;
    }

    combineLatest([
      this.entitiesService.listGeoLockProfiles(
        ownerId,
        true,
        0,
        100,
        'name',
        'state=active',
      ),
      this.entitiesService.listRoadProfiles(
        ownerId,
        true,
        0,
        100,
        'name',
        'state=active',
      ),
      this.entitiesService.listAssetStateProfiles(ownerId),
    ])
      .pipe(
        takeUntilDestroyed(this.destroyRef),
        catchError(() => {
          return of([{ items: [] }, { items: [] }, { items: [] }]);
        }),
      )
      .subscribe(([geoLockProfiles, roadProfiles, assetStateProfiles]) => {
        const noneOption = {
          label: this.translate.instant('SHARED.COMMON.NONE'),
          value: DEFAULT_SYSTEM_ID,
        };

        this.selectOptions = {
          geoLockProfiles: [
            noneOption,
            ...geoLockProfiles.items
              .map((item) => ({
                label: item.name ?? '',
                value: item.id,
              }))
              .sort((a, b) => a.label.localeCompare(b.label)),
          ],
          roadProfiles: [
            noneOption,
            ...roadProfiles.items
              .map((item) => ({
                label: item.name ?? '',
                value: item.id,
              }))
              .sort((a, b) => a.label.localeCompare(b.label)),
          ],
          assetStateProfiles: assetStateProfiles.items
            .map((item) => ({
              label: item.name ?? '',
              value: item.id,
            }))
            .sort((a, b) => a.label.localeCompare(b.label)),
        };

        this.selectOptionsLoaded.set(true);
      });
  }

  private setupSearchAssetRating() {
    this.searchAssetRatingSubject
      .pipe(
        debounceTime(300),
        takeUntilDestroyed(this.destroyRef),
        switchMap((searchTerm) => {
          if (searchTerm === null || searchTerm === undefined) {
            return of({
              count: 0,
              offset: 0,
              limit: DEFAULT_LIST_SIZE,
              items: [],
            } as AssetRatingProfileListResponse);
          }

          const trimmedSearchTerm = searchTerm.trim();

          if (trimmedSearchTerm.length === 0) {
            return of({
              count: 0,
              offset: 0,
              limit: DEFAULT_LIST_SIZE,
              items: [],
            } as AssetRatingProfileListResponse);
          }

          const filters = {
            state: { value: 'active', operator: '=' },
            name: { value: `*${trimmedSearchTerm}*`, operator: '=' },
          };
          const rqlFilter = this.utilityService.constructRqlFilter(filters);

          return this.entitiesService.listAssetRatingProfiles(
            this.effectiveOwnerId,
            0,
            10,
            'name',
            rqlFilter,
          );
        }),
      )
      .subscribe((response: AssetRatingProfileListResponse) => {
        this.assetRatingSuggestions.set(response.items);
      });
  }

  private searchAssetRating(searchTerm: string) {
    if (searchTerm === null || searchTerm === undefined) {
      this.assetRatingSuggestions.set([]);
      return;
    }

    this.searchAssetRatingSubject.next(searchTerm);
  }

  private initializeRequestMapper(): void {
    this.requestMapper = new FormToRequestMapper<AssetUpdateRequest>({
      ratingProfile: {
        requestProperty: 'ratingProfile',
        transform: (value) => {
          const profile = value as AssetRatingProfileListItem;
          return {
            id: profile.id,
            name: profile.name,
          };
        },
      },
      assetStateProfiles: {
        requestProperty: 'assetStateProfiles',
        transform: (value) => {
          const profiles = (value as AssetRatingProfileListItem[]).map(
            (profile) => {
              const item = this.selectOptions?.['assetStateProfiles']?.find(
                (item) => item.value === profile.id,
              );
              return {
                id: item?.value,
                name: item?.label,
              };
            },
          );
          return profiles;
        },
      },
      roadProfile: {
        requestProperty: 'roadProfile',
        transform: (value) => {
          const item = this.selectOptions?.['roadProfiles']?.find(
            (item) => item.value === value,
          );
          return {
            id: item?.value,
            name: item?.label,
          };
        },
      },
      geoLockProfile: {
        requestProperty: 'geoLockProfile',
        transform: (value) => {
          const item = this.selectOptions?.['geoLockProfiles']?.find(
            (item) => item.value === value,
          );
          return {
            id: item?.value,
            name: item?.label,
          };
        },
      },
    });
  }

  protected override updateFormFields(): void {
    this.formFields = this.buildFormFields(
      this.entity() as AssetResponse | null,
    );
  }

  protected buildFormFields(entity: AssetResponse | null): FormFieldConfig[] {
    return [
      createAutocompleteField(
        'ratingProfile',
        this.translate.instant('ADMIN.ASSETS.PROFILES.FIELDS.ASSET_RATING'),
        entity?.ratingProfile?.name,
        () => this.assetRatingSuggestions(),
        this.searchAssetRating.bind(this),
        {
          layout: 'horizontal',
          labelWidth: '1/3',
          name: 'ratingProfile',
          props: {
            appendTo: 'body',
            showClear: true,
            multiple: false,
            field: 'name',
            completeOnFocus: false,
            typeahead: true,
            showEmptyMessage: true,
            forceSelection: true,
          },
        },
      ),
      createMultiselectField(
        'assetStateProfiles',
        this.translate.instant('ADMIN.ASSETS.PROFILES.FIELDS.ASSET_STATE'),
        entity?.assetStateProfiles ?? [],
        this.selectOptions?.['assetStateProfiles'] ?? [],
        {
          layout: 'horizontal',
          labelWidth: '1/3',
          name: 'assetStateProfiles',
          props: {
            appendTo: 'body',
            multiple: true,
            showClear: true,
          },
        },
      ),
      createDropdownField(
        'roadProfile',
        this.translate.instant('ADMIN.ASSETS.PROFILES.FIELDS.ROAD_PROFILE'),
        this.selectOptions?.['roadProfiles'] ?? [],
        entity?.roadProfile?.id,
        {
          layout: 'horizontal',
          labelWidth: '1/3',
          name: 'roadProfile',
          props: {
            appendTo: 'body',
          },
        },
      ),
      createDropdownField(
        'geoLockProfile',
        this.translate.instant('ADMIN.ASSETS.PROFILES.FIELDS.GEO_LOCK_PROFILE'),
        this.selectOptions?.['geoLockProfiles'] ?? [],
        entity?.geoLockProfile?.id,
        {
          layout: 'horizontal',
          labelWidth: '1/3',
          name: 'geoLockProfile',
          props: {
            appendTo: 'body',
          },
        },
      ),
    ];
  }

  protected override submitBulkChanges(
    formData: Record<string, unknown>,
  ): void {
    const bulkEditContext = this.bulkContext();
    if (isNullOrUndefined(bulkEditContext)) return;

    if (!this.requestMapper) {
      this.initializeRequestMapper();
    }

    const payload = this.transformFormData(formData);
    this.isSubmitting.set(true);

    const saves$ = bulkEditContext.selectedEntities.map((entity) =>
      this.entitiesService.updateAsset(entity.id, payload),
    );

    forkJoin(saves$)
      .pipe(takeUntilDestroyed(this.destroyRef))
      .subscribe({
        next: () => {
          this.isSubmitting.set(false);
          this.isFormEditable.set(false);
          this.clearUnsavedChanges();
          this.broadcastService.broadcast('entity-updated', {
            entityType: 'asset',
            operation: 'update',
          });
        },
        error: () => {
          this.isSubmitting.set(false);
          this.isFormEditable.set(true);
        },
      });
  }

  protected override getUpdateMethod(): (
    id: string,
    data: AssetUpdateRequest,
  ) => Observable<AssetResponse> {
    return (id, data) => this.entitiesService.updateAsset(id, data);
  }

  protected override transformFormData(
    formData: Record<string, unknown> | Record<string, string | number>[],
  ): AssetUpdateRequest {
    if (!this.requestMapper) {
      throw new Error('Request mapper not initialized');
    }

    try {
      // Handle both possible input types
      const normalizedFormData = Array.isArray(formData)
        ? formData.reduce((acc, item) => ({ ...acc, ...item }), {})
        : formData;

      const partialRequest = this.requestMapper.transform(normalizedFormData);

      const updateRequest: Partial<AssetUpdateRequest> = {};

      for (const key in partialRequest) {
        if (Object.hasOwn(partialRequest, key)) {
          const value = partialRequest[key];
          if (value !== undefined && value !== null) {
            updateRequest[key] = value;
          }
        }
      }
      return updateRequest;
    } catch (error) {
      console.error('Form data transformation failed:', error);
      throw error;
    }
  }
}
