import { Component, computed, inject, input, signal } from '@angular/core';
import { AssetListItem, AssetResponse } from '../../../../../api';
import { AssetResponseWithSharedFrom } from '../../../services/tree-builders/asset-tree.builder';
import { AssetSectionConfigFactory } from '../../../factories/asset-section-config.factory';
import { DetailsAccordionContainerComponent } from '../../details-accordion-container/details-accordion-container.component';
import { EntityDetailsStateService } from '../../../services/entity/entity-details.state.service';
import { ProgressSpinnerModule } from 'primeng/progressspinner';
import { MessageModule } from 'primeng/message';
import { LanguageService } from '../../../../../core/services/language.service';

@Component({
  selector: 'app-asset-details-container',
  imports: [
    DetailsAccordionContainerComponent,
    ProgressSpinnerModule,
    MessageModule,
  ],
  templateUrl: './asset-details-container.component.html',
  styleUrl: './asset-details-container.component.scss',
})
export class AssetDetailsContainerComponent {
  readonly entity = input<AssetListItem | null>(null);
  readonly isBulkMode = input<boolean>(false);
  readonly selectedEntities = input<AssetListItem[]>([]);

  private readonly assetSectionFactory = inject(AssetSectionConfigFactory);
  readonly entityDetailsState = inject(EntityDetailsStateService);
  readonly languageService = inject(LanguageService);

  readonly isLoading = computed(() => this.entityDetailsState.isLoading());
  readonly isSoftRefreshing = computed(() =>
    this.entityDetailsState.isSoftRefreshing(),
  );
  readonly isInitialLoading = computed(
    () =>
      this.isLoading() &&
      !this.isSoftRefreshing() &&
      !this.fullAsset() &&
      !this.isBulkMode(),
  );
  readonly fullAsset = computed(() => {
    const entityDetails = this.entityDetailsState.selectedItem();

    if (!entityDetails) {
      return null;
    }
    return entityDetails as AssetResponseWithSharedFrom;
  });

  readonly sections = computed(() => {
    const isBulk = this.isBulkMode();
    const asset = this.fullAsset();
    if (!asset && !isBulk) return [];
    return this.assetSectionFactory.createAllAssetSections(
      asset,
      isBulk,
      this.selectedEntities() as unknown as AssetResponse[],
    );
  });
  readonly error = signal<string | null>(null);

  onEntityChange(entity: unknown): void {
    this.entityDetailsState.updateEntity(entity as AssetResponse);
    this.error.set(null);
  }
}
