import { CommonModule } from '@angular/common';
import {
  Component,
  computed,
  effect,
  inject,
  input,
  OnInit,
  signal,
  untracked,
} from '@angular/core';
import { Validators } from '@angular/forms';
import { EMPTY, Observable, Subject, debounceTime, of, switchMap } from 'rxjs';
import { takeUntilDestroyed } from '@angular/core/rxjs-interop';

import { ButtonModule } from 'primeng/button';

import {
  ExportTaskListItem,
  ExportTaskCreateRequest,
  ExportTaskUpdateRequest,
  ExportTaskResponse,
  EntitiesService,
  ClientListItem,
  ClientsService,
  AccountsService,
} from '../../../../../api';
import {
  createTextField,
  createDropdownField,
  createAutocompleteField,
  FormFieldConfig,
} from '../../../../../shared/models';
import { EntitySectionBaseComponent } from '../../base';
import {
  hasProperty,
  isDefined,
  isNullOrUndefined,
} from '../../../../../shared/utils';
import { GridComponent } from '../../../../../shared/components/grid/grid.component';
import { DynamicFormComponent } from '../../../../../shared/components/forms/dynamic-form/dynamic-form.component';
import { UtilityService } from '../../../../../core/services/utility.service';
import {
  CLIENT_SEARCH_LIMIT,
  SEARCH_DEBOUNCE_TIME,
} from '../../../../../core/models';
import { DialogService } from 'primeng/dynamicdialog';
import { ExportTaskCredentialsComponent } from '../export-task-credentials/export-task-credentials.component';
import { AuthDataService } from '../../../../../core/services/auth-data.service';
import { TranslatePipe } from '@ngx-translate/core';

type ExportTaskEntity = ExportTaskListItem | Partial<ExportTaskCreateRequest>;

@Component({
  selector: 'app-export-task-details-section',
  imports: [
    CommonModule,
    ButtonModule,
    GridComponent,
    DynamicFormComponent,
    TranslatePipe,
  ],
  templateUrl: './export-task-details-section.component.html',
  styleUrl: './export-task-details-section.component.scss',
})
export class ExportTaskDetailsSectionComponent
  extends EntitySectionBaseComponent<ExportTaskEntity>
  implements OnInit
{
  readonly ownerId = input<string | null>(null);

  private readonly entitiesService = inject(EntitiesService);
  private readonly clientsService = inject(ClientsService);
  private readonly accountsService = inject(AccountsService);
  private readonly authDataService = inject(AuthDataService);
  private readonly utilityService = inject(UtilityService);
  private readonly dialogService = inject(DialogService);

  readonly clientSearchResults = signal<ClientListItem[] | undefined>([]);
  private readonly isLoadingClients = signal<boolean>(false);
  private readonly searchSubject = new Subject<string>();
  private readonly companyType = signal<string | null>(null);

  readonly exportTaskDetails = computed(() => {
    this.languageService.currentLanguage();
    const entity = this.entity();
    if (!isDefined(entity)) return [];
    const na = this.translate.instant('SHARED.COMMON.NA');
    return [
      {
        key: this.translate.instant('ADMIN.EXPORT_TASKS.DETAILS.FIELDS.NAME'),
        value: entity.name ?? na,
      },
      {
        key: this.translate.instant('ADMIN.EXPORT_TASKS.DETAILS.FIELDS.MODE'),
        value: entity.deliveryMethod ?? na,
      },
      {
        key: this.translate.instant('ADMIN.EXPORT_TASKS.DETAILS.FIELDS.CLIENT'),
        value: (entity as ExportTaskListItem).client?.name ?? na,
      },
    ];
  });

  constructor() {
    super();
    this.columns = [
      { field: 'key', header: '', transform: 'uppercase' },
      { field: 'value', header: '' },
    ];

    // companyType loads async after the entity effect has already run.
    // Re-build form fields once it resolves so the mode options are correct.
    effect(() => {
      const type = this.companyType();
      if (!isDefined(type)) return;
      if (!this.formInitialized()) return;
      untracked(() => this.updateFormFields());
    });
  }

  ngOnInit(): void {
    this.setupClientSearch();
    this.loadCompanyType();
  }

  private loadCompanyType(): void {
    const ownerId = this.ownerId();
    if (!isDefined(ownerId)) return;

    this.accountsService
      .getCompany(ownerId)
      .pipe(takeUntilDestroyed(this.destroyRef))
      .subscribe({
        next: (company) => this.companyType.set(company.type ?? null),
        error: () => this.companyType.set(null),
      });
  }

  protected override updateFormFields(): void {
    const entity = this.entity() as ExportTaskListItem;
    const companyType = this.companyType(); // tracked — effect re-runs when company loads
    const isSystemUser = this.authDataService.isSystemUser();

    const clientField = this.buildClientField(entity);

    // HTTP: vendor/client companies only
    // Firehose: edit mode always; create mode only for system users
    // Stream / FTP: edit mode only
    const modeOptions = [
      ['vendor', 'client'].includes(companyType ?? '') && {
        label: this.translate.instant('ADMIN.EXPORT_TASKS.MODES.HTTP'),
        value: 'http',
      },
      (!this.createMode() || isSystemUser) && {
        label: this.translate.instant('ADMIN.EXPORT_TASKS.MODES.FIREHOSE'),
        value: 'firehose',
      },
      !this.createMode() && {
        label: this.translate.instant('ADMIN.EXPORT_TASKS.MODES.STREAM'),
        value: 'stream',
      },
      !this.createMode() && {
        label: this.translate.instant('ADMIN.EXPORT_TASKS.MODES.FTP'),
        value: 'ftp',
      },
    ].filter(Boolean) as { label: string; value: string }[];

    this.formFields = [
      createTextField(
        'name',
        this.translate.instant('ADMIN.EXPORT_TASKS.DETAILS.FIELDS.NAME'),
        entity?.name,
        {
          name: 'name',
          validations: [
            {
              name: 'required',
              validator: Validators.required,
              message: this.translate.instant(
                'SHARED.COMMON.FORMS.SHARED.REQUIRED',
                {
                  field: this.translate.instant(
                    'ADMIN.EXPORT_TASKS.DETAILS.FIELDS.NAME',
                  ),
                },
              ),
            },
          ],
        },
      ),
      createDropdownField(
        'deliveryMethod',
        this.translate.instant('ADMIN.EXPORT_TASKS.DETAILS.FIELDS.MODE'),
        modeOptions,
        entity?.deliveryMethod,
        {
          name: 'deliveryMethod',
          disabled: !this.createMode(),
          conditional: true,
          conditions: {
            http: [clientField],
            stream: [clientField],
            ftp: [clientField],
            firehose: [],
          },
          validations: [
            {
              name: 'required',
              validator: Validators.required,
              message: this.translate.instant(
                'SHARED.COMMON.FORMS.SHARED.REQUIRED',
                {
                  field: this.translate.instant(
                    'ADMIN.EXPORT_TASKS.DETAILS.FIELDS.MODE',
                  ),
                },
              ),
            },
          ],
        },
      ),
    ];
  }

  private buildClientField(entity: ExportTaskListItem): FormFieldConfig {
    const clientField = createAutocompleteField(
      'client',
      this.translate.instant('ADMIN.EXPORT_TASKS.DETAILS.FIELDS.CLIENT'),
      entity?.client ?? '',
      () => this.clientSearchResults() ?? [],
      this.searchClient.bind(this),
      {
        name: 'client',
        props: {
          forceSelection: true,
          field: 'name',
          completeOnFocus: true,
          typeahead: true,
          showEmptyMessage: true,
          appendTo: 'body',
        },
        autocompleteLoading: () => this.isLoadingClients(),
        validations: [
          {
            name: 'required',
            validator: Validators.required,
            message: this.translate.instant(
              'SHARED.COMMON.FORMS.SHARED.REQUIRED',
              {
                field: this.translate.instant(
                  'ADMIN.EXPORT_TASKS.DETAILS.FIELDS.CLIENT',
                ),
              },
            ),
          },
        ],
      },
    );

    // Lock client after creation — delivery method is also locked so this
    // value can never be changed once the task exists
    clientField.readonly = !this.createMode();

    return clientField;
  }

  searchClient(searchTerm: string): void {
    if (!searchTerm || searchTerm.trim().length < 3) {
      this.clientSearchResults.set([]);
      this.isLoadingClients.set(false);
    } else {
      this.searchSubject.next(searchTerm.trim());
    }
  }

  private setupClientSearch(): void {
    this.searchSubject
      .pipe(
        debounceTime(SEARCH_DEBOUNCE_TIME),
        takeUntilDestroyed(this.destroyRef),
        switchMap((searchTerm) => {
          this.isLoadingClients.set(true);

          const ownerId = this.ownerId();
          if (!isDefined(ownerId)) return of({ items: [] });

          const filters = {
            state: { value: 'active', operator: '=' },
            name: { value: `*${searchTerm}*`, operator: '=' },
          };
          const rqlFilter = this.utilityService.constructRqlFilter(filters);

          return this.clientsService.listClients(
            ownerId,
            0,
            CLIENT_SEARCH_LIMIT,
            'name',
            rqlFilter,
          );
        }),
      )
      .subscribe({
        next: (data) => {
          this.isLoadingClients.set(false);
          if (isDefined(data) && hasProperty(data, 'items')) {
            this.clientSearchResults.set(data.items ?? []);
          }
        },
        error: () => {
          this.isLoadingClients.set(false);
          this.clientSearchResults.set([]);
        },
      });
  }

  protected override buildUpdateRequest(
    formData: Record<string, unknown>,
  ): Observable<unknown> {
    const entity = this.entity();
    if (isNullOrUndefined(entity)) return EMPTY;

    const updateRequest: ExportTaskUpdateRequest = { ...formData };

    // Map autocomplete selection → { id, name } shape the API expects
    if (
      isDefined(formData['client']) &&
      typeof formData['client'] === 'object'
    ) {
      const selected = formData['client'] as { id?: string; name?: string };
      updateRequest.client = { id: selected.id ?? '', name: selected.name };
    }

    // Firehose tasks are always owned by the top-level owner, no client
    if (updateRequest.deliveryMethod === 'firehose') {
      updateRequest.client = { id: this.ownerId() ?? '' };
    }

    return this.entitiesService.updateExportTask(
      (entity as ExportTaskListItem).id,
      updateRequest,
    );
  }

  protected override onSubmitSuccess(response: unknown): void {
    const entity = this.entity();
    if (isNullOrUndefined(entity)) return;
    this.broadcastService.broadcast('entity-updated', {
      entityType: 'exporttask',
      operation: 'update',
      entityId: (entity as ExportTaskListItem).id,
      data: response,
    });
  }

  onShowCredentials(): void {
    const entity = this.entity() as ExportTaskResponse;
    if (!isDefined(entity)) return;

    const credentials = this.buildCredentials(entity);

    this.dialogService.open(ExportTaskCredentialsComponent, {
      header: this.translate.instant(
        'ADMIN.EXPORT_TASKS.DETAILS.CREDENTIALS.TITLE',
      ),
      width: '500px',
      data: { credentials },
    });
  }

  private buildCredentials(entity: ExportTaskResponse): Record<string, string> {
    switch (entity.deliveryMethod) {
      case 'http':
        return {
          Endpoint: entity.endpoint ?? '',
          'API Key': entity.password ?? '',
        };

      case 'stream':
        return {
          Endpoint: entity.endpoint ?? '',
          Username: entity.username ?? '',
          Password: entity.password ?? '',
        };

      case 'firehose': {
        let policy = '';
        try {
          policy = JSON.stringify(JSON.parse(entity.endpoint ?? '{}'), null, 2);
        } catch {
          policy = entity.endpoint ?? '';
        }
        return { 'S3 IAM Policy': policy };
      }

      default:
        return {};
    }
  }
}
