import { CommonModule } from '@angular/common';
import {
  Component,
  computed,
  effect,
  inject,
  OnInit,
  signal,
} from '@angular/core';
import { ReactiveFormsModule } from '@angular/forms';
import { ButtonModule } from 'primeng/button';
import { InputTextModule } from 'primeng/inputtext';
import { ChipModule } from 'primeng/chip';
import { ConfirmationService } from 'primeng/api';
import { BulkEntitySectionBaseComponent } from '../../../components/base/bulk-entity-section-base';
import { AssetBulkSaveService } from '../../../services/asset-bulk-save.service';
import {
  AssetCreateRequest,
  AssetResponse,
  EntitiesService,
  IdName,
} from '../../../../../api';
import {
  isDefined,
  isNullOrUndefined,
  isString,
} from '../../../../../shared/utils';
import { takeUntilDestroyed } from '@angular/core/rxjs-interop';
import {
  createDropdownField,
  createNumberField,
  FormFieldConfig,
  MeasurementUnitType,
} from '../../../../../shared/models';
import { GridComponent } from '../../../../../shared/components/grid/grid.component';
import { DynamicFormComponent } from '../../../../../shared/components/forms/dynamic-form/dynamic-form.component';
import { MeasurementUnitsService } from '../../../../../shared/services/measurement-units/measurement-units.service';
import { TranslatePipe } from '@ngx-translate/core';
import { forkJoin } from 'rxjs';

@Component({
  selector: 'app-asset-event-triggers-section',
  imports: [
    CommonModule,
    ReactiveFormsModule,
    ButtonModule,
    InputTextModule,
    ChipModule,
    GridComponent,
    DynamicFormComponent,
    TranslatePipe,
  ],
  providers: [ConfirmationService],
  templateUrl: './asset-event-triggers-section.component.html',
  styleUrl: './asset-event-triggers-section.component.scss',
})
export class AssetEventTriggersSectionComponent
  extends BulkEntitySectionBaseComponent<
    AssetResponse | Partial<AssetCreateRequest>
  >
  implements OnInit
{
  private readonly entitiesService = inject(EntitiesService);
  private readonly measurementUnitsService = inject(MeasurementUnitsService);
  private readonly bulkSaveService = inject(AssetBulkSaveService);
  private readonly confirmationService = inject(ConfirmationService);
  protected readonly selectOptionsLoaded = signal<boolean>(false);
  selectOptions: Record<string, { label: string; value: string }[]> = {};

  readonly assetEventTriggers = computed(() => {
    if (this.isBulkMode) {
      return [
        { key: 'Max Speed', value: '' },
        { key: 'Overspeed Profile', value: '' },
        { key: 'Excessive Idle', value: '' },
        { key: 'Max Trip Distance', value: '' },
        { key: 'Max Trip Time', value: '' },
        { key: 'Max inactive time', value: '' },
      ];
    }
    const asset = this.entity() as AssetResponse | null;
    const assetEventTriggers = asset?.parameters;
    this.languageService.currentLanguage();

    if (isNullOrUndefined(assetEventTriggers)) return [];

    const hasOverspeedProfile = isDefined(asset?.overspeedProfile?.id);

    const triggers = [
      {
        key: this.translate.instant(
          'ADMIN.ASSETS.EVENT_TRIGGERS.FIELDS.MAX_SPEED',
        ),
        value: isDefined(assetEventTriggers.overspeed)
          ? this.measurementUnitsService.format(
              assetEventTriggers.overspeed,
              MeasurementUnitType.SPEED,
            ).format
          : this.translate.instant('SHARED.COMMON.NONE'),
      },
      {
        key: this.translate.instant(
          'ADMIN.ASSETS.EVENT_TRIGGERS.FIELDS.OVERSPEED_PROFILE',
        ),
        value: isDefined(asset?.overspeedProfile)
          ? asset?.overspeedProfile?.name
          : this.translate.instant('SHARED.COMMON.NONE'),
      },
    ];

    // Only show Speed Tolerance when no overspeed profile is selected
    if (!hasOverspeedProfile) {
      triggers.push({
        key: this.translate.instant(
          'ADMIN.ASSETS.EVENT_TRIGGERS.FIELDS.SPEED_TOLERANCE',
        ),
        value: isDefined(assetEventTriggers.overspeedTolerance)
          ? `${assetEventTriggers.overspeedTolerance}%`
          : this.translate.instant('SHARED.COMMON.NONE'),
      });
    }

    triggers.push(
      {
        key: this.translate.instant(
          'ADMIN.ASSETS.EVENT_TRIGGERS.FIELDS.EXCESSIVE_IDLE',
        ),
        value: isDefined(assetEventTriggers.excessiveIdle)
          ? `${assetEventTriggers.excessiveIdle} ${this.translate.instant('ADMIN.ASSETS.EVENT_TRIGGERS.FIELDS.MINUTES')}`
          : this.translate.instant('SHARED.COMMON.NONE'),
      },
      {
        key: this.translate.instant(
          'ADMIN.ASSETS.EVENT_TRIGGERS.FIELDS.MAX_TRIP_DISTANCE',
        ),
        value: isDefined(assetEventTriggers.maxTripDistance)
          ? `${
              this.measurementUnitsService.format(
                assetEventTriggers.maxTripDistance,
                MeasurementUnitType.DISTANCE,
              ).value
            } ${this.measurementUnitsService.unit(
              MeasurementUnitType.DISTANCE,
            )}`
          : this.translate.instant('SHARED.COMMON.NONE'),
      },
      {
        key: this.translate.instant(
          'ADMIN.ASSETS.EVENT_TRIGGERS.FIELDS.MAX_TRIP_TIME',
        ),
        value: isDefined(assetEventTriggers.maxTripTime)
          ? `${assetEventTriggers.maxTripTime} ${this.translate.instant('ADMIN.ASSETS.EVENT_TRIGGERS.FIELDS.MINUTES')}`
          : this.translate.instant('SHARED.COMMON.NONE'),
      },
      {
        key: this.translate.instant(
          'ADMIN.ASSETS.EVENT_TRIGGERS.FIELDS.MAX_INACTIVE_TIME',
        ),
        value: isDefined(assetEventTriggers.maxInactiveTime)
          ? `${assetEventTriggers.maxInactiveTime} ${this.translate.instant('ADMIN.ASSETS.EVENT_TRIGGERS.FIELDS.MINUTES')}`
          : this.translate.instant('SHARED.COMMON.NONE'),
      },
    );

    return triggers;
  });

  constructor() {
    super();

    // Setup initial columns
    this.columns = [
      { field: 'key', header: '', transform: 'uppercase' },
      { field: 'value', header: '' },
    ];

    // React to entity changes
    effect(() => {
      const assetEventTriggers = this.entity();
      if (assetEventTriggers && this.selectOptionsLoaded()) {
        this.updateFormFields();
      }
    });
  }

  protected get effectiveOwnerId(): string {
    const bulkEditContext = this.bulkContext();
    if (bulkEditContext) return bulkEditContext.ownerId;
    const entity = this.entity() as AssetResponse | null;
    return entity?.owner?.id ?? '';
  }

  ngOnInit() {
    this.loadSelectOptions();
  }

  private loadSelectOptions() {
    const asset = this.entity() as AssetResponse | null;
    if (!isDefined(asset) || !isString(asset.id)) {
      this.selectOptions = {};
      this.selectOptionsLoaded.set(true);
      this.updateFormFields();
      return;
    }

    this.entitiesService
      .listOverspeedProfiles(asset.owner.id)
      .pipe(takeUntilDestroyed(this.destroyRef))
      .subscribe((response) => {
        this.selectOptions = {
          overspeedProfiles: response.items
            .map((item) => ({
              label: item.name ?? '',
              value: item.id,
            }))
            .sort((a, b) => a.label.localeCompare(b.label)),
        };

        this.selectOptionsLoaded.set(true);
      });
  }

  protected override updateFormFields(): void {
    this.formFields = this.buildFormFields(
      this.entity() as AssetResponse | null,
    );
  }

  protected buildFormFields(entity: AssetResponse | null): FormFieldConfig[] {
    const overspeedProfileSelected = isDefined(entity?.overspeedProfile?.id);

    const fields: FormFieldConfig[] = [
      createNumberField(
        'overspeed',
        this.translate.instant('ADMIN.ASSETS.EVENT_TRIGGERS.FIELDS.MAX_SPEED'),
        entity?.parameters?.overspeed !== undefined &&
          entity?.parameters?.overspeed !== null
          ? this.measurementUnitsService.fromBackend(
              MeasurementUnitType.SPEED,
              entity.parameters.overspeed,
            )
          : undefined,
        {
          layout: 'horizontal',
          labelWidth: '1/3',
          name: 'overspeed',
          props: {
            suffix: this.measurementUnitsService.unitSymbol(
              MeasurementUnitType.SPEED,
            ),
          },
        },
      ),
      createDropdownField(
        'overspeedProfile',
        this.translate.instant(
          'ADMIN.ASSETS.EVENT_TRIGGERS.FIELDS.OVERSPEED_PROFILE',
        ),
        this.selectOptions['overspeedProfiles'],
        entity?.overspeedProfile?.id ?? undefined,
        {
          layout: 'horizontal',
          labelWidth: '1/3',
          name: 'overspeedProfile',
          props: {
            placeholder: this.translate.instant(
              'SHARED.COMMON.SELECTION.TITLE',
              {
                field: this.translate.instant(
                  'ADMIN.ASSETS.EVENT_TRIGGERS.FIELDS.OVERSPEED_PROFILE',
                ),
              },
            ),
            filter: true,
            showClear: true,
            clearButtonAriaLabel: this.translate.instant(
              'SHARED.COMMON.ARIA.CLEAR_SELECTION',
            ),
          },
        },
      ),
      createNumberField(
        'overspeedTolerance',
        this.translate.instant(
          'ADMIN.ASSETS.EVENT_TRIGGERS.FIELDS.SPEED_TOLERANCE',
        ),
        entity?.parameters?.overspeedTolerance ?? undefined,
        {
          layout: 'horizontal',
          labelWidth: '1/3',
          name: 'overspeedTolerance',
          hidden: overspeedProfileSelected,
          props: {
            suffix: '%',
          },
        },
      ),
      createNumberField(
        'excessiveIdle',
        this.translate.instant(
          'ADMIN.ASSETS.EVENT_TRIGGERS.FIELDS.EXCESSIVE_IDLE',
        ),
        entity?.parameters?.excessiveIdle ?? undefined,
        {
          layout: 'horizontal',
          labelWidth: '1/3',
          name: 'excessiveIdle',
          props: {
            suffix: 'minutes',
          },
        },
      ),
      createNumberField(
        'maxTripDistance',
        this.translate.instant(
          'ADMIN.ASSETS.EVENT_TRIGGERS.FIELDS.MAX_TRIP_DISTANCE',
        ),
        entity?.parameters?.maxTripDistance !== undefined &&
          entity?.parameters?.maxTripDistance !== null
          ? this.measurementUnitsService.fromBackend(
              MeasurementUnitType.DISTANCE,
              entity.parameters.maxTripDistance,
            )
          : undefined,
        {
          layout: 'horizontal',
          labelWidth: '1/3',
          name: 'maxTripDistance',
          props: {
            suffix: this.measurementUnitsService.unit(
              MeasurementUnitType.DISTANCE,
            ),
          },
        },
      ),
      createNumberField(
        'maxTripTime',
        this.translate.instant(
          'ADMIN.ASSETS.EVENT_TRIGGERS.FIELDS.MAX_TRIP_TIME',
        ),
        entity?.parameters?.maxTripTime ?? undefined,
        {
          layout: 'horizontal',
          labelWidth: '1/3',
          name: 'maxTripTime',
          props: {
            suffix: 'minutes',
          },
        },
      ),
      createNumberField(
        'maxInactiveTime',
        this.translate.instant(
          'ADMIN.ASSETS.EVENT_TRIGGERS.FIELDS.MAX_INACTIVE_TIME',
        ),
        entity?.parameters?.maxInactiveTime ?? undefined,
        {
          layout: 'horizontal',
          labelWidth: '1/3',
          name: 'maxInactiveTime',
          props: {
            suffix: 'minutes',
          },
        },
      ),
    ];

    // In bulk mode, hide Speed Tolerance (no single profile context to check)
    if (this.isBulkMode) {
      return fields.filter((f) => f.key !== 'overspeedTolerance');
    }

    return fields;
  }

  protected override submitBulkChanges(
    formData: Record<string, string | number | object | null>,
  ): void {
    const bulkEditContext = this.bulkContext();
    if (isNullOrUndefined(bulkEditContext)) return;

    const typedData = formData as Record<string, string | number>;
    const { overspeedProfile, ...rawParameters } = typedData;

    // Convert measurement values to backend format
    const parameters: Record<string, string | number> = {};
    for (const [key, value] of Object.entries(rawParameters)) {
      if (value !== undefined && value !== null && value !== '') {
        switch (key) {
          case 'overspeed':
            parameters[key] = this.measurementUnitsService.toBackend(
              MeasurementUnitType.SPEED,
              value,
            );
            break;
          case 'maxTripDistance':
            parameters[key] = this.measurementUnitsService.toBackend(
              MeasurementUnitType.DISTANCE,
              value,
            );
            break;
          default:
            parameters[key] = value;
            break;
        }
      }
    }

    // Prepare update payload - only include parameters if not empty
    const updatePayload: {
      parameters?: Record<string, string | number>;
      overspeedProfile?: IdName;
    } = {};

    // Only include parameters if there are actual values
    if (Object.keys(parameters).length > 0) {
      updatePayload.parameters = parameters;
    }

    // Handle overspeedProfile - send null to clear, or the selected profile
    const selectedProfile = this.selectOptions['overspeedProfiles']?.find(
      (option) => option.value === overspeedProfile,
    );
    updatePayload.overspeedProfile = selectedProfile
      ? { id: selectedProfile.value, name: selectedProfile.label }
      : undefined;

    this.isSubmitting.set(true);

    const saves$ = bulkEditContext.selectedEntities.map((entity) =>
      this.entitiesService.updateAsset(entity.id, updatePayload),
    );

    forkJoin(saves$)
      .pipe(takeUntilDestroyed(this.destroyRef))
      .subscribe({
        next: () => {
          this.isSubmitting.set(false);
          this.isFormEditable.set(false);
          this.clearUnsavedChanges();
          this.broadcastService.broadcast('entity-updated', {
            entityType: 'asset',
            operation: 'update',
          });
        },
        error: () => {
          this.isSubmitting.set(false);
          this.isFormEditable.set(true);
        },
      });
  }

  protected override submitChanges(
    formData: Record<string, string | number>,
  ): void {
    const asset = this.entity() as AssetResponse | null;
    if (isNullOrUndefined(asset)) return;

    // Extract overspeedProfile from formData if present
    const { overspeedProfile, ...rawParameters } = formData;

    // Convert measurement values to backend format
    const parameters: Record<string, string | number> = {};

    for (const [key, value] of Object.entries(rawParameters)) {
      if (value !== undefined && value !== null && value !== '') {
        switch (key) {
          case 'overspeed':
            parameters[key] = this.measurementUnitsService.toBackend(
              MeasurementUnitType.SPEED,
              value,
            );
            break;
          case 'maxTripDistance':
            parameters[key] = this.measurementUnitsService.toBackend(
              MeasurementUnitType.DISTANCE,
              value,
            );
            break;
          default:
            parameters[key] = value;
            break;
        }
      }
    }

    // Prepare update payload - only include parameters if not empty
    const updatePayload: {
      parameters?: Record<string, string | number>;
      overspeedProfile?: IdName;
    } = {};

    // Only include parameters if there are actual values
    if (Object.keys(parameters).length > 0) {
      updatePayload.parameters = parameters;
    }

    // Handle overspeedProfile - send null to clear, or the selected profile
    const selectedProfile = this.selectOptions['overspeedProfiles']?.find(
      (option) => option.value === overspeedProfile,
    );

    if (selectedProfile) {
      updatePayload.overspeedProfile = {
        id: selectedProfile.value,
        name: selectedProfile.label,
      };
    } else {
      // Explicitly send null to clear the overspeed profile
      updatePayload.overspeedProfile = null as unknown as IdName;
    }

    this.handleEntityUpdate(
      this.entitiesService
        .updateAsset(asset.id, updatePayload)
        .pipe(takeUntilDestroyed(this.destroyRef)),
      'Asset Event triggers updated successfully',
    );
  }

  protected override onFormValueChange(
    formData: Record<string, string | number>,
  ): void {
    super.onFormValueChange(formData);

    const overspeedProfileValue = formData['overspeedProfile'];
    const hasProfile =
      isDefined(overspeedProfileValue) && overspeedProfileValue !== '';

    // Find the tolerance field and check if hidden state needs to change
    const toleranceField = this.formFields.find(
      (f) => f.key === 'overspeedTolerance',
    );

    if (toleranceField && toleranceField.hidden !== hasProfile) {
      // Update all field values to match current form state before rebuilding
      for (const field of this.formFields) {
        if (formData[field.key] === undefined) {
          field.value = undefined;
        } else {
          field.value = formData[field.key];
        }
      }

      // Update hidden state
      toleranceField.hidden = hasProfile;

      // Trigger rebuild with updated values
      this.formFields = [...this.formFields];
    }
  }
}
