import { CommonModule } from '@angular/common';
import {
  ChangeDetectorRef,
  Component,
  computed,
  effect,
  inject,
  input,
  OnInit,
  untracked,
} from '@angular/core';
import { ButtonModule } from 'primeng/button';
import { MessageModule } from 'primeng/message';
import { FontAwesomeModule } from '@fortawesome/angular-fontawesome';
import { faUser } from '@fortawesome/free-solid-svg-icons';

import {
  UserListItem,
  UserCreateRequest,
  AccountsService,
  ClientResponse,
  CostCentreResponse,
} from '../../../../../api';
import { EMPTY, Observable } from 'rxjs';
import { DynamicFormComponent } from '../../../../../shared/components/forms/dynamic-form/dynamic-form.component';
import { GridComponent } from '../../../../../shared/components/grid/grid.component';
import { isDefined, isNullOrUndefined } from '../../../../../shared/utils';
import { EntitySectionBaseComponent } from '../../base';

import { UserFormService } from './services/user-form.service';
import { ClientSearchService } from './services/client-search.service';
import { UserDataLoadingService } from './services/user-data-loading.service';
import { TranslatePipe } from '@ngx-translate/core';
@Component({
  selector: 'app-user-details-section',
  imports: [
    CommonModule,
    ButtonModule,
    GridComponent,
    DynamicFormComponent,
    MessageModule,
    FontAwesomeModule,
    TranslatePipe,
  ],
  templateUrl: './user-details-section.component.html',
  styleUrl: './user-details-section.component.scss',
})
export class UserDetailsSectionComponent
  extends EntitySectionBaseComponent<UserListItem | Partial<UserCreateRequest>>
  implements OnInit
{
  readonly ownerId = input<string | null>(null);

  // Injected services
  private readonly accountsService = inject(AccountsService);
  private readonly cdr = inject(ChangeDetectorRef);
  // Service dependencies
  private readonly userFormService: UserFormService = inject(UserFormService);
  private readonly dataLoadingService: UserDataLoadingService = inject(
    UserDataLoadingService,
  );
  private readonly clientSearchService: ClientSearchService =
    inject(ClientSearchService);

  // Computed properties
  protected readonly faUser = faUser;

  readonly userDetails = computed(() => {
    const userDetails = this.entity();
    const company = this.dataLoadingService.companyInfo();
    if (!isDefined(userDetails)) return [];

    const details = [
      {
        key: this.translate.instant('ADMIN.USERS.DETAILS.FIELDS.NAME'),
        value: userDetails.name,
      },
      {
        key: this.translate.instant('ADMIN.USERS.DETAILS.FIELDS.EMAIL_ADDRESS'),
        value: userDetails.emailAddress,
      },
      {
        key: this.translate.instant('ADMIN.USERS.DETAILS.FIELDS.MOBILE_NUMBER'),
        value: userDetails.mobile,
      },
      {
        key: this.translate.instant('ADMIN.USERS.DETAILS.FIELDS.PASSWORD'),
        value: '*********',
      },
    ];

    // Only add Cost Center if company type is 'client'
    if (company?.type === 'client') {
      details.push({
        key: this.translate.instant('ADMIN.USERS.DETAILS.FIELDS.COST_CENTRE'),
        value:
          userDetails.costCentre?.name ??
          this.translate.instant('SHARED.COMMON.NONE'),
      });
    }

    details.push({
      key: this.translate.instant('ADMIN.USERS.DETAILS.FIELDS.TIMEZONE'),
      value:
        userDetails.timeZoneId ?? this.translate.instant('SHARED.COMMON.NONE'),
    });

    return details;
  });

  constructor() {
    super();

    // Setup initial columns
    this.columns = [
      { field: 'key', header: '', transform: 'uppercase' },
      { field: 'value', header: '' },
    ];

    // Effect to update form fields when all necessary data is loaded
    effect(() => {
      if (this.dataLoadingService.isDataLoaded) {
        untracked(() => {
          this.updateFormFields();
        });
      }
    });

    effect(() => {
      const entity = this.entity();
      if (isDefined(entity) && !this.createMode()) {
        untracked(() => {
          this.updateFormFields();
        });
      }
    });
  }
  ngOnInit(): void {
    // Initialize client search service with owner ID
    const effectiveOwnerId = this.entity()?.owner?.id ?? this.ownerId();
    this.clientSearchService.initialize(effectiveOwnerId); // Load all required data
    this.dataLoadingService
      .loadUserFormData(effectiveOwnerId)
      .catch((error: unknown) => {
        console.error('Failed to load user form data:', error);
      });

    // Set up form change tracking after form is initialized
    setTimeout(() => {
      this.trackFormChanges();
    });
  }

  protected override updateFormFields(): void {
    const user = this.entity();
    if (!isDefined(user)) return;

    this.formFields = this.userFormService.createUserFormFields({
      user: user as UserListItem,
      company: this.dataLoadingService.companyInfo(),
      createMode: this.createMode(),
      costCenters: this.dataLoadingService.costCentersData(),
      timezones: this.dataLoadingService.timezonesData(),
      clientsSearchResults: () => this.clientSearchService.searchResults(),
      searchClient: (term: string) => this.clientSearchService.search(term),
      isLoadingClients: () => this.clientSearchService.isSearchLoading(),
    });

    this.cdr.detectChanges();
  }

  protected override buildUpdateRequest(
    formData: Record<string, unknown>,
  ): Observable<unknown> {
    const user = this.entity();
    if (isNullOrUndefined(user)) return EMPTY;
    return this.accountsService.updateUser(
      user.id,
      this.normalizeUserPayload(formData),
    );
  }

  protected override onSubmitSuccess(response: unknown): void {
    const user = this.entity();
    if (isNullOrUndefined(user)) return;
    this.broadcastService.broadcast('entity-updated', {
      entityType: 'user',
      operation: 'update',
      entityId: user.id,
      data: response,
    });
  }
  protected override onFormValueChange(
    formData: Record<string, string | number>,
  ): void {
    this.formValueChange.emit(this.normalizeUserPayload(formData));
    this.hasFormChanges = true;
  }

  private normalizeUserPayload(
    formData: Record<string, unknown>,
  ): Record<string, unknown> {
    const data: Record<string, unknown> = { ...formData };

    if (isDefined(data['defaultClient'])) {
      const client = data['defaultClient'] as ClientResponse;
      data['defaultClient'] = { id: client.id, name: client.name };
    } else {
      data['defaultClient'] = null;
    }

    if (isDefined(data['costCentre'])) {
      const costCentre = data['costCentre'] as CostCentreResponse;
      data['costCentre'] = { id: costCentre.id, name: costCentre.name };
    } else {
      data['costCentre'] = null;
    }

    return data;
  }
}
