import { Injectable } from '@angular/core';
import { AdminDetailSection } from '../models';
import { AssetDetailsSectionComponent } from '../components/assets/asset-details-section/asset-details-section.component';
import { AssetCategoriesSectionComponent } from '../components/assets/asset-categories-section/asset-categories-section.component';
import { AssetResponse } from '../../../api';
import { AssetContactsSectionComponent } from '../components/assets/asset-contacts-section/asset-contacts-section.component';
import { AssetProfilesSectionComponent } from '../components/assets/asset-profiles-section/asset-profiles-section.component';
import { AssetSharingSectionComponent } from '../components/assets/asset-sharing-section/asset-sharing-section.component';
import { AssetEventTriggersSectionComponent } from '../components/assets/asset-event-triggers-section/asset-event-triggers-section.component';
import { AssetRemindersSectionComponent } from '../components/assets/asset-reminders-section/asset-reminders-section.component';
import { AssetAnalogTriggersSectionComponent } from '../components/assets/asset-analog-triggers-section/asset-analog-triggers-section.component';
import { FeedSectionComponent } from '../components/shared/feed-section/feed-section.component';
import { AssetCurfewEventsSectionComponent } from '../components/assets/asset-curfew-events-section/asset-curfew-events-section.component';
import { AssetLabelsSectionComponent } from '../components/assets/asset-labels-section/asset-labels-section.component';
import { AssetCounterTypeSectionComponent } from '../components/assets/asset-counter-type-section/asset-counter-type-section.component';
import { InfoSectionComponent } from '../components/shared/info-section/info-section.component';
import { AssetZonesSectionComponent } from '../components/assets/asset-zones-section/asset-zones-section.component';
import { BulkEditContext } from '../models/bulk-edit-context.interface';

@Injectable({
  providedIn: 'root',
})
export class AssetSectionConfigFactory {
  /**
   * Build a bulk context object from the given parameters.
   * Returns null if not in bulk mode or if selectedEntities is empty —
   * so sections can safely treat null as "single-asset mode".
   */
  private buildBulkContext(
    isBulkMode: boolean,
    selectedEntities: AssetResponse[],
  ): BulkEditContext | null {
    if (!isBulkMode || selectedEntities.length === 0) return null;
    return {
      ownerId: selectedEntities[0].owner.id,
      selectedEntities,
    };
  }

  /**
   * Create sections for asset information
   */
  createAssetInformationSections(
    asset: AssetResponse | null,
    isBulkMode = false,
    selectedEntities: AssetResponse[] = [],
  ): AdminDetailSection[] {
    const bulkContext = this.buildBulkContext(isBulkMode, selectedEntities);

    return [
      {
        id: 'asset-details',
        title: 'Asset Details',
        component: AssetDetailsSectionComponent,
        componentInputs: {
          entity: asset,
          bulkContext,
        },
        category: 'information',
        order: 10,
        bulkApplicable: true,
      },
      {
        id: 'asset-categories',
        title: 'Categories',
        component: AssetCategoriesSectionComponent,
        componentInputs: { entity: asset, bulkContext },
        category: 'information',
        order: 20,
        bulkApplicable: true,
      },
      {
        id: 'asset-information',
        title: 'Asset Information',
        component: InfoSectionComponent<AssetResponse>,
        componentInputs: {
          entity: asset,
          dataPath: 'customFields',
          entityType: 'asset',
          isBulkMode,
          selectedEntities,
        },
        category: 'information',
        order: 30,
        bulkApplicable: false,
      },
      {
        id: 'asset-contacts',
        title: 'Contacts',
        component: AssetContactsSectionComponent,
        componentInputs: { entity: asset },
        category: 'information',
        order: 40,
        bulkApplicable: false,
      },
    ];
  }

  /**
   * Create sections for asset settings
   */
  createAssetSettingsSections(
    asset: AssetResponse | null,
    isBulkMode = false,
    selectedEntities: AssetResponse[] = [],
  ): AdminDetailSection[] {
    const bulkContext = this.buildBulkContext(isBulkMode, selectedEntities);

    return [
      {
        id: 'profiles',
        title: 'Profiles',
        component: AssetProfilesSectionComponent,
        componentInputs: { entity: asset, bulkContext },
        category: 'settings',
        order: 10,
        bulkApplicable: true,
      },
      {
        id: 'asset-sharing',
        title: 'Sharing',
        component: AssetSharingSectionComponent,
        componentInputs: { entity: asset, bulkContext },
        category: 'settings',
        order: 20,
        bulkApplicable: true,
      },
      {
        id: 'asset-odometer',
        title: 'Odometer',
        component: AssetCounterTypeSectionComponent,
        componentInputs: {
          entity: asset,
          counterType: 'odometer',
        },
        category: 'settings',
        order: 30,
        bulkApplicable: false,
      },
      {
        id: 'asset-hours',
        title: 'Engine Hours',
        component: AssetCounterTypeSectionComponent,
        componentInputs: {
          entity: asset,
          counterType: 'hours',
        },
        category: 'settings',
        order: 40,
        bulkApplicable: false,
      },
      {
        id: 'asset-reminders',
        title: 'Reminders',
        component: AssetRemindersSectionComponent,
        componentInputs: { entity: asset, bulkContext },
        category: 'settings',
        order: 50,
        bulkApplicable: true,
      },
      {
        id: 'asset-default-labels',
        title: 'Default Labels',
        component: AssetLabelsSectionComponent,
        componentInputs: { entity: asset, bulkContext },
        category: 'settings',
        order: 60,
        bulkApplicable: true,
      },
    ];
  }

  /**
   * Create sections for asset events
   */
  createAssetEventsSections(
    asset: AssetResponse | null,
    isBulkMode = false,
    selectedEntities: AssetResponse[] = [],
  ): AdminDetailSection[] {
    const bulkContext = this.buildBulkContext(isBulkMode, selectedEntities);

    return [
      {
        id: 'asset-event-triggers',
        title: 'Event Triggers',
        component: AssetEventTriggersSectionComponent,
        componentInputs: { entity: asset, bulkContext },
        category: 'events',
        order: 10,
        bulkApplicable: true,
      },
      {
        id: 'asset-curfew-events',
        title: 'Working Hours',
        component: AssetCurfewEventsSectionComponent,
        componentInputs: { entity: asset, bulkContext },
        category: 'events',
        order: 20,
        bulkApplicable: true,
      },
      {
        id: 'asset-analog-triggers',
        title: 'Analog Triggers',
        component: AssetAnalogTriggersSectionComponent,
        componentInputs: { entity: asset, bulkContext },
        category: 'events',
        order: 30,
        bulkApplicable: true,
      },
      {
        id: 'asset-zone-triggers',
        title: 'Geographic Triggers',
        component: AssetZonesSectionComponent,
        componentInputs: { entity: asset, bulkContext },
        category: 'events',
        order: 40,
        bulkApplicable: true,
      },
    ];
  }

  /**
   * Create sections for asset changes
   */
  createChangesSection(asset: AssetResponse | null): AdminDetailSection[] {
    return [
      {
        id: 'asset-changes',
        title: 'Changes',
        component: FeedSectionComponent,
        componentInputs: {
          entity: asset,
        },
        category: 'feed',
        order: 10,
        bulkApplicable: false,
      },
    ];
  }

  /**
   * Create all asset sections in one call
   */
  createAllAssetSections(
    asset: AssetResponse | null,
    isBulkMode = false,
    selectedEntities: AssetResponse[] = [],
  ): AdminDetailSection[] {
    return [
      ...this.createAssetInformationSections(
        asset,
        isBulkMode,
        selectedEntities,
      ),
      ...this.createAssetSettingsSections(asset, isBulkMode, selectedEntities),
      ...this.createAssetEventsSections(asset, isBulkMode, selectedEntities),
      ...this.createChangesSection(asset),
    ];
  }
}
