import {
  Component,
  computed,
  effect,
  inject,
  signal,
  untracked,
} from '@angular/core';
import { isDefined, isNullOrUndefined } from '../../../../../shared/utils';
import { CommonModule } from '@angular/common';
import { takeUntilDestroyed } from '@angular/core/rxjs-interop';
import { Validators } from '@angular/forms';
import { ButtonModule } from 'primeng/button';
import {
  AccountsService,
  ClientResponse,
  CustomFieldDefinition,
  IdName,
  VendorResponse,
} from '../../../../../api';
import { DynamicFormComponent } from '../../../../../shared/components/forms/dynamic-form/dynamic-form.component';
import { GridComponent } from '../../../../../shared/components/grid/grid.component';
import {
  createDropdownField,
  createTextAreaField,
  createTextField,
} from '../../../../../shared/models';
import { EntitySectionBaseComponent } from '../../base';
import { CustomFieldResponse } from '../../../models';
import { CustomFieldsDataAdapter } from '../../../services/adapters';
import { firstValueFrom, Observable } from 'rxjs';
import { DynamicDialogConfig } from 'primeng/dynamicdialog';
import { TranslatePipe } from '@ngx-translate/core';

@Component({
  selector: 'app-custom-field-details-section',
  imports: [
    CommonModule,
    ButtonModule,
    GridComponent,
    DynamicFormComponent,
    TranslatePipe,
  ],
  templateUrl: './custom-field-details-section.component.html',
  styleUrl: './custom-field-details-section.component.scss',
})
export class CustomFieldDetailsSectionComponent extends EntitySectionBaseComponent<
  CustomFieldResponse | Record<string, CustomFieldDefinition[]>
> {
  private readonly dialogConfig = inject(DynamicDialogConfig, {
    optional: true,
  });
  private readonly accountsService = inject(AccountsService);
  private readonly customFieldsAdapter = inject(CustomFieldsDataAdapter);
  readonly customFieldDetails = computed(() => {
    const customFieldDetails: CustomFieldResponse =
      this.entity() as CustomFieldResponse;
    this.languageService.currentLanguage();

    if (!isDefined(customFieldDetails)) return [];

    // Check if customFieldDetails is a CustomFieldResponse (has id property)
    if (!('id' in customFieldDetails)) return [];

    const [_ownerId, _entityTypeFromId, fieldId] =
      customFieldDetails.id.split('.');

    return [
      {
        key: this.translate.instant(
          'ADMIN.PROFILES.CUSTOM_FIELDS.DETAILS.FIELDS.ID',
        ),
        value: fieldId ?? this.translate.instant('SHARED.COMMON.NONE'),
      },
      {
        key: this.translate.instant(
          'ADMIN.PROFILES.CUSTOM_FIELDS.DETAILS.FIELDS.NAME',
        ),
        value:
          customFieldDetails.name ??
          this.translate.instant('SHARED.COMMON.NONE'),
      },
      {
        key: this.translate.instant(
          'ADMIN.PROFILES.CUSTOM_FIELDS.DETAILS.FIELDS.ENTITY',
        ),
        value:
          customFieldDetails?._entityType?.name ??
          this.translate.instant('SHARED.COMMON.NONE'),
      },
      {
        key: this.translate.instant(
          'ADMIN.PROFILES.CUSTOM_FIELDS.DETAILS.FIELDS.REQUIRED',
        ),
        value:
          customFieldDetails.required === true
            ? this.translate.instant('SHARED.COMMON.FORMS.CHECKBOX.YES')
            : this.translate.instant('SHARED.COMMON.FORMS.CHECKBOX.NO'),
      },
      {
        key: this.translate.instant(
          'ADMIN.PROFILES.CUSTOM_FIELDS.DETAILS.FIELDS.TYPE',
        ),
        value:
          customFieldDetails.type?.name ??
          this.translate.instant('SHARED.COMMON.NONE'),
      },
    ];
  });
  protected readonly selectOptionsLoaded = signal<boolean>(false);
  selectOptions: Record<string, { label: string; value: string | boolean }[]> =
    {};

  private readonly effectiveOwnerId = computed<string | null>(() => {
    if (isDefined(this.dialogConfig?.data?.ownerId)) {
      return this.dialogConfig?.data?.ownerId as string;
    }
    const customField = this.entity() as CustomFieldResponse;
    if (customField?.id && typeof customField.id === 'string') {
      const idParts = customField.id.split('.');
      if (idParts.length > 0 && idParts[0]) return idParts[0];
    }
    return null;
  });

  constructor() {
    super();

    this.columns = [
      { field: 'key', header: '', transform: 'uppercase' },
      { field: 'value', header: '' },
    ];

    effect(() => {
      const selectOptionsLoaded = this.selectOptionsLoaded();
      if (selectOptionsLoaded) {
        untracked(() => {
          this.updateFormFields();
        });
      }
    });

    effect(() => {
      const ownerId = this.effectiveOwnerId();
      this.selectOptionsLoaded.set(false);
      untracked(() => this.loadSelectOptions(ownerId));
    });
  }

  private loadSelectOptions(ownerId: string | null | undefined): void {
    if (isNullOrUndefined(ownerId)) {
      this.selectOptions = {};
      this.selectOptionsLoaded.set(true);
      this.updateFormFields();
      return;
    }

    this.customFieldsAdapter.getCachedAssetTypes(ownerId).subscribe({
      next: (assetTypes) => {
        this.selectOptions = {
          entityTypes: assetTypes
            .map((item) => ({ label: item.name ?? '', value: item.id }))
            .sort((a, b) => a.label.localeCompare(b.label)),
          required: [
            {
              label: this.translate.instant('SHARED.COMMON.FORMS.CHECKBOX.YES'),
              value: true,
            },
            {
              label: this.translate.instant('SHARED.COMMON.FORMS.CHECKBOX.NO'),
              value: false,
            },
          ],
          types: [
            {
              label: this.translate.instant(
                'ADMIN.PROFILES.CUSTOM_FIELDS.TYPES.TEXT',
              ),
              value: 'text',
            },
            {
              label: this.translate.instant(
                'ADMIN.PROFILES.CUSTOM_FIELDS.TYPES.MEMO',
              ),
              value: 'memo',
            },
            {
              label: this.translate.instant(
                'ADMIN.PROFILES.CUSTOM_FIELDS.TYPES.COMBO',
              ),
              value: 'combo',
            },
            {
              label: this.translate.instant(
                'ADMIN.PROFILES.CUSTOM_FIELDS.TYPES.CHECKBOX',
              ),
              value: 'checkbox',
            },
            {
              label: this.translate.instant(
                'ADMIN.PROFILES.CUSTOM_FIELDS.TYPES.DATE',
              ),
              value: 'date',
            },
            {
              label: this.translate.instant(
                'ADMIN.PROFILES.CUSTOM_FIELDS.TYPES.DATETIME',
              ),
              value: 'datetime',
            },
            {
              label: this.translate.instant(
                'ADMIN.PROFILES.CUSTOM_FIELDS.TYPES.URL',
              ),
              value: 'url',
            },
          ],
        };
        this.selectOptionsLoaded.set(true);
      },
      error: () => {
        this.selectOptionsLoaded.set(true);
      },
    });
  }

  protected override updateFormFields(): void {
    const customField = this.entity() as CustomFieldResponse;

    // Default values
    let ownerId = '';
    let fieldId = '';
    let name = '';
    let entityTypeId = '';
    let required = false;
    let typeId = '';

    // Extract values from customField if it exists
    if (isDefined(customField) && isDefined(customField.id)) {
      const [extractedOwnerId, _entityTypeFromId, extractedFieldId] =
        customField.id.split('.');
      ownerId = extractedOwnerId || '';
      fieldId = extractedFieldId || '';
      name = customField.name || '';
      entityTypeId = (customField._entityType as IdName)?.id || '';
      required = customField.required || false;
      typeId = (customField.type as IdName)?.id || '';
    } else if (isDefined(this.dialogConfig?.data?.ownerId)) {
      // Use ownerId from dialog config if customField is not defined (create mode)
      ownerId = String(this.dialogConfig?.data?.ownerId ?? '');
    }

    // Always create form fields, regardless of whether customField is defined
    this.formFields = [
      createTextField('ownerId', 'OwnerId', ownerId, {
        name: 'ownerId',
        hidden: true,
      }),
      createTextField(
        'tag',
        this.translate.instant(
          'ADMIN.PROFILES.CUSTOM_FIELDS.DETAILS.FIELDS.ID',
        ),
        fieldId,
        {
          name: 'tag',
          validations: [
            {
              name: 'required',
              validator: Validators.required,
              message: this.translate.instant(
                'SHARED.COMMON.FORMS.SHARED.REQUIRED',
                {
                  field: this.translate.instant(
                    'ADMIN.PROFILES.CUSTOM_FIELDS.DETAILS.FIELDS.ID',
                  ),
                },
              ),
            },
          ],
        },
      ),
      createTextField(
        'title',
        this.translate.instant(
          'ADMIN.PROFILES.CUSTOM_FIELDS.DETAILS.FIELDS.NAME',
        ),
        name,
        {
          name: 'title',
          validations: [
            {
              name: 'required',
              validator: Validators.required,
              message: this.translate.instant(
                'SHARED.COMMON.FORMS.SHARED.REQUIRED',
                {
                  field: this.translate.instant(
                    'ADMIN.PROFILES.CUSTOM_FIELDS.DETAILS.FIELDS.NAME',
                  ),
                },
              ),
            },
          ],
        },
      ),
      createDropdownField(
        'entityType',
        this.translate.instant(
          'ADMIN.PROFILES.CUSTOM_FIELDS.DETAILS.FIELDS.ENTITY',
        ),
        this.selectOptions['entityTypes'] ?? [],
        entityTypeId,
        {
          name: 'entityType',
          validations: [
            {
              name: 'required',
              validator: Validators.required,
              message: this.translate.instant(
                'SHARED.COMMON.FORMS.SHARED.REQUIRED',
                {
                  field: this.translate.instant(
                    'ADMIN.PROFILES.CUSTOM_FIELDS.DETAILS.FIELDS.ENTITY',
                  ),
                },
              ),
            },
          ],
          disabled: !this.createMode(),
          props: {
            appendTo: 'body',
          },
        },
      ),
      createDropdownField(
        'required',
        this.translate.instant(
          'ADMIN.PROFILES.CUSTOM_FIELDS.DETAILS.FIELDS.REQUIRED',
        ),
        this.selectOptions['required'] ?? [],
        required,
        {
          name: 'required',
          validations: [
            {
              name: 'required',
              validator: Validators.required,
              message: this.translate.instant(
                'SHARED.COMMON.FORMS.SHARED.REQUIRED',
                {
                  field: this.translate.instant(
                    'ADMIN.PROFILES.CUSTOM_FIELDS.DETAILS.FIELDS.REQUIRED',
                  ),
                },
              ),
            },
          ],
          props: {
            appendTo: 'body',
          },
        },
      ),
      createDropdownField(
        'type',
        this.translate.instant(
          'ADMIN.PROFILES.CUSTOM_FIELDS.DETAILS.FIELDS.TYPE',
        ),
        this.selectOptions['types'] ?? [],
        typeId,
        {
          name: 'type',
          validations: [
            {
              name: 'required',
              validator: Validators.required,
              message: this.translate.instant(
                'SHARED.COMMON.FORMS.SHARED.REQUIRED',
                {
                  field: this.translate.instant(
                    'ADMIN.PROFILES.CUSTOM_FIELDS.DETAILS.FIELDS.TYPE',
                  ),
                },
              ),
            },
          ],
          props: {
            appendTo: 'body',
          },
          conditional: true,
          conditions: {
            combo: [
              createTextAreaField(
                'values',
                this.translate.instant(
                  'ADMIN.PROFILES.CUSTOM_FIELDS.DETAILS.FIELDS.VALUES',
                ),
                isDefined(customField) ? customField.values : '',
                {
                  name: 'values',
                  validations: [
                    {
                      name: 'required',
                      validator: Validators.required,
                      message: this.translate.instant(
                        'SHARED.COMMON.FORMS.SHARED.REQUIRED',
                        {
                          field: this.translate.instant(
                            'ADMIN.PROFILES.CUSTOM_FIELDS.DETAILS.FIELDS.VALUES',
                          ),
                        },
                      ),
                    },
                  ],
                  hint: this.translate.instant(
                    'ADMIN.PROFILES.CUSTOM_FIELDS.DETAILS.FIELDS.VALUES_DESCRIPTION',
                  ),
                  props: {
                    rows: 5,
                    autoResize: true,
                  },
                },
              ),
            ],
          },
        },
      ),
    ];
  }

  protected override submitChanges(
    formData: Record<string, string | number | boolean | object>,
  ): void {
    const customField = this.entity();
    if (isNullOrUndefined(customField)) return;

    const data = this.transformFormData(formData);
    const customFieldData = Object.fromEntries(
      Object.entries({
        id: data['tag'] as string,
        title: data['title'] as string,
        type: data['type'] as string,
        required: data['required'] as boolean,
        values: data['values'] as { key: string; value: string }[],
      }).filter(([_, value]) => isDefined(value)),
    );

    const [companyId, entityType, id] = (customField.id as string).split('.');
    firstValueFrom(this.accountsService.getCompany(companyId))
      .then((company) => {
        const customFields: Record<string, CustomFieldDefinition[]> =
          JSON.parse(JSON.stringify(company.customFields));
        const bucket = customFields[entityType] ?? [];
        const idx = bucket.findIndex((x) => x.id === id);
        if (idx > -1) {
          bucket[idx] = {
            ...bucket[idx],
            ...customFieldData,
          };
        }
        customFields[entityType] = bucket;

        let request$: Observable<ClientResponse | VendorResponse>;

        if (company.type === 'client') {
          request$ = this.accountsService.updateClientDetails(company.id, {
            customFields,
          });
        } else if (company.type === 'vendor') {
          request$ = this.accountsService.updateVendorDetails(company.id, {
            customFields,
          });
        } else {
          console.error(
            'Neither clientId nor vendorId found in route parameters',
          );
          return;
        }

        request$.pipe(takeUntilDestroyed(this.destroyRef)).subscribe({
          next: (response: ClientResponse | VendorResponse) => {
            this.customFieldsAdapter.invalidateCache(company.id);
            this.clearUnsavedChanges();
            this.isFormEditable.set(false);
            this.isSubmitting.set(false);
            this.broadcastService.broadcast('entity-updated', {
              entityType: 'custom-field',
              operation: 'update',
              entityId: customField.id,
              data: response,
            });
          },
          error: (_error) => {
            this.isFormEditable.set(true);
            this.isSubmitting.set(false);
          },
        });
      })
      .catch(() => {});
  }

  protected override onFormValueChange(
    formData: Record<string, string | number | object>,
  ): void {
    const transformedData = this.transformFormData(formData);

    this.formValueChange.emit(transformedData);
  }

  protected override transformFormData(
    formData: Record<string, string | number | boolean | object>,
  ) {
    const transformedData = { ...formData };

    // Transform entityType ID to IdName object
    if (
      isDefined(transformedData['entityType']) &&
      typeof transformedData['entityType'] === 'string'
    ) {
      const entityTypeOption = this.selectOptions?.['entityTypes']?.find(
        (option) => option.value === transformedData['entityType'],
      );

      if (entityTypeOption) {
        transformedData['entityType'] = {
          id: entityTypeOption.value,
          name: entityTypeOption.label,
        };
      }
    }

    // Transform values string to array
    if (
      isDefined(transformedData['values']) &&
      typeof transformedData['values'] === 'string'
    ) {
      const valuesString = transformedData['values'];
      transformedData['values'] = valuesString
        .split('\n')
        .filter((line) => line.trim() !== '')
        .map((line) => ({ key: line.trim(), value: line.trim() }));
    }
    return transformedData;
  }
}
