import { CommonModule } from '@angular/common';
import {
  Component,
  DestroyRef,
  OnInit,
  TemplateRef,
  effect,
  inject,
  signal,
  viewChild,
} from '@angular/core';
import { takeUntilDestroyed } from '@angular/core/rxjs-interop';
import { ReactiveFormsModule } from '@angular/forms';

import { ButtonModule } from 'primeng/button';
import { DynamicDialogRef, DynamicDialogConfig } from 'primeng/dynamicdialog';
import { TranslatePipe, TranslateService } from '@ngx-translate/core';

import { WizardComponent } from '../../../../../shared/components/wizard/wizard.component';
import { isDefined, isNullOrUndefined } from '../../../../../shared/utils';
import { ContactDetailsSectionComponent } from '../contact-details-section/contact-details-section.component';
import { Step } from '../../../../../shared/models';
import { BroadcastEventMessageService } from '../../../services/broadcast-event-messages.service';
import {
  ContactCreateRequest,
  ContactDetailItem,
  ContactsService,
} from '../../../services/contacts.service';
import { ContactsCacheService } from '../../../../../core/services/contacts-cache.service';
import { finalize } from 'rxjs';

@Component({
  selector: 'app-contact-create-wizard',
  imports: [
    CommonModule,
    ReactiveFormsModule,
    WizardComponent,
    ButtonModule,
    ContactDetailsSectionComponent,
    TranslatePipe,
  ],
  templateUrl: './contact-create-wizard.component.html',
  styleUrl: './contact-create-wizard.component.scss',
})
export class ContactCreateWizardComponent implements OnInit {
  contactDetailsStep = viewChild<TemplateRef<{ $implicit: Step }>>('contactDetailsStep');
  confirmationTemplate = viewChild<TemplateRef<{ $implicit: Step }>>('confirmationTemplate');
  contactDetailsForm = viewChild<ContactDetailsSectionComponent>('contactDetailsForm');

  private readonly contactsService = inject(ContactsService);
  private readonly broadcastService = inject(BroadcastEventMessageService);
  private readonly translate = inject(TranslateService);
  protected readonly destroyRef = inject(DestroyRef);
  private readonly dialogRef = inject(DynamicDialogRef);
  private readonly dialogConfig = inject(DynamicDialogConfig);
  readonly contactsCache = inject(ContactsCacheService);

  newContact = signal<Partial<ContactDetailItem>>({});
  isSubmitting = signal<boolean>(false);

  steps: Step[] = [];
  ownerId: string | null = null;

  constructor() {
    effect(() => {
      const contactDetailsStep = this.contactDetailsStep();
      const confirmationTemplate = this.confirmationTemplate();

      if (isNullOrUndefined(contactDetailsStep) || isNullOrUndefined(confirmationTemplate)) {
        return;
      }

      this.steps = [
        {
          value: 1,
          header: this.translate.instant('ADMIN.CONTACTS.WIZARD.STEPS.DETAILS'),
          content: contactDetailsStep,
          complete: false,
          validate: () => this.contactDetailsForm()?.validate() ?? false,
        },
        {
          value: 2,
          header: this.translate.instant('ADMIN.CONTACTS.WIZARD.STEPS.CONFIRMATION'),
          content: confirmationTemplate,
          complete: true,
        },
      ];
    });
  }

  ngOnInit(): void {
    if (isDefined(this.dialogConfig.data)) {
      this.ownerId = this.dialogConfig.data.ownerId ?? null;
    }
    if (isDefined(this.ownerId)) {
      this.contactsCache.loadForClient(this.ownerId);
    }
  }

  onDetailsFormValidityChange(isValid: boolean): void {
    if (isDefined(this.steps[0])) {
      this.steps[0].disableNext = !isValid;
    }
  }

  updateContactDetails(formData: Record<string, unknown>): void {
    this.newContact.update((current) => {
      const updated: Partial<ContactDetailItem> = { ...current };
      Object.keys(formData).forEach((key) => {
        (updated as Record<string, unknown>)[key] = formData[key];
      });
      return updated;
    });
  }

  private buildCreateRequest(): ContactCreateRequest {
    const contact = this.newContact() as Record<string, unknown>;
    return {
      ownerId: this.ownerId ?? '',
      name: contact['name'] as string,
      type: contact['type'] as ContactCreateRequest['type'],
      emailAddress: contact['emailAddress'] as string | undefined,
      phoneMobile: contact['phoneMobile'] as string | undefined,
      phoneOffice: contact['phoneOffice'] as string | undefined,
      notes: contact['notes'] as string | undefined,
    };
  }

  onWizardComplete(): void {
    this.isSubmitting.set(true);
    this.contactsService
      .create(this.buildCreateRequest())
      .pipe(
        takeUntilDestroyed(this.destroyRef),
        finalize(() => this.isSubmitting.set(false)),
      )
      .subscribe({
        next: (response) => {
          this.broadcastService.broadcast('entity-updated', {
            entityType: 'contact',
            operation: 'create',
            entityId: response.id,
          });
          this.dialogRef.close(response);
        },
        error: () => {},
      });
  }

  onWizardCancel(): void {
    this.newContact.set({});
    this.dialogRef.close();
  }
}
