  readonly ioTypeDetails = computed(() => {
    const ioTypeDetails = this.entity();
    if (!isDefined(ioTypeDetails)) return [];

    // Get the type using ApiSchemaService for consistency
    const typeValue = this.apiSchemaService.getEntityType<
      Record<string, unknown>,
      IoTypeListItem.TypeEnum
    >(ioTypeDetails, 'Iotype');

    const result: Partial<IoTypeListItem> = {
      name: ioTypeDetails.name,
      type: typeValue,
      active: ioTypeDetails.text ? (ioTypeDetails.text.active ?? null) : null,
      inactive: ioTypeDetails.text
        ? (ioTypeDetails.text.inactive ?? null)
        : null,
      smoothingType: ioTypeDetails.smoothingType,
      unit: ioTypeDetails.unit,
      rateUnit: ioTypeDetails.rate?.unit,
      rateMultiplier: ioTypeDetails.rate?.multiplier,
      rateType: ioTypeDetails.rate?.type,
      lookups: ioTypeDetails.lookups,
    };
    for (const key of Object.keys(result)) {
      if (result[key] === undefined || result[key] === null) {
        delete result[key];
      }
    }

    return Object.keys(result).map((key) => {
      if (key === 'rateType') {
        return {
          key: this.utilityService.decamelize(key),
          value: this.utilityService.decamelize(result[key]),
        };
      }
      if (key === 'type') {
        return {
          key: this.utilityService.decamelize(key),
          value: this.typeOptions.find((type) => type.key === result[key])
            ?.label,
        };
      }
      if (key === 'lookups') {
        return {
          key: this.utilityService.decamelize(key),
          value: this.formatLookupsForDisplay(result[key]),
        };
      }
      if (key === 'smoothingType') {
        // Reuse the type resolved from the entity above. Re-resolving here via
        // getEntityType(result, ...) breaks under the modern schema, where the
        // type key would be 'ioTypeListItemType' but `result` stores it as 'type',
        // so the Filter row was silently dropped.
        if (
          typeValue === IoTypeListItem.TypeEnum.AnalogInput ||
          typeValue === IoTypeListItem.TypeEnum.TemperatureInput ||
          typeValue === IoTypeListItem.TypeEnum.CanInput
        ) {
          return {
            key: 'Filter',
            value: this.smoothingOptions.find(
              (smoothing) => smoothing.value === result[key],
            )?.label,
          };
        }
        return;
      }
      return {
        key: this.utilityService.decamelize(key),
        value: result[key],
      };
    });
  });

