import { CommonModule } from '@angular/common';
import {
  Component,
  computed,
  effect,
  inject,
  input,
  OnInit,
  signal,
  untracked,
} from '@angular/core';
import { Validators } from '@angular/forms';
import { EMPTY, Observable, Subject, debounceTime, of, switchMap } from 'rxjs';
import { takeUntilDestroyed } from '@angular/core/rxjs-interop';

import {
  ExportTaskListItem,
  ExportTaskCreateRequest,
  ExportTaskUpdateRequest,
  ExportTaskResponse,
  EntitiesService,
  ClientListItem,
  ClientsService,
  EventActorFilter,
} from '../../../../../api';
import {
  createTextField,
  createDropdownField,
  createMultiselectField,
  createPasswordField,
  createTextAreaField,
  createAssetFilterField,
  createAutocompleteField,
  FormFieldConfig,
} from '../../../../../shared/models';
import { EntitySectionBaseComponent } from '../../base';
import {
  hasProperty,
  isDefined,
  isNullOrUndefined,
} from '../../../../../shared/utils';
import { GridComponent } from '../../../../../shared/components/grid/grid.component';
import { DynamicFormComponent } from '../../../../../shared/components/forms/dynamic-form/dynamic-form.component';
import { UtilityService } from '../../../../../core/services/utility.service';
import {
  CLIENT_SEARCH_LIMIT,
  SEARCH_DEBOUNCE_TIME,
} from '../../../../../core/models';
import { TranslatePipe } from '@ngx-translate/core';

type ExportTaskEntity = ExportTaskListItem | Partial<ExportTaskCreateRequest>;

@Component({
  selector: 'app-export-task-settings-section',
  imports: [CommonModule, GridComponent, DynamicFormComponent, TranslatePipe],
  templateUrl: './export-task-settings-section.component.html',
  styleUrl: './export-task-settings-section.component.scss',
})
export class ExportTaskSettingsSectionComponent
  extends EntitySectionBaseComponent<ExportTaskEntity>
  implements OnInit
{
  readonly ownerId = input<string | null>(null);

  private readonly entitiesService = inject(EntitiesService);
  private readonly clientsService = inject(ClientsService);
  private readonly utilityService = inject(UtilityService);

  readonly clientSearchResults = signal<ClientListItem[] | undefined>([]);
  private readonly isLoadingClients = signal<boolean>(false);
  private readonly searchSubject = new Subject<string>();

  private get documentTypeOptions() {
    return [
      {
        label: this.translate.instant(
          'ADMIN.EXPORT_TASKS.DOCUMENT_TYPES.TELEMETRY',
        ),
        value: 'telemetry',
      },
      {
        label: this.translate.instant(
          'ADMIN.EXPORT_TASKS.DOCUMENT_TYPES.EVENT',
        ),
        value: 'event',
      },
      {
        label: this.translate.instant('ADMIN.EXPORT_TASKS.DOCUMENT_TYPES.TRIP'),
        value: 'trip',
      },
      {
        label: this.translate.instant(
          'ADMIN.EXPORT_TASKS.DOCUMENT_TYPES.CRASH_DATA',
        ),
        value: 'crashdata',
      },
      {
        label: this.translate.instant(
          'ADMIN.EXPORT_TASKS.DOCUMENT_TYPES.CHANGES',
        ),
        value: 'changes',
      },
    ];
  }

  // Tracks the two values that gate conditional form sections.
  // Memoised so the rebuild effect only fires when these actually change,
  // not on every settings-form emission that updates the entity signal.
  private readonly _createModeFormKey = computed(() => {
    const entity = this.entity() as ExportTaskResponse;
    const client = entity?.client as { id?: string } | undefined;
    return `${entity?.deliveryMethod ?? ''}:${client?.id ?? ''}`;
  });

  readonly exportTaskSettings = computed(() => {
    this.languageService.currentLanguage();
    const entity = this.entity() as ExportTaskResponse;
    if (!isDefined(entity)) return [];

    const na = this.translate.instant('SHARED.COMMON.NA');
    const docTypes =
      (entity.documentTypes ?? [])
        .map(
          (t) =>
            this.documentTypeOptions.find((o) => o.value === t)?.label ?? t,
        )
        .join(', ') || this.translate.instant('SHARED.COMMON.NONE');

    const rows: { key: string; value: string }[] = [
      {
        key: this.translate.instant(
          'ADMIN.EXPORT_TASKS.SETTINGS.FIELDS.DOCUMENT_TYPES',
        ),
        value: docTypes,
      },
      {
        key: this.translate.instant(
          'ADMIN.EXPORT_TASKS.SETTINGS.FIELDS.DOCUMENT_VERSION',
        ),
        value: entity.documentVersion ?? na,
      },
    ];

    if (entity.deliveryMethod !== 'firehose' && entity.client) {
      const assets = entity.assets ?? [];
      const assetText =
        assets.length > 0
          ? assets.map((a) => a.text).join(', ')
          : this.translate.instant('SHARED.COMMON.NONE');
      rows.push({
        key: this.translate.instant(
          'ADMIN.EXPORT_TASKS.SETTINGS.FIELDS.ASSETS',
        ),
        value: assetText,
      });
    }

    if (entity.deliveryMethod === 'firehose') {
      const settings = entity.settings as Record<string, unknown> | undefined;
      const assetCount = entity.assets?.length ?? 0;
      rows.push(
        {
          key: this.translate.instant(
            'ADMIN.EXPORT_TASKS.SETTINGS.FIELDS.CLIENTS',
          ),
          value:
            assetCount > 0
              ? this.translate.instant(
                  'ADMIN.EXPORT_TASKS.SETTINGS.FIELDS.CLIENT_COUNT',
                  { count: assetCount },
                )
              : this.translate.instant('SHARED.COMMON.NONE'),
        },
        {
          key: this.translate.instant(
            'ADMIN.EXPORT_TASKS.SETTINGS.FIELDS.ENDPOINT_TYPE',
          ),
          value: (settings?.['endpointType'] as string) ?? na,
        },
        {
          key: this.translate.instant(
            'ADMIN.EXPORT_TASKS.SETTINGS.FIELDS.ENDPOINT',
          ),
          value: (settings?.['endpoint'] as string) ?? na,
        },
      );
    }

    return rows;
  });

  constructor() {
    super();
    this.columns = [
      { field: 'key', header: '', transform: 'uppercase' },
      { field: 'value', header: '' },
    ];

    // The stepper renders all panels eagerly, so this component may be
    // initialized before step 1 is filled. Re-run field setup whenever
    // deliveryMethod or clientId change in create mode so conditional
    // fields (assets, firehose settings) appear correctly.
    effect(() => {
      if (!this.createMode()) return;
      this._createModeFormKey(); // tracked — memoised, only changes when deliveryMethod/clientId change
      untracked(() => this.updateFormFields());
    });
  }

  ngOnInit(): void {
    this.setupClientSearch();
  }

  protected override updateFormFields(): void {
    const entity = this.entity() as ExportTaskResponse;
    const settings = entity?.settings as Record<string, unknown> | undefined;
    const editable = this.createMode() || entity?.state !== 'active';

    const fields: FormFieldConfig[] = [
      createMultiselectField(
        'documentTypes',
        this.translate.instant(
          'ADMIN.EXPORT_TASKS.SETTINGS.FIELDS.DOCUMENT_TYPES',
        ),
        entity?.documentTypes,
        this.documentTypeOptions,
        {
          name: 'documentTypes',
          validations: [
            {
              name: 'required',
              validator: Validators.required,
              message: this.translate.instant(
                'SHARED.COMMON.FORMS.SHARED.REQUIRED',
                {
                  field: this.translate.instant(
                    'ADMIN.EXPORT_TASKS.SETTINGS.FIELDS.DOCUMENT_TYPES',
                  ),
                },
              ),
            },
          ],
          props: {
            appendTo: 'body',
          },
        },
      ),
      createDropdownField(
        'documentVersion',
        this.translate.instant(
          'ADMIN.EXPORT_TASKS.SETTINGS.FIELDS.DOCUMENT_VERSION',
        ),
        [
          {
            label: this.translate.instant(
              'ADMIN.EXPORT_TASKS.DOCUMENT_VERSIONS.V1',
            ),
            value: 'v1',
          },
          {
            label: this.translate.instant(
              'ADMIN.EXPORT_TASKS.DOCUMENT_VERSIONS.V2',
            ),
            value: 'v2',
          },
        ],
        entity?.documentVersion,
        {
          name: 'documentVersion',
          validations: [
            {
              name: 'required',
              validator: Validators.required,
              message: this.translate.instant(
                'SHARED.COMMON.FORMS.SHARED.REQUIRED',
                {
                  field: this.translate.instant(
                    'ADMIN.EXPORT_TASKS.SETTINGS.FIELDS.DOCUMENT_VERSION',
                  ),
                },
              ),
            },
          ],
          props: {
            appendTo: 'body',
          },
        },
      ),
    ];

    // Asset filter — shown when a client is assigned and not a firehose task
    if (entity?.client && entity?.deliveryMethod !== 'firehose') {
      fields.push(
        createAssetFilterField(
          'assets',
          this.translate.instant('ADMIN.EXPORT_TASKS.SETTINGS.FIELDS.ASSETS'),
          entity.assets ?? [],
          [],
          {
            name: 'assets',
            props: {
              ownerId: entity.client.id,
              multiSelect: true,
              showGroupTabs: true,
            },
            validations: [
              {
                name: 'required',
                validator: Validators.required,
                message: this.translate.instant(
                  'SHARED.COMMON.FORMS.SHARED.REQUIRED',
                  {
                    field: this.translate.instant(
                      'ADMIN.EXPORT_TASKS.SETTINGS.FIELDS.ASSETS',
                    ),
                  },
                ),
              },
            ],
          },
        ),
      );
    }

    // Client autocomplete — shown for firehose tasks (selects which clients' data to export)
    if (entity?.deliveryMethod === 'firehose') {
      const initialClients = (entity?.assets ?? [])
        .filter((a) => a.actorType === 'client')
        .map((a) => ({ id: a.actorId, name: a.actorName ?? a.text }));

      const clientsField = createAutocompleteField(
        'assets',
        this.translate.instant('ADMIN.EXPORT_TASKS.SETTINGS.FIELDS.CLIENTS'),
        initialClients,
        () => this.clientSearchResults() ?? [],
        this.searchClient.bind(this),
        {
          name: 'assets',
          props: {
            forceSelection: true,
            field: 'name',
            multiple: true,
            completeOnFocus: true,
            showEmptyMessage: true,
            appendTo: 'body',
          },
          autocompleteLoading: () => this.isLoadingClients(),
          validations: [
            {
              name: 'required',
              validator: Validators.required,
              message: this.translate.instant(
                'SHARED.COMMON.FORMS.SHARED.REQUIRED',
                {
                  field: this.translate.instant(
                    'ADMIN.EXPORT_TASKS.SETTINGS.FIELDS.CLIENTS',
                  ),
                },
              ),
            },
          ],
        },
      );
      fields.push(clientsField);
    }

    if (entity?.deliveryMethod === 'firehose') {
      const s3Fields: FormFieldConfig[] = [
        createTextField(
          'endpoint',
          this.translate.instant(
            'ADMIN.EXPORT_TASKS.SETTINGS.FIELDS.BUCKET_ARN',
          ),
          settings?.['endpoint'] as string,
          {
            name: 'endpoint',
            hint: this.translate.instant(
              'ADMIN.EXPORT_TASKS.SETTINGS.FIELDS.BUCKET_ARN_HINT',
            ),
            readonly: !editable,
            validations: [
              {
                name: 'required',
                validator: Validators.required,
                message: this.translate.instant(
                  'SHARED.COMMON.FORMS.SHARED.REQUIRED',
                  {
                    field: this.translate.instant(
                      'ADMIN.EXPORT_TASKS.SETTINGS.FIELDS.BUCKET_ARN',
                    ),
                  },
                ),
              },
            ],
          },
        ),
        createTextField(
          'prefix',
          this.translate.instant('ADMIN.EXPORT_TASKS.SETTINGS.FIELDS.PREFIX'),
          settings?.['prefix'] as string,
          {
            name: 'prefix',
            readonly: !editable,
            validations: [],
          },
        ),
      ];

      const httpFields: FormFieldConfig[] = [
        createTextField(
          'endpoint',
          this.translate.instant('ADMIN.EXPORT_TASKS.SETTINGS.FIELDS.URL'),
          settings?.['endpoint'] as string,
          {
            name: 'endpoint',
            hint: this.translate.instant(
              'ADMIN.EXPORT_TASKS.SETTINGS.FIELDS.URL_HINT',
            ),
            readonly: !editable,
            validations: [
              {
                name: 'required',
                validator: Validators.required,
                message: this.translate.instant(
                  'SHARED.COMMON.FORMS.SHARED.REQUIRED',
                  {
                    field: this.translate.instant(
                      'ADMIN.EXPORT_TASKS.SETTINGS.FIELDS.URL',
                    ),
                  },
                ),
              },
            ],
          },
        ),
        createPasswordField(
          'accessKey',
          this.translate.instant(
            'ADMIN.EXPORT_TASKS.SETTINGS.FIELDS.ACCESS_KEY',
          ),
          {
            name: 'accessKey',
            hint: this.translate.instant(
              'ADMIN.EXPORT_TASKS.SETTINGS.FIELDS.ACCESS_KEY_HINT',
            ),
            validations: [],
          },
        ),
        createDropdownField(
          'encoding',
          this.translate.instant('ADMIN.EXPORT_TASKS.SETTINGS.FIELDS.ENCODING'),
          [
            {
              label: this.translate.instant(
                'ADMIN.EXPORT_TASKS.ENCODING_OPTIONS.DISABLED',
              ),
              value: 'none',
            },
            {
              label: this.translate.instant(
                'ADMIN.EXPORT_TASKS.ENCODING_OPTIONS.GZIP',
              ),
              value: 'gzip',
            },
          ],
          (settings?.['encoding'] as string) ?? 'gzip',
          {
            name: 'encoding',
            disabled: !editable,
            validations: [
              {
                name: 'required',
                validator: Validators.required,
                message: this.translate.instant(
                  'SHARED.COMMON.FORMS.SHARED.REQUIRED',
                  {
                    field: this.translate.instant(
                      'ADMIN.EXPORT_TASKS.SETTINGS.FIELDS.ENCODING',
                    ),
                  },
                ),
              },
            ],
            props: {
              appendTo: 'body',
            },
          },
        ),
        createTextAreaField(
          'parameters',
          this.translate.instant('ADMIN.EXPORT_TASKS.SETTINGS.FIELDS.PARAMS'),
          settings?.['parameters'] as string,
          {
            name: 'parameters',
            hint: this.translate.instant(
              'ADMIN.EXPORT_TASKS.SETTINGS.FIELDS.PARAMS_HINT',
            ),
            readonly: !editable,
            validations: [],
          },
        ),
      ];

      fields.push(
        createDropdownField(
          'endpointType',
          this.translate.instant(
            'ADMIN.EXPORT_TASKS.SETTINGS.FIELDS.ENDPOINT_TYPE',
          ),
          [
            {
              label: this.translate.instant(
                'ADMIN.EXPORT_TASKS.ENDPOINT_TYPES.S3',
              ),
              value: 's3',
            },
            {
              label: this.translate.instant(
                'ADMIN.EXPORT_TASKS.ENDPOINT_TYPES.HTTP',
              ),
              value: 'http',
            },
          ],
          settings?.['endpointType'] as string,
          {
            name: 'endpointType',
            disabled: !editable,
            conditional: true,
            conditions: { s3: s3Fields, http: httpFields },
            validations: [
              {
                name: 'required',
                validator: Validators.required,
                message: this.translate.instant(
                  'SHARED.COMMON.FORMS.SHARED.REQUIRED',
                  {
                    field: this.translate.instant(
                      'ADMIN.EXPORT_TASKS.SETTINGS.FIELDS.ENDPOINT_TYPE',
                    ),
                  },
                ),
              },
            ],
            props: {
              appendTo: 'body',
            },
          },
        ),
      );
    }

    this.formFields = fields;
  }

  searchClient(searchTerm: string): void {
    if (!searchTerm || searchTerm.trim().length < 3) {
      this.clientSearchResults.set([]);
      this.isLoadingClients.set(false);
    } else {
      this.searchSubject.next(searchTerm.trim());
    }
  }

  private setupClientSearch(): void {
    this.searchSubject
      .pipe(
        debounceTime(SEARCH_DEBOUNCE_TIME),
        takeUntilDestroyed(this.destroyRef),
        switchMap((searchTerm) => {
          this.isLoadingClients.set(true);

          const ownerId = this.ownerId();
          if (!isDefined(ownerId)) return of({ items: [] });

          const filters = {
            state: { value: 'active', operator: '=' },
            name: { value: `*${searchTerm}*`, operator: '=' },
          };
          const rqlFilter = this.utilityService.constructRqlFilter(filters);

          return this.clientsService.listClients(
            ownerId,
            0,
            CLIENT_SEARCH_LIMIT,
            'name',
            rqlFilter,
          );
        }),
      )
      .subscribe({
        next: (data) => {
          this.isLoadingClients.set(false);
          if (isDefined(data) && hasProperty(data, 'items')) {
            this.clientSearchResults.set(data.items ?? []);
          }
        },
        error: () => {
          this.isLoadingClients.set(false);
          this.clientSearchResults.set([]);
        },
      });
  }

  protected override buildUpdateRequest(
    formData: Record<string, unknown>,
  ): Observable<unknown> {
    const entity = this.entity();
    if (isNullOrUndefined(entity)) return EMPTY;

    const updateRequest: ExportTaskUpdateRequest = {};
    const settingsFields = [
      'endpointType',
      'endpoint',
      'prefix',
      'encoding',
      'parameters',
      'accessKey',
    ];

    const isFirehose =
      (entity as ExportTaskResponse)?.deliveryMethod === 'firehose';

    Object.entries(formData).forEach(([key, value]) => {
      if (key === 'assets') return;
      if (!settingsFields.includes(key)) {
        (updateRequest as Record<string, unknown>)[key] = value;
      }
    });

    if ('assets' in formData) {
      if (isFirehose) {
        const clients = (formData['assets'] as ClientListItem[]) ?? [];
        updateRequest.assets = clients.map((c) => ({
          actorType: 'client',
          actorTypeId: c.id,
          actorTypeName: c.name,
          actorSelectionType: 'specific',
          actorId: c.id,
          actorName: c.name,
          text: c.name,
        }));
      } else {
        updateRequest.assets = formData['assets'] as EventActorFilter[];
      }
    }

    const settingsData: Record<string, unknown> = {};
    settingsFields.forEach((field) => {
      if (field in formData) {
        settingsData[field] = formData[field];
      }
    });

    if (Object.keys(settingsData).length > 0) {
      updateRequest.settings =
        settingsData as ExportTaskUpdateRequest['settings'];
    }

    return this.entitiesService.updateExportTask(
      (entity as ExportTaskListItem).id,
      updateRequest,
    );
  }

  protected override onSubmitSuccess(response: unknown): void {
    const entity = this.entity();
    if (isNullOrUndefined(entity)) return;
    this.broadcastService.broadcast('entity-updated', {
      entityType: 'exporttask',
      operation: 'update',
      entityId: (entity as ExportTaskListItem).id,
      data: response,
    });
  }
}
