import { Injectable } from '@angular/core';
import { AdminDetailSection } from '../models';

import { MapSetResponse } from '../../../api';
import { MapSetDetailsSectionComponent } from '../components/map-sets/map-set-details-section/map-set-details-section.component';
import { FeedSectionComponent } from '../components/shared/feed-section/feed-section.component';

@Injectable({ providedIn: 'root' })
export class MapSetSectionConfigFactory {
  /**
   * Create sections for Map Set information
   * @param mapSet The MapSet object to display in the section
   * @returns An array of AdminDetailSection objects representing the MapSet information sections
   */
  createMapSetInformationSections(
    mapSet: MapSetResponse | null,
  ): AdminDetailSection[] {
    return [
      {
        id: 'map-set-details',
        title: 'Map Set Details',
        component: MapSetDetailsSectionComponent,
        componentInputs: { entity: mapSet, entityType: 'map-set' },
        category: 'information',
        order: 10,
      },
    ];
  }

  /**
   * Create sections for Map Set changes
   * @param mapSet The MapSet object to display in the section
   * @returns An array of AdminDetailSection objects representing the MapSet changes sections
   */
  createChangesSection(mapSet: MapSetResponse | null): AdminDetailSection[] {
    return [
      {
        id: 'map-set-changes',
        title: 'Changes',
        component: FeedSectionComponent,
        componentInputs: {
          entity: mapSet,
        },
        category: 'feed',
        order: 10,
      },
    ];
  }

  /**
   * Create all Map Set sections in one call
   * @param mapSet The MapSet object to display in the sections
   * @returns An array of AdminDetailSection objects representing all MapSet sections
   */
  createAllMapSetSections(mapSet: MapSetResponse | null): AdminDetailSection[] {
    return [
      ...this.createMapSetInformationSections(mapSet),
      ...this.createChangesSection(mapSet),
    ];
  }
}
