import { CommonModule } from '@angular/common';
import {
  Component,
  computed,
  effect,
  inject,
  input,
  signal,
} from '@angular/core';
import { Validators } from '@angular/forms';
import { EMPTY, Observable } from 'rxjs';

import { ButtonModule } from 'primeng/button';
import { MessageModule } from 'primeng/message';
import { v4 as uuidv4 } from 'uuid';

import {
  AssetStateProfileListItem,
  AssetStateProfileCreateRequest,
  EntitiesService,
  AssetStateItem,
  EventFilter,
} from '../../../../../api';
import { DynamicFormComponent } from '../../../../../shared/components/forms/dynamic-form/dynamic-form.component';
import { ModalListFormComponent } from '../../../../../shared/components/forms/modal-list-form/modal-list-form.component';
import { GridComponent } from '../../../../../shared/components/grid/grid.component';
import {
  ListFieldModalConfig,
  FormFieldConfig,
  createTextField,
  createNumberField,
  createModalListField,
  createEventFilterField,
  createColorPickerField,
  ActorNodeData,
  EventNodeData,
  FilterCondition,
  TargetNodeData,
  TreeSelectNode,
} from '../../../../../shared/models';
import {
  isDefined,
  isEmpty,
  isNullOrUndefined,
} from '../../../../../shared/utils';
import { EntitySectionBaseComponent } from '../../base';
import { EventFilterService } from '../../../../../shared/services/event-filter.service';
import { TranslatePipe } from '@ngx-translate/core';

@Component({
  selector: 'app-asset-state-profile-details-section',
  imports: [
    CommonModule,
    ButtonModule,
    GridComponent,
    DynamicFormComponent,
    MessageModule,
    TranslatePipe,
  ],
  templateUrl: './asset-state-profile-details-section.component.html',
  styleUrl: './asset-state-profile-details-section.component.scss',
})
export class AssetStateProfileDetailsSectionComponent extends EntitySectionBaseComponent<
  AssetStateProfileListItem | Partial<AssetStateProfileCreateRequest>
> {
  readonly ownerId = input<string | null>(null);
  private readonly entitiesService = inject(EntitiesService);
  private readonly eventFilterService = inject(EventFilterService);

  readonly assetStateProfileDetails = computed(() => {
    const assetStateProfileDetails = this.entity();
    this.languageService.currentLanguage();
    if (!isDefined(assetStateProfileDetails)) return [];

    return [
      {
        key: this.translate.instant(
          'ADMIN.ASSET_STATE_PROFILES.DETAILS.FIELDS.NAME',
        ),
        value: assetStateProfileDetails.name,
      },
      {
        key: this.translate.instant(
          'ADMIN.ASSET_STATE_PROFILES.DETAILS.FIELDS.STATES',
        ),
        value: isEmpty(assetStateProfileDetails.items)
          ? this.translate.instant('SHARED.COMMON.NONE')
          : assetStateProfileDetails.items
              ?.map((item) => item.state)
              .join(', '),
      },
    ];
  });
  assetStateProfileItemModalConfig:
    | ListFieldModalConfig<AssetStateItem>
    | undefined;
  protected readonly warning = signal<string | null>(null);

  constructor() {
    super();

    // Setup initial columns
    this.columns = [
      { field: 'key', header: '', transform: 'uppercase' },
      { field: 'value', header: '' },
    ];

    effect(() => {
      const assetStateProfileDetails = this.entity();
      if (
        isNullOrUndefined(assetStateProfileDetails?.items) ||
        assetStateProfileDetails.items.length < 2
      ) {
        this.warning.set(
          this.translate.instant(
            'ADMIN.ASSET_STATE_PROFILES.WARNINGS.ITEM_LENGTH',
          ),
        );
      } else {
        this.warning.set(null);
      }
    });
  }

  protected override updateFormFields(): void {
    const assetStateProfile = this.entity();

    this.assetStateProfileItemModalConfig = {
      modalComponent: ModalListFormComponent,
      modalTitle: this.translate.instant(
        'ADMIN.ASSET_STATE_PROFILES.DETAILS.MODALS.STATE.TITLE',
      ),
      defaultItemProvider: () => ({
        id: uuidv4(),
        state: '',
        color: '#0000ff',
        radius: 0,
        filter: undefined,
      }),
      listItemFormatter: (item: AssetStateItem) =>
        this.stateItemToListItem(item),
      modalFields: (_item: AssetStateItem | undefined): FormFieldConfig[] => {
        return [
          createTextField('id', 'ID', _item?.id, {
            name: 'id',
            hidden: true,
          }),
          createTextField(
            'state',
            this.translate.instant(
              'ADMIN.ASSET_STATE_PROFILES.DETAILS.FIELDS.NAME',
            ),
            _item?.name,
            {
              name: 'state',
              validations: [
                {
                  name: 'required',
                  validator: Validators.required,
                  message: this.translate.instant(
                    'SHARED.COMMON.FORMS.SHARED.REQUIRED',
                    {
                      field: this.translate.instant(
                        'ADMIN.ASSET_STATE_PROFILES.DETAILS.FIELDS.NAME',
                      ),
                    },
                  ),
                },
              ],
            },
          ),
          createColorPickerField(
            'color',
            this.translate.instant(
              'ADMIN.ASSET_STATE_PROFILES.DETAILS.FIELDS.COLOR',
            ),
            undefined,
            {
              name: 'color',
              validations: [
                {
                  name: 'required',
                  validator: Validators.required,
                  message: this.translate.instant(
                    'SHARED.COMMON.FORMS.SHARED.REQUIRED',
                    {
                      field: this.translate.instant(
                        'ADMIN.ASSET_STATE_PROFILES.DETAILS.FIELDS.COLOR',
                      ),
                    },
                  ),
                },
              ],
              layout: 'horizontal',
              labelWidth: '1/3',
            },
          ),
          createNumberField(
            'radius',
            this.translate.instant(
              'ADMIN.ASSET_STATE_PROFILES.DETAILS.FIELDS.RADIUS',
            ),
            undefined,
            {
              name: 'radius',
              validations: [
                {
                  name: 'required',
                  validator: Validators.required,
                  message: this.translate.instant(
                    'SHARED.COMMON.FORMS.SHARED.REQUIRED',
                    {
                      field: this.translate.instant(
                        'ADMIN.ASSET_STATE_PROFILES.DETAILS.FIELDS.RADIUS',
                      ),
                    },
                  ),
                },
                {
                  name: 'min',
                  validator: Validators.min(0),
                  message: this.translate.instant(
                    'SHARED.COMMON.FORMS.NUMBER.MIN',
                    {
                      field: this.translate.instant(
                        'ADMIN.ASSET_STATE_PROFILES.DETAILS.FIELDS.RADIUS',
                      ),
                      min: 0,
                    },
                  ),
                },
                {
                  name: 'max',
                  validator: Validators.max(1000),
                  message: this.translate.instant(
                    'SHARED.COMMON.FORMS.NUMBER.MAX',
                    {
                      field: this.translate.instant(
                        'ADMIN.ASSET_STATE_PROFILES.DETAILS.FIELDS.RADIUS',
                      ),
                      max: 1000,
                    },
                  ),
                },
              ],
              layout: 'horizontal',
              labelWidth: '1/3',
              hint: this.translate.instant(
                'ADMIN.ASSET_STATE_PROFILES.DETAILS.FIELDS.RADIUS_DESCRIPTION',
              ),
              props: {
                suffix: 'meters',
              },
            },
          ),
          createEventFilterField(
            'filter',
            this.translate.instant(
              'ADMIN.ASSET_STATE_PROFILES.DETAILS.FIELDS.FILTER',
            ),
            undefined,
            ['costcentres', 'groups', 'types', 'categories'],
            {
              name: 'filter',
              required: true,
              validations: [
                {
                  name: 'required',
                  validator: Validators.required,
                  message: this.translate.instant(
                    'SHARED.COMMON.FORMS.SHARED.REQUIRED',
                    {
                      field: this.translate.instant(
                        'ADMIN.ASSET_STATE_PROFILES.DETAILS.FIELDS.FILTER',
                      ),
                    },
                  ),
                },
              ],
            },
          ),
        ];
      },
      subHeader: this.translate.instant(
        'ADMIN.ASSET_STATE_PROFILES.DETAILS.MODALS.STATE.DESCRIPTION',
      ),
    };
    this.formFields = [
      createTextField(
        'name',
        this.translate.instant(
          'ADMIN.ASSET_STATE_PROFILES.DETAILS.FIELDS.NAME',
        ),
        assetStateProfile?.name,
        {
          name: 'name',
          validations: [
            {
              name: 'required',
              validator: Validators.required,
              message: this.translate.instant(
                'SHARED.COMMON.FORMS.SHARED.REQUIRED',
                {
                  field: this.translate.instant(
                    'ADMIN.ASSET_STATE_PROFILES.DETAILS.FIELDS.NAME',
                  ),
                },
              ),
            },
          ],
        },
      ),
    ];

    if (!this.createMode()) {
      this.formFields.push(
        createModalListField<AssetStateItem>(
          'items',
          this.translate.instant(
            'ADMIN.ASSET_STATE_PROFILES.DETAILS.FIELDS.STATES',
          ),
          assetStateProfile?.items ?? [],
          {
            layout: 'horizontal',
            labelWidth: '1/3',
            name: 'items',
            props: {
              modalConfig: this.assetStateProfileItemModalConfig,
            },
          },
        ) as FormFieldConfig<unknown>,
      );
    }
  }

  protected override buildUpdateRequest(
    formData: Record<string, string | number | object | null | undefined>,
  ): Observable<unknown> {
    const assetStateProfile = this.entity();
    if (isNullOrUndefined(assetStateProfile)) return EMPTY;
    return this.entitiesService.updateAssetStateProfile(
      assetStateProfile.id,
      this.transformFormData(formData),
    );
  }

  protected override onSubmitSuccess(response: unknown): void {
    const assetStateProfile = this.entity();
    if (isNullOrUndefined(assetStateProfile)) return;
    this.broadcastService.broadcast('entity-updated', {
      entityType: 'asset-state-profile',
      operation: 'update',
      entityId: assetStateProfile.id,
      data: response,
    });
  }

  stateItemToListItem(item: AssetStateItem) {
    return {
      id: item.id,
      title: item.state,
      display: item.name,
      icon: `tag`,
      iconStyle: { color: item.color },
    };
  }

  protected override onFormValueChange(
    formData: Record<string, string | number | object | null | undefined>,
  ): void {
    const transformedData = this.transformFormData(formData);

    this.formValueChange.emit(transformedData);
  }

  protected override transformFormData(
    formData: Record<string, string | number | object | null | undefined>,
  ): Record<string, string | number | object | null | undefined> {
    const transformedData = { ...formData };

    // Transform each item in the "items" array (normalize name/state and filter)
    if (Array.isArray(transformedData['items'])) {
      transformedData['items'] = (
        transformedData['items'] as Record<string, unknown>[]
      ).map((item) => {
        const transformedItem: Record<string, unknown> = { ...item };

        // Ensure radius is a number
        if (isDefined(transformedItem['radius'])) {
          const r = transformedItem['radius'];
          transformedItem['radius'] = typeof r === 'string' ? Number(r) : r;
        }

        // Transform nested filter
        if (isDefined(transformedItem['filter'])) {
          const filter = transformedItem['filter'] as {
            actor?: TreeSelectNode<ActorNodeData>;
            action?: TreeSelectNode<EventNodeData>;
            target?: TreeSelectNode<TargetNodeData>;
            conditions?: FilterCondition[];
          };

          transformedItem['filter'] = {
            ...filter,
            actor: filter?.actor?.data,
            action: filter?.action?.data,
            target: filter?.target?.data,
            conditions:
              filter?.conditions?.map(({ id: _id, ...rest }) => rest) ?? [],
          };
        }

        // Normalize "state" (form field) to API "name"
        if (
          isDefined(transformedItem['state']) &&
          !isDefined(transformedItem['name'])
        ) {
          transformedItem['name'] = this.eventFilterService.getEventFilterText(
            transformedItem['filter'] as EventFilter,
          );
        }

        return transformedItem;
      });
    }

    return transformedData;
  }
}
