import { Component, inject } from '@angular/core';
import { CommonModule, KeyValuePipe } from '@angular/common';
import { DynamicDialogRef, DynamicDialogConfig } from 'primeng/dynamicdialog';
import { ButtonModule } from 'primeng/button';
import { TranslatePipe } from '@ngx-translate/core';

@Component({
  selector: 'app-export-task-credentials',
  imports: [CommonModule, KeyValuePipe, ButtonModule, TranslatePipe],
  templateUrl: './export-task-credentials.component.html',
  styleUrl: './export-task-credentials.component.scss',
})
export class ExportTaskCredentialsComponent {
  private readonly dialogRef = inject(DynamicDialogRef);
  private readonly dialogConfig = inject(DynamicDialogConfig);

  private readonly s3IamPolicyKey = 'S3 IAM Policy';

  get credentials(): Record<string, string> {
    return this.dialogConfig.data?.credentials ?? {};
  }

  isS3PolicyCredential(key: string): boolean {
    return key === this.s3IamPolicyKey;
  }

  onClose(): void {
    this.dialogRef.close();
  }
}
