import { Component, inject } from '@angular/core';
import { CommonModule } from '@angular/common';
import { TranslatePipe } from '@ngx-translate/core';
import { GoogleMapsZoneComponent } from '../../../../../shared/components/maps/google-maps-zone/google-maps-zone.component';
import { DynamicFormComponent } from '../../../../../shared/components/forms/dynamic-form/dynamic-form.component';
import {
  EntitiesService,
  ZoneListItem,
  ZoneResponse,
  ZoneUpdateRequest,
} from '../../../../../api';
import { EntitySectionBaseComponent } from '../../base';
import { FormAction } from '../../../../../shared/models/form-field.model';
import { isNullOrUndefined } from '../../../../../shared/utils';
import { EMPTY, Observable } from 'rxjs';

@Component({
  selector: 'app-geofence-map-section',
  imports: [
    CommonModule,
    TranslatePipe,
    GoogleMapsZoneComponent,
    DynamicFormComponent,
  ],
  templateUrl: './geofence-map-section.component.html',
  styleUrl: './geofence-map-section.component.scss',
})
export class GeofenceMapSectionComponent extends EntitySectionBaseComponent<
  ZoneListItem | ZoneResponse
> {
  private readonly entitiesService = inject(EntitiesService);
  private pendingRequest: ZoneUpdateRequest | null = null;

  protected override updateFormFields(): void {}

  protected override buildDefaultActions(): FormAction[] {
    return [
      {
        label: this.translate.instant('SHARED.COMMON.BUTTONS.CANCEL'),
        action: () => this.cancelEdit(),
        severity: 'secondary',
      },
      {
        label: this.translate.instant('SHARED.COMMON.BUTTONS.SAVE'),
        action: () => this.saveMap(),
        severity: 'primary',
        disabled: () => isNullOrUndefined(this.pendingRequest),
        loading: () => this.isSubmitting(),
      },
    ];
  }

  protected override onExitEditMode(): void {
    this.pendingRequest = null;
  }

  onZoneChanged(request: ZoneUpdateRequest): void {
    this.pendingRequest = request;
    this.actions = this.buildDefaultActions();
  }

  saveMap(): void {
    if (isNullOrUndefined(this.pendingRequest)) return;
    this.submitChanges(this.pendingRequest);
  }

  protected override buildUpdateRequest(
    formData: Record<string, unknown>,
  ): Observable<unknown> {
    const geofence = this.entity();
    if (isNullOrUndefined(geofence)) return EMPTY;
    return this.entitiesService.updateZone(geofence.id, formData);
  }

  protected override onSubmitSuccess(response: unknown): void {
    this.pendingRequest = null;
    super.onSubmitSuccess(response);
  }
}
