import { Injectable } from '@angular/core';
import { AdminDetailSection } from '../models';

import { ExportTaskResponse } from '../../../api';
import { ExportTaskDetailsSectionComponent } from '../components/export-tasks/export-task-details-section/export-task-details-section.component';
import { ExportTaskSettingsSectionComponent } from '../components/export-tasks/export-task-settings-section/export-task-settings-section.component';
import { FeedSectionComponent } from '../components/shared/feed-section/feed-section.component';

@Injectable({ providedIn: 'root' })
export class ExportTaskSectionConfigFactory {
  createExportTaskInformationSections(
    exportTask: ExportTaskResponse | null,
    ownerId: string | undefined,
  ): AdminDetailSection[] {
    return [
      {
        id: 'export-task-details',
        title: 'Export Task Details',
        component: ExportTaskDetailsSectionComponent,
        componentInputs: { entity: exportTask, ownerId: ownerId ?? null },
        category: 'information',
        order: 10,
      },
      {
        id: 'export-task-settings',
        title: 'Export Task Settings',
        component: ExportTaskSettingsSectionComponent,
        componentInputs: { entity: exportTask, ownerId: ownerId ?? null },
        category: 'information',
        order: 20,
      },
    ];
  }

  createChangesSection(
    exportTask: ExportTaskResponse | null,
  ): AdminDetailSection[] {
    return [
      {
        id: 'export-task-changes',
        title: 'Changes',
        component: FeedSectionComponent,
        componentInputs: { entity: exportTask },
        category: 'feed',
        order: 10,
      },
    ];
  }

  createAllExportTaskSections(
    exportTask: ExportTaskResponse | null,
    ownerId: string | undefined,
  ): AdminDetailSection[] {
    return [
      ...this.createExportTaskInformationSections(exportTask, ownerId),
      ...this.createChangesSection(exportTask),
    ];
  }
}
