import { DestroyRef, Injectable, inject, signal, computed } from '@angular/core';

import { Subject, switchMap } from 'rxjs';
import {
  ContactListItem,
  ContactsService,
} from '../../features/administration/services/contacts.service';
import { BroadcastEventMessageService } from '../../features/administration/services/broadcast-event-messages.service';
import { takeUntilDestroyed } from '@angular/core/rxjs-interop';
import { isDefined } from '../../shared/utils';

@Injectable({ providedIn: 'root' })
export class ContactsCacheService {
  private readonly contactsService = inject(ContactsService);
  private readonly broadcastService = inject(BroadcastEventMessageService);
  private readonly destroyRef = inject(DestroyRef);

  private readonly _cache = signal<Map<string, ContactListItem>>(new Map());
  private readonly _loadedClientId = signal<string | null>(null);
  private readonly _loading = signal<boolean>(false);
  private readonly _loadTrigger$ = new Subject<string>();

  readonly contacts = computed(() => Array.from(this._cache().values()));
  readonly loading = computed(() => this._loading());

  constructor() {
    this._loadTrigger$
      .pipe(
        switchMap((clientId) => {
          this._loading.set(true);
          this._loadedClientId.set(clientId);
          return this.contactsService.list(clientId);
        }),
        takeUntilDestroyed(this.destroyRef),
      )
      .subscribe({
        next: (response) => {
          const map = new Map<string, ContactListItem>();
          for (const item of response.items) {
            map.set(item.id, item);
          }
          this._cache.set(map);
          this._loading.set(false);
        },
        error: () => {
          this._loading.set(false);
          this._loadedClientId.set(null);
        },
      });

    this.broadcastService
      .on('entity-updated')
      .pipe(takeUntilDestroyed(this.destroyRef))
      .subscribe((event) => {
        if (event.entityType === 'contact') {
          const clientId = this._loadedClientId();
          if (isDefined(clientId)) this._loadTrigger$.next(clientId);
        }
      });
  }

  loadForClient(clientId: string): void {
    if (this._loadedClientId() === clientId) return;
    this._loadTrigger$.next(clientId);
  }

  hydrate(ids: string[]): ContactListItem[] {
    const cache = this._cache();
    return ids.flatMap((id) => {
      const contact = cache.get(id);
      return contact ? [contact] : [];
    });
  }

  invalidate(): void {
    this._loadedClientId.set(null);
    this._cache.set(new Map());
  }
}
