import { CommonModule } from '@angular/common';
import {
  Component,
  computed,
  effect,
  inject,
  input,
  signal,
  untracked,
} from '@angular/core';
import { Validators } from '@angular/forms';
import { EMPTY, Observable } from 'rxjs';

import { ButtonModule } from 'primeng/button';
import { v4 as uuidv4 } from 'uuid';

import {
  OverspeedProfileListItem,
  OverspeedProfileCreateRequest,
  EntitiesService,
  OverspeedBandItem,
} from '../../../../../api';
import { DynamicFormComponent } from '../../../../../shared/components/forms/dynamic-form/dynamic-form.component';
import { GridComponent } from '../../../../../shared/components/grid/grid.component';
import {
  createModalListField,
  createNumberField,
  createTextField,
  FormFieldConfig,
  ListFieldModalConfig,
  MeasurementUnitType,
} from '../../../../../shared/models';
import {
  isDefined,
  isNullOrUndefined,
  isNumber,
} from '../../../../../shared/utils';
import { EntitySectionBaseComponent } from '../../base';
import { ModalListFormComponent } from '../../../../../shared/components/forms/modal-list-form/modal-list-form.component';
import { MessageModule } from 'primeng/message';
import { MeasurementUnitsService } from '../../../../../shared/services/measurement-units/measurement-units.service';
import { TranslatePipe } from '@ngx-translate/core';

@Component({
  selector: 'app-overspeed-profile-details-section',
  imports: [
    CommonModule,
    ButtonModule,
    GridComponent,
    DynamicFormComponent,
    MessageModule,
    TranslatePipe,
  ],
  templateUrl: './overspeed-profile-details-section.component.html',
  styleUrl: './overspeed-profile-details-section.component.scss',
})
export class OverspeedProfileDetailsSectionComponent extends EntitySectionBaseComponent<
  OverspeedProfileListItem | Partial<OverspeedProfileCreateRequest>
> {
  readonly ownerId = input<string | null>(null);
  private readonly entitiesService = inject(EntitiesService);
  private readonly measurementUnitsService = inject(MeasurementUnitsService);

  readonly overspeedProfileDetails = computed(() => {
    const overspeedProfileDetails = this.entity();
    this.languageService.currentLanguage();

    if (!isDefined(overspeedProfileDetails)) return [];

    return [
      {
        key: this.translate.instant(
          'ADMIN.PROFILES.OVERSPEED.DETAILS.FIELDS.NAME',
        ),
        value: overspeedProfileDetails.name,
      },
      {
        key: this.translate.instant(
          'ADMIN.PROFILES.OVERSPEED.DETAILS.FIELDS.ITEMS',
        ),
        value: overspeedProfileDetails.items
          ?.map((item) => item.name)
          .join(', '),
      },
    ];
  });
  overspeedProfileBandsModalConfig:
    | ListFieldModalConfig<OverspeedBandItem>
    | undefined;
  protected readonly warning = signal<string | null>(null);

  constructor() {
    super();

    // Setup initial columns
    this.columns = [
      { field: 'key', header: '', transform: 'uppercase' },
      { field: 'value', header: '' },
    ];

    effect(() => {
      const overspeedProfile = this.entity();
      if (
        isNullOrUndefined(overspeedProfile?.items) ||
        overspeedProfile.items.length < 1
      ) {
        this.warning.set(
          this.translate.instant(
            'ADMIN.PROFILES.OVERSPEED.WARNINGS.ITEM_LENGTH',
          ),
        );
      } else {
        this.warning.set(null);
      }
    });

    effect(() => {
      const entity = this.entity();
      if (isDefined(entity) && !this.createMode()) {
        untracked(() => {
          this.updateFormFields();
        });
      }
    });
  }

  protected override updateFormFields(): void {
    const overspeedProfile = this.entity();

    let lastProcessedRawItemsRef: OverspeedBandItem[] | null = null;
    let itemToMaxMapCache: Map<OverspeedBandItem, number | undefined> | null =
      null;

    this.overspeedProfileBandsModalConfig = {
      modalComponent: ModalListFormComponent,
      modalTitle: this.translate.instant(
        'ADMIN.PROFILES.OVERSPEED.DETAILS.MODALS.STATE.TITLE',
      ),
      defaultItemProvider: () => ({
        id: uuidv4(),
        name: '',
        min: undefined,
        offset: undefined,
      }),
      listItemFormatter: (item: OverspeedBandItem) => {
        const currentItemsControl = this.dynamicForm?.form?.get('items');
        const currentRawItemsFromForm: OverspeedBandItem[] =
          currentItemsControl?.value ?? [];

        if (
          currentRawItemsFromForm !== lastProcessedRawItemsRef ||
          !itemToMaxMapCache
        ) {
          const sortedRawItems = [...currentRawItemsFromForm].sort(
            (a, b) => (a.min ?? 0) - (b.min ?? 0),
          );

          itemToMaxMapCache = new Map<OverspeedBandItem, number | undefined>();

          for (let i = 0; i < sortedRawItems.length; i++) {
            const currentItemInSortedList = sortedRawItems[i];
            let maxForCurrentItem: number | undefined;
            if (i < sortedRawItems.length - 1) {
              const nextItemInSortedList = sortedRawItems[i + 1];
              if (isNumber(nextItemInSortedList.min)) {
                maxForCurrentItem = nextItemInSortedList.min;
              }
            }
            itemToMaxMapCache.set(currentItemInSortedList, maxForCurrentItem);
          }
          lastProcessedRawItemsRef = currentRawItemsFromForm;
        }

        const max = itemToMaxMapCache.get(item);
        return this.stateItemToListItem(item, max);
      },
      modalFields: (
        _item: OverspeedBandItem | undefined,
      ): FormFieldConfig[] => {
        // For 'min' field, display value is internal_value - 100
        // If _item.min is 150 (internal), modal shows 50.
        // If new item, _item is undefined, defaultItemProvider gives min: 100 (internal), modal shows 0.
        const initialMinForModal = isDefined(_item?.min) ? _item.min - 100 : 0;

        return [
          createTextField('id', 'ID', _item?.id, {
            name: 'id',
            hidden: true,
          }),
          createTextField(
            'name',
            this.translate.instant(
              'ADMIN.PROFILES.OVERSPEED.DETAILS.FIELDS.NAME',
            ),
            _item?.name,
            {
              name: 'name',
              validations: [
                {
                  name: 'required',
                  validator: Validators.required,
                  message: this.translate.instant(
                    'SHARED.COMMON.FORMS.SHARED.REQUIRED',
                    {
                      field: this.translate.instant(
                        'ADMIN.PROFILES.OVERSPEED.DETAILS.FIELDS.NAME',
                      ),
                    },
                  ),
                },
              ],
            },
          ),
          createNumberField(
            'min',
            this.translate.instant(
              'ADMIN.PROFILES.OVERSPEED.DETAILS.FIELDS.MIN',
            ),
            initialMinForModal,
            {
              name: 'min',
              validations: [
                {
                  name: 'required',
                  validator: Validators.required,
                  message: this.translate.instant(
                    'SHARED.COMMON.FORMS.SHARED.REQUIRED',
                    {
                      field: this.translate.instant(
                        'ADMIN.PROFILES.OVERSPEED.DETAILS.FIELDS.MIN',
                      ),
                    },
                  ),
                },
                {
                  name: 'min',
                  validator: Validators.min(0),
                  message: this.translate.instant(
                    'SHARED.COMMON.FORMS.NUMBER.MIN',
                    {
                      field: this.translate.instant(
                        'ADMIN.PROFILES.OVERSPEED.DETAILS.FIELDS.MIN',
                      ),
                      min: 0,
                    },
                  ),
                },
              ],
              layout: 'horizontal',
              labelWidth: '1/3',
              props: {
                suffix: '%',
                min: 0,
              },
            },
          ),
          createNumberField(
            'offset',
            this.translate.instant(
              'ADMIN.PROFILES.OVERSPEED.DETAILS.FIELDS.OFFSET',
            ),
            this.measurementUnitsService.fromBackend(
              MeasurementUnitType.SPEED,
              _item?.offset ?? 0,
              2,
            ),
            {
              name: 'offset',
              validations: [
                {
                  name: 'required',
                  validator: Validators.required,
                  message: this.translate.instant(
                    'SHARED.COMMON.FORMS.SHARED.REQUIRED',
                    {
                      field: this.translate.instant(
                        'ADMIN.PROFILES.OVERSPEED.DETAILS.FIELDS.OFFSET',
                      ),
                    },
                  ),
                },
                {
                  name: 'min',
                  validator: Validators.min(-50),
                  message: this.translate.instant(
                    'SHARED.COMMON.FORMS.NUMBER.MIN',
                    {
                      field: this.translate.instant(
                        'ADMIN.PROFILES.OVERSPEED.DETAILS.FIELDS.OFFSET',
                      ),
                      min: -50,
                    },
                  ),
                },
                {
                  name: 'max',
                  validator: Validators.max(50),
                  message: this.translate.instant(
                    'SHARED.COMMON.FORMS.NUMBER.MAX',
                    {
                      field: this.translate.instant(
                        'ADMIN.PROFILES.OVERSPEED.DETAILS.FIELDS.OFFSET',
                      ),
                      max: 50,
                    },
                  ),
                },
              ],
              props: {
                suffix: this.measurementUnitsService.unit(
                  MeasurementUnitType.SPEED,
                ),
              },
            },
          ),
        ];
      },
      subHeader: '',
    };
    this.formFields = [
      createTextField(
        'name',
        this.translate.instant('ADMIN.PROFILES.OVERSPEED.DETAILS.FIELDS.NAME'),
        overspeedProfile?.name,
        {
          name: 'name',
          validations: [
            {
              name: 'required',
              validator: Validators.required,
              message: this.translate.instant(
                'SHARED.COMMON.FORMS.SHARED.REQUIRED',
                {
                  field: this.translate.instant(
                    'ADMIN.PROFILES.OVERSPEED.DETAILS.FIELDS.NAME',
                  ),
                },
              ),
            },
          ],
        },
      ),
    ];

    if (!this.createMode()) {
      this.formFields.push(
        createModalListField<OverspeedBandItem>(
          'items',
          this.translate.instant(
            'ADMIN.PROFILES.OVERSPEED.DETAILS.FIELDS.ITEMS',
          ),
          overspeedProfile?.items ?? [],
          {
            layout: 'horizontal',
            labelWidth: '1/3',
            name: 'items',
            props: {
              modalConfig: this.overspeedProfileBandsModalConfig,
            },
          },
        ) as FormFieldConfig<unknown>,
      );
    }
  }

  protected override buildUpdateRequest(
    formData: Record<string, unknown>,
  ): Observable<unknown> {
    const overspeedProfile = this.entity();
    if (isNullOrUndefined(overspeedProfile)) return EMPTY;
    return this.entitiesService.updateOverspeedProfile(
      overspeedProfile.id,
      formData,
    );
  }

  protected override onSubmitSuccess(response: unknown): void {
    const overspeedProfile = this.entity();
    if (isNullOrUndefined(overspeedProfile)) return;
    this.broadcastService.broadcast('entity-updated', {
      entityType: 'overspeed-profile',
      operation: 'update',
      entityId: overspeedProfile.id,
      data: response,
    });
  }

  stateItemToListItem(item: OverspeedBandItem, max?: number) {
    return {
      id: item.id,
      title: item.name,
      display: isDefined(max)
        ? this.translate.instant(
            'ADMIN.PROFILES.OVERSPEED.DETAILS.FIELDS.DESCRIPTION_MIN_AND_MAX',
            {
              min: item.min,
              max,
            },
          )
        : this.translate.instant(
            'ADMIN.PROFILES.OVERSPEED.DETAILS.FIELDS.DESCRIPTION_MIN_ONLY',
            {
              min: item.min,
            },
          ),
      icon: 'pi pi-gauge',
    };
  }

  stateItemsToListItems(items: OverspeedBandItem[]) {
    return (items ?? [])
      .sort((a, b) => {
        return a.min - b.min;
      })
      .map((x, idx, arr) => {
        const nextItem = idx < arr.length - 1 ? arr[idx + 1] : null;
        const max = nextItem?.min;
        return this.stateItemToListItem(x, max);
      });
  }

  protected override onFormValueChange(
    formData: Record<string, string | number | object>,
  ): void {
    const items = formData['items'] as OverspeedBandItem[];
    if (isDefined(items)) {
      const updatedItems = items.map((item) => ({
        ...item,
        min: isDefined(item.min) ? item.min + 100 : undefined,
        offset: this.measurementUnitsService.toBackend(
          MeasurementUnitType.SPEED,
          item.offset ?? 0,
        ),
      }));
      formData['items'] = updatedItems;
    }

    this.formValueChange.emit(formData);
  }
}
