import { Injectable } from '@angular/core';

import { AdminDetailSection } from '../models';
import { ContactDetailItem } from '../services/contacts.service';
import { ContactDetailsSectionComponent } from '../components/contacts/contact-details-section/contact-details-section.component';
import { FeedSectionComponent } from '../components/shared/feed-section/feed-section.component';

@Injectable({ providedIn: 'root' })
export class ContactSectionConfigFactory {
  createContactInformationSection(
    contact: ContactDetailItem | null,
  ): AdminDetailSection[] {
    return [
      {
        id: 'contact-details',
        title: 'Contact Details',
        component: ContactDetailsSectionComponent,
        componentInputs: { entity: contact, entityType: 'contact' },
        category: 'information',
        order: 10,
      },
    ];
  }

  createChangesSection(contact: ContactDetailItem | null): AdminDetailSection[] {
    return [
      {
        id: 'contact-changes',
        title: 'Changes',
        component: FeedSectionComponent,
        componentInputs: { entity: contact },
        category: 'feed',
        order: 10,
      },
    ];
  }

  createAllContactSections(contact: ContactDetailItem | null): AdminDetailSection[] {
    return [
      ...this.createContactInformationSection(contact),
      ...this.createChangesSection(contact),
    ];
  }
}
