import {
  Component,
  computed,
  effect,
  inject,
  input,
  OnInit,
  signal,
  WritableSignal,
} from '@angular/core';
import { takeUntilDestroyed } from '@angular/core/rxjs-interop';

import { TranslatePipe } from '@ngx-translate/core';
import { ButtonModule } from 'primeng/button';
import { InputTextModule } from 'primeng/inputtext';

import {
  EntitiesService,
  DeviceListItem,
  DeviceResponse,
  DeviceCreateRequest,
  SimCardListItem,
  AssetListItem,
  IdName,
} from '../../../../../api';
import { createAutocompleteField, FormAction } from '../../../../../shared/models';
import { EntitySectionBaseComponent } from '../../base';
import { isDefined, isNullOrUndefined } from '../../../../../shared/utils';
import { DynamicFormComponent } from '../../../../../shared/components/forms/dynamic-form/dynamic-form.component';
import { GridComponent } from '../../../../../shared/components/grid/grid.component';
import { CommonModule } from '@angular/common';
import { EntityOperationRegistryService } from '../../../services/entity/entity-operation-registry.service';
import { BehaviorSubject, catchError, debounceTime, Observable, of, switchMap } from 'rxjs';
import { UtilityService } from '../../../../../core/services/utility.service';
import { MessageModule } from 'primeng/message';
import { ApiSchemaService } from '../../../../../core/services/api-schema.service';
import { FormGroup } from '@angular/forms';
import { ConfirmationService } from 'primeng/api';

@Component({
  selector: 'app-device-linked-section',
  imports: [
    CommonModule,
    ButtonModule,
    InputTextModule,
    GridComponent,
    DynamicFormComponent,
    MessageModule,
    TranslatePipe,
  ],
  templateUrl: './device-linked-section.component.html',
  styleUrl: './device-linked-section.component.scss',
})
export class DeviceLinkedSectionComponent
  extends EntitySectionBaseComponent<DeviceListItem | DeviceResponse>
  implements OnInit {
  readonly ownerId = input<string | null>(null);
  readonly entitiesService = inject(EntitiesService);
  private readonly operationRegistry = inject(EntityOperationRegistryService);
  private readonly utilityService = inject(UtilityService);
  private readonly apiSchemaService = inject(ApiSchemaService);
  private readonly confirmationService = inject(ConfirmationService);
  protected override actions: FormAction[] = [
    {
      label: 'Cancel',
      action: () => this.cancelEdit(),
      severity: 'secondary',
    },
    {
      label: 'Save',
      severity: 'primary',
      disabled: (form?: FormGroup) => !form || form.pristine || form.invalid,
      loading: () => this.isSubmitting(),
      action: (form: FormGroup) => {
        const simCard = form.value['simcard'] as Partial<SimCardListItem> | null;
        const asset = form.value['asset'] as Partial<AssetListItem> | null;

        const simCardLinkedElsewhere = this.isSimCardLinkedElsewhere(simCard);
        const assetLinkedElsewhere = this.isAssetLinkedElsewhere(asset);

        if (simCardLinkedElsewhere || assetLinkedElsewhere) {
          const simCardLinked = simCardLinkedElsewhere && isDefined(simCard) ? `- SIM Card: ${this.simCardLinkedMessage(simCard)} <br> ` : '';
          const assetLinked = assetLinkedElsewhere && isDefined(asset) ? `- Asset: ${this.assetLinkedMessage(asset)}.` : '';
          const confirmationMessage = `The following are linked to different devices: <br> ${simCardLinked}${assetLinked} <br> Do you wish to proceed?`;
          this.confirmationService.confirm({
            message: confirmationMessage,
            header: 'Warning',
            icon: "warning",
            acceptIcon: "warning",
            acceptLabel: 'Proceed',
            rejectLabel: 'Cancel',
            closable: false,
            accept: () => this.onSubmit(form),
          });
          return
        }
        this.onSubmit(form);
      },
    },
  ];

  readonly deviceLinkedDetails = computed(() => {
    const deviceDetails = this.entity();
    if (!isDefined(deviceDetails)) return [];

    return [
      {
        key: 'Sim Card',
        value:
          deviceDetails.simcard?.name ??
          this.translate.instant('SHARED.COMMON.NONE'),
      },
      {
        key: 'Asset',
        value:
          deviceDetails.asset?.name ??
          this.translate.instant('SHARED.COMMON.NONE'),
      },
    ];
  });
  private readonly searchSIMCardsSubject = new BehaviorSubject<string | null>(
    null,
  );
  private readonly searchAssetsSubject = new BehaviorSubject<string | null>(
    null,
  );
  simCardSuggestions = signal<Partial<SimCardListItem>[]>([]);
  assetSuggestions = signal<Partial<AssetListItem>[]>([]);
  protected readonly warning = signal<string | null>(null);

  constructor() {
    super();

    this.columns = [
      { field: 'key', header: '', transform: 'uppercase' },
      { field: 'value', header: '' },
    ];

    effect(() => {
      const deviceDetails = this.entity();
      if (!isDefined(deviceDetails)) return;

      if (deviceDetails.asset) {
        this.checkAssetDevices(deviceDetails);
      }
    });
  }

  ngOnInit(): void {
    this.setupSimCardSearch();
    this.setupSearch(
      this.searchAssetsSubject,
      this.assetSuggestions,
      this.entitiesService.listAssets.bind(this.entitiesService),
      { state: 'active' },
    );
  }

  private isSimCardLinkedElsewhere(simCard: Partial<SimCardListItem> | null): boolean {
    return isDefined(simCard) && isDefined(simCard.device) && simCard.device.id !== this.entity()?.id;
  }

  private isAssetLinkedElsewhere(asset: Partial<AssetListItem> | null): boolean {
    return isDefined(asset) && isDefined(asset.devices) && asset.devices.some(d => d.id !== this.entity()?.id);
  }

  private simCardLinkedMessage(simCard: Partial<SimCardListItem>): string {
    return `This SIM Card is linked to another device ${this.escapeHtml(simCard.device?.name ?? '')}`;
  }

  private assetLinkedMessage(asset: Partial<AssetListItem>): string {
    const deviceNames = asset.devices?.filter(d => d.id !== this.entity()?.id).map(d => this.escapeHtml(d.name ?? '')).join(', ') ?? '';
    return `This asset is linked to different device(s) (${deviceNames})`;
  }

  private escapeHtml(value: string): string {
    return value
      .replaceAll('&', '&amp;')
      .replaceAll('<', '&lt;')
      .replaceAll(/>/g, '&gt;')
      .replaceAll(/"/g, '&quot;')
      .replaceAll(/'/g, '&#39;');
  }

  private readonly simCardDisplayFormatter = (item: unknown): string => {
    if (isNullOrUndefined(item)) return '';
    const simCard = item as Partial<SimCardListItem>;
    if (
      this.apiSchemaService.usesModernSchema() &&
      isDefined(simCard.number) &&
      simCard.number.length > 0
    ) {
      const escapedName = this.escapeHtml(simCard.name ?? '');
      const escapedNumber = this.escapeHtml(simCard.number);
      const deviceLinked = this.isSimCardLinkedElsewhere(simCard) ? `Warning: ${this.simCardLinkedMessage(simCard)}` : '';
      const description: string = isNullOrUndefined(simCard.description) ? '' : `Description: ${this.escapeHtml(simCard.description)}`;
      const parts = [`Name: ${escapedName} (Number: ${escapedNumber})`];
      if (description) parts.push(description);
      if (deviceLinked) parts.push(deviceLinked);
      return parts.join(' <br> ');
    }
    return this.escapeHtml(simCard.name ?? '');
  };

  private readonly assetDisplayFormatter = (item: unknown): string => {
    const asset = item as Partial<AssetListItem>;
    if (
      this.apiSchemaService.usesModernSchema() &&
      isDefined(asset.name)
    ) {
      const escapedName = this.escapeHtml(asset.name);
      const deviceLinked: string = this.isAssetLinkedElsewhere(asset) ? `Warning: ${this.assetLinkedMessage(asset)}.` : '';
      return deviceLinked ? `${escapedName} <br> ${deviceLinked}` : escapedName;
    }
    return this.escapeHtml(asset.name ?? '');
  }

  private setupSimCardSearch(): void {
    this.searchSIMCardsSubject
      .pipe(
        debounceTime(300),
        takeUntilDestroyed(this.destroyRef),
        switchMap((searchTerm) => {
          if (isNullOrUndefined(searchTerm)) {
            return of({ items: [] as Partial<SimCardListItem>[] });
          }

          const trimmedSearchTerm = searchTerm.trim();
          const ownerId = this.entity()?.owner.id ?? '';
          let rqlFilter: string;

          if (
            trimmedSearchTerm.length > 0 &&
            this.apiSchemaService.usesModernSchema()
          ) {
            const baseFilter = this.utilityService.constructRqlFilter({
              state: 'active',
            });
            const wildcardTerm = `*${trimmedSearchTerm}*`;
            rqlFilter = `${baseFilter}&(name=${wildcardTerm}|number=${wildcardTerm}|description=${wildcardTerm})`;
          } else {
            const filterParams: Record<string, unknown> = { state: 'active' };
            if (trimmedSearchTerm.length > 0) {
              filterParams['name'] = {
                value: `*${trimmedSearchTerm}*`,
                operator: '=',
              };
            }
            rqlFilter = this.utilityService.constructRqlFilter(filterParams);
          }

          return this.entitiesService.listSimCards(
            ownerId,
            0,
            10,
            'name',
            rqlFilter,
          );
        }),
      )
      .subscribe((response) => {
        this.simCardSuggestions.set(response.items);
      });
  }

  private checkAssetDevices(
    deviceDetails: DeviceListItem | DeviceResponse | undefined,
  ) {
    if (deviceDetails?.asset) {
      this.entitiesService
        .getAsset(deviceDetails.asset.id)
        .subscribe((asset) => {
          if (asset.devices && asset.devices.length > 1) {
            this.warning.set(`Multiple Devices assigned to linked Asset`);
          } else {
            this.warning.set(null);
          }
        });
    } else {
      this.warning.set(null);
    }
  }

  private setupSearch<T>(
    subject: BehaviorSubject<string | null>,
    suggestionSignal: WritableSignal<Partial<T>[]>,
    listMethod: (
      ownerId: string,
      offset: number,
      limit: number,
      orderBy: string,
      filter: string,
    ) => Observable<{ items: T[] }>,
    filters: Record<string, unknown>,
  ) {
    subject
      .pipe(
        debounceTime(300),
        takeUntilDestroyed(this.destroyRef),
        switchMap((searchTerm) => {
          if (isNullOrUndefined(searchTerm)) {
            return of({ items: [] });
          }

          const trimmedSearchTerm = searchTerm.trim();
          const filterParams: Record<string, unknown> = { ...filters };

          if (trimmedSearchTerm.length > 0) {
            filterParams['name'] = {
              value: `*${trimmedSearchTerm}*`,
              operator: '=',
            };
          }

          const rqlFilter =
            this.utilityService.constructRqlFilter(filterParams);
          return listMethod(
            this.entity()?.owner.id ?? '',
            0,
            10,
            'name',
            rqlFilter,
          );
        }),
      )
      .subscribe((response) => {
        suggestionSignal.set(response.items);
      });
  }

  private searchSIMCards(searchTerm: string) {
    const trimmedSearchTerm = searchTerm?.trim() ?? '';

    // Skip if null/empty or same as current search term
    if (
      isNullOrUndefined(searchTerm) ||
      trimmedSearchTerm === this.searchSIMCardsSubject.getValue()
    ) {
      return this.simCardSuggestions.set([...this.simCardSuggestions()]);
    }

    this.searchSIMCardsSubject.next(trimmedSearchTerm);
  }

  private searchAssets(searchTerm: string) {
    const trimmedSearchTerm = searchTerm?.trim() ?? '';

    if (
      isNullOrUndefined(searchTerm) ||
      trimmedSearchTerm === this.searchAssetsSubject.getValue()
    ) {
      return this.assetSuggestions.set([...this.assetSuggestions()]);
    }

    this.searchAssetsSubject.next(trimmedSearchTerm);
  }

  protected override updateFormFields(): void {
    const device = this.entity();
    if (device?.simcard) {
      this.entitiesService.getSimCard(device.simcard.id).pipe(
        takeUntilDestroyed(this.destroyRef),
        catchError(() => of(null)),
      ).subscribe(simCard => {
        if (simCard) this.simCardSuggestions.set([simCard as unknown as Partial<SimCardListItem>]);
      });
    }
    if (device?.asset) {
      this.entitiesService.getAsset(device.asset.id).pipe(
        takeUntilDestroyed(this.destroyRef),
        catchError(() => of(null)),
      ).subscribe(asset => {
        if (asset) this.assetSuggestions.set([asset as unknown as Partial<AssetListItem>]);
      });
    }
    // TODO(CHV-2638): Cross-client ownership validators are disabled because the SIM card and asset
    // searches are scoped to this.entity()?.owner.id, so foreign-owner entities never appear in
    // the dropdown — making these validators unreachable dead code. The AC requires cross-client
    // entities to be visible-but-disabled in the dropdown instead. Confirm with Heinz whether the
    // search should be unscoped before re-enabling. See PR #817 comment by Oneal Marange.
    //
    // const simcardValidator: ValidationRule = {
    //   name: 'ownershipValidationError',
    //   message: 'This SIM card belongs to a different owner. You do not have permission to alter this mapping.',
    //   params: { simcard: undefined },
    //   validator: (): ValidatorFn => {
    //     return (control: AbstractControl): ValidationErrors | null => {
    //       const simCard = control.value as Partial<SimCardListItem>;
    //       if (isNullOrUndefined(simCard) || typeof simCard === 'string') return null;
    //       const forbidden = simCard.owner?.id !== this.ownerId();
    //       return forbidden ? { ownershipValidationError: { value: `This SIM card is actively linked to Device ${simCard.device?.name} under ${simCard.owner?.name}. You do not have permission to alter this mapping. Please contact support to resolve.` } } : null;
    //     };
    //   }
    // };
    //
    // const assetValidation: ValidationRule = {
    //   name: 'ownershipValidationError',
    //   message: 'This asset belongs to a different owner. You do not have permission to alter this mapping.',
    //   params: { asset: undefined },
    //   validator: (): ValidatorFn => {
    //     return (control: AbstractControl): ValidationErrors | null => {
    //       const asset = control.value as Partial<AssetListItem>;
    //       if (isNullOrUndefined(asset) || typeof asset === 'string') return null;
    //       const forbidden = asset.owner?.id !== this.ownerId();
    //       return forbidden ? { ownershipValidationError: { value: `This Asset is actively linked to Device(s) ${asset.devices?.map(d => d.name).join(', ')} under ${asset.owner?.name}. You do not have permission to alter this mapping. Please contact support to resolve.` } } : null;
    //     };
    //   }
    // };
    this.formFields = [
      createAutocompleteField(
        'simcard',
        'SIM Card',
        device?.simcard?.name,
        () => this.simCardSuggestions(),
        this.searchSIMCards.bind(this),
        {
          layout: 'horizontal',
          labelWidth: '1/3',
          name: 'simcard',
          placeholder: 'Search SIM Card name, description, serial number or voice number.',
          validations: [],
          props: {
            appendTo: 'body',
            showClear: true,
            multiple: false,
            field: 'name',
            completeOnFocus: true,
            typeahead: true,
            showEmptyMessage: true,
            ...(this.apiSchemaService.usesModernSchema() && {
              itemDisplayFormatter: this.simCardDisplayFormatter,
            }),
          },
        },
      ),
      createAutocompleteField(
        'asset',
        'Asset',
        device?.asset?.name,
        () => this.assetSuggestions(),
        this.searchAssets.bind(this),
        {
          layout: 'horizontal',
          labelWidth: '1/3',
          name: 'asset',
          validations: [],
          props: {
            appendTo: 'body',
            showClear: true,
            multiple: false,
            field: 'name',
            completeOnFocus: true,
            typeahead: true,
            showEmptyMessage: true,
            ...(this.apiSchemaService.usesModernSchema() && {
              itemDisplayFormatter: this.assetDisplayFormatter,
            })
          },
        },
      ),
    ];
  }

  override getUpdateMethod(): (
    id: string,
    data: Partial<DeviceListItem | DeviceResponse>,
  ) => Observable<DeviceResponse> {
    return (
      this.operationRegistry.getOperation<
        DeviceListItem | DeviceResponse,
        DeviceCreateRequest,
        DeviceResponse,
        'update'
      >('device', 'update') ??
      ((id, data) => this.entitiesService.updateDevice(id, data))
    );
  }

  protected override transformFormData(
    formData: Record<string, string | number | object>,
  ): Record<string, string | number | object> {
    const transformedData: {
      simcard?: IdName;
      asset?: IdName;
    } = { ...formData };
    if (isDefined(transformedData['simcard'])) {
      transformedData['simcard'] = {
        id: transformedData?.simcard?.id,
        name: transformedData['simcard']?.name,
      };
    }

    if (isDefined(transformedData['asset'])) {
      transformedData['asset'] = {
        id: transformedData['asset']?.id,
        name: transformedData['asset']?.name,
      };
    }

    return transformedData;
  }
}
