import { CommonModule } from '@angular/common';
import {
  Component,
  computed,
  effect,
  inject,
  signal,
  untracked,
} from '@angular/core';
import { takeUntilDestroyed } from '@angular/core/rxjs-interop';

import { ButtonModule } from 'primeng/button';
import { ConfirmationService } from 'primeng/api';
import {
  AssetCreateRequest,
  AssetResponse,
  EntitiesService,
  LabelListItem,
  LabelListResponse,
  LabelValuePayload,
} from '../../../../../api';
import { DEFAULT_LIST_SIZE } from '../../../../../core/models';
import { DynamicFormComponent } from '../../../../../shared/components/forms/dynamic-form/dynamic-form.component';
import { GridComponent } from '../../../../../shared/components/grid/grid.component';
import {
  createAutocompleteField,
  FormFieldConfig,
} from '../../../../../shared/models';
import {
  isDefined,
  isEmpty,
  isNullOrUndefined,
} from '../../../../../shared/utils';
import { BulkEntitySectionBaseComponent } from '../../../components/base/bulk-entity-section-base';
import { AssetBulkSaveService } from '../../../services/asset-bulk-save.service';
import { UtilityService } from '../../../../../core/services/utility.service';
import { Subject, debounceTime, switchMap, of } from 'rxjs';
import { TranslatePipe } from '@ngx-translate/core';

@Component({
  selector: 'app-asset-labels-section',
  imports: [
    CommonModule,
    ButtonModule,
    GridComponent,
    DynamicFormComponent,
    TranslatePipe,
  ],
  providers: [ConfirmationService],
  templateUrl: './asset-labels-section.component.html',
  styleUrl: './asset-labels-section.component.scss',
})
export class AssetLabelsSectionComponent extends BulkEntitySectionBaseComponent<
  AssetResponse | Partial<AssetCreateRequest>
> {
  private readonly entitiesService = inject(EntitiesService);
  private readonly utilityService = inject(UtilityService);
  private readonly bulkSaveService = inject(AssetBulkSaveService);
  private readonly confirmationService = inject(ConfirmationService);

  readonly assetDetails = computed(() => {
    if (this.isBulkMode) {
      return [{ key: 'Default Trip Labels', value: '' }];
    }
    const assetDetails = this.entity() as AssetResponse | null;
    const availableLabels = this.labels();
    this.languageService.currentLanguage();

    if (!isDefined(assetDetails)) return [];

    const mappedTripLabels = (assetDetails.defaultTripLabels ?? []).map(
      (value) => {
        const [rootLabel, subLabel] = value.split('/');
        const label1 = availableLabels.find((x) => x.label === rootLabel);
        let label2: LabelValuePayload | undefined;
        if (label1?.values) {
          label2 = label1.values.find((x) => x.label === subLabel);
        }

        const name = label1
          ? [label1.name, label2?.name].filter((x) => isDefined(x)).join(': ')
          : value;

        return {
          id: value,
          name: name,
        };
      },
    );

    return [
      {
        key: this.translate.instant(
          'ADMIN.ASSETS.LABELS.FIELDS.DEFAULT_TRIP_LABELS',
        ),
        value:
          mappedTripLabels.map((l) => l.name).join(', ') ??
          this.translate.instant('SHARED.COMMON.NONE'), // Display names, join if multiple
      },
    ];
  });

  private readonly searchDefaultLabelsSubject = new Subject<string>();
  private readonly defaultLabelsSuggestions = signal<
    LabelListItem[] | undefined
  >([]);
  labels = signal<LabelListItem[]>([]);

  private readonly effectiveOwnerIdSignal = computed(() => {
    const bulkEditContext = this.bulkContext();
    if (bulkEditContext) return bulkEditContext.ownerId;
    const entity = this.entity() as AssetResponse | null;
    return entity?.owner?.id ?? '';
  });

  constructor() {
    super();

    this.columns = [
      { field: 'key', header: '', transform: 'uppercase' },
      { field: 'value', header: '' },
    ];

    effect(() => {
      const ownerId = this.effectiveOwnerIdSignal();
      untracked(() => this.loadLabels(ownerId));
    });

    effect(() => {
      const entity = this.entity();
      if (isDefined(entity)) {
        untracked(() => this.updateFormFields());
      }
    });

    this.setupSearchDefaultLabels();
  }

  protected get effectiveOwnerId(): string {
    return this.effectiveOwnerIdSignal();
  }

  private loadLabels(ownerId: string) {
    if (!isDefined(ownerId) || ownerId === '') {
      this.labels.set([]);
      return;
    }

    this.entitiesService
      .listLabels(ownerId, true, 0, DEFAULT_LIST_SIZE, 'name', 'state=active')
      .pipe(takeUntilDestroyed(this.destroyRef))
      .subscribe((response) => {
        this.labels.set(response.items);
      });
  }

  private setupSearchDefaultLabels() {
    this.searchDefaultLabelsSubject
      .pipe(
        debounceTime(300),
        takeUntilDestroyed(this.destroyRef),
        switchMap((searchTerm) => {
          if (isNullOrUndefined(searchTerm)) {
            return of({
              count: 0,
              offset: 0,
              limit: DEFAULT_LIST_SIZE,
              items: [],
            } as LabelListResponse);
          }

          const trimmedSearchTerm = searchTerm.trim();

          if (trimmedSearchTerm.length === 0) {
            return of({
              count: 0,
              offset: 0,
              limit: DEFAULT_LIST_SIZE,
              items: [],
            } as LabelListResponse);
          }

          const filters = {
            state: { value: 'active', operator: '=' },
            name: { value: `*${trimmedSearchTerm}*`, operator: '=' },
          };
          const rqlFilter = this.utilityService.constructRqlFilter(filters);

          return this.entitiesService.listLabels(
            this.entity()?.owner.id ?? '',
            true,
            0,
            10,
            'name',
            rqlFilter,
          );
        }),
      )
      .subscribe((response: LabelListResponse) => {
        this.defaultLabelsSuggestions.set(response.items);
      });
  }

  private searchDefaultLabels(searchTerm: string) {
    if (isNullOrUndefined(searchTerm)) {
      this.defaultLabelsSuggestions.set([]);
      return;
    }
    this.defaultLabelsSuggestions.set(undefined);
    this.searchDefaultLabelsSubject.next(searchTerm);
  }

  protected override updateFormFields(): void {
    this.formFields = this.buildFormFields(
      this.entity() as AssetResponse | null,
    );
  }

  protected buildFormFields(entity: AssetResponse | null): FormFieldConfig[] {
    return [
      createAutocompleteField(
        'defaultLabels',
        this.translate.instant(
          'ADMIN.ASSETS.LABELS.FIELDS.DEFAULT_TRIP_LABELS',
        ),
        entity?.ratingProfile?.name,
        this.defaultLabelsSuggestions(),
        this.searchDefaultLabels.bind(this),
        {
          layout: 'horizontal',
          labelWidth: '1/3',
          name: 'defaultLabels',
          hint: this.translate.instant(
            'ADMIN.ASSETS.LABELS.FIELDS.DEFAULT_TRIP_LABELS_DESCRIPTION',
          ),
          props: {
            appendTo: 'body',
            multiple: false,
            field: 'name',
            typeahead: true,
            showEmptyMessage: true,
            emptyMessage: 'No labels found',
            completeOnFocus: false,
          },
        },
      ),
    ];
  }

  protected override submitBulkChanges(
    formData: Record<string, string | number | object | null>,
  ): void {
    const bulkEditContext = this.bulkContext();
    if (isNullOrUndefined(bulkEditContext)) return;

    this.isSubmitting.set(true);
    this.bulkSaveService
      .confirmAndSave(
        bulkEditContext,
        formData as Record<string, unknown>,
        (id, data) => this.entitiesService.updateAsset(id, data),
        this.confirmationService,
      )
      .pipe(takeUntilDestroyed(this.destroyRef))
      .subscribe({
        next: () => {
          this.isSubmitting.set(false);
          this.isFormEditable.set(false);
          this.clearUnsavedChanges();
          this.broadcastService.broadcast('entity-updated', {
            entityType: 'asset',
            operation: 'update',
          });
        },
        error: () => {
          this.isSubmitting.set(false);
          this.isFormEditable.set(true);
        },
      });
  }

  protected override submitChanges(
    formData: Record<string, string | number>,
  ): void {
    const asset = this.entity() as AssetResponse | null;
    if (isNullOrUndefined(asset)) return;
    this.entitiesService
      .updateAsset(asset.id, formData)
      .pipe(takeUntilDestroyed(this.destroyRef))
      .subscribe({
        next: () => {
          this.isFormEditable.set(false);
          this.isSubmitting.set(false);
          this.broadcastService.broadcast('entity-updated', {
            entityType: 'asset',
            entityId: asset.id,
          });
        },
        error: () => {
          this.isFormEditable.set(true);
          this.isSubmitting.set(false);
        },
      });
  }

  searchLabel(query: string) {
    if (isEmpty(query)) {
      this.labels.set(this.labels());
      return;
    }

    const filteredLabels = this.labels().filter(
      (label) =>
        ((label.name?.toLowerCase().includes(query.toLowerCase()) ?? false) ||
          (label.label?.toLowerCase().includes(query.toLowerCase()) ??
            false)) ??
        false,
    );
    this.labels.set(filteredLabels);
  }
}
