import { CommonModule } from '@angular/common';
import { Component, computed, inject } from '@angular/core';
import { takeUntilDestroyed } from '@angular/core/rxjs-interop';
import { Validators } from '@angular/forms';
import { FontAwesomeModule } from '@fortawesome/angular-fontawesome';
import { faKey } from '@fortawesome/free-solid-svg-icons';
import { ButtonModule } from 'primeng/button';
import {
  UserApiKeyCreateRequest,
  AccountsService,
  UserResponse,
  ApiKey,
} from '../../../../../api';
import { DynamicFormComponent } from '../../../../../shared/components/forms/dynamic-form/dynamic-form.component';
import { ModalListFormComponent } from '../../../../../shared/components/forms/modal-list-form/modal-list-form.component';
import { GridComponent } from '../../../../../shared/components/grid/grid.component';
import {
  ListFieldModalConfig,
  FormFieldConfig,
  createTextField,
  createModalListField,
  createTextAreaField,
} from '../../../../../shared/models';
import {
  isDefined,
  isEmpty,
  isNullOrUndefined,
} from '../../../../../shared/utils';
import { EntitySectionBaseComponent } from '../../base';
import { firstValueFrom } from 'rxjs';
import { DialogService, DynamicDialogRef } from 'primeng/dynamicdialog';
import { ConfirmationService, ConfirmEventType } from 'primeng/api';
import { TranslatePipe } from '@ngx-translate/core';

@Component({
  selector: 'app-user-api-keys-section',
  imports: [
    CommonModule,
    ButtonModule,
    GridComponent,
    DynamicFormComponent,
    FontAwesomeModule,
    TranslatePipe,
  ],
  templateUrl: './user-api-keys-section.component.html',
  styleUrl: './user-api-keys-section.component.scss',
})
export class UserApiKeysSectionComponent extends EntitySectionBaseComponent<
  UserResponse | UserApiKeyCreateRequest
> {
  private readonly accountsService = inject(AccountsService);
  private readonly dialogService = inject(DialogService);
  private readonly confirmationService = inject(ConfirmationService);
  faKey = faKey;

  readonly userApiKeyDetails = computed(() => {
    const apiKeyDetails: Record<string, ApiKey> = this.entity()?.apiKeys;
    if (!isDefined(apiKeyDetails)) return [];

    return [
      {
        key: this.translate.instant('ADMIN.USERS.API_KEYS.FIELDS.KEYS'),
        value: !isEmpty(apiKeyDetails)
          ? Object.values(apiKeyDetails)
              .map((item) => item.name)
              .join(', ')
          : this.translate.instant('SHARED.COMMON.NONE'),
      },
    ];
  });
  userApiKeysModalConfig: ListFieldModalConfig<ApiKey> | undefined;

  constructor() {
    super();

    // Setup initial columns
    this.columns = [
      { field: 'key', header: '', transform: 'uppercase' },
      { field: 'value', header: '' },
    ];
  }

  protected override updateFormFields(): void {
    const userEntity = this.entity(); // Can be UserResponse or UserApiKeyCreateRequest

    this.userApiKeysModalConfig = {
      modalComponent: ModalListFormComponent,
      modalTitle: this.translate.instant(
        'ADMIN.USERS.API_KEYS.MODALS.NEW.TITLE',
      ),
      defaultItemProvider: () => ({
        name: '',
        policies: [],
      }),
      listItemFormatter: (item: Record<string, ApiKey>) => ({
        id: Object.keys(item)[0] ?? '',
        title: item[Object.keys(item)[0]].name ?? '',
        display: Object.keys(item)[0] ?? '',
      }),
      modalFields: (item: Partial<ApiKey> | undefined): FormFieldConfig[] => [
        createTextField(
          'name',
          this.translate.instant('ADMIN.USERS.API_KEYS.FIELDS.NAME'),
          item?.name,
          {
            name: 'name',
            validations: [
              {
                name: 'required',
                validator: Validators.required,
                message: 'Name is required',
              },
            ],
          },
        ),
      ],
      subHeader: this.translate.instant(
        'ADMIN.USERS.API_KEYS.MODALS.NEW.DESCRIPTION',
      ),
      onSubmit: async (formInput: ApiKey, dialogRef: DynamicDialogRef) => {
        const createRequest: UserApiKeyCreateRequest = {
          name: formInput.name ?? '',
          policies: formInput.policies ?? [],
        };

        const currentOwnerId = userEntity?.id;
        if (isNullOrUndefined(currentOwnerId)) {
          console.error('Owner ID is missing. Cannot create API key.');
          // Potentially show an error dialog, though original only logged for this specific check.
          // For consistency with how other errors are handled, let's show a dialog.
          this._showErrorDialog(
            'Error Creating API Key',
            'Cannot create API key: User information is missing.',
          );
          return false;
        }

        try {
          const createdApiKey = await firstValueFrom(
            this.accountsService
              .createApiKey(currentOwnerId, createRequest)
              .pipe(takeUntilDestroyed(this.destroyRef)),
          );

          dialogRef.close(createdApiKey); // Close the current (creation) dialog
          this._showCreatedApiKeyDialog(createdApiKey, userEntity);
          return; // Indicate success to ModalListFormComponent
        } catch (error) {
          console.error('Failed to create API key:', error);
          this._showErrorDialog(
            'Error Creating API Key',
            'An error occurred while creating the API key. Please try again or contact support.',
          );
          return false; // Keep the original creation dialog open
        }
      },
      onDeleteItem: async (item: Record<string, ApiKey>) => {
        const apiKeyId = Object.keys(item)[0];
        const currentOwnerId = userEntity?.id;

        if (isNullOrUndefined(apiKeyId)) {
          console.error('Missing apiKeyId for deletion.');
          // Original did not show a dialog here, just returned false.
          // To maintain consistency with other error handling, a dialog could be added.
          // However, sticking to minimal change for this specific console error.
          return false;
        }

        if (isNullOrUndefined(currentOwnerId)) {
          console.error('Owner ID is missing. Cannot delete API key.');
          this._showErrorDialog(
            'Error Deleting API Key',
            'Cannot delete API key: User information is missing.',
          );
          return false;
        }

        return this.handleApiKeyRemoval(currentOwnerId, apiKeyId);
      },
    };
    this.formFields = [
      createModalListField(
        'apiKeys',
        this.translate.instant('ADMIN.USERS.API_KEYS.FIELDS.KEYS'),
        isDefined(userEntity?.apiKeys)
          ? Object.entries(userEntity?.apiKeys).map(([key, value]) => ({
              [key]: value,
            }))
          : [],
        {
          layout: 'horizontal',
          labelWidth: '1/3',
          name: 'apiKeys',
          props: {
            modalConfig: this.userApiKeysModalConfig,
          },
        },
      ) as FormFieldConfig<unknown>,
    ];
  }

  private handleApiKeyRemoval(
    currentOwnerId: string,
    apiKeyId: string,
  ): boolean | void | PromiseLike<boolean | void> {
    return new Promise<boolean>((resolve) => {
      this.confirmationService.confirm({
        message: this.translate.instant(
          'ADMIN.USERS.API_KEYS.MODALS.DELETE.DESCRIPTION',
        ),
        header: 'Confirmation',
        icon: 'pi pi-exclamation-triangle',
        acceptButtonProps: {
          label: this.translate.instant('SHARED.COMMON.BUTTONS.DELETE'),
        },
        rejectButtonProps: {
          label: this.translate.instant('SHARED.COMMON.BUTTONS.CANCEL'),
          severity: 'secondary',
        },
        accept: async () => {
          try {
            await firstValueFrom(
              this.accountsService
                .deleteApiKey(currentOwnerId, apiKeyId)
                .pipe(takeUntilDestroyed(this.destroyRef)),
            ).then(() => {
              this.broadcastService.broadcast('entity-updated', {
                entityType: 'user',
                operation: 'delete',
                entityId: currentOwnerId,
                data: { apiKeyId },
              });
              resolve(true);
            });
          } catch (error) {
            console.error(
              'Failed to delete API key via custom handler:',
              error,
            );
            const errorMessage = `Failed to delete API key: ${(error as Error).message || 'Unknown error'}`;
            this._showErrorDialog(
              'Error Deleting API Key',
              'An error occurred. Please try again or contact support.',
              [
                {
                  type: 'custom',
                  key: 'errorMessageDisplay',
                  template: 'errorDisplay', // Ensure this template is handled by ModalListFormComponent
                  props: { message: errorMessage },
                  name: 'custom',
                },
              ],
            );
            resolve(false); // Prevent default client-side deletion
          }
        },
        reject: (type: ConfirmEventType) => {
          if (
            type === ConfirmEventType.REJECT ||
            type === ConfirmEventType.CANCEL
          ) {
            resolve(false);
          }
        },
      });
    });
  }

  private _showCreatedApiKeyDialog(
    createdApiKey: ApiKey,
    userEntity: UserResponse | UserApiKeyCreateRequest | null,
  ): void {
    // Delay to ensure the creation dialog closes before opening the new one
    setTimeout(() => {
      const newDialogRef = this.dialogService.open(ModalListFormComponent, {
        header: 'API Key Created Successfully',
        width: '500px',
        contentStyle: { 'max-height': '500px', overflow: 'auto' },
        data: {
          fields: [
            createTextField(
              'displayedKeyName',
              'Key Name',
              createdApiKey.name,
              {
                name: 'displayedKeyName',
                disabled: true,
              },
            ),
            createTextAreaField(
              'apiTokenValue',
              'API Key',
              createdApiKey['key'],
              {
                name: 'apiTokenValue',
                readonly: true,
              },
            ),
          ],
          actions: [
            {
              label: 'Copy Key & Close',
              severity: 'primary',
              icon: 'pi pi-copy',
              action: () => {
                if (isDefined(createdApiKey['key'])) {
                  navigator.clipboard
                    .writeText(createdApiKey['key'])
                    .then(() =>
                      this.broadcastService.broadcast('entity-updated', {
                        entityType: 'user',
                        operation: 'update',
                        entityId: userEntity?.id,
                        data: userEntity, // Note: userEntity might be slightly stale here regarding its own apiKeys list
                      }),
                    )
                    .catch((err) =>
                      console.error('Failed to copy API Key: ', err),
                    );
                }
                newDialogRef?.close();
              },
            },
          ],
          modalTitle: this.translate.instant(
            'ADMIN.USERS.API_KEYS.MODALS.DETAILS.TITLE',
          ),
          subHeader: this.translate.instant(
            'ADMIN.USERS.API_KEYS.MODALS.DETAILS.DESCRIPTION',
          ),
          hideForm: true,
          isDisplayMode: true,
        },
      });
    }, 300);
  }

  private _showErrorDialog(
    header: string,
    subHeader: string,
    fields?: FormFieldConfig[],
  ): void {
    // eslint-disable-next-line prefer-const
    let dialogRefItself: DynamicDialogRef | undefined | null;

    const dialogConfigData = {
      actions: [
        {
          label: 'Close',
          severity: 'secondary',
          action: () => {
            if (dialogRefItself) {
              dialogRefItself.close();
            }
          },
        },
      ],
      subHeader,
      hideForm: true,
      isDisplayMode: true,
      fields: [] as FormFieldConfig[],
    };

    if (fields) {
      dialogConfigData.fields = fields;
    }

    dialogRefItself = this.dialogService.open(ModalListFormComponent, {
      header,
      width: '400px', // Consistent width for error dialogs
      data: dialogConfigData,
    });
  }

  protected override submitChanges(
    _formData: Record<string, Record<string, unknown>[]>,
  ): void {
    const user = this.entity();
    if (isNullOrUndefined(user)) return;

    this.clearUnsavedChanges();
    this.isFormEditable.set(false);
    this.isSubmitting.set(false);
    this.broadcastService.broadcast('entity-updated', {
      entityType: 'user',
      operation: 'update',
      entityId: user.id,
      data: user,
    });
  }
}
