import { Injectable, inject } from '@angular/core';
import { HttpClient } from '@angular/common/http';
import { Observable } from 'rxjs';
import { Configuration } from '../../../api/configuration';
import { isDefined } from '../../../shared/utils';

export type OdoHourChangeType = 'odo' | 'hours';

export interface OdoHourChangeCreateRequest {
  type: OdoHourChangeType;
  value: number;
  fromDate: string;
}

export interface OdoHourChangeUpdateRequest {
  type?: OdoHourChangeType;
  value?: number;
  fromDate?: string;
}

export interface OdoHourChangeRecord {
  id: string;
  assetId: string;
  changeType: OdoHourChangeType;
  value: number;
  fromDate: string;
  createdBy?: string;
  createdDate?: string;
  updatedBy?: string;
  updatedDate?: string;
}

export interface OdoHourChangeListResponse {
  count: number;
  offset: number;
  limit: number;
  items: OdoHourChangeRecord[];
}

@Injectable({
  providedIn: 'root',
})
export class OdoHourChangesService {
  private readonly http = inject(HttpClient);
  private readonly configuration = inject(Configuration);

  private url(assetId: string, id?: string): string {
    const base = `${this.configuration.basePath}/assets/${encodeURIComponent(assetId)}/odo-hours-changes`;
    return isDefined(id) ? `${base}/${encodeURIComponent(id)}` : base;
  }

  private get headers(): Record<string, string> {
    const token = this.configuration.lookupCredential('access_token');
    return isDefined(token) ? { 'x-access-token': token } : {};
  }

  list(
    assetId: string,
    type?: OdoHourChangeType,
  ): Observable<OdoHourChangeListResponse> {
    const params: Record<string, string> = {};
    if (type) params['type'] = type;

    return this.http.get<OdoHourChangeListResponse>(this.url(assetId), {
      headers: this.headers,
      params,
      responseType: 'json' as const,
    });
  }

  create(
    assetId: string,
    request: OdoHourChangeCreateRequest,
  ): Observable<OdoHourChangeRecord> {
    return this.http.post<OdoHourChangeRecord>(this.url(assetId), request, {
      headers: this.headers,
      responseType: 'json' as const,
    });
  }

  update(
    assetId: string,
    id: string,
    request: OdoHourChangeUpdateRequest,
  ): Observable<OdoHourChangeRecord> {
    return this.http.put<OdoHourChangeRecord>(this.url(assetId, id), request, {
      headers: this.headers,
      responseType: 'json' as const,
    });
  }

  delete(assetId: string, id: string): Observable<OdoHourChangeRecord> {
    return this.http.delete<OdoHourChangeRecord>(this.url(assetId, id), {
      headers: this.headers,
      responseType: 'json' as const,
    });
  }
}
