import { CommonModule } from '@angular/common';
import { Component, computed, effect, inject, input, signal, untracked } from '@angular/core';
import { Validators } from '@angular/forms';

import { ButtonModule } from 'primeng/button';
import { TranslatePipe } from '@ngx-translate/core';

import { EntitySectionBaseComponent } from '../../base/entity-section-base';
import { Contact } from '../../../../../api';
import { ContactCreateRequest, ContactDetailItem, ContactListItem, ContactUpdateRequest } from '../../../services/contacts.service';
import { isDefined, isEmpty } from '../../../../../shared/utils';
import { mobileValidator, phoneValidator } from '../../../../../shared/utils/phone-number-utils';
import { createTextField, createDropdownField, createTextAreaField } from '../../../../../shared/models';
import { Observable } from 'rxjs';
import { DynamicFormComponent } from '../../../../../shared/components/forms/dynamic-form/dynamic-form.component';
import { GridComponent } from '../../../../../shared/components/grid/grid.component';
import { EntityOperationRegistryService } from '../../../services/entity/entity-operation-registry.service';

@Component({
  selector: 'app-contact-details-section',
  imports: [CommonModule, ButtonModule, DynamicFormComponent, GridComponent, TranslatePipe],
  templateUrl: './contact-details-section.component.html',
  styleUrl: './contact-details-section.component.scss',
})
export class ContactDetailsSectionComponent extends EntitySectionBaseComponent<
  ContactDetailItem
> {
  private readonly operationRegistry = inject(EntityOperationRegistryService);

  readonly existingContacts = input<ContactListItem[]>([]);
  readonly duplicateError = signal<string | null>(null);
  readonly contactDetails = computed(() => {
    const contact = this.entity();
    if (!isDefined(contact)) return [];
    const none = this.translate.instant('SHARED.COMMON.NONE');
    return [
      { key: this.translate.instant('ADMIN.ASSETS.CONTACTS.FIELDS.NAME'), value: contact.name ?? none },
      { key: this.translate.instant('ADMIN.ASSETS.CONTACTS.FIELDS.TYPE'), value: contact.type ? contact.type.charAt(0).toUpperCase() + contact.type.slice(1) : none },
      { key: this.translate.instant('ADMIN.ASSETS.CONTACTS.FIELDS.EMAIL'), value: contact.emailAddress ?? none },
      { key: this.translate.instant('ADMIN.ASSETS.CONTACTS.FIELDS.MOBILE'), value: contact.phoneMobile ?? none },
      { key: this.translate.instant('ADMIN.ASSETS.CONTACTS.FIELDS.PHONE'), value: contact.phoneOffice ?? none },
      { key: this.translate.instant('ADMIN.ASSETS.CONTACTS.FIELDS.NOTES'), value: contact.notes ?? none },
    ];
  });

  constructor() {
    super();

    this.columns = [
      { field: 'key', header: '', transform: 'uppercase' },
      { field: 'value', header: '' },
    ];

    effect(() => {
      const entity = this.entity();
      if (isDefined(entity) && !this.createMode()) {
        untracked(() => {
          this.updateFormFields();
        });
      }
    });
  }

  protected override updateFormFields(): void {
    const contact = this.entity();
    const t = (key: string, params?: object) => this.translate.instant(key, params);
    this.formFields = [
      createTextField(
        'name',
        t('ADMIN.ASSETS.CONTACTS.FIELDS.NAME'),
        contact?.name,
        {
          name: 'name',
          validations: [
            {
              name: 'required',
              validator: Validators.required,
              message: t('SHARED.COMMON.FORMS.SHARED.REQUIRED', { field: t('ADMIN.ASSETS.CONTACTS.FIELDS.NAME') }),
            },
          ],
        },
      ),
      createDropdownField(
        'type',
        t('ADMIN.ASSETS.CONTACTS.FIELDS.TYPE'),
        [
          { label: t('SHARED.CONTACTS.TYPES.Emergency'), value: Contact.TypeEnum.Emergency },
          { label: t('SHARED.CONTACTS.TYPES.Administrative'), value: Contact.TypeEnum.Administrative },
          { label: t('SHARED.CONTACTS.TYPES.Technical'), value: Contact.TypeEnum.Technical },
          { label: t('SHARED.CONTACTS.TYPES.Operational'), value: Contact.TypeEnum.Operational },
          { label: t('SHARED.CONTACTS.TYPES.Management'), value: Contact.TypeEnum.Management },
          { label: t('SHARED.CONTACTS.TYPES.Owner'), value: Contact.TypeEnum.Owner },
        ],
        contact?.type ?? null,
        {
          name: 'type',
          validations: [
            {
              name: 'required',
              validator: Validators.required,
              message: t('SHARED.COMMON.FORMS.SHARED.REQUIRED', { field: t('ADMIN.ASSETS.CONTACTS.FIELDS.TYPE') }),
            },
          ],
        },
      ),
      createTextField(
        'emailAddress',
        t('ADMIN.ASSETS.CONTACTS.FIELDS.EMAIL'),
        contact?.emailAddress,
        {
          name: 'emailAddress',
          validations: [
            {
              name: 'email',
              validator: Validators.email,
              message: t('SHARED.COMMON.VALIDATION.INVALID_EMAIL'),
            },
          ],
        },
      ),
      createTextField(
        'phoneMobile',
        t('ADMIN.ASSETS.CONTACTS.FIELDS.MOBILE'),
        contact?.phoneMobile,
        {
          name: 'phoneMobile',
          validations: [
            {
              name: 'mobile',
              validator: mobileValidator(),
              message: t('SHARED.COMMON.VALIDATION.INVALID_PHONE'),
            },
          ],
        },
      ),
      createTextField(
        'phoneOffice',
        t('ADMIN.ASSETS.CONTACTS.FIELDS.PHONE'),
        contact?.phoneOffice,
        {
          name: 'phoneOffice',
          validations: [
            {
              name: 'phone',
              validator: phoneValidator(),
              message: t('SHARED.COMMON.VALIDATION.INVALID_PHONE'),
            },
          ],
        },
      ),
      createTextAreaField(
        'notes',
        t('ADMIN.ASSETS.CONTACTS.FIELDS.NOTES'),
        contact?.notes,
        { name: 'notes' },
      ),
    ];
  }

  override getUpdateMethod(): (id: string, data: Partial<ContactDetailItem | ContactUpdateRequest>) => Observable<ContactDetailItem> {
    return (
      this.operationRegistry.getOperation<
        ContactDetailItem | ContactUpdateRequest,
        ContactCreateRequest,
        ContactDetailItem,
        'update'
      >('contact', 'update') ?? ((_id, _data) => new Observable((obs) => obs.complete()))
    );
  }

  override validate(): boolean {
    const formValid = super.validate();
    if (!formValid || !this.createMode()) return formValid;

    this.duplicateError.set(null);

    const formValue = this.dynamicForm?.form?.value ?? {};
    const email = (formValue['emailAddress'] as string | null)?.trim().toLowerCase();
    const mobile = (formValue['phoneMobile'] as string | null)?.trim();
    const office = (formValue['phoneOffice'] as string | null)?.trim();

    for (const contact of this.existingContacts()) {
      if (!isEmpty(email) && contact.emailAddress?.trim().toLowerCase() === email) {
        this.duplicateError.set(this.translate.instant('ADMIN.CONTACTS.ERRORS.EMAIL_DUPLICATE', { email: formValue['emailAddress'], name: contact.name }));
        return false;
      }
      if (!isEmpty(mobile) && contact.phoneMobile?.trim() === mobile) {
        this.duplicateError.set(this.translate.instant('ADMIN.CONTACTS.ERRORS.MOBILE_DUPLICATE', { mobile, name: contact.name }));
        return false;
      }
      if (!isEmpty(office) && contact.phoneOffice?.trim() === office) {
        this.duplicateError.set(this.translate.instant('ADMIN.CONTACTS.ERRORS.PHONE_DUPLICATE', { phone: office, name: contact.name }));
        return false;
      }
    }

    return true;
  }
}
