import { CommonModule } from '@angular/common';
import {
  Component,
  computed,
  effect,
  inject,
  OnInit,
  signal,
} from '@angular/core';
import { ReactiveFormsModule, Validators } from '@angular/forms';

import { ButtonModule } from 'primeng/button';
import { CardModule } from 'primeng/card';
import { ConfirmationService } from 'primeng/api';

import {
  AssetResponse,
  EntitiesService,
  AssetCurfewParameter,
  AssetCreateRequest,
  AssetParameters,
} from '../../../../../api';
import { UtilityService } from '../../../../../core/services/utility.service';
import { GridComponent } from '../../../../../shared/components/grid/grid.component';
import {
  createDropdownField,
  createModalListField,
  FormFieldConfig,
  ListFieldModalConfig,
  createDateField,
  createListboxField,
  createTextField,
} from '../../../../../shared/models';
import { isNullOrUndefined } from '../../../../../shared/utils';
import { WEEKDAY_OPTIONS } from '../../../models';
import { BulkEntitySectionBaseComponent } from '../../../components/base/bulk-entity-section-base';
import { AssetBulkSaveService } from '../../../services/asset-bulk-save.service';
import { DynamicFormComponent } from '../../../../../shared/components/forms/dynamic-form/dynamic-form.component';
import { ModalListFormComponent } from '../../../../../shared/components/forms/modal-list-form/modal-list-form.component';
import { HttpClient } from '@angular/common/http';
import { forkJoin, Observable } from 'rxjs';
import { takeUntilDestroyed } from '@angular/core/rxjs-interop';
import { v4 as uuidv4 } from 'uuid';
import { EntityOperationRegistryService } from '../../../services/entity/entity-operation-registry.service';
import { AuthDataService } from '../../../../../core/services/auth-data.service';
import { ListFieldModalConfigBuilder } from '../../../../../shared/services/forms/modal-forms.index';
import { TranslatePipe } from '@ngx-translate/core';

@Component({
  selector: 'app-asset-curfew-events-section',
  imports: [
    CommonModule,
    ReactiveFormsModule,
    ButtonModule,
    GridComponent,
    DynamicFormComponent,
    CardModule,
    TranslatePipe,
  ],
  providers: [ConfirmationService],
  templateUrl: './asset-curfew-events-section.component.html',
  styleUrl: './asset-curfew-events-section.component.scss',
})
export class AssetCurfewEventsSectionComponent
  extends BulkEntitySectionBaseComponent<
    AssetResponse | Partial<AssetCreateRequest>
  >
  implements OnInit
{
  private readonly http = inject(HttpClient);
  private readonly entitiesService = inject(EntitiesService);
  private readonly utilityService = inject(UtilityService);
  private readonly operationRegistry = inject(EntityOperationRegistryService);
  private readonly authDataService = inject(AuthDataService);
  private readonly bulkSaveService = inject(AssetBulkSaveService);
  private readonly confirmationService = inject(ConfirmationService);

  timezones: { label: string; value: string }[] = [];

  selectOptions: Record<
    string,
    { label: string; value: string; type: string }[]
  > = {};

  private readonly formState = signal<AssetCurfewParameter[]>([]);

  readonly assetCurfewEvents = computed(() => {
    if (this.isBulkMode) {
      return [{ key: 'Working Hours', value: '' }];
    }
    const asset = this.entity() as AssetResponse | null;
    const assetCurfewEvents = this.formState() ?? asset?.parameters?.curfews;
    this.languageService.currentLanguage();

    if (isNullOrUndefined(assetCurfewEvents)) return [];
    return [
      {
        key: this.translate.instant(
          'ADMIN.ASSETS.CURFEW_EVENTS.FIELDS.CURFEWS',
        ),
        value: assetCurfewEvents
          .map((event) => `${event.from} - ${event.to}`)
          .join(', '),
      },
    ];
  });

  showModal = false;
  assetCurfewModalConfig?: ListFieldModalConfig<AssetCurfewParameter>;

  constructor() {
    super();

    // Setup initial columns
    this.columns = [
      { field: 'key', header: '', transform: 'uppercase' },
      { field: 'value', header: '' },
    ];

    effect(() => {
      const entity = this.entity();
      if (entity && !this.createMode()) {
        this.updateFormFields();
      }
    });
  }

  protected get effectiveOwnerId(): string {
    const bulkEditContext = this.bulkContext();
    if (bulkEditContext) return bulkEditContext.ownerId;
    const entity = this.entity() as AssetResponse | null;
    return entity?.owner?.id ?? '';
  }

  ngOnInit(): void {
    this.loadTimezones();
    this.assetCurfewModalConfig =
      new ListFieldModalConfigBuilder<AssetCurfewParameter>()
        .withModalComponent(ModalListFormComponent)
        .withTitle(this.translate.instant('ADMIN.ASSETS.CURFEW_EVENTS.TITLE'))
        .withFields((item) => this.createWorkingHoursFields(item))
        .withDefaultProvider(() => ({
          id: uuidv4(),
          from: '00:00',
          to: '23:59',
          timeZoneId: this.authDataService.getUserProfile()?.timeZoneId ?? '',
          days: WEEKDAY_OPTIONS.map((day) => day.value),
        }))
        .withFormatter((item) => {
          return {
            id: item.id,
            title: `${item.from} - ${item.to}`,
            display: this.translate.instant(
              'ADMIN.ASSETS.CURFEW_EVENTS.FIELDS.CURFEW_DESCRIPTION',
              {
                from: item.from,
                to: item.to,
                days: this.utilityService.getWeekdaysString(item.days),
              },
            ),
            icon: 'clock',
          };
        })
        .withShowEditButton(true)
        .build();
  }

  private createWorkingHoursFields(
    item?: AssetCurfewParameter | null,
  ): FormFieldConfig[] {
    return [
      createTextField('id', 'ID', item?.id, {
        name: 'id',
        hidden: true,
      }),
      createDateField(
        'from',
        this.translate.instant('ADMIN.ASSETS.CURFEW_EVENTS.FIELDS.FROM'),
        item?.from ?? '',
        {
          name: 'from',
          placeholder: this.translate.instant('SHARED.COMMON.SELECTION.TITLE', {
            type: this.translate.instant(
              'ADMIN.ASSETS.CURFEW_EVENTS.FIELDS.FROM',
            ),
          }),
          props: {
            timeOnly: true,
            showSeconds: false,
            hourFormat: '24',
          },
          style: { width: '100%' },
        },
      ),
      createDateField(
        'to',
        this.translate.instant('ADMIN.ASSETS.CURFEW_EVENTS.FIELDS.TO'),
        item?.to ?? '',
        {
          name: 'to',
          placeholder: this.translate.instant('SHARED.COMMON.SELECTION.TITLE', {
            type: this.translate.instant(
              'ADMIN.ASSETS.CURFEW_EVENTS.FIELDS.TO',
            ),
          }),
          props: {
            timeOnly: true,
            showSeconds: false,
            hourFormat: '24',
          },
          style: { width: '100%' },
        },
      ),
      createDropdownField(
        'timeZoneId',
        this.translate.instant('ADMIN.ASSETS.CURFEW_EVENTS.FIELDS.TIMEZONE'),
        this.timezones,
        item?.timeZoneId ?? '',
        {
          layout: 'horizontal',
          labelWidth: '1/3',
          placeholder: this.translate.instant('SHARED.COMMON.SELECTION.TITLE', {
            type: this.translate.instant(
              'ADMIN.ASSETS.CURFEW_EVENTS.FIELDS.TIMEZONE',
            ),
          }),
          name: 'timeZone',
          props: {
            appendTo: 'body',
          },
        },
      ),
      createListboxField(
        'days',
        this.translate.instant('ADMIN.ASSETS.CURFEW_EVENTS.FIELDS.DAYS'),
        item?.days ?? [],
        WEEKDAY_OPTIONS,
        {
          name: 'days',
          validations: [
            {
              name: 'required',
              validator: Validators.required,
              message: this.translate.instant(
                'SHARED.COMMON.FORMS.SHARED.REQUIRED',
                {
                  field: this.translate.instant(
                    'ADMIN.ASSETS.CURFEW_EVENTS.FIELDS.DAYS',
                  ),
                },
              ),
            },
          ],
          props: {
            checkmark: true,
            multiple: true,
          },
        },
      ),
    ];
  }

  private loadTimezones(): void {
    this.http
      .get<{ id: string; name: string }[]>('/assets/docs/timezones.json')
      .subscribe((data) => {
        this.timezones = data
          .map((tz) => ({ label: tz.id, value: tz.id }))
          .sort((a, b) => a.label.localeCompare(b.label));
        this.updateFormFields();
      });
  }

  protected override updateFormFields(): void {
    this.formFields = this.buildFormFields(
      this.entity() as AssetResponse | null,
    );
  }

  protected buildFormFields(entity: AssetResponse | null): FormFieldConfig[] {
    // In bulk mode entity is null — render with an empty curfews list so form shows
    const currentCurfews = entity?.parameters?.curfews ?? [];
    this.formState.set(currentCurfews);

    return [
      createModalListField(
        'curfews',
        this.translate.instant('ADMIN.ASSETS.CURFEW_EVENTS.FIELDS.CURFEWS'),
        currentCurfews,
        {
          layout: 'horizontal',
          labelWidth: '1/3',
          name: 'curfews',
          props: {
            modalConfig: this.assetCurfewModalConfig,
          },
        },
      ) as FormFieldConfig<unknown>,
    ];

    // We'll use the (formValueChange) output in the template instead of this subscription
    // since this.form may not be initialized at this point.
  }

  protected override submitBulkChanges(
    _formData: Record<string, string | number | object | null>,
  ): void {
    const bulkEditContext = this.bulkContext();
    if (isNullOrUndefined(bulkEditContext)) return;

    const curfews = this.formState();
    this.isSubmitting.set(true);

    const saves$ = bulkEditContext.selectedEntities.map((entity) =>
      this.entitiesService.updateAsset(entity.id, {
        parameters: { curfews },
      }),
    );

    forkJoin(saves$)
      .pipe(takeUntilDestroyed(this.destroyRef))
      .subscribe({
        next: () => {
          this.isSubmitting.set(false);
          this.isFormEditable.set(false);
          this.clearUnsavedChanges();
          this.broadcastService.broadcast('entity-updated', {
            entityType: 'asset',
            operation: 'update',
          });
        },
        error: () => {
          this.isSubmitting.set(false);
          this.isFormEditable.set(true);
        },
      });
  }

  protected override onFormValueChange(
    formValue: Record<string, unknown>,
  ): void {
    super.onFormValueChange(formValue as Record<string, string | number>);
    if (Array.isArray(formValue?.['curfews'])) {
      this.formState.set(formValue['curfews'] as AssetCurfewParameter[]);
    }
  }

  override getUpdateMethod(): (
    id: string,
    data: AssetParameters,
  ) => Observable<AssetResponse> {
    return (
      this.operationRegistry.getOperation<
        AssetResponse | AssetCreateRequest,
        AssetCreateRequest,
        AssetResponse,
        'update'
      >('asset', 'update') ??
      ((id, data) =>
        this.entitiesService.updateAsset(id, {
          parameters: data,
        }))
    );
  }

  onClose() {
    this.showModal = false;
  }
}
