import { CommonModule } from '@angular/common';
import { Component, computed, effect, inject } from '@angular/core';

import { forkJoin, Observable } from 'rxjs';
import { takeUntilDestroyed } from '@angular/core/rxjs-interop';
import { ConfirmationService } from 'primeng/api';

import {
  AssetCreateRequest,
  AssetResponse,
  AssetUpdateRequest,
  EntitiesService,
  AssetZoneTarget,
} from '../../../../../api';
import { DynamicFormComponent } from '../../../../../shared/components/forms/dynamic-form/dynamic-form.component';
import { GridComponent } from '../../../../../shared/components/grid/grid.component';
import {
  createZoneFilterField,
  createListboxField,
  ActorNodeData,
  FormFieldConfig,
} from '../../../../../shared/models';
import { FormToRequestMapper } from '../../../utils/form-to-request-mapper';
import { BulkTypedEntitySectionBaseComponent } from '../../../components/base/bulk-typed-entity-section-base';
import { isDefined } from '../../../../../shared/utils';
import { FontAwesomeModule } from '@fortawesome/angular-fontawesome';
import { faRoute } from '@fortawesome/free-solid-svg-icons';
import { TranslatePipe } from '@ngx-translate/core';

@Component({
  selector: 'app-asset-zones-section',
  imports: [
    CommonModule,
    GridComponent,
    DynamicFormComponent,
    FontAwesomeModule,
    TranslatePipe,
  ],
  providers: [ConfirmationService],
  templateUrl: './asset-zones-section.component.html',
  styleUrl: './asset-zones-section.component.scss',
})
export class AssetZonesSectionComponent extends BulkTypedEntitySectionBaseComponent<
  AssetResponse,
  AssetUpdateRequest,
  AssetCreateRequest,
  AssetResponse
> {
  private readonly entitiesService = inject(EntitiesService);
  readonly assetDetails = computed(() => {
    const assetDetails = this.entity();
    this.languageService.currentLanguage();

    if (this.isBulkMode) {
      return [
        { key: 'Geofences', value: '' },
        { key: 'Borders', value: '' },
      ];
    }

    if (!isDefined(assetDetails)) return [];

    return [
      {
        key: this.translate.instant('ADMIN.ASSETS.ZONES.FIELDS.ZONES'),
        value:
          (assetDetails.zones ?? [])?.length > 0
            ? assetDetails.zones?.map((zone) => zone.targetName).join(', ')
            : this.translate.instant('SHARED.COMMON.NONE'),
      },
      {
        key: this.translate.instant('ADMIN.ASSETS.ZONES.FIELDS.BORDERS'),
        value:
          assetDetails.parameters?.borders
            ?.map(
              (border) =>
                border.charAt(0).toUpperCase() + border.slice(1).toLowerCase(),
            )
            .join(', ') ?? this.translate.instant('SHARED.COMMON.NONE'),
      },
    ];
  });
  private requestMapper?: FormToRequestMapper<AssetUpdateRequest>;
  faRoute = faRoute;

  constructor() {
    super();

    // Setup initial columns
    this.columns = [
      { field: 'key', header: '', transform: 'uppercase' },
      { field: 'value', header: '' },
    ];

    // React to entity changes
    effect(() => {
      const assetDetails = this.entity();
      if (assetDetails) {
        this.initializeRequestMapper();
        this.updateFormFields();
      }
    });
  }

  protected get effectiveOwnerId(): string {
    const bulkEditContext = this.bulkContext();
    if (isDefined(bulkEditContext)) return bulkEditContext.ownerId;
    const entity = this.entity() as AssetResponse | null;
    return entity?.owner?.id ?? '';
  }

  private initializeRequestMapper(): void {
    this.requestMapper = new FormToRequestMapper<AssetUpdateRequest>({
      zones: {
        requestProperty: 'zones',
        transform: (value) => {
          const zones = value as (ActorNodeData & { zoneType?: string })[];
          return zones.map((zone) => ({
            zoneType:
              (zone.zoneType as AssetZoneTarget.ZoneTypeEnum) ?? 'location',
            targetSelectionType:
              zone.actorSelectionType === 'group' ? 'group' : 'specific',
            targetId: zone.actorId,
            targetName: zone.actorName,
          }));
        },
      },
      borders: {
        requestProperty: 'parameters',
        transform: (value) => {
          return {
            borders: value as string[],
          };
        },
      },
    });
  }

  protected override updateFormFields(): void {
    this.formFields = this.buildFormFields(
      this.entity() as AssetResponse | null,
    );
  }

  protected buildFormFields(entity: AssetResponse | null): FormFieldConfig[] {
    // Convert existing zones to ActorNodeData format (empty array in bulk mode)
    const existingZones: ActorNodeData[] = (entity?.zones ?? []).map(
      (zone) => ({
        actorId: zone.targetId ?? '',
        actorName: zone.targetName ?? '',
        actorSelectionType:
          zone.targetSelectionType === 'group' ? 'group' : 'specific',
        actorType: 'zone',
        actorTypeId: zone.zoneType ?? 'location',
        actorTypeName: 'Zone',
        text: zone.targetName ?? '',
        zoneType: zone.zoneType,
      }),
    );

    this.formFields = [
      createZoneFilterField(
        'zones',
        this.translate.instant('ADMIN.ASSETS.ZONES.FIELDS.ZONES'),
        existingZones,
        {
          layout: 'horizontal',
          labelWidth: '1/3',
          name: 'zones',
          props: {
            ownerId: entity?.owner?.id,
            multi: true,
          },
        },
      ),
      createListboxField(
        'borders',
        this.translate.instant('ADMIN.ASSETS.ZONES.FIELDS.BORDERS'),
        entity?.parameters?.borders ?? [],
        [
          {
            label: this.translate.instant(
              'ADMIN.ASSETS.ZONES.BORDER_VALUES.COUNTRY',
            ),
            value: 'country',
          },
          {
            label: this.translate.instant(
              'ADMIN.ASSETS.ZONES.BORDER_VALUES.STATE',
            ),
            value: 'state',
          },
        ],
        {
          name: 'borders',
          layout: 'horizontal',
          labelWidth: '1/3',
          props: {
            checkbox: true,
            multiple: true,
          },
          hint: this.translate.instant(
            'ADMIN.ASSETS.ZONES.FIELDS.BORDERS_DESCRIPTION',
          ),
        },
      ),
    ];

    return this.formFields;
  }

  protected override submitBulkChanges(
    formData: Record<string, unknown>,
  ): void {
    const bulkEditContext = this.bulkContext();
    if (!isDefined(bulkEditContext)) return;

    if (!this.requestMapper) {
      this.initializeRequestMapper();
    }

    const payload = this.transformFormData(formData);
    this.isSubmitting.set(true);

    const saves$ = bulkEditContext.selectedEntities.map((entity) =>
      this.entitiesService.updateAsset(entity.id, payload),
    );

    forkJoin(saves$)
      .pipe(takeUntilDestroyed(this.destroyRef))
      .subscribe({
        next: () => {
          this.isSubmitting.set(false);
          this.isFormEditable.set(false);
          this.clearUnsavedChanges();
          this.broadcastService.broadcast('entity-updated', {
            entityType: 'asset',
            operation: 'update',
          });
        },
        error: () => {
          this.isSubmitting.set(false);
          this.isFormEditable.set(true);
        },
      });
  }

  protected override getUpdateMethod(): (
    id: string,
    data: AssetUpdateRequest,
  ) => Observable<AssetResponse> {
    return (id, data) => this.entitiesService.updateAsset(id, data);
  }

  protected override transformFormData(
    formData: Record<string, unknown> | Record<string, string | number>[],
  ): AssetUpdateRequest {
    if (!this.requestMapper) {
      throw new Error('Request mapper not initialized');
    }

    try {
      // Handle both possible input types
      const normalizedFormData = Array.isArray(formData)
        ? formData.reduce((acc, item) => ({ ...acc, ...item }), {})
        : formData;

      const partialRequest = this.requestMapper.transform(normalizedFormData);

      const updateRequest: Partial<AssetUpdateRequest> = {};

      for (const key in partialRequest) {
        if (Object.hasOwn(partialRequest, key)) {
          const value = partialRequest[key];
          if (value !== undefined && value !== null) {
            updateRequest[key] = value;
          }
        }
      }
      return updateRequest;
    } catch (error) {
      console.error('Form data transformation failed:', error);
      throw error;
    }
  }
}
