import {
  Component,
  computed,
  DestroyRef,
  inject,
  input,
  OnInit,
  signal,
} from '@angular/core';
import { Router } from '@angular/router';

import { MessageModule } from 'primeng/message';
import { ProgressSpinnerModule } from 'primeng/progressspinner';

import { TranslatePipe } from '@ngx-translate/core';

import { isDefined, isNullOrUndefined } from '../../../../../shared/utils';
import { EntityDetailsStateService } from '../../../services/entity/entity-details.state.service';
import { EntityOperationRegistryService } from '../../../services/entity/entity-operation-registry.service';
import { DetailsAccordionContainerComponent } from '../../details-accordion-container/details-accordion-container.component';
import { ContactSectionConfigFactory } from '../../../factories/contact-section-config.factory';
import { BroadcastEventMessageService } from '../../../services/broadcast-event-messages.service';
import { takeUntilDestroyed } from '@angular/core/rxjs-interop';
import { ContactDetailItem, ContactListItem, ContactsService, ContactUpdateRequest } from '../../../services/contacts.service';

interface EntityUpdatedMessage {
  entityType: string;
  data: ContactDetailItem;
}

@Component({
  selector: 'app-contact-details-container',
  imports: [DetailsAccordionContainerComponent, ProgressSpinnerModule, MessageModule, TranslatePipe],
  templateUrl: './contact-details-container.component.html',
  styleUrl: './contact-details-container.component.scss',
})
export class ContactDetailsContainerComponent implements OnInit {
  readonly entity = input<ContactListItem | null>(null);

  private readonly contactSectionFactory = inject(ContactSectionConfigFactory);
  readonly entityDetailsState = inject(EntityDetailsStateService);
  private readonly contactsService = inject(ContactsService);
  private readonly operationRegistry = inject(EntityOperationRegistryService);
  private readonly broadcastService = inject(BroadcastEventMessageService);
  private readonly router = inject(Router);
  private readonly destroyRef = inject(DestroyRef);

  readonly isLoading = computed(() => this.entityDetailsState.isLoading());
  readonly isSoftRefreshing = computed(() => this.entityDetailsState.isSoftRefreshing());
  readonly isInitialLoading = computed(
    () => this.isLoading() && !this.isSoftRefreshing() && !this.fullContact(),
  );

  readonly fullContact = computed(() => {
    const entityDetails = this.entityDetailsState.selectedItem();
    if (isNullOrUndefined(entityDetails)) return null;
    return entityDetails as ContactDetailItem;
  });

  readonly sections = computed(() => {
    const contact = this.fullContact();
    if (isNullOrUndefined(contact)) return [];
    return this.contactSectionFactory.createAllContactSections(contact);
  });

  readonly error = signal<string | null>(null);

  private isEntityUpdatedMessage(message: unknown): message is EntityUpdatedMessage {
    return (
      isDefined(message) &&
      message !== null &&
      typeof message === 'object' &&
      'entityType' in message &&
      'data' in message &&
      (message as EntityUpdatedMessage).entityType === 'contact'
    );
  }

  private getClientIdFromUrl(): string | undefined {
    return this.router.url.match(/\/client\/([^/]+)\//)?.[1];
  }

  constructor() {
    this.operationRegistry.registerEntityOperations<ContactDetailItem, ContactDetailItem, ContactDetailItem>('contact', {
      update: (id, data) => this.contactsService.update(id, data as ContactUpdateRequest),
      create: (data) => this.contactsService.create(data as never),
      get: (id) => this.contactsService.get(id, this.getClientIdFromUrl()),
    });
  }

  ngOnInit(): void {
    this.broadcastService
      .on('entity-updated')
      .pipe(takeUntilDestroyed(this.destroyRef))
      .subscribe((message) => {
        if (this.isEntityUpdatedMessage(message)) {
          this.onEntityChange(message.data);
        }
      });
  }

  onEntityChange(entity: unknown): void {
    this.entityDetailsState.updateEntity(entity as ContactDetailItem);
    this.error.set(null);
  }
}
