import { Injectable } from '@angular/core';
import { ConfirmationService } from 'primeng/api';
import { forkJoin, Observable } from 'rxjs';
import { AssetUpdateRequest } from '../../../api';
import { BulkEditContext } from '../models/bulk-edit-context.interface';

@Injectable({ providedIn: 'root' })
export class AssetBulkSaveService {
  /**
   * Show a confirmation dialog then fan out a save call to every selected asset.
   *
   * @param context     Bulk context containing ownerId and selected entities
   * @param payload     The partial update request to apply to each asset
   * @param saveCallback      Function that takes (assetId, payload) and returns an Observable
   * @param confirmationService  PrimeNG ConfirmationService (injected per-component)
   * @returns Observable that completes after all saves succeed
   */
  confirmAndSave(
    context: BulkEditContext,
    payload: Partial<AssetUpdateRequest>,
    saveCallback: (
      id: string,
      data: Partial<AssetUpdateRequest>,
    ) => Observable<unknown>,
    confirmationService: ConfirmationService,
  ): Observable<unknown[]> {
    const count = context.selectedEntities.length;

    return new Observable<unknown[]>((subscriber) => {
      confirmationService.confirm({
        header: 'Apply Bulk Changes',
        message: `Apply changes to ${count} asset${count === 1 ? '' : 's'}?`,
        acceptLabel: 'Apply',
        rejectLabel: 'Cancel',
        accept: () => {
          const saves$ = context.selectedEntities.map((entity) =>
            saveCallback(entity.id, payload),
          );

          forkJoin(saves$).subscribe({
            next: (results) => {
              subscriber.next(results);
              subscriber.complete();
            },
            error: (saveError) => subscriber.error(saveError),
          });
        },
        reject: () => {
          subscriber.complete();
        },
      });
    });
  }
}
