import {
  Component,
  computed,
  OnInit,
  inject,
  effect,
  input,
} from '@angular/core';
import { DeviceTypeResponse } from '../../../../../api/model/deviceTypeResponse';
import { DeviceTypeAccessory } from '../../../../../api/model/deviceTypeAccessory';
import { EntitySectionBaseComponent } from '../../base';
import {
  isNullOrUndefined,
  isDefined,
  isArray,
} from '../../../../../shared/utils';
import {
  createModalListField,
  createTextField,
  FormFieldConfig,
  ListFieldModalConfig,
} from '../../../../../shared/models';
import { EntityOperationRegistryService } from '../../../services/entity/entity-operation-registry.service';
import { DeviceTypesService } from '../../../../../api';
import { tap } from 'rxjs';
import { Validators } from '@angular/forms';
import { ToastService } from '../../../../../core/services/toast.service';
import { DynamicFormComponent } from '../../../../../shared/components/forms/dynamic-form/dynamic-form.component';
import { GridComponent } from '../../../../../shared/components/grid/grid.component';
import { ModalListFormComponent } from '../../../../../shared/components/forms/modal-list-form/modal-list-form.component';
import { ConfirmationService } from 'primeng/api';
import { TranslatePipe } from '@ngx-translate/core';

interface AccessoryItem {
  key: string;
  name: string;
}

@Component({
  selector: 'app-device-types-accessories-section',
  imports: [DynamicFormComponent, GridComponent, TranslatePipe],
  templateUrl: './device-types-accessories-section.component.html',
  styleUrl: './device-types-accessories-section.component.scss',
})
export class DeviceTypesAccessoriesSectionComponent
  extends EntitySectionBaseComponent<DeviceTypeResponse>
  implements OnInit
{
  private readonly operationRegistry = inject(EntityOperationRegistryService);
  private readonly deviceTypesService = inject(DeviceTypesService);
  private readonly toastService = inject(ToastService);
  private readonly confirmationService = inject(ConfirmationService);

  constructor() {
    super();
    this.columns = [
      { field: 'key', header: '' },
      { field: 'value', header: '' },
    ];

    effect(() => {
      const entity = this.entity();
      if (entity && !this.createMode()) {
        this.updateFormFields();
      }
    });
  }

  override entity = input<DeviceTypeResponse | null>(null);

  accessoryModalConfig: ListFieldModalConfig<AccessoryItem> | undefined;

  // Display accessories as a simple grid with comma-separated list
  readonly accessoriesDisplay = computed(() => {
    const deviceType = this.entity();
    const accessories = deviceType?.accessories;
    this.languageService.currentLanguage();
    const title = this.translate.instant(
      'ADMIN.DEVICES.TYPES.ACCESSORIES.TITLE',
    );
    const empty = this.translate.instant(
      'ADMIN.DEVICES.TYPES.ACCESSORIES.EMPTY',
    );
    if (isNullOrUndefined(accessories)) {
      return [{ key: title, value: empty }];
    }

    const accessoryNames = Object.entries(accessories)
      .filter(([key]) => isDefined(accessories[key]))
      .map(([key, accessory]) => accessory.name ?? key)
      .join(', ');

    return [{ key: title, value: accessoryNames ?? empty }];
  });

  getAccessoryDisplayName(key: string, name?: string | null): string {
    return isDefined(name) && name.trim() !== '' ? name : key;
  }

  // Get currently configured accessories as list for modal
  readonly currentAccessoriesList = computed(() => {
    const accessories = this.entity()?.accessories ?? {};
    return Object.entries(accessories)
      .filter(([key]) => isDefined(accessories[key]))
      .map(([key, accessory]) => ({
        key,
        name: accessory.name ?? '',
      }));
  });

  protected override updateFormFields(): void {
    this.accessoryModalConfig = {
      modalComponent: ModalListFormComponent,
      modalTitle: this.translate.instant(
        'ADMIN.DEVICES.TYPES.ACCESSORIES.MODAL.TITLE',
      ),
      defaultItemProvider: () => this.getDefaultItem(),
      listItemFormatter: (item: AccessoryItem) => ({
        id: item.key,
        title: this.getAccessoryDisplayName(item.key, item.name),
        display: item.key,
        icon: 'pi pi-th-large',
      }),
      modalFields: (item: AccessoryItem | undefined): FormFieldConfig[] => {
        return this.getModalFields(item);
      },
      onSubmit: async (item: AccessoryItem) => {
        // Validate the item
        if (!item.key?.trim()) {
          return false;
        }

        // Check for duplicates
        const existing = this.currentAccessoriesList().find(
          (existing) => existing.key === item.key,
        );
        if (existing) {
          this.toastService.showError(
            this.translate.instant(
              'ADMIN.DEVICES.TYPES.ACCESSORIES.ERRORS.DUPLICATE_TITLE',
            ),
            this.translate.instant(
              'ADMIN.DEVICES.TYPES.ACCESSORIES.ERRORS.DUPLICATE_MESSAGE',
            ),
          );
          return false;
        }

        return true; // Close modal
      },
      onDeleteItem: async (item: AccessoryItem) => {
        return new Promise<boolean>((resolve) => {
          this.confirmationService.confirm({
            header: this.translate.instant('SHARED.COMMON.DIALOG.CONFIRMATION'),
            message: this.translate.instant(
              'ADMIN.DEVICES.TYPES.ACCESSORIES.CONFIRM.REMOVE',
              { name: this.getAccessoryDisplayName(item.key, item.name) },
            ),
            closable: true,
            closeOnEscape: true,
            icon: 'pi pi-exclamation-triangle',
            rejectButtonProps: {
              label: this.translate.instant('SHARED.COMMON.BUTTONS.CANCEL'),
              severity: 'secondary',
              outlined: true,
            },
            acceptButtonProps: {
              label: this.translate.instant('SHARED.COMMON.BUTTONS.REMOVE'),
              severity: 'danger',
            },
            accept: () => {
              resolve(true); // Allow default deletion
            },
            reject: () => {
              resolve(false); // Cancel deletion
            },
          });
        });
      },
      subHeader: '',
      showEditButton: true,
    };

    this.formFields = [
      createModalListField<AccessoryItem>(
        'accessories',
        this.translate.instant('ADMIN.DEVICES.TYPES.ACCESSORIES.TITLE'),
        this.currentAccessoriesList(),
        {
          layout: 'horizontal',
          labelWidth: '1/3',
          name: 'accessories',
          props: {
            modalConfig: this.accessoryModalConfig,
          },
        },
      ) as FormFieldConfig<unknown>,
    ];
  }

  private getDefaultItem(): AccessoryItem {
    return { key: '', name: '' };
  }

  private getModalFields(item: AccessoryItem | undefined): FormFieldConfig[] {
    return [
      createTextField(
        'key',
        this.translate.instant(
          'ADMIN.DEVICES.TYPES.ACCESSORIES.MODAL.FIELDS.KEY',
        ),
        item?.key ?? '',
        {
          placeholder: this.translate.instant(
            'ADMIN.DEVICES.TYPES.ACCESSORIES.MODAL.FIELDS.KEY_PLACEHOLDER',
          ),
          hint: this.translate.instant(
            'ADMIN.DEVICES.TYPES.ACCESSORIES.MODAL.FIELDS.KEY_HINT',
          ),
          validations: [
            {
              name: 'required',
              validator: Validators.required,
              message: this.translate.instant(
                'SHARED.COMMON.FORMS.SHARED.REQUIRED',
                {
                  field: this.translate.instant(
                    'ADMIN.DEVICES.TYPES.ACCESSORIES.MODAL.FIELDS.KEY',
                  ),
                },
              ),
            },
            {
              name: 'pattern',
              validator: Validators.pattern(/^[a-z0-9_]+$/),
              message: this.translate.instant(
                'SHARED.COMMON.VALIDATION.PATTERN',
              ),
            },
          ],
          props: {
            layout: 'horizontal',
            labelWidth: '1/3',
          },
        },
      ),
      createTextField(
        'name',
        this.translate.instant(
          'ADMIN.DEVICES.TYPES.ACCESSORIES.MODAL.FIELDS.NAME',
        ),
        item?.name ?? '',
        {
          placeholder: this.translate.instant(
            'ADMIN.DEVICES.TYPES.ACCESSORIES.MODAL.FIELDS.NAME_PLACEHOLDER',
          ),
          hint: this.translate.instant(
            'ADMIN.DEVICES.TYPES.ACCESSORIES.MODAL.FIELDS.NAME_HINT',
          ),
          validations: [
            {
              name: 'required',
              validator: Validators.required,
              message: this.translate.instant(
                'SHARED.COMMON.FORMS.SHARED.REQUIRED',
                {
                  field: this.translate.instant(
                    'ADMIN.DEVICES.TYPES.ACCESSORIES.MODAL.FIELDS.NAME',
                  ),
                },
              ),
            },
          ],
          props: {
            layout: 'horizontal',
            labelWidth: '1/3',
          },
        },
      ),
    ];
  }

  protected override transformFormData(
    formData: Record<string, unknown>,
  ): Partial<DeviceTypeResponse> {
    // If accessories field exists and is an array, transform it to object format
    if (
      isDefined(formData['accessories']) &&
      isArray(formData['accessories'])
    ) {
      const accessoriesArray = formData['accessories'] as AccessoryItem[];
      const entity = this.entity();

      // Start with existing accessories to preserve their configuration
      const accessoriesObject: Record<string, DeviceTypeAccessory> = isDefined(
        entity?.accessories,
      )
        ? { ...entity.accessories }
        : {};

      // Update accessories based on the form array
      this.syncAccessoriesToFormResponse(accessoriesArray, accessoriesObject);

      return {
        accessories: accessoriesObject,
      };
    }

    return formData;
  }

  private syncAccessoriesToFormResponse(
    accessoriesArray: AccessoryItem[],
    accessoriesObject: Record<string, DeviceTypeAccessory | null>,
  ) {
    // First, remove accessories that are no longer in the array
    const accessoryKeys = new Set(accessoriesArray.map((a) => a.key));
    for (const existingKey of Object.keys(accessoriesObject)) {
      if (!accessoryKeys.has(existingKey)) {
        accessoriesObject[existingKey] = null;
      }
    }

    // Then, add or preserve accessories from the array
    for (const accessory of accessoriesArray) {
      if (isDefined(accessory.key)) {
        // If accessory already exists, preserve its configuration and just update name
        if (isDefined(accessoriesObject[accessory.key])) {
          accessoriesObject[accessory.key] = {
            ...accessoriesObject[accessory.key],
            name: accessory.name,
          };
        } else {
          // If it's new, create with minimal structure
          accessoriesObject[accessory.key] = {
            name: accessory.name,
            ioCapabilities: {},
            settingsDefinition: null,
            features: {},
          };
        }
      }
    }
  }

  protected override getUpdateMethod() {
    return (
      this.operationRegistry.getOperation('device-types', 'update') ??
      ((id, data) =>
        this.deviceTypesService.updateDeviceType(id, data).pipe(
          tap((response) => {
            this.entityChange.emit(response);
            this.broadcastService.broadcast('entity-updated', {
              entityType: 'device-types',
              operation: 'update',
              entityId: response.id,
              data: response,
            });
          }),
        ))
    );
  }

  ngOnInit(): void {
    this.updateFormFields();
  }
}
