import { Injectable, inject } from '@angular/core';

import { Configuration } from '../../../api/configuration';
import { Contact } from '../../../api';
import { HttpClient } from '@angular/common/http';
import { Observable } from 'rxjs';
import { isDefined } from '../../../shared/utils';

export type ContactStateEnum = 'active' | 'deleted';

export interface ContactOwner {
  id: string;
  name: string;
}

export interface ContactListItem {
  [key: string]: unknown;
  id: string;
  owner: ContactOwner;
  type: Contact.TypeEnum;
  state: ContactStateEnum;
  name: string;
  emailAddress?: string | null;
  phoneMobile?: string | null;
  phoneOffice?: string | null;
  notes?: string | null;
  creationDate: string;
  modifiedDate: string;
}

export interface ContactDetailItem {
  [key: string]: unknown;
  id: string;
  owner: ContactOwner;
  type: Contact.TypeEnum;
  state: ContactStateEnum;
  name: string;
  emailAddress?: string | null;
  phoneMobile?: string | null;
  phoneOffice?: string | null;
  notes?: string | null;
  entity: {
    creationDate: string;
    modifiedDate: string;
  };
}

export interface ContactListResponse {
  count: number;
  items: ContactListItem[];
}

export interface ContactCreateRequest {
  ownerId: string;
  name: string;
  type: Contact.TypeEnum;
  emailAddress?: string;
  phoneMobile?: string;
  phoneOffice?: string;
  notes?: string;
}

export interface ContactUpdateRequest {
  name?: string;
  type?: Contact.TypeEnum;
  state?: ContactStateEnum;
  emailAddress?: string;
  phoneMobile?: string;
  phoneOffice?: string;
  notes?: string;
}

@Injectable({
  providedIn: 'root',
})
export class ContactsService {
  private readonly http = inject(HttpClient);
  private readonly configuration = inject(Configuration);

  private url(id?: string): string {
    const base = `${this.configuration.basePath}/entities/contacts`;
    return isDefined(id) ? `${base}/${encodeURIComponent(id)}` : base;
  }

  private get headers(): Record<string, string> {
    const token = this.configuration.lookupCredential('access_token');
    return isDefined(token) ? { 'x-access-token': token } : {};
  }

  list(
    clientId: string,
    offset = 0,
    limit = 100,
    sort?: string,
    filter?: string,
  ): Observable<ContactListResponse> {
    const params: Record<string, string | number> = { owner: clientId, offset, limit };
    if (isDefined(sort)) params['sort'] = sort;
    if (isDefined(filter)) params['filter'] = filter;

    return this.http.get<ContactListResponse>(this.url(), {
      headers: this.headers,
      params: params as Record<string, string>,
      responseType: 'json' as const,
    });
  }

  create(request: ContactCreateRequest): Observable<ContactDetailItem> {
    return this.http.post<ContactDetailItem>(this.url(), request, {
      headers: this.headers,
      responseType: 'json' as const,
    });
  }

  update(id: string, request: ContactUpdateRequest): Observable<ContactDetailItem> {
    // Contacts API requires PUT (full replacement) — no PATCH endpoint exists
    return this.http.put<ContactDetailItem>(this.url(id), request, {
      headers: this.headers,
      responseType: 'json' as const,
    });
  }

  updateState(id: string, state: ContactStateEnum): Observable<ContactDetailItem> {
    return this.update(id, { state });
  }

  get(id: string, ownerId?: string): Observable<ContactDetailItem> {
    const params: Record<string, string> = {};
    if (isDefined(ownerId)) params['owner'] = ownerId;
    return this.http.get<ContactDetailItem>(this.url(id), {
      headers: this.headers,
      params,
      responseType: 'json' as const,
    });
  }
}
