import {
  Component,
  computed,
  OnInit,
  inject,
  effect,
  input,
} from '@angular/core';
import { DeviceTypeResponse } from '../../../../../api/model/deviceTypeResponse';
import { EntitySectionBaseComponent } from '../../base';
import {
  isNullOrUndefined,
  isDefined,
  isArray,
} from '../../../../../shared/utils';
import {
  createModalListField,
  createTextField,
  createDropdownField,
  createNumberField,
  FormFieldConfig,
  ListFieldModalConfig,
} from '../../../../../shared/models';
import { EntityOperationRegistryService } from '../../../services/entity/entity-operation-registry.service';
import { DeviceTypesService } from '../../../../../api';
import { tap } from 'rxjs';
import { Validators } from '@angular/forms';
import { ToastService } from '../../../../../core/services/toast.service';
import { DynamicFormComponent } from '../../../../../shared/components/forms/dynamic-form/dynamic-form.component';
import { GridComponent } from '../../../../../shared/components/grid/grid.component';
import { ModalListFormComponent } from '../../../../../shared/components/forms/modal-list-form/modal-list-form.component';
import { ConfirmationService } from 'primeng/api';
import { TranslatePipe } from '@ngx-translate/core';

interface SettingFieldItem {
  id: string;
  title: string;
  type: 'combo' | 'number' | 'text' | 'boolean';
  values?: { key: string; value: string }[];
  unit?: string;
  min?: number;
  max?: number;
  width?: number;
  defaultValue?: unknown;
  placeholder?: string;
  description?: string;
  required?: boolean;
}

@Component({
  selector: 'app-device-types-settings-section',
  imports: [DynamicFormComponent, GridComponent, TranslatePipe],
  templateUrl: './device-types-settings-section.component.html',
  styleUrl: './device-types-settings-section.component.scss',
})
export class DeviceTypesSettingsSectionComponent
  extends EntitySectionBaseComponent<DeviceTypeResponse>
  implements OnInit
{
  private readonly operationRegistry = inject(EntityOperationRegistryService);
  private readonly deviceTypesService = inject(DeviceTypesService);
  private readonly toastService = inject(ToastService);
  private readonly confirmationService = inject(ConfirmationService);

  constructor() {
    super();
    this.columns = [
      { field: 'key', header: '' },
      { field: 'value', header: '' },
    ];

    effect(() => {
      const entity = this.entity();
      if (entity && !this.createMode()) {
        this.updateFormFields();
      }
    });
  }

  override entity = input<DeviceTypeResponse | null>(null);

  settingFieldModalConfig: ListFieldModalConfig<SettingFieldItem> | undefined;

  // Display settings as a simple grid with comma-separated list
  readonly settingsDisplay = computed(() => {
    const deviceType = this.entity();
    const settingsDefinition = deviceType?.settingsDefinition;
    this.languageService.currentLanguage();
    const title = this.translate.instant('ADMIN.DEVICES.TYPES.SETTINGS.TITLE');
    const empty = this.translate.instant('ADMIN.DEVICES.TYPES.SETTINGS.EMPTY');

    if (
      isNullOrUndefined(settingsDefinition) ||
      settingsDefinition.trim() === ''
    ) {
      return [{ key: title, value: empty }];
    }

    try {
      const parsed = JSON.parse(settingsDefinition);
      const fields = this.extractFieldsFromDefinition(parsed);

      if (fields.length === 0) {
        return [{ key: title, value: empty }];
      }

      const fieldNames = fields.map((f) => f.title || f.id).join(', ');
      return [
        { key: title, value: `${fields.length} field(s): ${fieldNames}` },
      ];
    } catch {
      return [
        {
          key: title,
          value: this.translate.instant('ADMIN.DEVICES.TYPES.SETTINGS.INVALID'),
        },
      ];
    }
  });

  // Get currently configured settings fields as list for modal
  readonly currentSettingsList = computed(() => {
    const deviceType = this.entity();
    const settingsDefinition = deviceType?.settingsDefinition;

    if (
      isNullOrUndefined(settingsDefinition) ||
      settingsDefinition.trim() === ''
    ) {
      return [];
    }

    try {
      const parsed = JSON.parse(settingsDefinition);
      return this.extractFieldsFromDefinition(parsed);
    } catch {
      return [];
    }
  });

  private extractFieldsFromDefinition(
    parsed: Record<string, unknown>,
  ): SettingFieldItem[] {
    const fields: SettingFieldItem[] = [];

    if (isDefined(parsed['groups']) && Array.isArray(parsed['groups'])) {
      for (const group of parsed['groups']) {
        if (isDefined(group['fields']) && Array.isArray(group['fields'])) {
          for (const field of group['fields']) {
            fields.push(field as SettingFieldItem);
          }
        }
      }
    }

    return fields;
  }

  protected override updateFormFields(): void {
    this.settingFieldModalConfig = {
      modalComponent: ModalListFormComponent,
      modalTitle: this.translate.instant(
        'ADMIN.DEVICES.TYPES.SETTINGS.MODAL.TITLE',
      ),
      defaultItemProvider: () => this.getDefaultItem(),
      listItemFormatter: (item: SettingFieldItem) => ({
        id: item.id,
        title: item.title || item.id,
        display: `${item.title} (${item.type})`,
        icon: 'pi pi-sliders-h',
      }),
      modalFields: (item: SettingFieldItem | undefined): FormFieldConfig[] => {
        return this.getModalFields(item);
      },
      onSubmit: async (item: SettingFieldItem) => {
        // Validate the item
        if (!item.id?.trim() || !item.title?.trim()) {
          return false;
        }

        // Check for duplicates
        const existing = this.currentSettingsList().find(
          (existing) => existing.id === item.id,
        );
        if (existing) {
          this.toastService.showError(
            this.translate.instant(
              'ADMIN.DEVICES.TYPES.SETTINGS.ERRORS.DUPLICATE_TITLE',
            ),
            this.translate.instant(
              'ADMIN.DEVICES.TYPES.SETTINGS.ERRORS.DUPLICATE_MESSAGE',
            ),
          );
          return false;
        }

        return true;
      },
      onDeleteItem: async (item: SettingFieldItem) => {
        return new Promise<boolean>((resolve) => {
          this.confirmationService.confirm({
            header: this.translate.instant('SHARED.COMMON.DIALOG.CONFIRMATION'),
            message: this.translate.instant(
              'ADMIN.DEVICES.TYPES.SETTINGS.CONFIRM.REMOVE',
              { name: item.title },
            ),
            closable: true,
            closeOnEscape: true,
            icon: 'pi pi-exclamation-triangle',
            rejectButtonProps: {
              label: this.translate.instant('SHARED.COMMON.BUTTONS.CANCEL'),
              severity: 'secondary',
              outlined: true,
            },
            acceptButtonProps: {
              label: this.translate.instant('SHARED.COMMON.BUTTONS.REMOVE'),
              severity: 'danger',
            },
            accept: () => {
              resolve(true);
            },
            reject: () => {
              resolve(false);
            },
          });
        });
      },
      subHeader: '',
      showEditButton: false,
    };

    this.formFields = [
      createModalListField<SettingFieldItem>(
        'settings',
        this.translate.instant('ADMIN.DEVICES.TYPES.SETTINGS.TITLE'),
        this.currentSettingsList(),
        {
          layout: 'horizontal',
          labelWidth: '1/3',
          name: 'settings',
          props: {
            modalConfig: this.settingFieldModalConfig,
          },
        },
      ) as FormFieldConfig<unknown>,
    ];
  }

  private getDefaultItem(): SettingFieldItem {
    return {
      id: '',
      title: '',
      type: 'text',
      values: [],
      unit: '',
      min: undefined,
      max: undefined,
      width: undefined,
      defaultValue: '',
      placeholder: '',
      description: '',
      required: false,
    };
  }

  private getModalFields(
    item: SettingFieldItem | undefined,
  ): FormFieldConfig[] {
    return [
      createTextField(
        'id',
        this.translate.instant('ADMIN.DEVICES.TYPES.SETTINGS.MODAL.FIELDS.ID'),
        item?.id ?? '',
        {
          placeholder: this.translate.instant(
            'ADMIN.DEVICES.TYPES.SETTINGS.MODAL.FIELDS.ID_PLACEHOLDER',
          ),
          hint: this.translate.instant(
            'ADMIN.DEVICES.TYPES.SETTINGS.MODAL.FIELDS.ID_HINT',
          ),
          validations: [
            {
              name: 'required',
              validator: Validators.required,
              message: this.translate.instant(
                'SHARED.COMMON.FORMS.SHARED.REQUIRED',
                {
                  field: this.translate.instant(
                    'ADMIN.DEVICES.TYPES.SETTINGS.MODAL.FIELDS.ID',
                  ),
                },
              ),
            },
            {
              name: 'pattern',
              validator: Validators.pattern(/^\w+$/),
              message: this.translate.instant(
                'SHARED.COMMON.VALIDATION.PATTERN',
              ),
            },
          ],
          props: {
            layout: 'horizontal',
            labelWidth: '1/3',
          },
        },
      ),
      createTextField(
        'title',
        this.translate.instant(
          'ADMIN.DEVICES.TYPES.SETTINGS.MODAL.FIELDS.TITLE_LABEL',
        ),
        item?.title ?? '',
        {
          placeholder: this.translate.instant(
            'ADMIN.DEVICES.TYPES.SETTINGS.MODAL.FIELDS.TITLE_PLACEHOLDER',
          ),
          hint: this.translate.instant(
            'ADMIN.DEVICES.TYPES.SETTINGS.MODAL.FIELDS.TITLE_HINT',
          ),
          validations: [
            {
              name: 'required',
              validator: Validators.required,
              message: this.translate.instant(
                'SHARED.COMMON.FORMS.SHARED.REQUIRED',
                {
                  field: this.translate.instant(
                    'ADMIN.DEVICES.TYPES.SETTINGS.MODAL.FIELDS.TITLE_LABEL',
                  ),
                },
              ),
            },
          ],
          props: {
            layout: 'horizontal',
            labelWidth: '1/3',
          },
        },
      ),
      createDropdownField(
        'type',
        this.translate.instant(
          'ADMIN.DEVICES.TYPES.SETTINGS.MODAL.FIELDS.TYPE',
        ),
        [
          {
            label: this.translate.instant(
              'ADMIN.DEVICES.TYPES.SETTINGS.MODAL.TYPES.TEXT',
            ),
            value: 'text',
          },
          {
            label: this.translate.instant(
              'ADMIN.DEVICES.TYPES.SETTINGS.MODAL.TYPES.NUMBER',
            ),
            value: 'number',
          },
          {
            label: this.translate.instant(
              'ADMIN.DEVICES.TYPES.SETTINGS.MODAL.TYPES.COMBO',
            ),
            value: 'combo',
          },
          {
            label: this.translate.instant(
              'ADMIN.DEVICES.TYPES.SETTINGS.MODAL.TYPES.BOOLEAN',
            ),
            value: 'boolean',
          },
        ],
        item?.type ?? 'text',
        {
          hint: this.translate.instant(
            'ADMIN.DEVICES.TYPES.SETTINGS.MODAL.FIELDS.TYPE_HINT',
          ),
          validations: [
            {
              name: 'required',
              validator: Validators.required,
              message: this.translate.instant(
                'SHARED.COMMON.FORMS.SHARED.REQUIRED',
                {
                  field: this.translate.instant(
                    'ADMIN.DEVICES.TYPES.SETTINGS.MODAL.FIELDS.TYPE',
                  ),
                },
              ),
            },
          ],
          props: {
            layout: 'horizontal',
            labelWidth: '1/3',
          },
        },
      ),
      createTextField(
        'unit',
        this.translate.instant(
          'ADMIN.DEVICES.TYPES.SETTINGS.MODAL.FIELDS.UNIT',
        ),
        item?.unit ?? '',
        {
          placeholder: this.translate.instant(
            'ADMIN.DEVICES.TYPES.SETTINGS.MODAL.FIELDS.UNIT_PLACEHOLDER',
          ),
          hint: this.translate.instant(
            'ADMIN.DEVICES.TYPES.SETTINGS.MODAL.FIELDS.UNIT_HINT',
          ),
          props: {
            layout: 'horizontal',
            labelWidth: '1/3',
          },
        },
      ),
      createNumberField(
        'min',
        this.translate.instant('ADMIN.DEVICES.TYPES.SETTINGS.MODAL.FIELDS.MIN'),
        item?.min,
        {
          placeholder: this.translate.instant(
            'ADMIN.DEVICES.TYPES.SETTINGS.MODAL.FIELDS.MIN_PLACEHOLDER',
          ),
          hint: this.translate.instant(
            'ADMIN.DEVICES.TYPES.SETTINGS.MODAL.FIELDS.MIN_HINT',
          ),
          props: {
            layout: 'horizontal',
            labelWidth: '1/3',
          },
        },
      ),
      createNumberField(
        'max',
        this.translate.instant('ADMIN.DEVICES.TYPES.SETTINGS.MODAL.FIELDS.MAX'),
        item?.max,
        {
          placeholder: this.translate.instant(
            'ADMIN.DEVICES.TYPES.SETTINGS.MODAL.FIELDS.MAX_PLACEHOLDER',
          ),
          hint: this.translate.instant(
            'ADMIN.DEVICES.TYPES.SETTINGS.MODAL.FIELDS.MAX_HINT',
          ),
          props: {
            layout: 'horizontal',
            labelWidth: '1/3',
          },
        },
      ),
      createNumberField(
        'width',
        this.translate.instant(
          'ADMIN.DEVICES.TYPES.SETTINGS.MODAL.FIELDS.WIDTH',
        ),
        item?.width,
        {
          placeholder: this.translate.instant(
            'ADMIN.DEVICES.TYPES.SETTINGS.MODAL.FIELDS.WIDTH_PLACEHOLDER',
          ),
          hint: this.translate.instant(
            'ADMIN.DEVICES.TYPES.SETTINGS.MODAL.FIELDS.WIDTH_HINT',
          ),
          props: {
            layout: 'horizontal',
            labelWidth: '1/3',
          },
        },
      ),
      createTextField(
        'defaultValue',
        this.translate.instant(
          'ADMIN.DEVICES.TYPES.SETTINGS.MODAL.FIELDS.DEFAULT',
        ),
        isDefined(item?.defaultValue) ? String(item?.defaultValue) : '',
        {
          placeholder: this.translate.instant(
            'ADMIN.DEVICES.TYPES.SETTINGS.MODAL.FIELDS.DEFAULT_PLACEHOLDER',
          ),
          hint: this.translate.instant(
            'ADMIN.DEVICES.TYPES.SETTINGS.MODAL.FIELDS.DEFAULT_HINT',
          ),
          props: {
            layout: 'horizontal',
            labelWidth: '1/3',
          },
        },
      ),
      createTextField(
        'placeholder',
        this.translate.instant(
          'ADMIN.DEVICES.TYPES.SETTINGS.MODAL.FIELDS.PLACEHOLDER_LABEL',
        ),
        item?.placeholder ?? '',
        {
          placeholder: this.translate.instant(
            'ADMIN.DEVICES.TYPES.SETTINGS.MODAL.FIELDS.PLACEHOLDER_PLACEHOLDER',
          ),
          hint: this.translate.instant(
            'ADMIN.DEVICES.TYPES.SETTINGS.MODAL.FIELDS.PLACEHOLDER_HINT',
          ),
          props: {
            layout: 'horizontal',
            labelWidth: '1/3',
          },
        },
      ),
      createTextField(
        'description',
        this.translate.instant(
          'ADMIN.DEVICES.TYPES.SETTINGS.MODAL.FIELDS.DESCRIPTION',
        ),
        item?.description ?? '',
        {
          placeholder: this.translate.instant(
            'ADMIN.DEVICES.TYPES.SETTINGS.MODAL.FIELDS.DESCRIPTION_PLACEHOLDER',
          ),
          hint: this.translate.instant(
            'ADMIN.DEVICES.TYPES.SETTINGS.MODAL.FIELDS.DESCRIPTION_HINT',
          ),
          props: {
            layout: 'horizontal',
            labelWidth: '1/3',
          },
        },
      ),
    ];
  }

  protected override transformFormData(
    formData: Record<string, unknown>,
  ): Partial<DeviceTypeResponse> {
    if (isDefined(formData['settings']) && isArray(formData['settings'])) {
      const settingsArray = formData['settings'] as SettingFieldItem[];

      // Create the settings definition JSON structure
      const settingsDefinition = {
        groups: [
          {
            fields: settingsArray,
          },
        ],
      };

      return {
        settingsDefinition: JSON.stringify(settingsDefinition),
      };
    }

    return formData;
  }

  protected override getUpdateMethod() {
    return (
      this.operationRegistry.getOperation('device-types', 'update') ??
      ((id, data) =>
        this.deviceTypesService.updateDeviceType(id, data).pipe(
          tap((response) => {
            this.entityChange.emit(response);
            this.broadcastService.broadcast('entity-updated', {
              entityType: 'device-types',
              operation: 'update',
              entityId: response.id,
              data: response,
            });
          }),
        ))
    );
  }

  ngOnInit(): void {
    this.updateFormFields();
  }
}
