import { CommonModule } from '@angular/common';
import {
  Component,
  computed,
  effect,
  inject,
  input,
  untracked,
} from '@angular/core';
import { Validators } from '@angular/forms';

import { ButtonModule } from 'primeng/button';
import { v4 as uuidv4 } from 'uuid';

import {
  RoadProfileListItem,
  RoadProfileCreateRequest,
  EntitiesService,
  RoadSpeedModifierEntry,
  RoadProfileResponse,
} from '../../../../../api';
import { DynamicFormComponent } from '../../../../../shared/components/forms/dynamic-form/dynamic-form.component';
import { GridComponent } from '../../../../../shared/components/grid/grid.component';
import {
  ActorNodeData,
  createDropdownField,
  createEventFilterField,
  createModalListField,
  createNumberField,
  createTextField,
  EventNodeData,
  FilterCondition,
  FormFieldConfig,
  ListFieldModalConfig,
  MeasurementUnitType,
  TargetNodeData,
  TreeSelectNode,
} from '../../../../../shared/models';
import { isDefined } from '../../../../../shared/utils';
import { EntitySectionBaseComponent } from '../../base';
import { ModalListFormComponent } from '../../../../../shared/components/forms/modal-list-form/modal-list-form.component';
import { MessageModule } from 'primeng/message';
import { MeasurementUnitsService } from '../../../../../shared/services/measurement-units/measurement-units.service';
import { faRoad } from '@fortawesome/free-solid-svg-icons';
import { FontAwesomeModule } from '@fortawesome/angular-fontawesome';
import { GeoFilterService } from '../../../../../shared/services/geo-filter.service';
import { Observable } from 'rxjs';
import { EntityOperationRegistryService } from '../../../services/entity/entity-operation-registry.service';
import { TranslatePipe } from '@ngx-translate/core';

type FormValue = string | number | object | null | undefined;
@Component({
  selector: 'app-road-profile-details-section',
  imports: [
    CommonModule,
    ButtonModule,
    GridComponent,
    DynamicFormComponent,
    MessageModule,
    FontAwesomeModule,
    TranslatePipe,
  ],
  templateUrl: './road-profile-details-section.component.html',
  styleUrl: './road-profile-details-section.component.scss',
})
export class RoadProfileDetailsSectionComponent extends EntitySectionBaseComponent<
  RoadProfileListItem | Partial<RoadProfileCreateRequest>
> {
  readonly ownerId = input<string | null>(null);
  private readonly entitiesService = inject(EntitiesService);
  private readonly measurementUnitsService = inject(MeasurementUnitsService);
  private readonly filterService = inject(GeoFilterService);
  private readonly operationRegistry = inject(EntityOperationRegistryService);

  readonly roadProfileDetails = computed(() => {
    const roadProfileDetails = this.entity();
    if (!isDefined(roadProfileDetails)) return [];

    return [
      {
        key: this.translate.instant('ADMIN.PROFILES.ROAD.DETAILS.FIELDS.NAME'),
        value: roadProfileDetails.name,
      },
      {
        key: this.translate.instant('ADMIN.PROFILES.ROAD.DETAILS.FIELDS.ITEMS'),
        value:
          roadProfileDetails.speedModifiers &&
          roadProfileDetails.speedModifiers.length > 0
            ? roadProfileDetails.speedModifiers
                ?.map((item) => `${item.name} (${item.speed}${item.unit})`)
                .join(', ')
            : this.translate.instant('SHARED.COMMON.NONE'),
      },
    ];
  });
  roadProfileSpeedModifiersModalConfig:
    | ListFieldModalConfig<RoadSpeedModifierEntry>
    | undefined;

  faIconRoad = faRoad;

  constructor() {
    super();

    // Setup initial columns
    this.columns = [
      { field: 'key', header: '', transform: 'uppercase' },
      { field: 'value', header: '' },
    ];

    effect(() => {
      const entity = this.entity();
      if (isDefined(entity) && !this.createMode()) {
        untracked(() => {
          this.updateFormFields();
        });
      }
    });
  }

  protected override updateFormFields(): void {
    const roadProfile = this.entity();

    this.roadProfileSpeedModifiersModalConfig = {
      modalComponent: ModalListFormComponent,
      modalTitle: this.translate.instant(
        'ADMIN.PROFILES.ROAD.DETAILS.MODALS.MODIFIER.TITLE',
      ),
      subHeader: this.translate.instant(
        'ADMIN.PROFILES.ROAD.DETAILS.MODALS.MODIFIER.DESCRIPTION',
      ),
      defaultItemProvider: () => ({
        id: uuidv4(),
        name: '',
        filter: undefined,
        speed: 0,
        unit: RoadSpeedModifierEntry.UnitEnum.Kmh,
      }),
      listItemFormatter: (item: RoadSpeedModifierEntry) => {
        return this.stateItemToListItem(item);
      },
      modalFields: (
        item: RoadSpeedModifierEntry | undefined,
      ): FormFieldConfig[] => {
        return [
          createTextField('id', 'ID', item?.id, {
            name: 'id',
            hidden: true,
          }),
          createTextField(
            'name',
            this.translate.instant('ADMIN.PROFILES.ROAD.DETAILS.FIELDS.NAME'),
            item?.name,
            {
              name: 'name',
              validations: [
                {
                  name: 'required',
                  validator: Validators.required,
                  message: this.translate.instant(
                    'SHARED.COMMON.FORMS.SHARED.REQUIRED',
                    {
                      field: this.translate.instant(
                        'ADMIN.PROFILES.ROAD.DETAILS.FIELDS.NAME',
                      ),
                    },
                  ),
                },
              ],
            },
          ),
          createEventFilterField(
            'filter',
            this.translate.instant('ADMIN.PROFILES.ROAD.DETAILS.FIELDS.FILTER'),
            item?.filter,
            [],
            {
              name: 'filter',
              required: true,
              validations: [
                {
                  name: 'required',
                  validator: Validators.required,
                  message: this.translate.instant(
                    'SHARED.COMMON.FORMS.SHARED.REQUIRED',
                    {
                      field: this.translate.instant(
                        'ADMIN.PROFILES.ROAD.DETAILS.FIELDS.FILTER',
                      ),
                    },
                  ),
                },
              ],
              props: {
                filterService: this.filterService,
                requireActorBeforeAction: false,
              },
            },
          ),
          createNumberField(
            'speed',
            this.translate.instant('ADMIN.PROFILES.ROAD.DETAILS.FIELDS.SPEED'),
            item?.speed,
            {
              name: 'speed',
              validations: [
                {
                  name: 'required',
                  validator: Validators.required,
                  message: this.translate.instant(
                    'SHARED.COMMON.FORMS.SHARED.REQUIRED',
                    {
                      field: this.translate.instant(
                        'ADMIN.PROFILES.ROAD.DETAILS.FIELDS.SPEED',
                      ),
                    },
                  ),
                },
                {
                  name: 'min',
                  validator: Validators.min(0),
                  message: this.translate.instant(
                    'SHARED.COMMON.FORMS.NUMBER.MIN',
                    {
                      field: this.translate.instant(
                        'ADMIN.PROFILES.ROAD.DETAILS.FIELDS.SPEED',
                      ),
                      min: 0,
                    },
                  ),
                },
                {
                  name: 'max',
                  validator: Validators.max(1000),
                  message: this.translate.instant(
                    'SHARED.COMMON.FORMS.NUMBER.MAX',
                    {
                      field: this.translate.instant(
                        'ADMIN.PROFILES.ROAD.DETAILS.FIELDS.SPEED',
                      ),
                      max: 1000,
                    },
                  ),
                },
              ],
              layout: 'horizontal',
              labelWidth: '1/3',
              props: {
                suffix: this.measurementUnitsService.unit(
                  MeasurementUnitType.SPEED,
                ),
              },
            },
          ),
          createDropdownField(
            'unit',
            this.translate.instant('ADMIN.PROFILES.ROAD.DETAILS.FIELDS.UNIT'),
            [
              { value: 'kmh', label: 'km/h' },
              { value: 'mph', label: 'mph' },
            ],
            item?.unit,
            {
              name: 'unit',
              validations: [
                {
                  name: 'required',
                  validator: Validators.required,
                  message: this.translate.instant(
                    'SHARED.COMMON.FORMS.SHARED.REQUIRED',
                    {
                      field: this.translate.instant(
                        'ADMIN.PROFILES.ROAD.DETAILS.FIELDS.UNIT',
                      ),
                    },
                  ),
                },
              ],
            },
          ),
        ];
      },
    };
    this.formFields = [
      createTextField(
        'name',
        this.translate.instant('ADMIN.PROFILES.ROAD.DETAILS.FIELDS.NAME'),
        roadProfile?.name,
        {
          name: 'name',
          validations: [
            {
              name: 'required',
              validator: Validators.required,
              message: this.translate.instant(
                'SHARED.COMMON.FORMS.SHARED.REQUIRED',
                {
                  field: this.translate.instant(
                    'ADMIN.PROFILES.ROAD.DETAILS.FIELDS.NAME',
                  ),
                },
              ),
            },
          ],
        },
      ),
    ];

    if (!this.createMode()) {
      this.formFields.push(
        createModalListField<RoadSpeedModifierEntry>(
          'speedModifiers',
          this.translate.instant('ADMIN.PROFILES.ROAD.DETAILS.FIELDS.ITEMS'),
          roadProfile?.speedModifiers ?? [],
          {
            layout: 'horizontal',
            labelWidth: '1/3',
            name: 'speedModifiers',
            props: {
              modalConfig: this.roadProfileSpeedModifiersModalConfig,
            },
          },
        ) as FormFieldConfig<unknown>,
      );
    }
  }

  override getUpdateMethod(): (
    id: string,
    data: Partial<RoadProfileResponse | RoadProfileCreateRequest>,
  ) => Observable<RoadProfileResponse> {
    return (
      this.operationRegistry.getOperation<
        RoadProfileResponse | RoadProfileCreateRequest,
        RoadProfileCreateRequest,
        RoadProfileResponse,
        'update'
      >('road-profile', 'update') ??
      ((id, data) => this.entitiesService.updateRoadProfile(id, data))
    );
  }

  stateItemToListItem(item: RoadSpeedModifierEntry) {
    return {
      id: item.id,
      title: `${item.name} (${item.speed}${item.unit})`,
      display: this.filterService.getEventFilterText(item.filter),
      icon: 'pi pi-gauge',
    };
  }

  protected override onFormValueChange(
    formData: Record<string, FormValue>,
  ): void {
    const transformedData = this.transformFormData(formData);

    this.formValueChange.emit(transformedData);
  }

  protected override transformFormData(
    formData: Record<string, unknown>,
  ): Record<string, string | number | object | null | undefined> {
    const transformedData = { ...formData };

    if (
      isDefined(transformedData?.['speedModifiers']) &&
      Array.isArray(transformedData['speedModifiers'])
    ) {
      transformedData['speedModifiers'].forEach((element) => {
        const filter = element.filter as {
          actor: TreeSelectNode<ActorNodeData> | undefined;
          action: TreeSelectNode<EventNodeData> | undefined;
          target: TreeSelectNode<TargetNodeData> | undefined;
          conditions: FilterCondition[];
        };
        element.filter = {
          ...filter,
          actor: filter?.['actor']?.['data'] ?? filter?.['actor'],
          action: filter?.['action']?.['data'] ?? filter?.['action'],
          target: filter?.['target']?.['data'] ?? filter?.['target'],
          conditions: filter?.['conditions']?.map((condition) => {
            const { id: _, ...rest } = condition;
            return rest;
          }),
        };
      });
    }

    return transformedData as Record<
      string,
      string | number | object | null | undefined
    >;
  }
}
