import { CommonModule } from '@angular/common';
import {
  Component,
  computed,
  effect,
  inject,
  input,
  signal,
} from '@angular/core';
import { Validators } from '@angular/forms';

import { FontAwesomeModule } from '@fortawesome/angular-fontawesome';
import { faEnvelopeOpenText } from '@fortawesome/free-solid-svg-icons';
import { ButtonModule } from 'primeng/button';
import { InputTextModule } from 'primeng/inputtext';
import { TranslatePipe } from '@ngx-translate/core';
import { Observable } from 'rxjs';

import {
  CompanyGroupResponse,
  CompanyGroupCreateRequest,
  AccountsService,
} from '../../../../../api';
import { DEFAULT_SYSTEM_ID } from '../../../../../core/models';
import { DynamicFormComponent } from '../../../../../shared/components/forms/dynamic-form/dynamic-form.component';
import { GridComponent } from '../../../../../shared/components/grid/grid.component';
import {
  AssetGroupingItem,
  createTextAreaField,
  createTextField,
} from '../../../../../shared/models';
import { EntityOperationRegistryService } from '../../../services/entity/entity-operation-registry.service';
import { EntitySectionBaseComponent } from '../../base';
import { isDefined } from '../../../../../shared/utils';

type CompanyGroupEntity = CompanyGroupResponse | CompanyGroupCreateRequest;

@Component({
  selector: 'app-company-group-email-template-section',
  imports: [
    CommonModule,
    ButtonModule,
    InputTextModule,
    GridComponent,
    DynamicFormComponent,
    FontAwesomeModule,
    TranslatePipe,
  ],
  templateUrl: './company-group-email-template-section.component.html',
  styleUrl: './company-group-email-template-section.component.scss',
})
export class CompanyGroupEmailTemplateSectionComponent extends EntitySectionBaseComponent<CompanyGroupEntity> {
  readonly ownerId = input<string | null>(null);
  readonly emailType = input.required<
    'user_invite' | 'user_reset' | 'forgot_password'
  >();
  private readonly operationRegistry = inject(EntityOperationRegistryService);
  private readonly accountsService = inject(AccountsService);

  get defaults() {
    const defaultName = this.translate.instant(
      'ADMIN.COMPANY_GROUPS.EMAIL_CUSTOMIZATION.DEFAULT_TEMPLATE_NAME',
    );
    return {
      user_invite: {
        title: this.translate.instant(
          'ADMIN.COMPANY_GROUPS.EMAIL_CUSTOMIZATION.USER_INVITE.TITLE',
        ),
        description: this.translate.instant(
          'ADMIN.COMPANY_GROUPS.EMAIL_CUSTOMIZATION.USER_INVITE.DESCRIPTION',
        ),
        template: { id: DEFAULT_SYSTEM_ID, name: defaultName },
        subject: this.translate.instant(
          'ADMIN.COMPANY_GROUPS.EMAIL_CUSTOMIZATION.USER_INVITE.SUBJECT',
        ),
        body: this.translate.instant(
          'ADMIN.COMPANY_GROUPS.EMAIL_CUSTOMIZATION.USER_INVITE.BODY',
        ),
      },
      forgot_password: {
        title: this.translate.instant(
          'ADMIN.COMPANY_GROUPS.EMAIL_CUSTOMIZATION.FORGOT_PASSWORD.TITLE',
        ),
        description: this.translate.instant(
          'ADMIN.COMPANY_GROUPS.EMAIL_CUSTOMIZATION.FORGOT_PASSWORD.DESCRIPTION',
        ),
        template: { id: DEFAULT_SYSTEM_ID, name: defaultName },
        subject: this.translate.instant(
          'ADMIN.COMPANY_GROUPS.EMAIL_CUSTOMIZATION.FORGOT_PASSWORD.SUBJECT',
        ),
        body: this.translate.instant(
          'ADMIN.COMPANY_GROUPS.EMAIL_CUSTOMIZATION.FORGOT_PASSWORD.BODY',
        ),
      },
      user_reset: {
        title: this.translate.instant(
          'ADMIN.COMPANY_GROUPS.EMAIL_CUSTOMIZATION.USER_RESET.TITLE',
        ),
        description: this.translate.instant(
          'ADMIN.COMPANY_GROUPS.EMAIL_CUSTOMIZATION.USER_RESET.DESCRIPTION',
        ),
        template: { id: DEFAULT_SYSTEM_ID, name: defaultName },
        subject: this.translate.instant(
          'ADMIN.COMPANY_GROUPS.EMAIL_CUSTOMIZATION.USER_RESET.SUBJECT',
        ),
        body: this.translate.instant(
          'ADMIN.COMPANY_GROUPS.EMAIL_CUSTOMIZATION.USER_RESET.BODY',
        ),
      },
    };
  }

  readonly companyGroupDetails = computed(() => {
    const companyGroupDetails = this.entity();
    this.languageService.currentLanguage();
    const defaultTemplate = this.defaults[this.emailType()];
    if (!isDefined(companyGroupDetails)) return [];

    return [
      {
        key: this.translate.instant(
          'ADMIN.COMPANY_GROUPS.EMAIL_CUSTOMIZATION.FIELDS.SUBJECT',
        ),
        value:
          companyGroupDetails?.email?.templates?.[this.emailType()]?.subject ??
          defaultTemplate.subject,
      },
      {
        key: this.translate.instant(
          'ADMIN.COMPANY_GROUPS.EMAIL_CUSTOMIZATION.FIELDS.BODY',
        ),
        value:
          companyGroupDetails?.email?.templates?.[this.emailType()]?.body ??
          defaultTemplate.body,
      },
    ];
  });
  title = signal<string>('');
  description = signal<string>('');

  faEnvelopeOpenText = faEnvelopeOpenText;
  companyGroupGroups: AssetGroupingItem[] = [];

  constructor() {
    super();

    this.columns = [
      { field: 'key', header: '', transform: 'uppercase' },
      {
        field: 'value',
        header: '',
        transform: 'whitespace-pre-wrap break-words',
      },
    ];

    effect(() => {
      this.languageService.currentLanguage();
      this.title.set(this.defaults[this.emailType()].title);
      this.description.set(this.defaults[this.emailType()].description);
    });
  }

  protected override updateFormFields(): void {
    const companyGroup = this.entity();

    this.formFields = [
      createTextField(
        'subject',
        this.translate.instant(
          'ADMIN.COMPANY_GROUPS.EMAIL_CUSTOMIZATION.FIELDS.SUBJECT',
        ),
        companyGroup?.email?.templates?.[this.emailType()]?.subject ??
          this.defaults[this.emailType()].subject,
        {
          name: 'subject',
          validations: [
            {
              name: 'required',
              validator: Validators.required,
              message: this.translate.instant(
                'SHARED.COMMON.FORMS.SHARED.REQUIRED',
                {
                  field: this.translate.instant(
                    'ADMIN.COMPANY_GROUPS.EMAIL_CUSTOMIZATION.FIELDS.SUBJECT',
                  ),
                },
              ),
            },
          ],
        },
      ),
      createTextAreaField(
        'body',
        this.translate.instant(
          'ADMIN.COMPANY_GROUPS.EMAIL_CUSTOMIZATION.FIELDS.BODY',
        ),
        companyGroup?.email?.templates?.[this.emailType()]?.body ??
          this.defaults[this.emailType()].body,
        {
          name: 'body',
          validations: [
            {
              name: 'required',
              validator: Validators.required,
              message: this.translate.instant(
                'SHARED.COMMON.FORMS.SHARED.REQUIRED',
                {
                  field: this.translate.instant(
                    'ADMIN.COMPANY_GROUPS.EMAIL_CUSTOMIZATION.FIELDS.BODY',
                  ),
                },
              ),
            },
          ],
        },
      ),
    ];
  }

  override getUpdateMethod(): (
    id: string,
    data: Partial<CompanyGroupEntity>,
  ) => Observable<CompanyGroupResponse> {
    return (
      this.operationRegistry.getOperation<
        CompanyGroupEntity,
        CompanyGroupCreateRequest,
        CompanyGroupResponse,
        'update'
      >('company-group', 'update') ??
      ((id, data) => this.accountsService.updateCompanyGroup(id, data))
    );
  }
}
