import {
  AfterViewInit,
  Component,
  computed,
  effect,
  inject,
  signal,
  untracked,
} from '@angular/core';
import { Observable } from 'rxjs';
import { CommonModule } from '@angular/common';
import { takeUntilDestroyed } from '@angular/core/rxjs-interop';
import { FormsModule, ReactiveFormsModule } from '@angular/forms';

import { ButtonModule } from 'primeng/button';
import { MultiSelectModule } from 'primeng/multiselect';
import { DividerModule } from 'primeng/divider';
import { PanelModule } from 'primeng/panel';
import { TooltipModule } from 'primeng/tooltip';
import { DialogService, DynamicDialogRef } from 'primeng/dynamicdialog';
import { TranslatePipe } from '@ngx-translate/core';

import { AssetResponse, AssetUpdateRequest, Contact, EntitiesService } from '../../../../../api';
import { UtilityService } from '../../../../../core/services/utility.service';
import { ContactsCacheService } from '../../../../../core/services/contacts-cache.service';
import { ApiSchemaService } from '../../../../../core/services/api-schema.service';
import { FormAction } from '../../../../../shared/models';
import { isDefined, isNullOrUndefined } from '../../../../../shared/utils';
import { EntitySectionBaseComponent } from '../../base';
import { ContactCreateWizardComponent } from '../../../components/contacts/contact-create-wizard/contact-create-wizard.component';
import { ContactDetailItem } from '../../../services/contacts.service';
import { AssetResponseWithContactIds, AssetUpdateRequestWithContactIds } from '../../../models';
import { AdminNavigationService } from '../../../services/navigation/admin-navigation.service';

@Component({
  selector: 'app-asset-contacts-section',
  imports: [
    CommonModule,
    FormsModule,
    ReactiveFormsModule,
    ButtonModule,
    MultiSelectModule,
    DividerModule,
    PanelModule,
    TooltipModule,
    TranslatePipe,
  ],
  providers: [DialogService],
  templateUrl: './asset-contacts-section.component.html',
  styleUrl: './asset-contacts-section.component.scss',
})
export class AssetContactsSectionComponent
  extends EntitySectionBaseComponent<AssetResponse>
  implements AfterViewInit
{
  private readonly entitiesService = inject(EntitiesService);
  private readonly dialogService = inject(DialogService);
  private readonly apiSchemaService = inject(ApiSchemaService);
  private readonly adminNavigation = inject(AdminNavigationService);
  protected readonly contactsCache = inject(ContactsCacheService);
  readonly utilityService = inject(UtilityService);

  private dialogRef: DynamicDialogRef | undefined;

  selectedContactIds = signal<string[]>([]);
  readonly selectedContacts = computed(() => {
    const ids = new Set(this.selectedContactIds());
    return this.contactsCache.contacts().filter((c) => ids.has(c.id));
  });
  readonly availableContacts = computed(() => this.contactsCache.contacts());

  readonly pickerDisabled = computed(() => this.contactsCache.loading());

  override readonly actions: FormAction[] = [];

  constructor() {
    super();

    effect(() => {
      const asset = this.entity();
      if (!isDefined(asset)) return;

      untracked(() => {
        if (isDefined(asset.owner?.id)) {
          this.contactsCache.loadForClient(asset.owner.id);
        }

        const ids: string[] =
          (asset as AssetResponseWithContactIds).contactIds ??
          (asset.contacts ?? []).map((c) => c.id);

        this.selectedContactIds.set(ids);
      });
    });
  }

  override ngAfterViewInit(): void {
    super.ngAfterViewInit();
  }

  onMultiSelectChange(): void {
    this.markFormAsDirty();
  }

  navigateToContact(contactId: string): void {
    const owner = this.entity()?.owner;
    if (!isDefined(owner)) return;
    void this.adminNavigation.navigateToEntityDetails('contact', contactId, owner);
  }

  removeContact(contactId: string): void {
    this.selectedContactIds.update((ids) =>
      ids.filter((id) => id !== contactId),
    );
    this.markFormAsDirty();
  }

  openCreateModal(): void {
    const ownerId = this.entity()?.owner?.id;
    if (!isDefined(ownerId)) return;

    this.dialogRef = this.dialogService.open(ContactCreateWizardComponent, {
      header: this.translate.instant('ADMIN.ASSETS.CONTACTS.MODAL_CREATE'),
      data: { ownerId },
      position: 'top',
      modal: true,
      contentStyle: { overflow: 'auto' },
    }) as DynamicDialogRef;

    this.dialogRef.onClose
      .pipe(takeUntilDestroyed(this.destroyRef))
      .subscribe((created: ContactDetailItem | undefined) => {
        if (!isDefined(created)) return;
        this.selectedContactIds.update((ids) => [...ids, created.id]);
        this.markFormAsDirty();
      });
  }

  protected override buildUpdateRequest(
    _formData: Record<string, unknown>,
  ): Observable<unknown> {
    const asset = this.entity();
    if (isNullOrUndefined(asset))
      return new Observable((obs) => obs.complete());

    const selectedIds = new Set(this.selectedContactIds());

    const payload: AssetUpdateRequestWithContactIds | AssetUpdateRequest =
      this.apiSchemaService.usesModernSchema()
        ? { contactIds: this.selectedContactIds() }
        : {
            contacts: this.contactsCache
              .contacts()
              .filter((c) => selectedIds.has(c.id))
              .map(
                (c): Contact => ({
                  id: c.id,
                  type: c.type,
                  name: c.name,
                  emailAddress: c.emailAddress,
                  phoneMobile: c.phoneMobile,
                  phoneOffice: c.phoneOffice,
                  notes: c.notes,
                }),
              ),
          };

    return this.entitiesService.updateAsset(asset.id, payload);
  }

  protected override cancelEdit(): void {
    const asset = this.entity();
    if (isDefined(asset)) {
      const ids: string[] =
        (asset as AssetResponseWithContactIds).contactIds ??
        (asset.contacts ?? []).map((c) => c.id);
      this.selectedContactIds.set(ids);
    }
    super.cancelEdit();
  }

  protected override updateFormFields(): void {}

  private markFormAsDirty(): void {
    this.hasFormChanges = true;
  }

  protected override showSuccessMessage(message: string): void {
    this.messageService.add({
      severity: 'success',
      summary: this.translate.instant('SHARED.COMMON.MESSAGES.SUCCESS'),
      detail: message,
      life: 3000,
    });
  }

  protected override showErrorMessage(error: unknown): void {
    const detail = error instanceof Error ? error.message : this.translate.instant('SHARED.COMMON.MESSAGES.ERROR_GENERIC');
    this.messageService.add({
      severity: 'error',
      summary: this.translate.instant('SHARED.COMMON.MESSAGES.ERROR'),
      detail,
      life: 5000,
    });
  }
}
