import {
  Component,
  computed,
  effect,
  inject,
  input,
  signal,
} from '@angular/core';
import { CommonModule } from '@angular/common';
import { takeUntilDestroyed } from '@angular/core/rxjs-interop';
import { FormGroup, Validators } from '@angular/forms';
import { catchError, finalize, forkJoin, of } from 'rxjs';

import { ButtonModule } from 'primeng/button';
import { CardModule } from 'primeng/card';
import { TableModule } from 'primeng/table';

import { UsersService } from '../../../../../api/api/users.service';
import {
  createDateField,
  createNumberField,
  FormAction,
  FormFieldConfig,
  MeasurementUnitType,
} from '../../../../../shared/models';
import {
  isDefined,
  isEmpty,
  isNullOrUndefined,
} from '../../../../../shared/utils';
import { EntitySectionBaseComponent } from '../../base';
import { GridComponent } from '../../../../../shared/components/grid/grid.component';
import { DynamicFormModalComponent } from '../../../../../shared/components/forms/dynamic-form-modal/dynamic-form-modal.component';
import { MeasurementUnitsService } from '../../../../../shared/services/measurement-units/measurement-units.service';
import {
  OdoHourChangesService,
  OdoHourChangeRecord,
  OdoHourChangeCreateRequest,
  OdoHourChangeUpdateRequest,
} from '../../../services/odo-hour-changes.service';
import { TranslatePipe } from '@ngx-translate/core';

@Component({
  selector: 'app-asset-odo-hour-changes-section',
  imports: [
    CommonModule,
    ButtonModule,
    CardModule,
    TableModule,
    GridComponent,
    DynamicFormModalComponent,
    TranslatePipe,
  ],
  templateUrl: './asset-odo-hour-changes-section.component.html',
  styleUrl: './asset-odo-hour-changes-section.component.scss',
})
export class AssetOdoHourChangesSectionComponent extends EntitySectionBaseComponent<{
  id: string;
}> {
  private readonly odoHourChangesService = inject(OdoHourChangesService);
  private readonly usersService = inject(UsersService);
  private readonly measurementsService = inject(MeasurementUnitsService);

  /** Whether this section shows 'odo' or 'hours' changes */
  readonly changeType = input<'odo' | 'hours'>('odo');

  /** When true, renders without the card wrapper/header (for embedding in another section) */
  readonly embedded = input<boolean>(false);

  // State
  readonly isLoadingChanges = signal<boolean>(false);
  private readonly changesData = signal<OdoHourChangeRecord[]>([]);
  private readonly editingChange = signal<OdoHourChangeRecord | null>(null);

  // Modal controls
  readonly showChangeModal = signal<boolean>(false);
  readonly currentModalTitle = signal<string>('');

  // Track pending changes
  private readonly newChanges = signal<OdoHourChangeCreateRequest[]>([]);
  private readonly updatedChanges = signal<
    { id: string; request: OdoHourChangeUpdateRequest }[]
  >([]);
  private readonly deletedChangeIds = signal<string[]>([]);

  // Track the currently loaded asset ID to prevent duplicate loads
  private loadedAssetId: string | null = null;

  // Cache for resolved user names — only used as fallback when the API
  // could not resolve the user (createdBy still arrives as a raw GUID).
  private readonly userNameCache = signal<Record<string, string>>({});

  // Matches a 36-char UUID like "319fb370-5ff7-49e9-a5e6-74394921d2df"
  private static readonly UUID_REGEX =
    /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;

  // Computed
  readonly sortedChanges = computed(() => {
    const existing = this.changesData().filter(
      (c) => !this.deletedChangeIds().includes(c.id),
    );
    return existing.sort(
      (a, b) => new Date(b.fromDate).getTime() - new Date(a.fromDate).getTime(),
    );
  });

  readonly hasChanges = computed(() => {
    return (
      this.newChanges().length > 0 ||
      this.updatedChanges().length > 0 ||
      this.deletedChangeIds().length > 0
    );
  });

  readonly changesSummary = computed(() => {
    const changes = this.changesData();
    return [
      {
        key:
          this.changeType() === 'odo'
            ? 'Odometer Changes'
            : 'Engine Hours Changes',
        value: isEmpty(changes)
          ? this.translate.instant('SHARED.COMMON.NONE')
          : `${changes.length} record(s)`,
      },
    ];
  });

  readonly sectionIcon = computed(() => {
    return this.changeType() === 'odo' ? 'pi pi-car' : 'pi pi-clock';
  });

  readonly sectionLabel = computed(() => {
    return this.changeType() === 'odo'
      ? 'Odometer Changes'
      : 'Engine Hours Changes';
  });

  readonly sectionDescription = computed(() => {
    return this.changeType() === 'odo'
      ? 'Manage odometer change records for this asset.'
      : 'Manage engine hours change records for this asset.';
  });

  readonly valueLabel = computed(() => {
    if (this.changeType() === 'odo') {
      const unit = this.measurementsService.getUnitConfig(
        MeasurementUnitType.DISTANCE,
      );
      return `Odometer (${unit})`;
    }
    return 'Hours';
  });

  override readonly actions: FormAction[] = [
    {
      label: this.translate.instant('SHARED.COMMON.BUTTONS.CANCEL'),
      action: () => {
        this.showChangeModal.set(false);
        this.editingChange.set(null);
      },
      severity: 'secondary',
    },
    {
      label: this.translate.instant('SHARED.COMMON.BUTTONS.OK'),
      action: (formData) => {
        this.onChangeSubmit(formData);
      },
      severity: 'primary',
      disabled: (form) => {
        return form?.invalid ?? false;
      },
    },
  ];

  constructor() {
    super();

    this.columns = [
      { field: 'key', header: '', transform: 'uppercase' },
      { field: 'value', header: '' },
    ];

    effect(() => {
      const asset = this.entity();
      if (isDefined(asset?.id)) {
        if (asset.id !== this.loadedAssetId) {
          this.loadChanges(asset);
        }
      } else {
        this.changesData.set([]);
        this.loadedAssetId = null;
        this.resetChanges();
      }
    });
  }

  private loadChanges(asset: { id: string }): void {
    if (this.isLoadingChanges()) return;

    this.loadedAssetId = asset.id;
    this.isLoadingChanges.set(true);

    this.odoHourChangesService
      .list(asset.id)
      .pipe(
        takeUntilDestroyed(this.destroyRef),
        catchError(() => {
          this.isLoadingChanges.set(false);
          return of({ items: [], count: 0, offset: 0, limit: 1000 });
        }),
      )
      .subscribe({
        next: (response) => {
          const items = (response.items ?? []).filter(
            (item) => item.changeType === this.changeType(),
          );
          this.changesData.set(items);
          this.isLoadingChanges.set(false);
          this.resetChanges();
          this.resolveUserNames(items);
        },
      });
  }

  getCreatedByName(createdBy: string | undefined): string {
    return this.resolveDisplayName(createdBy);
  }

  getUpdatedByName(updatedBy: string | undefined): string {
    return this.resolveDisplayName(updatedBy);
  }

  private resolveDisplayName(value: string | undefined): string {
    if (!isDefined(value) || value === '') return '-';
    // Prefer whatever the backend sent: if it's already a name (non-UUID),
    // use it directly. Only consult the cache when the backend returned a
    // raw GUID because it couldn't resolve the user server-side.
    if (!AssetOdoHourChangesSectionComponent.UUID_REGEX.test(value)) {
      return value;
    }
    return this.userNameCache()[value] ?? value;
  }

  private resolveUserNames(changes: OdoHourChangeRecord[]): void {
    const cache = this.userNameCache();
    const uniqueIds = [
      ...new Set(
        changes
          .flatMap((c) => [c.createdBy, c.updatedBy])
          .filter(
            (id): id is string =>
              isDefined(id) &&
              AssetOdoHourChangesSectionComponent.UUID_REGEX.test(id) &&
              !isDefined(cache[id]),
          ),
      ),
    ];

    if (isEmpty(uniqueIds)) return;

    const lookups = uniqueIds.map((id) =>
      this.usersService.getUser(id).pipe(catchError(() => of(null))),
    );

    forkJoin(lookups)
      .pipe(takeUntilDestroyed(this.destroyRef))
      .subscribe((users) => {
        const updated = { ...this.userNameCache() };
        users.forEach((user, index) => {
          if (isDefined(user?.name) && user.name !== '') {
            updated[uniqueIds[index]] = user.name;
          }
        });
        this.userNameCache.set(updated);
      });
  }

  openAddModal(): void {
    this.editingChange.set(null);
    this.currentModalTitle.set(
      `Add ${this.changeType() === 'odo' ? 'Odometer' : 'Engine Hours'} Change`,
    );
    this.updateFormFields();
    this.showChangeModal.set(true);
  }

  openEditModal(change: OdoHourChangeRecord): void {
    this.editingChange.set(change);
    this.currentModalTitle.set(
      `Edit ${this.changeType() === 'odo' ? 'Odometer' : 'Engine Hours'} Change`,
    );
    this.updateFormFields();
    this.showChangeModal.set(true);
  }

  protected override updateFormFields(): void {
    const editing = this.editingChange();
    const unitSuffix =
      this.changeType() === 'odo'
        ? ` ${this.measurementsService.getUnitConfig(MeasurementUnitType.DISTANCE)}`
        : ' hrs';

    const displayValue = isDefined(editing)
      ? this.toDisplayValue(editing.value)
      : undefined;

    const fields: FormFieldConfig[] = [
      createNumberField('value', this.valueLabel(), displayValue, {
        name: 'value',
        layout: 'horizontal',
        labelWidth: '1/3',
        validations: [
          {
            name: 'required',
            validator: Validators.required,
            message: `${this.valueLabel()} is required`,
          },
          {
            name: 'min',
            validator: Validators.min(0),
            message: 'Value must be 0 or greater',
          },
        ],
        props: {
          suffix: unitSuffix,
        },
      }),
      createDateField('fromDate', 'From Date', editing?.fromDate ?? '', {
        name: 'fromDate',
        layout: 'horizontal',
        labelWidth: '1/3',
        validations: [
          {
            name: 'required',
            validator: Validators.required,
            message: 'From Date is required',
          },
        ],
        props: {
          appendTo: 'body',
          showTime: true,
          showSeconds: true,
          dateFormat: 'yy/mm/dd',
        },
      }),
    ];

    this.formFields = fields;
  }

  onChangeSubmit(formGroup: FormGroup): void {
    const entity = this.entity();
    if (isNullOrUndefined(entity?.id)) return;

    const formData = formGroup.value;
    const editing = this.editingChange();
    const fromDate = this.convertToISOString(formData['fromDate']);
    const backendValue = this.toBackendValue(formData['value'] as number);

    if (isDefined(editing)) {
      const updateRequest: OdoHourChangeUpdateRequest = {
        type: this.changeType(),
        value: backendValue,
        fromDate,
      };
      this.updatedChanges.set([
        ...this.updatedChanges(),
        { id: editing.id, request: updateRequest },
      ]);

      this.changesData.set(
        this.changesData().map((c) =>
          c.id === editing.id
            ? {
                ...c,
                value: updateRequest.value ?? c.value,
                fromDate: fromDate ?? c.fromDate,
              }
            : c,
        ),
      );
    } else {
      const createRequest: OdoHourChangeCreateRequest = {
        type: this.changeType(),
        value: backendValue,
        fromDate: fromDate ?? new Date().toISOString(),
      };
      this.newChanges.set([...this.newChanges(), createRequest]);

      this.changesData.set([
        ...this.changesData(),
        {
          id: `temp-${Date.now()}`,
          assetId: entity.id,
          changeType: this.changeType(),
          value: createRequest.value,
          fromDate: createRequest.fromDate,
        },
      ]);
    }

    this.showChangeModal.set(false);
    this.editingChange.set(null);
  }

  deleteChange(change: OdoHourChangeRecord): void {
    if (change.id.startsWith('temp-')) {
      const idx = this.changesData().findIndex((c) => c.id === change.id);
      if (idx >= 0) {
        const newIdx =
          idx - (this.changesData().length - this.newChanges().length);
        if (newIdx >= 0) {
          this.newChanges.set(this.newChanges().filter((_, i) => i !== newIdx));
        }
        this.changesData.set(
          this.changesData().filter((c) => c.id !== change.id),
        );
      }
    } else {
      this.deletedChangeIds.set([...this.deletedChangeIds(), change.id]);
    }

    this.messageService.add({
      severity: 'info',
      summary: 'Change Removed',
      detail: 'Change has been marked for deletion.',
    });
  }

  resetChanges(): void {
    this.newChanges.set([]);
    this.updatedChanges.set([]);
    this.deletedChangeIds.set([]);
  }

  saveAllChanges(): void {
    const asset = this.entity();
    if (isNullOrUndefined(asset?.id)) return;

    this.isLoadingChanges.set(true);

    const createObservables = this.newChanges().map((req) =>
      this.odoHourChangesService.create(asset.id, req),
    );

    const updateObservables = this.updatedChanges().map((item) =>
      this.odoHourChangesService.update(asset.id, item.id, item.request),
    );

    const deleteObservables = this.deletedChangeIds().map((id) =>
      this.odoHourChangesService.delete(asset.id, id),
    );

    forkJoin({
      creates: !isEmpty(createObservables)
        ? forkJoin(createObservables)
        : of(null),
      updates: !isEmpty(updateObservables)
        ? forkJoin(updateObservables)
        : of(null),
      deletes: !isEmpty(deleteObservables)
        ? forkJoin(deleteObservables)
        : of(null),
    })
      .pipe(
        takeUntilDestroyed(this.destroyRef),
        finalize(() => this.isLoadingChanges.set(false)),
        catchError(() => {
          this.messageService.add({
            severity: 'error',
            summary: 'Error',
            detail: `Failed to save ${this.sectionLabel().toLowerCase()}`,
          });
          return of(null);
        }),
      )
      .subscribe({
        next: () => {
          this.messageService.add({
            severity: 'success',
            summary: 'Success',
            detail: `${this.sectionLabel()} updated successfully`,
          });

          this.loadedAssetId = null;
          this.loadChanges(asset);

          this.isFormEditable.set(false);
          this.isSubmitting.set(false);
          this.clearUnsavedChanges();
          this.broadcastService.broadcast('entity-updated', {
            entityType: 'asset',
            entityId: asset.id,
          });
        },
        error: () => {
          this.isFormEditable.set(true);
          this.isSubmitting.set(false);
        },
      });
  }

  protected override submitChanges(
    _formData: Record<string, string | number>,
  ): void {
    this.saveAllChanges();
  }

  onCancel(): void {
    this.isFormEditable.set(false);
    this.loadedAssetId = null;
    const asset = this.entity();
    if (isDefined(asset?.id)) {
      this.loadChanges(asset);
    }
    this.resetChanges();
    this.clearUnsavedChanges();
  }

  formatDate(dateStr: string): string {
    if (!dateStr) return '';
    const date = new Date(dateStr);
    return Number.isNaN(date.getTime()) ? dateStr : date.toLocaleString();
  }

  formatValue(value: number | undefined): string {
    if (value === undefined || value === null) return '-';
    const display = this.toDisplayValue(value);
    if (this.changeType() === 'odo') {
      const unit = this.measurementsService.getUnitConfig(
        MeasurementUnitType.DISTANCE,
      );
      return `${display.toLocaleString()} ${unit}`;
    }
    return `${display.toLocaleString()} hrs`;
  }

  private toDisplayValue(backendValue: number): number {
    if (this.changeType() === 'odo') {
      return this.measurementsService.fromBackend(
        MeasurementUnitType.DISTANCE,
        backendValue,
        4,
      );
    }
    return Math.round(backendValue * 10) / 10;
  }

  private toBackendValue(displayValue: number): number {
    if (this.changeType() === 'odo') {
      return Number(
        this.measurementsService.toBackend(
          MeasurementUnitType.DISTANCE,
          displayValue,
          4,
        ),
      );
    }
    return Math.round(displayValue * 10) / 10;
  }

  private convertToISOString(value: unknown): string | undefined {
    if (value instanceof Date) {
      return value.toISOString();
    }
    if (typeof value === 'string') {
      const date = new Date(value);
      return Number.isNaN(date.getTime()) ? value : date.toISOString();
    }
    return undefined;
  }
}
