import { Injectable, inject } from '@angular/core';
import { Observable, of } from 'rxjs';
import { Router } from '@angular/router';

import { isNullOrUndefined } from '../../../../shared/utils';
import { DataGridParams, EntityDataAdapter, GridResponse } from '../../../../shared/models';
import { ContactDetailItem, ContactListItem, ContactStateEnum, ContactsService } from '../contacts.service';
import { ActionIcon, EntityConfigAdapter, StateOption } from '../../models';
import { EntityDetailsStateService } from '../entity/entity-details.state.service';

@Injectable({
  providedIn: 'root',
})
export class ContactsDataAdapter
  implements EntityDataAdapter<ContactListItem, ContactDetailItem>, EntityConfigAdapter
{
  private readonly contactsService = inject(ContactsService);
  private readonly router = inject(Router);
  private readonly entityStateService = inject(EntityDetailsStateService);

  getList(params: DataGridParams): Observable<GridResponse<ContactListItem>> {
    const { owner, offset, limit, sortField, filters } = params;

    if (isNullOrUndefined(owner)) {
      return of({ items: [], count: 0 });
    }

    return this.contactsService.list(owner, offset, limit, sortField as string, filters);
  }

  getById(id: string): Observable<ContactDetailItem> {
    const clientId = this.getClientIdFromUrl();
    if (isNullOrUndefined(clientId)) {
      return of({} as ContactDetailItem);
    }
    return this.contactsService.get(id, clientId);
  }

  getStateOptions(): StateOption[] {
    return [
      { label: 'Active', value: 'active' satisfies ContactStateEnum },
      { label: 'Deleted', value: 'deleted' satisfies ContactStateEnum },
    ];
  }

  updateState(id: string, state: unknown): Observable<ContactDetailItem> {
    return this.contactsService.updateState(id, state as ContactStateEnum);
  }

  getActionIcons(_entityId: string): ActionIcon[] {
    return [
      {
        id: 'changeState',
        icon: 'pi pi-trash',
        tooltip: 'Change Contact State',
        visible: true,
        showPopover: true,
        popoverType: 'state',
        action: () => {
          this.entityStateService.togglePopover('changeState');
        },
      },
    ];
  }

  private getClientIdFromUrl(): string | null {
    const match = this.router.url.match(/\/client\/([^/]+)\//);
    return match?.[1] ?? null;
  }
}
