import { CommonModule } from '@angular/common';
import {
  Component,
  computed,
  effect,
  inject,
  input,
  untracked,
} from '@angular/core';
import { Validators } from '@angular/forms';
import { ButtonModule } from 'primeng/button';

import { EntitySectionBaseComponent } from '../../../components/base/entity-section-base';
import {
  SimCardCreateRequest,
  SimCardListItem,
  EntitiesService,
} from '../../../../../api';
import { isDefined, isNullOrUndefined } from '../../../../../shared/utils';
import { internationalSimNumberValidator } from '../../../../../shared/utils/phone-number-utils';
import { createTextField } from '../../../../../shared/models';
import { EMPTY, Observable } from 'rxjs';
import { GridComponent } from '../../../../../shared/components/grid/grid.component';
import { DynamicFormComponent } from '../../../../../shared/components/forms/dynamic-form/dynamic-form.component';
import { TranslatePipe } from '@ngx-translate/core';

@Component({
  selector: 'app-sim-card-details-section',
  imports: [
    CommonModule,
    ButtonModule,
    GridComponent,
    DynamicFormComponent,
    TranslatePipe,
  ],
  templateUrl: './sim-card-details-section.component.html',
  styleUrl: './sim-card-details-section.component.scss',
})
export class SimCardDetailsSectionComponent extends EntitySectionBaseComponent<
  SimCardListItem | Partial<SimCardCreateRequest>
> {
  readonly ownerId = input<string | null>(null);
  private readonly entitiesService = inject(EntitiesService);

  readonly simCardDetails = computed(() => {
    const simCardDetails = this.entity();
    this.languageService.currentLanguage();
    if (!isDefined(simCardDetails)) return [];

    return [
      {
        key: this.translate.instant(
          'ADMIN.SIM_CARDS.DETAILS.FIELDS.SERIAL_NUMBER',
        ),
        value: simCardDetails.name,
      },
      {
        key: this.translate.instant('ADMIN.SIM_CARDS.DETAILS.FIELDS.NETWORK'),
        value: simCardDetails.networkName,
      },
      {
        key: this.translate.instant('ADMIN.SIM_CARDS.DETAILS.FIELDS.NUMBER'),
        value: simCardDetails.number,
      },
      {
        key: this.translate.instant(
          'ADMIN.SIM_CARDS.DETAILS.FIELDS.DESCRIPTION',
        ),
        value: simCardDetails.description,
      },
    ];
  });

  constructor() {
    super();

    // Setup initial columns
    this.columns = [
      { field: 'key', header: '', transform: 'uppercase' },
      { field: 'value', header: '' },
    ];

    effect(() => {
      const entity = this.entity();
      if (isDefined(entity) && !this.createMode()) {
        untracked(() => {
          this.updateFormFields();
        });
      }
    });
  }

  protected override updateFormFields(): void {
    const simCard = this.entity();
    this.formFields = [
      createTextField(
        'name',
        this.translate.instant('ADMIN.SIM_CARDS.DETAILS.FIELDS.SERIAL_NUMBER'),
        simCard?.name,
        {
          name: 'name',
          validations: [
            {
              name: 'required',
              validator: Validators.required,
              message: this.translate.instant(
                'SHARED.COMMON.FORMS.SHARED.REQUIRED',
                {
                  field: this.translate.instant(
                    'ADMIN.SIM_CARDS.DETAILS.FIELDS.SERIAL_NUMBER',
                  ),
                },
              ),
            },
          ],
        },
      ),
      createTextField(
        'networkName',
        this.translate.instant('ADMIN.SIM_CARDS.DETAILS.FIELDS.NETWORK'),
        simCard?.networkName,
        {
          name: 'networkName',
          validations: [
            {
              name: 'required',
              validator: Validators.required,
              message: this.translate.instant(
                'SHARED.COMMON.FORMS.SHARED.REQUIRED',
                {
                  field: this.translate.instant(
                    'ADMIN.SIM_CARDS.DETAILS.FIELDS.NETWORK',
                  ),
                },
              ),
            },
          ],
        },
      ),
      createTextField(
        'number',
        this.translate.instant('ADMIN.SIM_CARDS.DETAILS.FIELDS.NUMBER'),
        simCard?.number,
        {
          name: 'number',
          placeholder: 'e.g., +27123456789',
          validations: [
            {
              name: 'required',
              validator: Validators.required,
              message: this.translate.instant(
                'SHARED.COMMON.FORMS.SHARED.REQUIRED',
                {
                  field: this.translate.instant(
                    'ADMIN.SIM_CARDS.DETAILS.FIELDS.NUMBER',
                  ),
                },
              ),
            },
            {
              name: 'internationalSimNumber',
              validator: internationalSimNumberValidator(),
              message: this.translate.instant(
                'SHARED.COMMON.VALIDATION.INVALID_PHONE',
              ),
            },
          ],
        },
      ),
      createTextField(
        'description',
        this.translate.instant('ADMIN.SIM_CARDS.DETAILS.FIELDS.DESCRIPTION'),
        simCard?.description,
        {
          name: 'description',
          validations: [
            {
              name: 'required',
              validator: Validators.required,
              message: this.translate.instant(
                'SHARED.COMMON.FORMS.SHARED.REQUIRED',
                {
                  field: this.translate.instant(
                    'ADMIN.SIM_CARDS.DETAILS.FIELDS.DESCRIPTION',
                  ),
                },
              ),
            },
          ],
        },
      ),
    ];
  }

  protected override buildUpdateRequest(
    formData: Record<string, unknown>,
  ): Observable<unknown> {
    const simCard = this.entity();
    if (isNullOrUndefined(simCard)) return EMPTY;
    return this.entitiesService.updateSimCard(simCard.id, formData);
  }

  protected override onSubmitSuccess(response: unknown): void {
    const simCard = this.entity();
    if (isNullOrUndefined(simCard)) return;
    this.broadcastService.broadcast('entity-updated', {
      entityType: 'simcard',
      operation: 'update',
      entityId: simCard.id,
      data: response,
    });
  }
}
