import { Component, effect } from '@angular/core';
import { EntitySectionBaseComponent } from './entity-section-base';
import { BulkCapableSection } from '../../models/admin-details-base.interface';
import { FormFieldConfig } from '../../../../shared/models/form-field.model';

/**
 * Base component for entity sections that support bulk edit mode.
 * Extends EntitySectionBaseComponent and satisfies the BulkCapableSection
 * marker interface, so the details-accordion-container dev-mode guard passes
 * without each component needing to declare isBulkCapable individually.
 */
@Component({ template: '' })
export abstract class BulkEntitySectionBaseComponent<T>
  extends EntitySectionBaseComponent<T>
  implements BulkCapableSection
{
  // eslint-disable-next-line @typescript-eslint/class-literal-property-style
  get isBulkCapable(): true {
    return true;
  }

  protected get isBulkMode(): boolean {
    return this.bulkContext() !== null;
  }

  protected abstract buildFormFields(entity: unknown): FormFieldConfig[];

  constructor() {
    super();
    effect(() => {
      if (this.bulkContext() !== null) {
        this.formFields = this.buildFormFields(null);
      }
    });
  }
}
