  constructor() {
    super();

    // Setup initial columns
    this.columns = [
      { field: 'key', header: '', transform: 'uppercase' },
      { field: 'value', header: '' },
    ];

    // React to entity and bulk mode changes
    effect(async () => {
      const entity = this.entity();
      this.bulkContext(); // track signal
      if (isDefined(entity) && !this.createMode()) {
        this.updateFormFields();
        await this.loadAssetImage(); // Load image when entity changes
        this.loadParentAssetName(entity);
      }
    });

    effect(() => {
      const ownerId = this.effectiveOwnerId();
      this.selectOptionsLoaded.set(false);
      untracked(() => this.loadSelectOptions(ownerId));
    });
  }

  private loadParentAssetName(entity: unknown): void {
    const parentId = (entity as AssetWithInternalProperties).parentId;

    if (isDefined(parentId)) {
      this.entitiesService
        .getAsset(parentId)
        .pipe(
          takeUntilDestroyed(this.destroyRef),
          catchError(() => of(null)),
        )
        .subscribe((asset) => {
          if (asset) {
            this.fetchedParentAssetName.set(asset.name ?? 'Unknown Asset');
            // Re-update form fields to show the name in autocomplete
            this.updateFormFields();
          } else {
            this.fetchedParentAssetName.set(null);
          }
        });
    } else {
      this.fetchedParentAssetName.set(null);
    }
  }

  ngOnInit() {
    this.setUpAssetTagsSearch();
    this.setUpParentAssetsSearch();
  }

  private loadSelectOptions(ownerId: string | null) {
    if (isNullOrUndefined(ownerId)) {
      this.selectOptions = {};
      this.selectOptionsLoaded.set(true);
      this.updateFormFields();
      return;
    }

    Promise.all([
      this.assetGroupingService.getAssetTypes(ownerId),
      firstValueFrom(this.entitiesService.listCostCentres(ownerId)),
      this.assetGroupingService.getAssetGroupsAsTree(ownerId),
    ])
      .then(([assetTypes, costCentres, assetGroups]) => {
        this.selectOptions = {
          assetTypes: assetTypes
            .map((item) => ({
              label: item.name ?? '',
              value: item.id,
            }))
            .sort((a, b) => a.label.localeCompare(b.label)),
          costCentres: costCentres.items
            .map((costCentre) => ({
              label: costCentre.name ?? '',
              value: costCentre.id,
            }))
            .sort((a, b) => a.label.localeCompare(b.label)),
          groups: assetGroups,
        };

        this.selectOptionsLoaded.set(true);
        this.updateFormFields();
      })
      .catch(() => {
        this.selectOptionsLoaded.set(false);
      });
  }

  private setUpParentAssetsSearch(): void {
    this.parentSearchSubject
      .pipe(
        debounceTime(SEARCH_DEBOUNCE_TIME),
        takeUntilDestroyed(this.destroyRef),
        switchMap((searchTerm) => {
          const asset = this.entity();
          const effectiveOwnerId =
            asset?.owner?.id ??
            this.bulkContext()?.ownerId ??
            this.ownerId() ??
            null;

          if (isNullOrUndefined(effectiveOwnerId)) {
            return of({ items: [] });
          }

          const trimmedSearchTerm = searchTerm.trim();

          if (trimmedSearchTerm.length === 0) {
            return of({ items: [] });
          }

          const filters = {
            state: { value: 'active', operator: '=' },
            name: { value: `*${trimmedSearchTerm}*`, operator: '=' },
          };

          const rqlFilter = this.utilityService.constructRqlFilter(filters);

          return this.entitiesService
            .listAssets(effectiveOwnerId, 0, 10, 'name', rqlFilter)
            .pipe(
              catchError(() => {
                return of({ items: [] });
              }),
            );
        }),
      )
      .subscribe({
        next: (data) => {
          if (isDefined(data) && hasProperty(data, 'items')) {
            this.parentAssetsSearchResults.set(
              isNullOrUndefined(data.items)
                ? []
                : data.items.filter((a) => a.id !== this.entity()?.id),
            );
          }
        },
        error: (error) => {
          console.error('Error searching parent assets:', error);
          this.parentAssetsSearchResults.set([]);
        },
      });
  }

  private setUpAssetTagsSearch(): void {
    this.searchSubject
      .pipe(
        debounceTime(SEARCH_DEBOUNCE_TIME),
        takeUntilDestroyed(this.destroyRef),
        switchMap((searchTerm) => {
          const owner = this.entity()?.owner;

          if (isNullOrUndefined(owner?.id)) {
            return of({ items: [] });
          }

          const trimmedSearchTerm = searchTerm.trim();

          if (trimmedSearchTerm.length === 0) {
            return of({ items: [] });
          }

          const filters = {
            state: { value: 'active', operator: '=' },
            name: { value: `*${trimmedSearchTerm}*`, operator: '=' },
          };
          const rqlFilter = this.utilityService.constructRqlFilter(filters);

          return this.entitiesService
            .listAssetTags(owner.id, 0, 10, 'name', rqlFilter)
            .pipe(
              catchError(() => {
                return of({ items: [] });
              }),
            );
        }),
      )
      .subscribe({
        next: (data) => {
          if (isDefined(data) && hasProperty(data, 'items')) {
            this.assetTagsSearchResults.set(
              isNullOrUndefined(data.items) ? [] : data.items,
            );
          }
        },
        error: (error) => {
          console.error('Error searching asset tags:', error);
          this.assetTagsSearchResults.set([]);
        },
      });
  }

