import { Injectable, inject, signal } from '@angular/core';
import {
  combineLatest,
  EMPTY,
  map,
  Observable,
  of,
  switchMap,
  tap,
  throwError,
} from 'rxjs';
import { ConfirmationService } from 'primeng/api';

import { isDefined, isNullOrUndefined } from '../../../../shared/utils';
import {
  EntitiesService,
  AccountsService,
  IdName,
  CustomFieldDefinition,
} from '../../../../api';
import { DataGridParams, EntityDataAdapter } from '../../../../shared/models';
import { RequestCacheService } from '../../../../shared/services/request-cache.service';
import { UtilityService } from '../../../../core/services/utility.service';
import {
  CustomFieldResponse,
  CUSTOM_FIELD_TYPES,
  CUSTOM_FIELD_TYPES_MAP,
  CustomFieldResponseList,
  ActionIcon,
} from '../../models';
import { EntityConfigAdapter } from '../../models/entity-config-adapter.interface';
import { BroadcastEventMessageService } from '../broadcast-event-messages.service';

@Injectable({
  providedIn: 'root',
})
export class CustomFieldsDataAdapter
  implements
    EntityDataAdapter<CustomFieldResponse, CustomFieldResponse>,
    EntityConfigAdapter
{
  private readonly entitiesService = inject(EntitiesService);
  private readonly accountsService = inject(AccountsService);
  private readonly cacheService = inject(RequestCacheService);
  private readonly utilityService = inject(UtilityService);
  private readonly confirmationService = inject(ConfirmationService);
  private readonly broadcastService = inject(BroadcastEventMessageService);
  assetTypes = signal<IdName[]>([]);
  types = signal<IdName[]>([]);

  getList(params: DataGridParams): Observable<CustomFieldResponseList> {
    const { owner, limit, offset, filters, sortField } = params;

    if (isNullOrUndefined(owner)) {
      return of({ items: [], count: 0, title: '', type: '', limit, offset });
    }

    return this.getCachedCustomFields(owner).pipe(
      map((items) => {
        const filteredItems = this.filter(filters ?? '', items);
        const sortedItems = this.sortItems(
          filteredItems,
          Array.isArray(sortField) ? sortField[0] : sortField,
        );
        const start = offset ?? 0;
        const end = limit ? start + limit : undefined;

        return {
          title: 'Custom Fields',
          type: 'custom-field',
          count: filteredItems.length,
          limit,
          offset,
          items: sortedItems.slice(start, end),
        };
      }),
    );
  }

  private sortItems(
    items: CustomFieldResponse[],
    sortField?: string,
  ): CustomFieldResponse[] {
    const [field, direction] = (sortField ?? 'name:asc').split(':');
    const multiplier = direction === 'desc' ? -1 : 1;

    const fieldMap: Record<string, (item: CustomFieldResponse) => string> = {
      entityType: (item) => item._entityType?.name?.toLowerCase() ?? '',
      type: (item) => item.type?.name?.toLowerCase() ?? '',
    };

    const getValue =
      fieldMap[field] ??
      ((item) => (this.getNestedValue(item, field) ?? '').toLowerCase());

    return [...items].sort(
      (a, b) => getValue(a).localeCompare(getValue(b)) * multiplier,
    );
  }

  invalidateCache(ownerId: string): void {
    this.cacheService.clearCache(`customFields-${ownerId}`);
  }

  private getCachedCustomFields(
    ownerId: string,
  ): Observable<CustomFieldResponse[]> {
    const cacheKey = `customFields-${ownerId}`;
    return this.cacheService.getOrFetch(cacheKey, () =>
      combineLatest([
        this.accountsService.getCompany(ownerId),
        this.getCachedAssetTypes(ownerId),
        this.getTypes(),
      ]).pipe(
        map(([company, assetTypes, types]) => {
          this.assetTypes.set(assetTypes);
          this.types.set(types);
          return this.buildCustomFieldItems(
            ownerId,
            company,
            assetTypes,
            types,
          );
        }),
      ),
    );
  }

  private buildCustomFieldItems(
    ownerId: string,
    company: {
      type?: string;
      customFields?: Record<string, CustomFieldDefinition[]>;
    },
    assetTypes: IdName[],
    types: IdName[],
  ): CustomFieldResponse[] {
    const items: CustomFieldResponse[] = [];
    Object.keys(company.customFields ?? {}).forEach((fieldType) => {
      const fields = (company.customFields?.[fieldType] ?? []).filter(
        (x) => x['owner'] === company.type,
      );
      fields.forEach((field) => {
        items.push(
          this.customFieldDefinitionToCustomFieldResponse(
            assetTypes,
            types,
            ownerId,
            fieldType,
            field,
          ),
        );
      });
    });
    return items;
  }

  getById(_id: string) {
    const [ownerId] = _id.split('.');
    if (!ownerId) {
      return EMPTY;
    }

    const params: DataGridParams = {
      owner: ownerId,
      limit: 0, // We don't need pagination here
      offset: 0,
    };

    return this.getList(params).pipe(
      map((responseList) => {
        return responseList.items.find((item) => item.id === _id);
      }),
      map((item) => {
        if (!item) {
          return {} as CustomFieldResponse;
        }
        return item;
      }),
    );
  }

  delete(entityId: string): Observable<unknown> {
    if (isNullOrUndefined(entityId)) {
      return throwError(
        () => new Error('Entity ID is required for custom field deletion.'),
      );
    }

    const [companyId, entityType, fieldId] = entityId.split('.');

    if (!companyId || !entityType || !fieldId) {
      return throwError(
        () =>
          new Error(
            'Invalid custom field entity ID format. Expected: companyId.entityType.fieldId',
          ),
      );
    }

    // First get the company to determine its type and current customFields
    return this.accountsService.getCompany(companyId).pipe(
      switchMap((company) => {
        if (!company.customFields) {
          return throwError(
            () => new Error('Company has no custom fields to delete.'),
          );
        }

        // Deep clone the customFields to avoid mutation
        const customFields: Record<string, CustomFieldDefinition[]> =
          structuredClone(company.customFields);

        // Get the current custom fields for this entity type
        const currentFields = customFields[entityType];
        if (!Array.isArray(currentFields) || currentFields.length === 0) {
          return throwError(
            () =>
              new Error(
                `No custom fields found for entity type: ${entityType}`,
              ),
          );
        }

        // Filter out the field to be deleted
        const filteredFields = currentFields.filter(
          (field) => field.id !== fieldId,
        );

        // Update the customFields object
        customFields[entityType] = filteredFields;

        // Determine the update method based on company type
        switch (company.type) {
          case 'client':
            return this.accountsService.updateClientDetails(companyId, {
              customFields,
            });
          case 'vendor':
            return this.accountsService.updateVendorDetails(companyId, {
              customFields,
            });
          case 'distributor':
            return this.accountsService.updateDistributorDetails(companyId, {
              customFields,
            });
          default:
            return throwError(
              () =>
                new Error(
                  `Unsupported company type ('${company.type}') for custom field deletion.`,
                ),
            );
        }
      }),
      tap(() => this.cacheService.clearCache(`customFields-${companyId}`)),
    );
  }

  getActionIcons(entityId: string): ActionIcon[] {
    return [
      {
        id: 'delete',
        icon: 'pi pi-trash',
        tooltip: 'Delete Custom Field',
        visible: true,
        action: () => {
          this.confirmDelete(entityId);
        },
      },
    ];
  }

  private confirmDelete(entityId: string): void {
    const message = `Are you sure you want to delete this custom field?`;

    this.confirmationService.confirm({
      message,
      header: 'Confirm Delete',
      icon: 'pi pi-exclamation-triangle',
      accept: () => {
        this.delete(entityId).subscribe({
          next: (result) => {
            this.broadcastService.broadcast('entity-deleted', {
              entityType: 'custom-field',
              operation: 'delete',
              entityId,
              data: result,
            });
          },
          error: (error) => {
            console.error('Delete failed', error);
          },
        });
      },
      acceptButtonProps: { label: 'Delete' },
      rejectButtonProps: { label: 'Cancel', severity: 'secondary' },
    });
  }

  customFieldDefinitionToCustomFieldResponse(
    entityTypes: IdName[],
    types: IdName[],
    ownerId: string,
    entityType: string,
    field: CustomFieldDefinition,
  ): CustomFieldResponse {
    return {
      id: `${ownerId}.${entityType}.${field.id}`,
      tag: field.id,
      name: field.title,
      required: field.required,
      _entityType: entityTypes.find(
        (x) => x.id === entityType || x.name === entityType,
      ),
      type: types.find((x) => x.id === field.type),
      values: (field.values ?? []).map((x) => x.key).join('\n'),
    };
  }

  getTypes(): Observable<IdName[]> {
    return of(
      CUSTOM_FIELD_TYPES.map((type) => ({
        id: type,
        name: CUSTOM_FIELD_TYPES_MAP[type],
      })),
    );
  }

  getCachedAssetTypes(ownerId: string): Observable<IdName[]> {
    const staticTypes: IdName[] = [
      { id: 'simcard', name: 'Sim Card' },
      { id: 'assettag', name: 'Asset Tag' },
      { id: 'device', name: 'Device' },
      { id: 'asset', name: 'Asset' },
      { id: 'event', name: 'Event' },
    ];
    const cacheKey = `assetTypes-${ownerId}`;
    return this.cacheService
      .getOrFetch(cacheKey, () => this.entitiesService.listAssetTypes(ownerId))
      .pipe(
        map(({ items }) => [
          ...staticTypes,
          ...items
            .map((x) => ({ id: x.id, name: x.name }))
            .sort((a, b) => a.name.localeCompare(b.name)),
        ]),
      );
  }

  filter(filter: string, items: CustomFieldResponse[]): CustomFieldResponse[] {
    const matches = (f: string, item: CustomFieldResponse): boolean => {
      const [field, match] = f.split('=');
      if (!match) {
        return true;
      }
      const value = this.getNestedValue(item, field) ?? '';
      if (match.includes('*')) {
        // User specified text search, be generous in matching.
        return this.utilityService
          .escapeRqlValue(value)
          .toLowerCase()
          .includes(match.replace(/\*/g, '').toLowerCase());
      }
      // Chosen from predefined list, match exactly.
      return value.toLowerCase() === match.toLowerCase();
    };

    // Filter string format: AND conditions separated by '&' (or ','), OR conditions as (a|b)
    // e.g. (_entityType.id=simcard|_entityType.id=asset)&type.id=text

    const filters = (filter || '')
      .split(/[,&]/)
      .filter((term) => term)
      .map((term) => {
        if (term.includes('|')) {
          return term.slice(1, term.length - 1).split('|');
        }
        return [term];
      });

    return filters.reduce(
      (result, column) =>
        result.filter((item) => column.some((term) => matches(term, item))),
      items,
    );
  }

  getCustomFieldResponseFromCompany(
    company: CustomFieldResponseList,
    id: string,
  ): CustomFieldResponse | undefined {
    const customField = company.items.find((x) => x.id === id);
    if (customField) {
      return customField;
    }
    return undefined;
  }

  private getNestedValue<T>(obj: T, path: string): string | undefined {
    return path.split('.').reduce((acc, key) => {
      if (
        isDefined(acc) &&
        acc !== null &&
        typeof acc === 'object' &&
        key in acc
      ) {
        return (acc as Record<string, unknown>)[key];
      }
      return undefined;
    }, obj as unknown) as string | undefined;
  }
}
