import {
  Component,
  computed,
  effect,
  inject,
  input,
  signal,
  untracked,
} from '@angular/core';
import { CommonModule } from '@angular/common';
import { takeUntilDestroyed } from '@angular/core/rxjs-interop';
import { ReactiveFormsModule } from '@angular/forms';

import { ButtonModule } from 'primeng/button';
import { ConfirmationService } from 'primeng/api';

import {
  AssetCreateRequest,
  AssetResponse,
  AssetUpdateRequest,
  EntitiesService,
} from '../../../../../api';
import {
  AssetGroupingItem,
  createDropdownField,
  FormFieldConfig,
} from '../../../../../shared/models';
import {
  isDefined,
  isEmpty,
  isNullOrUndefined,
  isString,
} from '../../../../../shared/utils';
import { BulkEntitySectionBaseComponent } from '../../../components/base/bulk-entity-section-base';
import { DynamicFormComponent } from '../../../../../shared/components/forms/dynamic-form/dynamic-form.component';
import { GridComponent } from '../../../../../shared/components/grid/grid.component';
import { AssetGroupingService } from '../../../../../shared/services/asset-grouping.service';
import { CacheInvalidationService } from '../../../../../shared/services/cache-invalidation.service';
import { DEFAULT_SYSTEM_ID } from '../../../../../core/models';
import { AssetBulkSaveService } from '../../../services/asset-bulk-save.service';
import { TranslatePipe } from '@ngx-translate/core';

@Component({
  selector: 'app-asset-categories-section',
  imports: [
    CommonModule,
    ReactiveFormsModule,
    ButtonModule,
    GridComponent,
    DynamicFormComponent,
    TranslatePipe,
  ],
  providers: [ConfirmationService],
  templateUrl: './asset-categories-section.component.html',
  styleUrl: './asset-categories-section.component.scss',
})
export class AssetCategoriesSectionComponent extends BulkEntitySectionBaseComponent<
  AssetResponse | Partial<AssetCreateRequest>
> {
  readonly ownerId = input<string | null>(null);

  private readonly entitiesService = inject(EntitiesService);
  private readonly assetGroupingService = inject(AssetGroupingService);
  private readonly cacheInvalidationService = inject(CacheInvalidationService);
  private readonly bulkSaveService = inject(AssetBulkSaveService);
  private readonly confirmationService = inject(ConfirmationService);
  protected readonly selectOptionsLoaded = signal<boolean>(false);
  selectOptions: Record<string, { label: string; value: string }[]> = {};

  private readonly effectiveOwnerIdSignal = computed(() => {
    const bulkEditContext = this.bulkContext();
    if (bulkEditContext) return bulkEditContext.ownerId;
    const entity = this.entity() as AssetResponse | null;
    return entity?.owner?.id ?? this.ownerId() ?? '';
  });

  readonly assetDetails = computed(() => {
    const assetDetails = this.entity();
    this.languageService.currentLanguage();
    if (this.isBulkMode) {
      return this.assetCategories()
        .filter((cat) => cat.parent === DEFAULT_SYSTEM_ID)
        .map((cat) => ({ key: cat.name, value: '' }));
    }

    if (!isDefined(assetDetails)) return [];

    const parentGroups = this.assetCategories().filter(
      (cat) => cat.parent === DEFAULT_SYSTEM_ID,
    );

    if (parentGroups.length === 0) {
      return [
        {
          key: 'Categories',
          value: isEmpty(assetDetails.categories)
            ? this.translate.instant('SHARED.COMMON.NONE')
            : (assetDetails.categories ?? [])
                .filter(isDefined)
                .map((c) => c?.name)
                .join(', '),
        },
      ];
    }

    return parentGroups.map((group) => {
      const selectedCategory = (assetDetails.categories ?? [])
        .filter(isDefined)
        .find((selected) => {
          const fullCat = this.assetCategories().find(
            (cat) => cat.id === selected.id,
          );
          return fullCat?.index === group.index;
        });
      return {
        key: group.name,
        value:
          selectedCategory?.name ??
          this.translate.instant('SHARED.COMMON.NONE'),
      };
    });
  });
  readonly assetCategories = signal<AssetGroupingItem[]>([]);

  constructor() {
    super();

    // Setup initial columns
    this.columns = [
      { field: 'key', header: '', transform: 'uppercase' },
      { field: 'value', header: '' },
    ];

    effect(() => {
      if (this.selectOptionsLoaded()) {
        this.updateFormFields();
      }
    });

    effect(() => {
      const ownerId = this.effectiveOwnerIdSignal();
      this.selectOptionsLoaded.set(false);
      untracked(() => this.loadSelectOptions(ownerId));
    });
  }

  protected get effectiveOwnerId(): string {
    return this.effectiveOwnerIdSignal();
  }

  private loadSelectOptions(ownerId: string) {
    if (!isDefined(ownerId) || ownerId === '') {
      this.selectOptions = {};
      this.selectOptionsLoaded.set(true);
      return;
    }

    // Check if we need to refresh cache (e.g., if this is a create mode)
    const shouldRefreshCache = this.createMode();
    if (shouldRefreshCache) {
      this.cacheInvalidationService.refreshAssetCategories(ownerId);
    }

    this.assetGroupingService
      .getAssetCategories(ownerId)
      .then((assetCategories) => {
        this.assetCategories.set(assetCategories);
        this.selectOptions = {
          assetCategories: assetCategories
            .map((item) => ({
              label: item.name ?? '',
              value: item.id,
            }))
            .sort((a, b) => a.label.localeCompare(b.label)),
        };
        this.selectOptionsLoaded.set(true);
      })
      .catch(() => {
        this.selectOptions = {};
        this.selectOptionsLoaded.set(false);
      });
  }

  protected override updateFormFields(): void {
    this.formFields = this.buildFormFields(
      this.entity() as AssetResponse | null,
    );
  }

  protected buildFormFields(entity: AssetResponse | null): FormFieldConfig[] {
    const fields: FormFieldConfig[] = [];
    this.assetCategories()
      .filter((category) => category?.parent === DEFAULT_SYSTEM_ID)
      .forEach((category) => {
        const items = this.assetCategories().filter(
          (cat) =>
            cat.index === category.index && cat.parent !== DEFAULT_SYSTEM_ID,
        );
        const options = items.map((item) => ({
          label: item.name ?? '',
          value: item.id,
        }));
        fields.push(
          createDropdownField(
            `category${category.index}`,
            category.name,
            options,
            entity?.categories?.find((selected) => {
              const fullCat = this.assetCategories().find(
                (cat) => cat.id === selected?.id,
              );
              return (
                fullCat?.index === category.index &&
                fullCat?.parent !== DEFAULT_SYSTEM_ID
              );
            })?.id ?? '',
            {
              layout: 'horizontal',
              labelWidth: '1/3',
              name: `category${category.index}`,
              props: {
                appendTo: 'body',
              },
            },
          ),
        );
      });
    return fields;
  }

  protected override submitBulkChanges(
    formData: Record<string, string | number | object | null>,
  ): void {
    const bulkEditContext = this.bulkContext();
    if (isNullOrUndefined(bulkEditContext)) return;

    const payload = this.transformFormData(formData);
    this.isSubmitting.set(true);

    this.bulkSaveService
      .confirmAndSave(
        bulkEditContext,
        payload,
        (id, data) => this.entitiesService.updateAsset(id, data),
        this.confirmationService,
      )
      .pipe(takeUntilDestroyed(this.destroyRef))
      .subscribe({
        next: () => {
          this.isSubmitting.set(false);
          this.isFormEditable.set(false);
          this.clearUnsavedChanges();
          this.broadcastService.broadcast('entity-updated', {
            entityType: 'asset',
            operation: 'update',
          });
        },
        error: () => {
          this.isSubmitting.set(false);
          this.isFormEditable.set(true);
        },
      });
  }

  override getUpdateMethod() {
    return (id: string, data: unknown) =>
      this.entitiesService.updateAsset(id, data as AssetUpdateRequest);
  }

  protected override onSubmitSuccess(_response: unknown): void {
    const asset = this.entity() as AssetResponse | null;
    if (isNullOrUndefined(asset)) return;
    this.broadcastService.broadcast('entity-updated', {
      entityType: 'asset',
      operation: 'update',
      entityId: asset.id,
    });
  }

  protected override onFormValueChange(
    formData: Record<string, unknown>,
  ): void {
    const transformedData = this.transformFormData(formData);

    // Emit the transformed values
    this.formValueChange.emit(transformedData);
  }

  // Iterate through form fields by their names (e.g., 'category0', 'category1')
  override transformFormData(formData: Record<string, unknown>) {
    // Build a map of category type index -> selected category, seeded from
    // the entity's existing categories so untouched fields are preserved.
    const categoryByIndex = new Map<number, { id: string; name: string }>();

    const existingAsset = this.entity() as AssetResponse | null;
    (existingAsset?.categories ?? []).filter(isDefined).forEach((selected) => {
      const fullCat = this.assetCategories().find(
        (cat) => cat.id === selected.id,
      );
      if (isDefined(fullCat?.index)) {
        categoryByIndex.set(fullCat.index, {
          id: selected.id,
          name: selected.name ?? '',
        });
      }
    });

    // Apply dirty form values — override or clear each touched category type.
    const parentCategories = this.assetCategories().filter(
      (category) => category?.parent === DEFAULT_SYSTEM_ID,
    );

    parentCategories.forEach((parentCategory) => {
      const fieldName = `category${parentCategory.index}`;
      if (!(fieldName in formData)) return;

      const value = formData[fieldName];
      const index = parentCategory.index ?? 0;

      if (isDefined(value) && isString(value) && value !== '') {
        const category = this.assetCategories().find((cat) => cat.id === value);
        if (isDefined(category)) {
          categoryByIndex.set(index, { id: category.id, name: category.name });
        }
      } else {
        categoryByIndex.delete(index);
      }
    });

    return { categories: Array.from(categoryByIndex.values()) };
  }
}
