import { CommonModule } from '@angular/common';
import {
  ChangeDetectorRef,
  Component,
  computed,
  effect,
  inject,
  input,
  OnInit,
  signal,
  untracked,
} from '@angular/core';

import { ButtonModule } from 'primeng/button';
import { ConfirmationService } from 'primeng/api';
import { ConfirmDialog } from 'primeng/confirmdialog';
import {
  combineLatest,
  defer,
  firstValueFrom,
  forkJoin,
  Observable,
} from 'rxjs';

import {
  EntitiesService,
  DeviceResponse,
  DeviceCreateRequest,
  DeviceUpdateRequest,
  AccountsService,
  DeviceConfigProfileListItem,
  ClientResponse,
} from '../../../../../api';
import { DynamicFormComponent } from '../../../../../shared/components/forms/dynamic-form/dynamic-form.component';
import { GridComponent } from '../../../../../shared/components/grid/grid.component';
import {
  createDropdownField,
  createTextField,
  FormFieldConfig,
} from '../../../../../shared/models';
import {
  getAllRouteParams,
  isDefined,
  isNullOrUndefined,
} from '../../../../../shared/utils';
import { DeviceEntity } from '../../../models';
import { EntityOperationRegistryService } from '../../../services/entity/entity-operation-registry.service';
import { Validators } from '@angular/forms';
import { BulkEntitySectionBaseComponent } from '../../base/bulk-entity-section-base';
import { DEFAULT_SYSTEM_ID } from '../../../../../core/models';
import { TranslatePipe } from '@ngx-translate/core';
import { takeUntilDestroyed } from '@angular/core/rxjs-interop';
import { RequestCacheService } from '../../../../../shared/services/request-cache.service';
import { AdminStateService } from '../../../services/state/admin-state.service';
import { ActivatedRoute } from '@angular/router';

@Component({
  selector: 'app-device-details-section',
  imports: [
    CommonModule,
    ButtonModule,
    GridComponent,
    DynamicFormComponent,
    TranslatePipe,
    ConfirmDialog,
  ],
  templateUrl: './device-details-section.component.html',
  styleUrl: './device-details-section.component.scss',
  providers: [ConfirmationService],
})
export class DeviceDetailsSectionComponent
  extends BulkEntitySectionBaseComponent<DeviceEntity>
  implements OnInit
{
  readonly sectionHeader = input<string>('Device Details');

  readonly ownerId = input<string | null>(null);
  readonly entitiesService = inject(EntitiesService);
  private readonly operationRegistry = inject(EntityOperationRegistryService);
  public readonly adminState = inject(AdminStateService);
  private readonly accountsService = inject(AccountsService);
  private readonly cdr = inject(ChangeDetectorRef);
  private readonly requestCache = inject(RequestCacheService);
  private readonly confirmationService = inject(ConfirmationService);
  protected readonly selectOptionsLoaded = signal<boolean>(false);
  private readonly route = inject(ActivatedRoute);

  private readonly effectiveOwnerId = computed(
    () =>
      this.entity()?.owner?.id ??
      this.bulkContext()?.ownerId ??
      this.ownerId() ??
      null,
  );

  readonly detailsDisplay = computed(() => {
    if (this.bulkContext() !== null) {
      const none = this.translate.instant('SHARED.COMMON.NONE');
      return [
        { key: 'Device Type', value: none },
        { key: 'Configuration', value: none },
        { key: 'State', value: none },
        { key: 'Device Provider', value: none },
      ];
    }

    const details: DeviceEntity | null = { ...this.entity() };

    if (isNullOrUndefined(details)) {
      return [];
    }
    if (isNullOrUndefined(details.configProfile)) {
      details.configProfile = {
        id: DEFAULT_SYSTEM_ID,
        name: 'Manually Configured',
      };
    }

    return [
      {
        key: 'Serial Number',
        value: details.name ?? this.translate.instant('SHARED.COMMON.NONE'),
      },
      {
        key: 'Device Type',
        value:
          details.deviceType?.name ??
          this.translate.instant('SHARED.COMMON.NONE'),
      },
      {
        key: 'Configuration',
        value:
          details.configProfile?.name ??
          this.translate.instant('SHARED.COMMON.NONE'),
      },
    ];
  });
  selectOptions: Record<
    string,
    { label: string; value: string; data?: unknown }[]
  > = {};

  constructor() {
    super();

    // Setup initial columns
    this.columns = [
      { field: 'key', header: '', transform: 'uppercase' },
      { field: 'value', header: '' },
    ];

    effect(() => {
      const selectOptionsLoaded = this.selectOptionsLoaded();
      if (selectOptionsLoaded) {
        untracked(() => {
          this.updateFormFields();
          this.cdr.detectChanges(); // Ensure change detection runs after updating form fields
        });
      }
    });

    effect(() => {
      const entity = this.entity();
      if (isDefined(entity) && !this.createMode()) {
        untracked(() => {
          this.updateFormFields();
        });
      }
    });
  }

  ngOnInit(): void {
    this.loadSelectOptions();
  }

  private loadSelectOptions(): void {
    const effectiveOwnerId = this.effectiveOwnerId();

    if (isNullOrUndefined(effectiveOwnerId)) {
      this.selectOptions = {
        deviceTypes: [],
        deviceProviders: [],
        deviceConfigProfiles: [],
      };
      this.selectOptionsLoaded.set(true);
      this.updateFormFields();
      return;
    }

    const cacheTTL = 300000; // 5 minutes

    combineLatest([
      this.requestCache.getOrFetch(
        `device-types-${effectiveOwnerId}`,
        () => this.entitiesService.listDeviceTypes(effectiveOwnerId),
        cacheTTL,
      ),
      this.requestCache.getOrFetch(
        `device-providers-${effectiveOwnerId}-true`,
        () => this.entitiesService.listDeviceProviders(effectiveOwnerId, true),
        cacheTTL,
      ),
      this.requestCache.getOrFetch(
        `device-config-profiles-${effectiveOwnerId}-true`,
        () =>
          this.entitiesService.listDeviceConfigProfiles(effectiveOwnerId, true),
        cacheTTL,
      ),
      defer(() =>
        this.getAvailableRootDeviceTypeIdsForClient().catch(
          () => [] as string[],
        ),
      ),
    ])
      .pipe(takeUntilDestroyed(this.destroyRef))
      .subscribe(
        ([
          deviceTypes,
          deviceProviders,
          deviceConfigProfiles,
          availableDeviceTypeIds,
        ]) => {
          const filteredDeviceTypes = deviceTypes.items.filter(
            (deviceType) =>
              deviceType.state === 'active' &&
              isDefined(deviceType.parent) &&
              (deviceType.owner.id === effectiveOwnerId ||
                availableDeviceTypeIds.length === 0 ||
                availableDeviceTypeIds.includes(deviceType.parent.id)),
          );

          this.selectOptions = {
            deviceTypes: filteredDeviceTypes
              .map((item) => ({
                label: `${item?.parent?.name} - ${item?.name}`,
                value: item.id,
                data: item,
              }))
              .sort((a, b) => a.label.localeCompare(b.label)),
            deviceProviders: deviceProviders.items.map((item) => ({
              label: item.name ?? '',
              value: item.id,
            })),
            deviceConfigProfiles: deviceConfigProfiles.items.map((item) => ({
              label: item.name ?? '',
              value: item.id,
              data: item,
            })),
          };

          this.selectOptionsLoaded.set(true);
        },
      );
  }

  private getConfigProfiles(deviceTypeId: string | null | undefined) {
    const device = this.entity();
    return [
      {
        label: 'Manually Configured',
        value: DEFAULT_SYSTEM_ID,
      },
      ...(this.selectOptions['deviceConfigProfiles'] ?? [])
        .filter((x) => {
          const profile = x.data as DeviceConfigProfileListItem;
          return (
            (profile.state === 'active' ||
              profile.id === device?.configProfile?.id) &&
            profile?.deviceType?.id === deviceTypeId
          );
        })
        .map((x) => {
          const profile = x.data as DeviceConfigProfileListItem;
          return {
            label: profile.name ?? '',
            value: profile.id,
          };
        }),
    ];
  }

  protected override buildFormFields(_entity: unknown): FormFieldConfig[] {
    // Called by the bulk base effect whenever bulkContext is set — build the
    // bulk fields here so they populate regardless of option-load timing.
    return this.buildBulkFormFields();
  }

  protected override updateFormFields(): void {
    if (this.bulkContext() !== null) {
      this.formFields = this.buildBulkFormFields();
      this.cdr.detectChanges();
      return;
    }

    const device = this.entity();

    this.formFields = [
      createTextField('name', 'Serial Number', device?.name ?? '', {
        name: 'name',
        validations: [
          {
            name: 'required',
            validator: Validators.required,
            message: 'Serial Number is required',
          },
          {
            name: 'pattern',
            validator: Validators.pattern(/^[a-zA-Z0-9]+$/),
            message: 'Serial Number must be alphanumeric',
          },
        ],
      }),
      createDropdownField(
        'deviceType',
        'Device Type',
        this.selectOptions['deviceTypes'] ?? [],
        device?.deviceType?.id ?? '',
        {
          name: 'deviceType',
          validations: [
            {
              name: 'required',
              validator: Validators.required,
              message: 'Device Type is required',
            },
          ],
          props: {
            appendTo: 'body',
          },
          events: {
            onChange: (value) => {
              const configProfileField = this.formFields.find(
                (field) => field.key === 'configProfile',
              );
              if (configProfileField) {
                configProfileField.options = this.getConfigProfiles(value);
                this.form?.patchValue({ configProfile: DEFAULT_SYSTEM_ID });
              }
            },
          },
        },
      ),
      createDropdownField(
        'configProfile',
        'Configuration Profile',
        this.getConfigProfiles(device?.deviceType?.id),
        device?.configProfile?.id ?? DEFAULT_SYSTEM_ID,
        {
          name: 'configProfile',
          props: {
            appendTo: 'body',
          },
        },
      ),
    ];

    if (
      this.createMode() &&
      this.selectOptions['deviceProviders']?.length > 0
    ) {
      this.formFields.push(
        createDropdownField(
          'provider',
          'Device Provider',
          this.selectOptions['deviceProviders'] ?? [],
          device?.provider?.id ?? '',
          {
            name: 'provider',
            validations: [
              {
                name: 'required',
                validator: Validators.required,
                message: 'Device Provider is required',
              },
            ],
            props: {
              appendTo: 'body',
            },
          },
        ),
      );
    }
  }

  /**
   * Build the bulk-edit form: only the fields that can safely be applied to many
   * devices at once (device type, config profile, state, provider). Each starts
   * blank/pristine so untouched fields are omitted from the merge-patch payload.
   */
  private buildBulkFormFields(): FormFieldConfig[] {
    return [
      createDropdownField(
        'deviceType',
        'Device Type',
        this.selectOptions['deviceTypes'] ?? [],
        null,
        {
          name: 'deviceType',
          props: { appendTo: 'body' },
          events: {
            onChange: (value) => {
              const configProfileField = this.formFields.find(
                (field) => field.key === 'configProfile',
              );
              if (configProfileField) {
                configProfileField.options = this.getConfigProfiles(value);
                this.form?.patchValue({ configProfile: DEFAULT_SYSTEM_ID });
              }
            },
          },
        },
      ),
      createDropdownField(
        'configProfile',
        'Configuration Profile',
        this.getConfigProfiles(null),
        null,
        {
          name: 'configProfile',
          props: { appendTo: 'body' },
        },
      ),
      createDropdownField(
        'state',
        'State',
        [
          { label: 'Active', value: 'active' },
          { label: 'Inactive', value: 'inactive' },
          { label: 'Suspended', value: 'suspended' },
        ],
        null,
        {
          name: 'state',
          props: { appendTo: 'body' },
        },
      ),
      createDropdownField(
        'provider',
        'Device Provider',
        this.selectOptions['deviceProviders'] ?? [],
        null,
        {
          name: 'provider',
          props: { appendTo: 'body' },
        },
      ),
    ];
  }

  protected override submitBulkChanges(
    formData: Record<string, string | number | object | null>,
  ): void {
    const ids = (this.bulkContext()?.selectedEntities ?? []).map(
      (selectedEntity) => selectedEntity.id,
    );
    const payload = this.transformFormData(
      formData as Record<string, string | number | object>,
    ) as unknown as DeviceUpdateRequest;

    this.confirmationService.confirm({
      header: 'Bulk Update',
      message: `Apply changes to ${ids.length} device${ids.length === 1 ? '' : 's'}?`,
      icon: 'pi pi-exclamation-triangle',
      accept: () => {
        this.isSubmitting.set(true);
        forkJoin(
          ids.map((id) =>
            this.entitiesService.updateDevice(String(id), payload),
          ),
        )
          .pipe(takeUntilDestroyed(this.destroyRef))
          .subscribe({
            next: () => {
              this.isFormEditable.set(false);
              this.isSubmitting.set(false);
              this.clearUnsavedChanges();
              this.broadcastService.broadcast('entity-updated', {
                entityType: 'device',
              });
            },
            error: () => {
              this.isFormEditable.set(true);
              this.isSubmitting.set(false);
            },
          });
      },
      reject: () => {
        this.isSubmitting.set(false);
      },
      acceptButtonProps: { label: 'Apply' },
      rejectButtonProps: { label: 'Cancel', severity: 'secondary' },
    });
  }

  override getUpdateMethod(): (
    id: string,
    data: Partial<DeviceEntity>,
  ) => Observable<DeviceResponse> {
    return (
      this.operationRegistry.getOperation<
        DeviceEntity,
        DeviceCreateRequest,
        DeviceResponse,
        'update'
      >('device', 'update') ??
      ((id, data) => this.entitiesService.updateDevice(id, data))
    );
  }

  async getAvailableRootDeviceTypeIdsForClient() {
    // Get all route params including parent routes
    const routeParams = getAllRouteParams(this.route.snapshot);
    const clientId = routeParams['clientId'];

    if (isNullOrUndefined(clientId)) {
      // Fallback to adminState if no route param
      const client = this.adminState.selectedClient();
      if (isNullOrUndefined(client?.id)) return [];
      return this.getAvailableDeviceTypesForClient(client.id);
    }

    return this.getAvailableDeviceTypesForClient(clientId);
  }

  private async getAvailableDeviceTypesForClient(
    clientId: string,
  ): Promise<string[]> {
    try {
      // Try to get from adminState first (cheap operation)
      const adminClient = this.adminState.selectedClient();
      if (
        adminClient?.id === clientId &&
        isDefined(adminClient.availableDeviceTypes)
      ) {
        return this.extractAvailableDeviceTypeIds(adminClient);
      }

      // Cache and fetch full client details if not in adminState
      const client = await this.requestCache.getOrFetchAsync(
        `client-${clientId}`,
        () => firstValueFrom(this.accountsService.getClient(clientId)),
        300000, // 5 minutes cache
      );

      return this.extractAvailableDeviceTypeIds(client);
    } catch (error) {
      console.error('Error fetching client device types:', error);
      return [];
    }
  }

  private async extractAvailableDeviceTypeIds(
    client: ClientResponse,
  ): Promise<string[]> {
    let available = (client.availableDeviceTypes ?? []).map((x) => x.id);

    // Fallback to vendor's available device types if client has none
    if (available.length === 0 && isDefined(client.owner?.id)) {
      const ownerId = client.owner.id;
      const vendor = await this.requestCache.getOrFetchAsync(
        `vendor-${ownerId}`,
        () => firstValueFrom(this.accountsService.getVendor(ownerId)),
        300000, // 5 minutes cache
      );
      available = (vendor.availableDeviceTypes ?? []).map((x) => x.id);
    }

    return available;
  }

  protected override onFormValueChange(
    formData: Record<string, string | number | object>,
  ): void {
    const transformedData = this.transformFormData(formData);

    // Emit the transformed values
    this.formValueChange.emit(transformedData);
  }

  protected override transformFormData(
    formData: Record<string, string | number | object>,
  ): Record<string, string | number | object> {
    const transformedData = { ...formData };

    // Transform deviceType ID to IdName object
    if (
      isDefined(transformedData['deviceType']) &&
      typeof transformedData['deviceType'] === 'string'
    ) {
      const deviceTypeOption = this.selectOptions?.['deviceTypes']?.find(
        (option) => option.value === transformedData['deviceType'],
      );

      if (deviceTypeOption) {
        transformedData['deviceType'] = {
          id: deviceTypeOption.value,
          name: deviceTypeOption.label,
        };
      }
    }

    // Transform configProfile ID to IdName object
    if (
      isDefined(transformedData['configProfile']) &&
      typeof transformedData['configProfile'] === 'string'
    ) {
      const configProfileOption = this.selectOptions?.['deviceConfigProfiles']
        ?.concat({
          label: 'Manually Configured',
          value: DEFAULT_SYSTEM_ID,
        })
        ?.find((option) => option.value === transformedData['configProfile']);

      if (configProfileOption) {
        transformedData['configProfile'] = {
          id: configProfileOption.value,
          name: configProfileOption.label,
        };
      }
    }

    // Transform provider ID to IdName object
    if (
      isDefined(transformedData['provider']) &&
      typeof transformedData['provider'] === 'string'
    ) {
      const providerOption = this.selectOptions?.['deviceProviders']?.find(
        (option) => option.value === transformedData['provider'],
      );

      if (providerOption) {
        transformedData['provider'] = {
          id: providerOption.value,
          name: providerOption.label,
        };
      }
    }

    return transformedData;
  }
}
