import { Component, computed, inject, input, signal } from '@angular/core';
import { MessageModule } from 'primeng/message';
import { ProgressSpinnerModule } from 'primeng/progressspinner';

import { ExportTaskListItem, ExportTaskResponse } from '../../../../../api';
import { EntityDetailsStateService } from '../../../services/entity/entity-details.state.service';
import { DetailsAccordionContainerComponent } from '../../details-accordion-container/details-accordion-container.component';
import { ExportTaskSectionConfigFactory } from '../../../factories/export-task-section-config.factory';

@Component({
  selector: 'app-export-task-details-container',
  imports: [
    DetailsAccordionContainerComponent,
    ProgressSpinnerModule,
    MessageModule,
  ],
  templateUrl: './export-task-details-container.component.html',
  styleUrl: './export-task-details-container.component.scss',
})
export class ExportTaskDetailsContainerComponent {
  readonly entity = input<ExportTaskListItem | null>(null);

  private readonly exportTaskSectionFactory = inject(
    ExportTaskSectionConfigFactory,
  );
  readonly entityDetailsState = inject(EntityDetailsStateService);

  readonly isLoading = computed(() => this.entityDetailsState.isLoading());
  readonly isSoftRefreshing = computed(() =>
    this.entityDetailsState.isSoftRefreshing(),
  );
  readonly isInitialLoading = computed(
    () =>
      this.isLoading() && !this.isSoftRefreshing() && !this.fullExportTask(),
  );

  readonly fullExportTask = computed(() => {
    const entityDetails = this.entityDetailsState.selectedItem();
    if (!entityDetails) return null;
    return entityDetails as ExportTaskResponse;
  });

  readonly sections = computed(() => {
    const exportTask = this.fullExportTask();
    if (!exportTask) return [];
    return this.exportTaskSectionFactory.createAllExportTaskSections(
      exportTask,
      exportTask.owner?.id,
    );
  });

  readonly error = signal<string | null>(null);

  onEntityChange(entity: unknown): void {
    this.entityDetailsState.updateEntity(entity as ExportTaskResponse);
    this.error.set(null);
  }
}
