import { Injectable, inject } from '@angular/core';
import { Observable, of } from 'rxjs';
import { DialogService, DynamicDialogRef } from 'primeng/dynamicdialog';
import { BroadcastEventMessageService } from '../broadcast-event-messages.service';

import { isNullOrUndefined } from '../../../../shared/utils';
import { AssetListItem, AssetResponse, EntitiesService } from '../../../../api';
import {
  DataGridParams,
  EntityDataAdapter,
  GridResponse,
} from '../../../../shared/models';

import { ActionIcon, StateOption } from '../../models';
import { EntityConfigAdapter } from '../../models/entity-config-adapter.interface';
import { AuthDataService } from '../../../../core/services/auth-data.service';
import { EntityDetailsStateService } from '../entity/entity-details.state.service';
@Injectable({
  providedIn: 'root',
})
export class AssetsDataAdapter
  implements
    EntityDataAdapter<AssetListItem, AssetResponse>,
    EntityConfigAdapter
{
  private readonly entitiesService = inject(EntitiesService);
  private readonly authDataService = inject(AuthDataService);
  private readonly entityStateService = inject(EntityDetailsStateService);
  private readonly dialogService = inject(DialogService);
  private readonly broadcastService = inject(BroadcastEventMessageService);
  private dialogRef: DynamicDialogRef | null = null;

  getList(params: DataGridParams): Observable<GridResponse<AssetListItem>> {
    const { owner, limit, offset, sortField, filters } = params;

    if (isNullOrUndefined(owner)) {
      return of({ items: [], count: 0 });
    }

    return this.entitiesService.listAssets(
      owner,
      offset,
      limit,
      sortField as string,
      filters,
    );
  }

  /**
   * Fetch children assets for a given parent ID
   * Used for lazy loading in tree view
   * @param parentId The parent asset ID
   * @param owner The client/owner ID
   * @param limit Optional pagination limit
   * @param offset Optional pagination offset
   * @param sortField Optional sort field
   * @returns Observable of assets with the given parentId
   */
  getChildren(
    parentId: string,
    owner: string,
    limit = 50,
    offset = 0,
    sortField = 'name:asc',
  ): Observable<GridResponse<AssetListItem>> {
    if (isNullOrUndefined(owner) || isNullOrUndefined(parentId)) {
      return of({ items: [], count: 0 });
    }

    // Build RQL filter for children: parentId equals the given ID
    const parentFilter = `parentId='${parentId}'`;

    return this.entitiesService.listAssets(
      owner,
      offset,
      limit,
      sortField,
      parentFilter,
    );
  }

  getById(id: string): Observable<AssetResponse> {
    return this.entitiesService.getAsset(id);
  }

  getStateOptions(): StateOption[] {
    return [
      { label: 'Active', value: AssetResponse.StateEnum.Active },
      { label: 'Inactive', value: AssetResponse.StateEnum.Inactive },
      { label: 'Suspended', value: AssetResponse.StateEnum.Suspended },
      { label: 'Deleted', value: AssetResponse.StateEnum.Deleted },
    ];
  }

  updateState(id: string, state: unknown): Observable<unknown> {
    return this.entitiesService.updateAsset(id, {
      state: state as AssetResponse.StateEnum,
    });
  }

  getActionIcons(entityId: string): ActionIcon[] {
    if (!this.authDataService.hasPermission('assets:create')) {
      return [];
    }

    const asset =
      this.entityStateService.selectedItem() as AssetResponse | null;
    const hasDevice = (asset?.devices?.length ?? 0) > 0;

    const icons: ActionIcon[] = [];

    if (this.authDataService.isSuperAdmin()) {
      icons.push({
        id: 'syncToKeys',
        icon: 'pi pi-sync',
        tooltip: hasDevice
          ? 'Sync Asset to Key Telematics'
          : 'A linked device is required before syncing to Keys',
        visible: true,
        disabled: !hasDevice,
        action: () => {
          this.openSyncDialog();
        },
      });
    }

    icons.push(
      {
        id: 'move',
        icon: 'assets/sprites/sprite.svg#share-from-square-regular',
        tooltip: 'Move Asset',
        bulkTooltip: (ids) =>
          `Move ${ids.length} Asset${ids.length === 1 ? '' : 's'}`,
        visible: true,
        isSvg: true,
        bulkAware: true,
        action: () => {
          this.openMoveAssetDialog([entityId]);
        },
        bulkAction: (ids) => {
          this.openMoveAssetDialog(ids);
        },
      },
      {
        id: 'changeState',
        icon: 'pi pi-trash',
        tooltip: 'Change Asset State',
        visible: true,
        showPopover: true,
        popoverType: 'state',
        bulkAware: true,
        action: () => {
          this.entityStateService.togglePopover('changeState');
        },
        bulkAction: (_ids) => {
          this.entityStateService.togglePopover('changeState');
        },
      },
    );

    return icons;
  }

  private openSyncDialog(): void {
    void import('../../components/assets/keys-sync-dialog/key-telematics-sync-dialog.component').then(
      ({ KeyTelematicsSyncDialogComponent }) => {
        this.dialogRef = this.dialogService.open(
          KeyTelematicsSyncDialogComponent,
          {
            header: 'Sync Asset to Key Telematics',
            width: '450px',
            modal: true,
            position: 'top',
            baseZIndex: 10000,
            contentStyle: { overflow: 'visible' },
          },
        );
      },
    );
  }

  private openMoveAssetDialog(assetIds: string[]): void {
    void import('../../components/assets/asset-move-form/asset-move-form.component').then(
      ({ AssetMoveFormComponent }) => {
        this.dialogRef = this.dialogService.open(AssetMoveFormComponent, {
          header: 'Move Asset',
          contentStyle: { overflow: 'auto', 'margin-top': '1rem' },
          baseZIndex: 10000,
          position: 'top',
          modal: true,
          width: '500px',
          data: {
            assetIds,
            ownerId: this.authDataService.getUserProfile()?.owner.id,
          },
        });
      },
    );
  }
}
