import {
  Component,
  computed,
  effect,
  inject,
  OnInit,
  signal,
} from '@angular/core';
import { takeUntilDestroyed } from '@angular/core/rxjs-interop';
import {
  AssetAnalogParameter,
  AssetCreateRequest,
  AssetResponse,
  AssetTemperatureParameter,
  EntitiesService,
  IoTypeListItem,
} from '../../../../../api';
import {
  MeasurementUnitType,
  createNumberField,
  createDropdownField,
  createModalListField,
  ListFieldModalConfig,
  FormFieldConfig,
} from '../../../../../shared/models';
import { MeasurementUnitsService } from '../../../../../shared/services/measurement-units/measurement-units.service';
import {
  isDefined,
  isEmpty,
  isNullOrUndefined,
  isString,
} from '../../../../../shared/utils';
import { BulkEntitySectionBaseComponent } from '../../../components/base/bulk-entity-section-base';
import { AssetBulkSaveService } from '../../../services/asset-bulk-save.service';
import { CommonModule } from '@angular/common';
import { ReactiveFormsModule } from '@angular/forms';
import { ButtonModule } from 'primeng/button';
import { ConfirmationService } from 'primeng/api';
import { GridComponent } from '../../../../../shared/components/grid/grid.component';
import { DEFAULT_LIST_SIZE } from '../../../../../core/models';
import { UtilityService } from '../../../../../core/services/utility.service';
import { ApiSchemaService } from '../../../../../core/services/api-schema.service';
import { combineLatest, finalize } from 'rxjs';
import { DynamicFormComponent } from '../../../../../shared/components/forms/dynamic-form/dynamic-form.component';
import { ModalListFormComponent } from '../../../../../shared/components/forms/modal-list-form/modal-list-form.component';
import { ListFieldModalConfigBuilder } from '../../../../../shared/services/forms/modal-forms.index';
import { TranslatePipe } from '@ngx-translate/core';

@Component({
  selector: 'app-asset-analog-triggers-section',
  imports: [
    CommonModule,
    ReactiveFormsModule,
    ButtonModule,
    GridComponent,
    DynamicFormComponent,
    TranslatePipe,
  ],
  providers: [ConfirmationService],
  templateUrl: './asset-analog-triggers-section.component.html',
  styleUrl: './asset-analog-triggers-section.component.scss',
})
export class AssetAnalogTriggersSectionComponent
  extends BulkEntitySectionBaseComponent<
    AssetResponse | Partial<AssetCreateRequest>
  >
  implements OnInit
{
  private readonly entitiesService = inject(EntitiesService);
  private readonly measurementUnitsService = inject(MeasurementUnitsService);
  private readonly utilityService = inject(UtilityService);
  private readonly apiSchemaService = inject(ApiSchemaService);
  private readonly bulkSaveService = inject(AssetBulkSaveService);
  private readonly confirmationService = inject(ConfirmationService);

  protected readonly selectOptionsLoaded = signal<boolean>(false);
  selectOptions: Record<
    string,
    { label: string; value: string; type: string }[]
  > = {};

  private readonly formState = signal<{
    analogs: AssetAnalogParameter[];
    temperatures: AssetTemperatureParameter[];
  } | null>(null);

  analogModalConfig?: ListFieldModalConfig<AssetAnalogParameter>;
  temperatureModalConfig?: ListFieldModalConfig<AssetTemperatureParameter>;

  constructor() {
    super();

    // Setup initial columns
    this.columns = [
      { field: 'key', header: '', transform: 'uppercase' },
      { field: 'value', header: '' },
    ];

    effect(() => {
      const entity = this.entity();
      if (entity && !this.createMode()) {
        this.updateFormFields();
      }
    });
  }

  protected get effectiveOwnerId(): string {
    const bulkEditContext = this.bulkContext();
    if (isDefined(bulkEditContext)) return bulkEditContext.ownerId;
    const entity = this.entity() as AssetResponse | null;
    return entity?.owner?.id ?? '';
  }

  ngOnInit(): void {
    this.loadSelectOptions();
    this.setupModalConfigs();
  }

  private setupModalConfigs(): void {
    this.analogModalConfig =
      new ListFieldModalConfigBuilder<AssetAnalogParameter>()
        .withModalComponent(ModalListFormComponent)
        .withTitle(
          this.translate.instant(
            'ADMIN.ASSETS.ANALOG_TRIGGERS.MODALS.ANALOG.TITLE',
          ),
        )
        .withFields((item) => this.createAnalogFields(item))
        .withDefaultProvider(() => ({
          id: '',
          minRange: 0,
          maxRange: 100,
          rangeDebounce: 0,
          decValue: 0,
          incValue: 0,
        }))
        .withFormatter((item) => ({
          id: item.id,
          title:
            item.name ??
            this.selectOptions?.['analogInputTypes']?.find(
              (selectOption) => selectOption.value === item.id,
            )?.label,
          display: this.translate.instant(
            'ADMIN.ASSETS.ANALOG_TRIGGERS.FIELDS.ANALOG_DESCRIPTION',
            {
              minRange: item.minRange,
              maxRange: item.maxRange,
              rangeDebounce: item.rangeDebounce,
            },
          ),
          icon: 'wave-pulse',
        }))
        .withSubHeader(
          this.translate.instant(
            'ADMIN.ASSETS.ANALOG_TRIGGERS.MODALS.ANALOG.DESCRIPTION',
          ),
        )
        .withShowEditButton(true)
        .build();

    this.temperatureModalConfig =
      new ListFieldModalConfigBuilder<AssetTemperatureParameter>()
        .withModalComponent(ModalListFormComponent)
        .withTitle(
          this.translate.instant(
            'ADMIN.ASSETS.ANALOG_TRIGGERS.MODALS.TEMPERATURE.TITLE',
          ),
        )
        .withFields((item) => this.createTemperatureFields(item))
        .withDefaultProvider(() => ({
          id: '',
          minRange: 0,
          maxRange: 100,
          rangeDebounce: 0,
        }))
        .withFormatter((item) => ({
          id: item.id,
          title:
            item.name ??
            this.selectOptions?.['temperatureInputTypes']?.find(
              (selectOption) => selectOption.value === item.id,
            )?.label,
          display: this.translate.instant(
            'ADMIN.ASSETS.ANALOG_TRIGGERS.FIELDS.TEMPERATURE_DESCRIPTION',
            {
              minRange: item.minRange,
              maxRange: item.maxRange,
              rangeDebounce: item.rangeDebounce,
            },
          ),
          icon: 'thermometer',
        }))
        .withSubHeader(
          this.translate.instant(
            'ADMIN.ASSETS.ANALOG_TRIGGERS.MODALS.TEMPERATURE.DESCRIPTION',
          ),
        )
        .withShowEditButton(true)
        .build();
  }

  private createAnalogFields(_item?: AssetAnalogParameter): FormFieldConfig[] {
    return [
      createDropdownField(
        'id',
        this.translate.instant(
          'ADMIN.ASSETS.ANALOG_TRIGGERS.FIELDS.ANALOG_INPUT',
        ),
        this.selectOptions?.['analogInputTypes'] ?? [],
        '',
        {
          layout: 'horizontal',
          labelWidth: '1/3',
          name: 'id',
          props: {
            appendTo: 'body',
          },
        },
      ),
      createNumberField(
        'minRange',
        this.translate.instant('ADMIN.ASSETS.ANALOG_TRIGGERS.FIELDS.MIN_RANGE'),
        0,
        {
          layout: 'horizontal',
          labelWidth: '1/3',
          name: 'minRange',
        },
      ),
      createNumberField(
        'maxRange',
        this.translate.instant('ADMIN.ASSETS.ANALOG_TRIGGERS.FIELDS.MAX_RANGE'),
        100,
        {
          layout: 'horizontal',
          labelWidth: '1/3',
          name: 'maxRange',
        },
      ),
      createNumberField(
        'rangeDebounce',
        this.translate.instant(
          'ADMIN.ASSETS.ANALOG_TRIGGERS.FIELDS.RANGE_DEBOUNCE',
        ),
        0,
        {
          layout: 'horizontal',
          labelWidth: '1/3',
          name: 'rangeDebounce',
        },
      ),
      createNumberField(
        'decValue',
        this.translate.instant(
          'ADMIN.ASSETS.ANALOG_TRIGGERS.FIELDS.DROP_AMOUNT',
        ),
        0,
        {
          layout: 'horizontal',
          labelWidth: '1/3',
          name: 'decValue',
        },
      ),
      createNumberField(
        'incValue',
        this.translate.instant(
          'ADMIN.ASSETS.ANALOG_TRIGGERS.FIELDS.INCREASE_AMOUNT',
        ),
        0,
        {
          layout: 'horizontal',
          labelWidth: '1/3',
          name: 'incValue',
        },
      ),
    ];
  }

  private createTemperatureFields(
    _item?: AssetTemperatureParameter,
  ): FormFieldConfig[] {
    return [
      createDropdownField(
        'id',
        this.translate.instant(
          'ADMIN.ASSETS.ANALOG_TRIGGERS.FIELDS.TEMPERATURE_INPUT',
        ),
        this.selectOptions?.['temperatureInputTypes'] ?? [],
        '',
        {
          layout: 'horizontal',
          labelWidth: '1/3',
          name: 'id',
          props: {
            appendTo: 'body',
          },
        },
      ),
      createNumberField(
        'minRange',
        this.translate.instant('ADMIN.ASSETS.ANALOG_TRIGGERS.FIELDS.MIN_RANGE'),
        0,
        {
          layout: 'horizontal',
          labelWidth: '1/3',
          name: 'minRange',
          props: {
            suffix: this.measurementUnitsService.unitSymbol(
              MeasurementUnitType.TEMPERATURE,
            ),
          },
        },
      ),
      createNumberField(
        'maxRange',
        this.translate.instant('ADMIN.ASSETS.ANALOG_TRIGGERS.FIELDS.MAX_RANGE'),
        100,
        {
          layout: 'horizontal',
          labelWidth: '1/3',
          name: 'maxRange',
          props: {
            suffix: this.measurementUnitsService.unitSymbol(
              MeasurementUnitType.TEMPERATURE,
            ),
          },
        },
      ),
      createNumberField(
        'rangeDebounce',
        this.translate.instant(
          'ADMIN.ASSETS.ANALOG_TRIGGERS.FIELDS.RANGE_DEBOUNCE',
        ),
        0,
        {
          layout: 'horizontal',
          labelWidth: '1/3',
          name: 'rangeDebounce',
        },
      ),
    ];
  }

  readonly assetAnalogAndTemperatureTriggersList = computed(() => {
    const asset = this.entity();
    this.languageService.currentLanguage();
    if (this.isBulkMode) {
      return [
        { key: 'Analogs', value: '' },
        { key: 'Temperature', value: '' },
      ];
    }
    if (!asset) return [];

    // Use form state if editing, otherwise use entity state
    const state = this.formState() ?? {
      analogs: asset.parameters?.analogs ?? [],
      temperatures: asset.parameters?.temperatures ?? [],
    };

    return [
      {
        key: this.translate.instant(
          'ADMIN.ASSETS.ANALOG_TRIGGERS.FIELDS.ANALOGS',
        ),
        value:
          state.analogs.length > 0
            ? state.analogs.map((analog) => analog.name).join(', ')
            : this.translate.instant('SHARED.COMMON.NONE'),
      },
      {
        key: this.translate.instant(
          'ADMIN.ASSETS.ANALOG_TRIGGERS.FIELDS.TEMPERATURES',
        ),
        value:
          state.temperatures.length > 0
            ? state.temperatures.map((temp) => temp.name).join(', ')
            : this.translate.instant('SHARED.COMMON.NONE'),
      },
    ];
  });

  private loadSelectOptions() {
    const asset = this.entity() as AssetResponse | null;
    if (!isDefined(asset) || !isString(asset.id)) {
      return;
    }
    combineLatest([
      this.loadIOTypes(asset.owner.id, ['analog_input', 'can_input']),
      this.loadIOTypes(asset.owner.id, ['temperature_input']),
    ])
      .pipe(takeUntilDestroyed(this.destroyRef))
      .subscribe(([ioTypes, temperatureIoTypes]) => {
        this.selectOptions = {
          analogInputTypes: ioTypes.items
            .map((item) => ({
              label: item.name ?? '',
              value: item.id,
              type:
                this.apiSchemaService.getEntityType<
                  Record<string, unknown>,
                  IoTypeListItem.TypeEnum
                >(item as Record<string, unknown>, 'iotype') ?? '',
            }))
            .sort((a, b) => a.label.localeCompare(b.label)),
          temperatureInputTypes: temperatureIoTypes.items
            .map((item) => ({
              label: item.name ?? '',
              value: item.id,
              type:
                this.apiSchemaService.getEntityType<
                  Record<string, unknown>,
                  IoTypeListItem.TypeEnum
                >(item as Record<string, unknown>, 'iotype') ?? '',
            }))
            .sort((a, b) => a.label.localeCompare(b.label)),
        };
        this.selectOptionsLoaded.set(true);
      });
  }

  private loadIOTypes(owner: string, types: string[]) {
    const typePropertyKey = this.apiSchemaService.getTypePropertyKey('Iotype');
    const filters = isEmpty(types)
      ? {
          state: {
            value: 'active',
            operator: 'in',
          },
        }
      : {
          state: {
            value: 'active',
            operator: '=',
          },
          [typePropertyKey]: {
            value: types,
            operator: 'in',
          },
        };
    return this.entitiesService
      .listIoTypes(
        owner,
        true,
        0,
        DEFAULT_LIST_SIZE,
        'name',
        this.utilityService.constructRqlFilter(filters),
      )
      .pipe(takeUntilDestroyed(this.destroyRef));
  }

  protected override updateFormFields(): void {
    this.formFields = this.buildFormFields(
      this.entity() as AssetResponse | null,
    );
  }

  protected buildFormFields(entity: AssetResponse | null): FormFieldConfig[] {
    // Initialize form state with current entity values (or empty arrays in bulk mode)
    this.formState.set({
      analogs: entity?.parameters?.analogs ?? [],
      temperatures: entity?.parameters?.temperatures ?? [],
    });

    return [
      createModalListField(
        'analogs',
        this.translate.instant('ADMIN.ASSETS.ANALOG_TRIGGERS.FIELDS.ANALOGS'),
        entity?.parameters?.analogs ?? [],
        {
          name: 'analogs',
          props: {
            modalConfig: this.analogModalConfig,
          },
        },
      ) as FormFieldConfig<unknown>,
      createModalListField(
        'temperatures',
        this.translate.instant(
          'ADMIN.ASSETS.ANALOG_TRIGGERS.FIELDS.TEMPERATURES',
        ),
        entity?.parameters?.temperatures ?? [],
        {
          name: 'temperatures',
          props: {
            modalConfig: this.temperatureModalConfig,
          },
        },
      ) as FormFieldConfig<unknown>,
    ];
  }

  protected override onFormValueChange(
    formValue: Record<string, unknown>,
  ): void {
    super.onFormValueChange(formValue as Record<string, string | number>);
    this.formState.set({
      analogs: (formValue['analogs'] as AssetAnalogParameter[]) ?? [],
      temperatures:
        (formValue['temperatures'] as AssetTemperatureParameter[]) ?? [],
    });
  }

  protected override submitBulkChanges(
    _formData: Record<string, string | number | object | null>,
  ): void {
    const bulkEditContext = this.bulkContext();
    if (isNullOrUndefined(bulkEditContext)) return;

    const state = this.formState();
    const analogs = (state?.analogs ?? []).map((item) => {
      const selectedOption = this.selectOptions?.['analogInputTypes']?.find(
        (selectOption) => selectOption.value === item.id,
      );
      return {
        ...item,
        ioType: selectedOption?.type ?? '',
        name: selectedOption?.label ?? item.id,
      };
    });
    const temperatures = (state?.temperatures ?? []).map((item) => {
      const selectedOption = this.selectOptions?.[
        'temperatureInputTypes'
      ]?.find((selectOption) => selectOption.value === item.id);
      return {
        ...item,
        ioType: selectedOption?.type ?? '',
        name: selectedOption?.label ?? item.id,
      };
    });

    this.isSubmitting.set(true);

    this.bulkSaveService
      .confirmAndSave(
        bulkEditContext,
        { parameters: { analogs, temperatures } },
        (id, data) => this.entitiesService.updateAsset(id, data),
        this.confirmationService,
      )
      .pipe(takeUntilDestroyed(this.destroyRef))
      .subscribe({
        next: () => {
          this.isSubmitting.set(false);
          this.isFormEditable.set(false);
          this.formState.set(null);
          this.clearUnsavedChanges();
          this.broadcastService.broadcast('entity-updated', {
            entityType: 'asset',
            operation: 'update',
          });
        },
        error: () => {
          this.isSubmitting.set(false);
          this.isFormEditable.set(true);
        },
      });
  }

  protected override submitChanges(formData: Record<string, unknown>): void {
    const asset = this.entity() as AssetResponse | null;
    if (isNullOrUndefined(asset)) return;
    this.isSubmitting.set(true);

    const analogs = (
      (formData['analogs'] as AssetAnalogParameter[]) ??
      asset.parameters?.analogs ??
      []
    ).map((item) => {
      const selectedOption = this.selectOptions?.['analogInputTypes']?.find(
        (selectOption) => selectOption.value === item.id,
      );
      return {
        ...item,
        ioType: selectedOption?.type ?? '',
        name: selectedOption?.label ?? item.id,
      };
    });

    const temperatures = (
      (formData['temperatures'] as AssetTemperatureParameter[]) ??
      asset.parameters?.temperatures ??
      []
    ).map((item) => {
      const selectedOption = this.selectOptions?.[
        'temperatureInputTypes'
      ]?.find((selectOption) => selectOption.value === item.id);
      return {
        ...item,
        ioType: selectedOption?.type ?? '',
        name: selectedOption?.label ?? item.id,
      };
    });

    this.handleEntityUpdate(
      this.entitiesService
        .updateAsset(asset.id, {
          parameters: {
            analogs,
            temperatures,
          },
        })
        .pipe(
          takeUntilDestroyed(this.destroyRef),
          finalize(() => {
            this.isSubmitting.set(false);
            this.formState.set(null); // Reset to entity state after save
          }),
        ),
      'Asset Analog triggers updated successfully',
    );
  }
}
