import { Component, Input, inject } from '@angular/core';
import { CommonModule } from '@angular/common';
import { ThemeColorService } from '../../../services/theme/theme-color.service';
import { ThemeColor } from '../../../../../shared/models/theme-color';

interface RowData {
  key: string;
  value: string;
}

@Component({
  selector: 'app-theme-value-display',
  imports: [CommonModule],
  templateUrl: './theme-value-display.component.html',
  styleUrl: './theme-value-display.component.scss',
})
export class ThemeValueDisplayComponent {
  @Input({ required: true }) rowData!: RowData;
  @Input({ required: true }) group!: string;

  private readonly colorService = inject(ThemeColorService);

  isColorRow(): boolean {
    return this.colorService.isColorValue(this.rowData.value, this.rowData.key);
  }

  getColorLabelAndValue(): { label: string; value: string } {
    const computedColor = this.colorService.computeColor(this.rowData.value);

    // When the stored value is a CSS variable reference, look it up directly in the
    // ref-based preset map. This avoids ambiguity when two variables happen to resolve
    // to the same hex color (e.g. "Secondary Color" and "Auto" both being white).
    if (this.rowData.value?.startsWith('var(')) {
      const presetRefs = this.colorService.getColorPresetRefs(this.group, [
        'main',
        'content',
        'header',
        'footer',
        'navigation',
        'sidebar',
      ]);
      const directLabel = Object.keys(presetRefs).find(
        (key) => presetRefs[key] === this.rowData.value,
      );
      if (directLabel !== undefined) {
        return { label: directLabel, value: computedColor };
      }
    }

    // Fall back to hex matching for raw hex values (e.g. picked via color picker)
    const contextualPresets = this.colorService.getContextualColorPresets(
      this.rowData.key,
      this.group,
      ['main', 'content', 'header', 'footer', 'navigation', 'sidebar'],
    );
    let presetKey = Object.keys(contextualPresets).find(
      (key) => contextualPresets[key] === computedColor,
    );
    if (presetKey !== undefined) {
      return { label: presetKey, value: computedColor };
    }

    const allPresets = this.getAllColorPresets();
    presetKey = Object.keys(allPresets).find(
      (key) => allPresets[key] === computedColor,
    );
    if (presetKey !== undefined) {
      return { label: presetKey, value: computedColor };
    }

    return { label: computedColor, value: computedColor };
  }

  /**
   * Collect all available color presets from all sources
   */
  private getAllColorPresets(): Record<string, string> {
    const additionalGroups = [
      'main',
      'content',
      'header',
      'footer',
      'navigation',
      'sidebar',
    ];

    return this.colorService.getAllColorPresets(this.group, additionalGroups);
  }

  getBorderColor(): string {
    const originalColor = this.getColorLabelAndValue().value;
    return new ThemeColor(originalColor).darken(0.2).hex();
  }
}
