import {
  ChangeDetectorRef,
  Component,
  computed,
  effect,
  inject,
  input,
  signal,
  untracked,
} from '@angular/core';
import { faUserLock } from '@fortawesome/free-solid-svg-icons';
import { EMPTY, Observable } from 'rxjs';

import {
  AccountsService,
  IdName,
  UserCreateRequest,
  UserListItem,
} from '../../../../../api';
import { createListboxField } from '../../../../../shared/models';
import {
  isDefined,
  isEmpty,
  isNullOrUndefined,
} from '../../../../../shared/utils';
import { EntitySectionBaseComponent } from '../../base';
import { CommonModule } from '@angular/common';
import { FontAwesomeModule } from '@fortawesome/angular-fontawesome';
import { ButtonModule } from 'primeng/button';
import { DynamicFormComponent } from '../../../../../shared/components/forms/dynamic-form/dynamic-form.component';
import { GridComponent } from '../../../../../shared/components/grid/grid.component';
import { DEFAULT_SYSTEM_ID } from '../../../../../core/models';
import { TranslatePipe } from '@ngx-translate/core';

@Component({
  selector: 'app-user-roles-section',
  imports: [
    CommonModule,
    ButtonModule,
    GridComponent,
    DynamicFormComponent,
    FontAwesomeModule,
    TranslatePipe,
  ],
  templateUrl: './user-roles-section.component.html',
  styleUrl: './user-roles-section.component.scss',
})
export class UserRolesSectionComponent extends EntitySectionBaseComponent<
  UserListItem | Partial<UserCreateRequest>
> {
  readonly ownerId = input<string | null>(null);
  private readonly accountsService = inject(AccountsService);
  private readonly cdr = inject(ChangeDetectorRef);

  faUserLock = faUserLock;

  readonly userRoleDetails = computed(() => {
    const userRoles: IdName[] = this.entity()?.roles;

    if (!isDefined(userRoles)) {
      return [];
    }
    return [
      {
        key: 'Roles',
        value: isEmpty(userRoles)
          ? this.translate.instant('SHARED.COMMON.NONE')
          : userRoles.map((role) => role.name).join(', '),
      },
    ];
  });
  protected readonly selectOptionsLoaded = signal<boolean>(false);
  selectOptions: Record<string, { label: string; value: string }[]> = {};

  private readonly effectiveOwnerId = computed(
    () => this.entity()?.owner?.id ?? this.ownerId(),
  );

  constructor() {
    super();

    // Setup initial columns
    this.columns = [
      { field: 'key', header: '', transform: 'uppercase' },
      { field: 'value', header: '', transform: 'capitalize' },
    ];

    effect(() => {
      const selectOptionsLoaded = this.selectOptionsLoaded();
      if (selectOptionsLoaded) {
        untracked(() => {
          this.updateFormFields();
          this.cdr.detectChanges();
        });
      }
    });

    effect(() => {
      const entity = this.entity();
      if (isDefined(entity) && !this.createMode()) {
        untracked(() => {
          this.updateFormFields();
        });
      }
    });

    effect(() => {
      const ownerId = this.effectiveOwnerId();
      this.selectOptionsLoaded.set(false);
      untracked(() => this.loadSelectOptions(ownerId));
    });
  }

  private loadSelectOptions(ownerId: string | null | undefined): void {
    if (isNullOrUndefined(ownerId)) {
      this.selectOptions = {};
      this.selectOptionsLoaded.set(true);
      this.updateFormFields();
      return;
    }

    this.accountsService.listUserRoles(ownerId, 0, 100).subscribe({
      next: (userRoles) => {
        const hasDefaultSystemId = userRoles.items.some(
          (item) => item.id === DEFAULT_SYSTEM_ID,
        );
        const options = userRoles.items
          .map((item) => ({
            label: item.name ?? '',
            value: item.id,
          }))
          .sort((a, b) => a.label.localeCompare(b.label));

        this.selectOptions = {
          userRoles: hasDefaultSystemId
            ? options
            : [
                { value: DEFAULT_SYSTEM_ID, label: 'Administrator' },
                ...options,
              ],
        };
        this.selectOptionsLoaded.set(true);
      },
      error: () => {
        this.selectOptionsLoaded.set(true);
      },
    });
  }

  protected override updateFormFields(): void {
    this.formFields = [
      createListboxField(
        'roles',
        'Roles',
        this.entity()?.roles?.map((role: IdName) => role.id) ?? [],
        this.selectOptions['userRoles'],
        {
          name: 'userRoles',
          props: {
            checkbox: true,
            multiple: true,
          },
        },
      ),
    ];
  }

  protected override buildUpdateRequest(
    formData: Record<string, unknown>,
  ): Observable<unknown> {
    const userRole = this.entity();
    if (isNullOrUndefined(userRole)) return EMPTY;
    return this.accountsService.updateUser(
      userRole.id,
      this.transformFormData(formData),
    );
  }

  protected override onSubmitSuccess(response: unknown): void {
    const userRole = this.entity();
    if (isNullOrUndefined(userRole)) return;
    this.broadcastService.broadcast('entity-updated', {
      entityType: 'user-role',
      operation: 'update',
      entityId: userRole.id,
      data: response,
    });
  }

  protected override transformFormData(
    formData:
      | Record<string, unknown>
      | Record<string, Record<string, unknown>[]>,
  ) {
    const data = { ...formData };

    if (isDefined(data)) {
      const userRole = this.entity();
      if (isNullOrUndefined(userRole)) return data;

      const roles = data['roles'] as string[];
      if (isDefined(roles)) {
        data['roles'] = roles.map((role) => ({
          id: role,
          name: this.selectOptions['userRoles']?.find(
            (option) => option.value === role,
          )?.label,
        }));
      }
    }
    return data;
  }

  protected override onFormValueChange(
    formData: Record<string, string | number>,
  ): void {
    const transformedData = this.transformFormData(formData);
    this.formValueChange.emit(transformedData);
  }
}
