import { CommonModule } from '@angular/common';
import {
  ChangeDetectorRef,
  Component,
  computed,
  effect,
  inject,
  input,
  OnInit,
  signal,
  untracked,
} from '@angular/core';
import { FormsModule, Validators } from '@angular/forms';

import { EntitySectionBaseComponent } from '../../../components/base/entity-section-base';
import {
  AccountsService,
  AlertCreateRequest,
  AlertListItem,
  AlertNotify,
  AlertResponse,
  EntitiesService,
} from '../../../../../api';
import { isDefined, isNullOrUndefined } from '../../../../../shared/utils';
import {
  ActorNodeData,
  createDropdownField,
  createEventFilterField,
  createIconSelectorField,
  createTextField,
  createTreeSplitButtonListField,
  EventNodeData,
  FilterCondition,
  FormFieldConfig,
  TargetNodeData,
  TreeSelectNode,
} from '../../../../../shared/models';
import { GridComponent } from '../../../../../shared/components/grid/grid.component';
import { DynamicFormComponent } from '../../../../../shared/components/forms/dynamic-form/dynamic-form.component';
import { MultiSelectModule } from 'primeng/multiselect';
import { combineLatest, Observable } from 'rxjs';
import { TreeNode } from 'primeng/api';
import { AuthDataService } from '../../../../../core/services/auth-data.service';
import { AlertIconStorageService } from '../../../../../shared/services/alert-icon-storage.service';
import { findIconEntry } from '../../../../../shared/components/icon-selector/icon-selector.component';
import { EntityOperationRegistryService } from '../../../services/entity/entity-operation-registry.service';
import { EventFilterService } from '../../../../../shared/services/event-filter.service';
import { TranslatePipe } from '@ngx-translate/core';

@Component({
  selector: 'app-alert-details-section',
  imports: [
    CommonModule,
    GridComponent,
    DynamicFormComponent,
    MultiSelectModule,
    FormsModule,
    TranslatePipe,
  ],
  templateUrl: './alert-details-section.component.html',
  styleUrl: './alert-details-section.component.scss',
})
export class AlertDetailsSectionComponent
  extends EntitySectionBaseComponent<
    AlertListItem | Partial<AlertCreateRequest>
  >
  implements OnInit
{
  readonly ownerId = input<string | null>(null);
  private readonly entitiesService = inject(EntitiesService);
  private readonly accountsService = inject(AccountsService);
  private readonly authDataService = inject(AuthDataService);
  private readonly alertIconStorageService = inject(AlertIconStorageService);
  private readonly operationRegistry = inject(EntityOperationRegistryService);
  private readonly eventFilterService = inject(EventFilterService);

  private readonly cdr = inject(ChangeDetectorRef);
  protected readonly selectOptionsLoaded = signal<boolean>(false);

  readonly alertDetails = computed(() => {
    const alertDetails = this.entity();
    this.languageService.currentLanguage();
    if (!isDefined(alertDetails)) return [];

    const filter = isDefined(alertDetails.filter)
      ? this.eventFilterService.getEventFilterText(alertDetails.filter)
      : this.translate.instant('SHARED.COMMON.NONE');

    return [
      {
        key: this.translate.instant('ADMIN.ALERTS.DETAILS.FIELDS.NAME'),
        value: alertDetails.name,
      },
      {
        key: this.translate.instant('ADMIN.ALERTS.DETAILS.FIELDS.ICON'),
        value:
          alertDetails['iconName'] ??
          this.alertIconStorageService.getDefaultIcon(),
      },
      {
        key: this.translate.instant('ADMIN.ALERTS.DETAILS.FIELDS.COST_CENTRE'),
        value:
          alertDetails.costCentre?.name ??
          this.translate.instant('SHARED.COMMON.NONE'),
      },
      {
        key: this.translate.instant('ADMIN.ALERTS.DETAILS.FIELDS.PRIORITY'),
        value: alertDetails.priority
          ? alertDetails.priority.charAt(0).toUpperCase() +
            alertDetails.priority.slice(1)
          : this.translate.instant('SHARED.COMMON.NONE'),
      },
      {
        key: this.translate.instant('ADMIN.ALERTS.DETAILS.FIELDS.FILTER'),
        value: filter ?? this.translate.instant('SHARED.COMMON.NONE'),
      },
      {
        key: this.translate.instant('ADMIN.ALERTS.DETAILS.FIELDS.NOTIFY'),
        value:
          isDefined(alertDetails.notify) && alertDetails.notify.length > 0
            ? alertDetails.notify
                .map((element: AlertNotify) => element.name)
                .join(', ')
            : this.translate.instant('SHARED.COMMON.NONE'),
      },
    ];
  });

  readonly alertIcon = computed(() => {
    const alert = this.entity();
    let iconName: string = alert?.['iconName'];
    if (
      isNullOrUndefined(iconName) ||
      iconName.toLowerCase().trim() === 'default'
    ) {
      iconName = this.alertIconStorageService.getDefaultIcon();
    }
    return iconName;
  });

  readonly resolvedAlertIcon = computed(() => findIconEntry(this.alertIcon() ?? ''));

  selectOptions: Record<string, { label: string; value: string }[]> = {};
  notifyTree = signal<TreeNode[]>([]);

  constructor() {
    super();

    this.columns = [
      { field: 'key', header: '', transform: 'uppercase' },
      { field: 'value', header: '' },
    ];

    // React to entity changes
    effect(() => {
      const entity = this.entity();
      if (entity && !this.createMode()) {
        untracked(() => {
          this.updateFormFields();
          this.cdr.detectChanges();
        });
      }
    });
  }

  ngOnInit() {
    this.loadSelectOptions();
  }

  private loadSelectOptions(): void {
    const asset = this.entity();
    const ownerIdValue = this.ownerId();

    const effectiveOwnerId = asset?.owner?.id ?? ownerIdValue;

    if (isNullOrUndefined(effectiveOwnerId)) {
      this.selectOptions = {};
      this.selectOptionsLoaded.set(true);
      this.updateFormFields();
      return;
    }

    combineLatest([
      this.accountsService.listUserRoles(effectiveOwnerId, 0, 100),
      this.accountsService.listUsers(
        effectiveOwnerId,
        0,
        100,
        undefined,
        'state=active',
      ),
      this.entitiesService.listCostCentres(effectiveOwnerId),
    ]).subscribe({
      next: ([userRoles, users, costCentres]) => {
        this.selectOptions = {
          userRoles: userRoles.items
            .map((item) => ({ label: item.name ?? '', value: item.id }))
            .sort((a, b) => a.label.localeCompare(b.label)),
          users: users.items
            .map((item) => ({ label: item.name ?? '', value: item.id }))
            .sort((a, b) => a.label.localeCompare(b.label)),
          costCentres: costCentres.items
            .map((item) => ({ label: item.name ?? '', value: item.id }))
            .sort((a, b) => a.label.localeCompare(b.label)),
        };
        this.selectOptionsLoaded.set(true);
        const userProfile = this.authDataService.getUserProfile();
        this.notifyTree.set([
          {
            key: `user.${userProfile?.id}`,
            label: this.translate.instant('ADMIN.ALERTS.NOTIFY.ME'),
            selectable: true,
            data: { id: userProfile?.id, type: 'user', name: 'Me' },
          },
          {
            key: 'roles',
            label: this.translate.instant('ADMIN.ALERTS.NOTIFY.ROLES'),
            selectable: false,
            children: userRoles.items.map((role) => ({
              key: role.id,
              label: role.name ?? '',
              selectable: true,
              data: { id: role.id, type: 'role', name: role.name ?? '' },
            })),
          },
          {
            key: 'users',
            label: this.translate.instant('ADMIN.ALERTS.NOTIFY.USERS'),
            selectable: false,
            children: users.items.map((user) => ({
              key: user.id,
              label: user.name ?? '',
              selectable: true,
              data: { id: user.id, type: 'user', name: user.name ?? '' },
            })),
          },
        ]);
        this.updateFormFields();
      },
      error: () => {
        this.selectOptionsLoaded.set(true);
      },
    });
  }

  protected override updateFormFields(): void {
    const alert = this.entity();

    const priorityOptions = [
      {
        label: this.translate.instant('ADMIN.ALERTS.PRIORITIES.LOW'),
        value: 'low',
      },
      {
        label: this.translate.instant('ADMIN.ALERTS.PRIORITIES.MEDIUM'),
        value: 'medium',
      },
      {
        label: this.translate.instant('ADMIN.ALERTS.PRIORITIES.HIGH'),
        value: 'high',
      },
    ];
    this.formFields = [
      createTextField(
        'name',
        this.translate.instant('ADMIN.ALERTS.DETAILS.FIELDS.NAME'),
        alert?.name ?? '',
        {
          name: 'name',
          validations: [
            {
              name: 'required',
              validator: Validators.required,
              message: this.translate.instant(
                'SHARED.COMMON.FORMS.SHARED.REQUIRED',
                {
                  field: this.translate.instant(
                    'ADMIN.ALERTS.DETAILS.FIELDS.NAME',
                  ),
                },
              ),
            },
          ],
        },
      ),
      ...(this.createMode() === false
        ? [
            createIconSelectorField(
              'iconName',
              this.translate.instant('ADMIN.ALERTS.DETAILS.FIELDS.ICON'),
              isNullOrUndefined(alert?.['iconName']) ||
                (alert?.['iconName'] as string).toLocaleLowerCase().trim() ===
                  'default'
                ? this.alertIconStorageService.getDefaultIcon()
                : alert?.['iconName'],
              {
                name: 'iconName',
                hint: this.translate.instant(
                  'ADMIN.ALERTS.DETAILS.FIELDS.ICON_DESCRIPTION',
                ),
              },
            ),
          ]
        : []),
      createDropdownField(
        'costCentre',
        this.translate.instant('ADMIN.ALERTS.DETAILS.FIELDS.COST_CENTRE'),
        this.selectOptions['costCentres'],
        alert?.costCentre?.id ?? '',
        {
          validations: [
            {
              name: 'required',
              validator: Validators.required,
              message: this.translate.instant(
                'SHARED.COMMON.FORMS.SHARED.REQUIRED',
                {
                  field: this.translate.instant(
                    'ADMIN.ALERTS.DETAILS.FIELDS.COST_CENTRE',
                  ),
                },
              ),
            },
          ],
          props: {
            appendTo: 'body',
          },
        },
      ),

      createDropdownField(
        'priority',
        this.translate.instant('ADMIN.ALERTS.DETAILS.FIELDS.PRIORITY'),
        priorityOptions,
        alert?.priority ?? '',
        {
          validations: [
            {
              name: 'required',
              validator: Validators.required,
              message: this.translate.instant(
                'SHARED.COMMON.FORMS.SHARED.REQUIRED',
                {
                  field: this.translate.instant(
                    'ADMIN.ALERTS.DETAILS.FIELDS.PRIORITY',
                  ),
                },
              ),
            },
          ],
          props: {
            appendTo: 'body',
          },
        },
      ),
      createEventFilterField(
        'filter',
        this.translate.instant('ADMIN.ALERTS.DETAILS.FIELDS.FILTER'),
        alert?.filter,
        ['costcentres', 'groups', 'types'],
        {
          name: 'filter',
          required: true,
          validations: [
            {
              name: 'required',
              validator: Validators.required,
              message: this.translate.instant(
                'SHARED.COMMON.FORMS.SHARED.REQUIRED',
                {
                  field: this.translate.instant(
                    'ADMIN.ALERTS.DETAILS.FIELDS.FILTER',
                  ),
                },
              ),
            },
          ],
        },
      ),
      createTreeSplitButtonListField<AlertNotify>(
        'notify',
        this.translate.instant('ADMIN.ALERTS.DETAILS.FIELDS.NOTIFY'),
        alert?.notify ?? [],
        this.notifyTree(),
        {
          name: 'notify',
          props: {
            appendTo: 'body',
          },
          transformTreeNodeToItem: (node: TreeNode) =>
            this.transformTreeNodeToItem(node),
          listItemFormatter: (item: AlertNotify) => {
            return {
              id: `${item.type}-${item.id}`,
              display: item.name || item.id,
              title: item.type
                ? item.type.charAt(0).toUpperCase() + item.type.slice(1)
                : 'Item',
              icon: item.type === 'user' ? 'pi-user' : 'pi-users',
            };
          },
          addButtonLabel: this.translate.instant('SHARED.COMMON.BUTTONS.ADD'),
        },
      ) as FormFieldConfig<unknown>,
    ];
  }

  override getUpdateMethod(): (
    id: string,
    data: Partial<AlertResponse | AlertCreateRequest>,
  ) => Observable<AlertResponse> {
    return (
      this.operationRegistry.getOperation<
        AlertResponse | AlertCreateRequest,
        AlertCreateRequest,
        AlertResponse,
        'update'
      >('alert', 'update') ??
      ((id, data) => this.entitiesService.updateAlert(id, data))
    );
  }

  protected override onFormValueChange(
    formData: Record<string, string | number | object | null | undefined>,
  ): void {
    const transformedData = this.transformFormData(formData);

    this.formValueChange.emit(transformedData);
  }

  protected override transformFormData(
    formData: Record<string, string | number | object | null | undefined>,
  ): Record<string, string | number | object | null | undefined> {
    const transformedData = { ...formData };

    // Transform costCentre ID to IdName object
    if (isDefined(transformedData['costCentre'])) {
      const costCentreOption = this.selectOptions?.['costCentres']?.find(
        (option) => option.value === transformedData['costCentre'],
      );

      if (costCentreOption) {
        transformedData['costCentre'] = {
          id: costCentreOption.value,
          name: costCentreOption.label,
        };
      }
    }

    // Transform filter TreeSelectNode structure to EventFilter structure
    if (isDefined(transformedData['filter'])) {
      const filter = transformedData['filter'] as {
        actor: TreeSelectNode<ActorNodeData> | undefined;
        action: TreeSelectNode<EventNodeData> | undefined;
        target: TreeSelectNode<TargetNodeData> | undefined;
        conditions: FilterCondition[];
      };
      transformedData['filter'] = {
        ...filter,
        actor: filter?.['actor']?.['data'],
        action: filter?.['action']?.['data'],
        target: filter?.['target']?.['data'],
        conditions: filter?.['conditions']?.map((condition) => {
          const { id: _, ...rest } = condition;
          return rest;
        }),
      };
    }

    // Ensure notify is an array of AlertNotify objects (not a string)
    if (isDefined(transformedData['notify'])) {
      const notifyValue = transformedData['notify'];

      // If it's already an array, keep it as is
      if (Array.isArray(notifyValue)) {
        transformedData['notify'] = notifyValue;
      }
      // If it's a single object (AlertNotify), convert to array
      else if (
        typeof notifyValue === 'object' &&
        notifyValue !== null &&
        'id' in notifyValue &&
        'type' in notifyValue
      ) {
        transformedData['notify'] = [notifyValue as AlertNotify];
      }
      // Otherwise (string or invalid), set to empty array
      else {
        transformedData['notify'] = [];
      }
    } else {
      // Ensure notify exists and is an empty array if not provided
      transformedData['notify'] = [];
    }

    return transformedData;
  }

  notifyToTreeItem(notify: AlertNotify): TreeNode {
    const notifyType = notify.type;
    const notifyId = notify.id;

    if (notifyType === 'user') {
      const user = this.authDataService.getUserProfile();
      return {
        key: `user.${user?.id}`,
        label: user?.name ?? '',
      };
    }

    return {
      key: `notify.${notifyId}`,
      label: notify?.name ?? '',
    };
  }

  transformTreeNodeToItem(node: TreeNode): AlertNotify {
    if (
      isDefined(node.data) &&
      typeof node.data === 'object' &&
      'id' in node.data &&
      'type' in node.data
    ) {
      // If node.data is already an AlertNotify object (recommended)
      return node.data as AlertNotify;
    }

    // Fallback/example logic if node.data is not directly the AlertNotify object.
    // You'll need to adapt this based on your TreeNode structure in notifyTree().
    // For instance, if 'Me' is type 'user' and its key is the user ID:
    if (node.label === 'Me') {
      // Example for 'Me'
      const userProfile = this.authDataService.getUserProfile(); // Assuming you have authDataService
      return { id: userProfile?.id ?? 'me', type: 'user', name: 'Me' };
    }

    // Example for roles or users based on parent key or node key structure
    let type: 'user' | 'role' = 'user'; // Default
    const id = node.key ?? 'unknown_id';
    const name = node.label ?? 'Unknown Name';

    if (
      node.parent?.key === 'roles' ||
      (node.key?.startsWith('role_') ?? false)
    ) {
      type = 'role';
    }
    // No need to assign 'user' again as it's already the default
    // This is a simplified example; ensure your logic correctly maps TreeNodes to AlertNotify.
    return { id, type, name };
  }
}
