import { CommonModule } from '@angular/common';
import {
  Component,
  computed,
  effect,
  inject,
  input,
  signal,
} from '@angular/core';
import { Validators } from '@angular/forms';
import { EMPTY, Observable } from 'rxjs';

import { ButtonModule } from 'primeng/button';
import { MessageModule } from 'primeng/message';
import { v4 as uuidv4 } from 'uuid';

import {
  AssetRatingProfileListItem,
  AssetRatingProfileCreateRequest,
  EntitiesService,
  AssetRatingPenalty,
} from '../../../../../api';
import { DynamicFormComponent } from '../../../../../shared/components/forms/dynamic-form/dynamic-form.component';
import { ModalListFormComponent } from '../../../../../shared/components/forms/modal-list-form/modal-list-form.component';
import { GridComponent } from '../../../../../shared/components/grid/grid.component';
import {
  ListFieldModalConfig,
  FormFieldConfig,
  createTextField,
  createNumberField,
  createModalListField,
  createEventFilterField,
  ActorNodeData,
  EventNodeData,
  FilterCondition,
  TargetNodeData,
  TreeSelectNode,
} from '../../../../../shared/models';
import {
  isDefined,
  isEmpty,
  isNullOrUndefined,
} from '../../../../../shared/utils';
import { EntitySectionBaseComponent } from '../../base';
import { TranslatePipe } from '@ngx-translate/core';

type FormDataValue = string | number | object | null | undefined;
@Component({
  selector: 'app-asset-rating-profile-details-section',
  imports: [
    CommonModule,
    ButtonModule,
    GridComponent,
    DynamicFormComponent,
    MessageModule,
    TranslatePipe,
  ],
  templateUrl: './asset-rating-profile-details-section.component.html',
  styleUrl: './asset-rating-profile-details-section.component.scss',
})
export class AssetRatingProfileDetailsSectionComponent extends EntitySectionBaseComponent<
  AssetRatingProfileListItem | Partial<AssetRatingProfileCreateRequest>
> {
  readonly ownerId = input<string | null>(null);
  private readonly entitiesService = inject(EntitiesService);

  readonly assetRatingProfileDetails = computed(() => {
    const assetRatingProfileDetails = this.entity();
    this.languageService.currentLanguage();
    if (!isDefined(assetRatingProfileDetails)) return [];

    return [
      {
        key: this.translate.instant(
          'ADMIN.ASSET_RATING_PROFILES.DETAILS.FIELDS.NAME',
        ),
        value: assetRatingProfileDetails.name,
      },
      {
        key: this.translate.instant(
          'ADMIN.ASSET_RATING_PROFILES.DETAILS.FIELDS.PENALTIES',
        ),
        value: isEmpty(assetRatingProfileDetails.items)
          ? this.translate.instant('SHARED.COMMON.NONE')
          : assetRatingProfileDetails.items
              ?.map((item) => item.name)
              .join(', '),
      },
    ];
  });
  assetRatingProfilePenaltyModalConfig:
    | ListFieldModalConfig<AssetRatingPenalty>
    | undefined;
  protected readonly warning = signal<string | null>(null);

  constructor() {
    super();

    // Setup initial columns
    this.columns = [
      { field: 'key', header: '', transform: 'uppercase' },
      { field: 'value', header: '' },
    ];

    effect(() => {
      const assetRatingProfileDetails = this.entity();
      if (
        isNullOrUndefined(assetRatingProfileDetails?.items) ||
        assetRatingProfileDetails.items.length < 1
      ) {
        this.warning.set(
          this.translate.instant(
            'ADMIN.ASSET_RATING_PROFILES.WARNINGS.ITEM_LENGTH',
          ),
        );
      } else {
        this.warning.set(null);
      }
    });
  }

  protected override updateFormFields(): void {
    const assetRatingProfile = this.entity();

    this.assetRatingProfilePenaltyModalConfig = {
      modalComponent: ModalListFormComponent,
      modalTitle: this.translate.instant(
        'ADMIN.ASSET_RATING_PROFILES.DETAILS.MODALS.STATE.TITLE',
      ),
      defaultItemProvider: () => ({
        id: uuidv4(),
        name: '',
        max: 100,
        offset: undefined,
        penalty: 1,
        cost: undefined,
      }),
      listItemFormatter: (item: AssetRatingPenalty) =>
        this.stateItemToListItem(item),
      modalFields: (
        _item: AssetRatingPenalty | undefined,
      ): FormFieldConfig[] => {
        return [
          createTextField('id', 'ID', _item?.id, {
            name: 'id',
            hidden: true,
          }),
          createTextField(
            'name',
            this.translate.instant(
              'ADMIN.ASSET_RATING_PROFILES.DETAILS.FIELDS.NAME',
            ),
            _item?.name,
            {
              name: 'name',
              validations: [
                {
                  name: 'required',
                  validator: Validators.required,
                  message: this.translate.instant(
                    'SHARED.COMMON.FORMS.SHARED.REQUIRED',
                    {
                      field: this.translate.instant(
                        'ADMIN.ASSET_RATING_PROFILES.DETAILS.FIELDS.NAME',
                      ),
                    },
                  ),
                },
              ],
            },
          ),
          createNumberField(
            'penalty',
            this.translate.instant(
              'ADMIN.ASSET_RATING_PROFILES.DETAILS.FIELDS.PENALTY',
            ),
            undefined,
            {
              name: 'penalty',
              validations: [
                {
                  name: 'required',
                  validator: Validators.required,
                  message: this.translate.instant(
                    'SHARED.COMMON.FORMS.SHARED.REQUIRED',
                    {
                      field: this.translate.instant(
                        'ADMIN.ASSET_RATING_PROFILES.DETAILS.FIELDS.PENALTY',
                      ),
                    },
                  ),
                },
                {
                  name: 'min',
                  validator: Validators.min(1),
                  message: this.translate.instant(
                    'SHARED.COMMON.FORMS.NUMBER.MIN',
                    {
                      field: this.translate.instant(
                        'ADMIN.ASSET_RATING_PROFILES.DETAILS.FIELDS.PENALTY',
                      ),
                      min: 1,
                    },
                  ),
                },
                {
                  name: 'max',
                  validator: Validators.max(100),
                  message: this.translate.instant(
                    'SHARED.COMMON.FORMS.NUMBER.MAX',
                    {
                      field: this.translate.instant(
                        'ADMIN.ASSET_RATING_PROFILES.DETAILS.FIELDS.PENALTY',
                      ),
                      max: 100,
                    },
                  ),
                },
              ],
              layout: 'horizontal',
              labelWidth: '1/3',
            },
          ),
          createNumberField(
            'max',
            this.translate.instant(
              'ADMIN.ASSET_RATING_PROFILES.DETAILS.FIELDS.MAX_PENALTY',
            ),
            undefined,
            {
              name: 'max',
              validations: [
                {
                  name: 'required',
                  validator: Validators.required,
                  message: this.translate.instant(
                    'SHARED.COMMON.FORMS.SHARED.REQUIRED',
                    {
                      field: this.translate.instant(
                        'ADMIN.ASSET_RATING_PROFILES.DETAILS.FIELDS.MAX_PENALTY',
                      ),
                    },
                  ),
                },
                {
                  name: 'min',
                  validator: Validators.min(1),
                  message: this.translate.instant(
                    'SHARED.COMMON.FORMS.NUMBER.MIN',
                    {
                      field: this.translate.instant(
                        'ADMIN.ASSET_RATING_PROFILES.DETAILS.FIELDS.MAX_PENALTY',
                      ),
                      min: 1,
                    },
                  ),
                },
                {
                  name: 'max',
                  validator: Validators.max(100),
                  message: this.translate.instant(
                    'SHARED.COMMON.FORMS.NUMBER.MAX',
                    {
                      field: this.translate.instant(
                        'ADMIN.ASSET_RATING_PROFILES.DETAILS.FIELDS.MAX_PENALTY',
                      ),
                      max: 100,
                    },
                  ),
                },
              ],
              layout: 'horizontal',
              labelWidth: '1/3',
            },
          ),
          createNumberField(
            'cost',
            this.translate.instant(
              'ADMIN.ASSET_RATING_PROFILES.DETAILS.FIELDS.COST',
            ),
            undefined,
            {
              name: 'cost',
              validations: [
                {
                  name: 'required',
                  validator: Validators.required,
                  message: this.translate.instant(
                    'SHARED.COMMON.FORMS.SHARED.REQUIRED',
                    {
                      field: this.translate.instant(
                        'ADMIN.ASSET_RATING_PROFILES.DETAILS.FIELDS.COST',
                      ),
                    },
                  ),
                },
                {
                  name: 'min',
                  validator: Validators.min(0),
                  message: this.translate.instant(
                    'SHARED.COMMON.FORMS.NUMBER.MIN',
                    {
                      field: this.translate.instant(
                        'ADMIN.ASSET_RATING_PROFILES.DETAILS.FIELDS.COST',
                      ),
                      min: 0,
                    },
                  ),
                },
                {
                  name: 'max',
                  validator: Validators.max(1000000),
                  message: this.translate.instant(
                    'SHARED.COMMON.FORMS.NUMBER.MAX',
                    {
                      field: this.translate.instant(
                        'ADMIN.ASSET_RATING_PROFILES.DETAILS.FIELDS.COST',
                      ),
                      max: 1000000,
                    },
                  ),
                },
              ],
              layout: 'horizontal',
              labelWidth: '1/3',
            },
          ),
          createEventFilterField(
            'filter',
            this.translate.instant(
              'ADMIN.ASSET_RATING_PROFILES.DETAILS.FIELDS.FILTER',
            ),
            undefined,
            ['costcentres', 'groups', 'types'],
            {
              name: 'filter',
              required: true,
              validations: [
                {
                  name: 'required',
                  validator: Validators.required,
                  message: this.translate.instant(
                    'SHARED.COMMON.FORMS.SHARED.REQUIRED',
                    {
                      field: this.translate.instant(
                        'ADMIN.ASSET_RATING_PROFILES.DETAILS.FIELDS.FILTER',
                      ),
                    },
                  ),
                },
              ],
            },
          ),
        ];
      },
      subHeader: this.translate.instant(
        'ADMIN.ASSET_RATING_PROFILES.DETAILS.MODALS.STATE.DESCRIPTION',
      ),
    };
    this.formFields = [
      createTextField(
        'name',
        this.translate.instant(
          'ADMIN.ASSET_RATING_PROFILES.DETAILS.FIELDS.NAME',
        ),
        assetRatingProfile?.name,
        {
          name: 'name',
          validations: [
            {
              name: 'required',
              validator: Validators.required,
              message: this.translate.instant(
                'SHARED.COMMON.FORMS.SHARED.REQUIRED',
                {
                  field: this.translate.instant(
                    'ADMIN.ASSET_RATING_PROFILES.DETAILS.FIELDS.NAME',
                  ),
                },
              ),
            },
          ],
        },
      ),
    ];

    if (!this.createMode()) {
      this.formFields.push(
        createModalListField<AssetRatingPenalty>(
          'items',
          this.translate.instant(
            'ADMIN.ASSET_RATING_PROFILES.DETAILS.FIELDS.PENALTIES',
          ),
          assetRatingProfile?.items ?? [],
          {
            layout: 'horizontal',
            labelWidth: '1/3',
            name: 'items',
            props: {
              modalConfig: this.assetRatingProfilePenaltyModalConfig,
            },
          },
        ) as FormFieldConfig<unknown>,
      );
    }
  }

  protected override buildUpdateRequest(
    formData: Record<string, FormDataValue>,
  ): Observable<unknown> {
    const assetRatingProfile = this.entity();
    if (isNullOrUndefined(assetRatingProfile)) return EMPTY;
    return this.entitiesService.updateAssetRatingProfile(
      assetRatingProfile.id,
      this.transformFormData(formData),
    );
  }

  protected override onSubmitSuccess(response: unknown): void {
    const assetRatingProfile = this.entity();
    if (isNullOrUndefined(assetRatingProfile)) return;
    this.broadcastService.broadcast('entity-updated', {
      entityType: 'asset-rating-profile',
      operation: 'update',
      entityId: assetRatingProfile.id,
      data: response,
    });
  }

  stateItemToListItem(item: AssetRatingPenalty) {
    const costString = item.cost ? `, cost ${item.cost}` : '';
    const display = `${item.penalty} (${item.max} max${costString})`;
    return {
      id: item.id,
      title: item.name,
      display,
      icon: 'pi pi-star',
    };
  }

  protected override onFormValueChange(
    formData: Record<string, FormDataValue>,
  ): void {
    const transformedData = this.transformFormData(formData);

    this.formValueChange.emit(transformedData);
  }

  protected override transformFormData(
    formData: Record<string, FormDataValue>,
  ): Record<string, FormDataValue> {
    const transformedData = { ...formData };

    // Transform each item in the "items" array (normalize name/state and filter)
    if (Array.isArray(transformedData['items'])) {
      transformedData['items'] = (
        transformedData['items'] as Record<string, unknown>[]
      ).map((item) => {
        const transformedItem: Record<string, unknown> = { ...item };

        // Transform nested filter
        if (isDefined(transformedItem['filter'])) {
          const filter = transformedItem['filter'] as {
            actor?: TreeSelectNode<ActorNodeData>;
            action?: TreeSelectNode<EventNodeData>;
            target?: TreeSelectNode<TargetNodeData>;
            conditions?: FilterCondition[];
          };

          transformedItem['filter'] = {
            ...filter,
            actor: filter?.actor?.data,
            action: filter?.action?.data,
            target: filter?.target?.data,
            conditions:
              filter?.conditions?.map(({ id: _id, ...rest }) => rest) ?? [],
          };
        }

        return transformedItem;
      });
    }

    return transformedData;
  }
}
